(7, 1523543833, '94.240.245.46', 1, 'სახელი გვარი', 'nope', 'test@gmail.com', 'სდლკფსკლდ მკდსფ მკსდფლკსმდფკ ჯნსდკჯფ ნსდჯკფ ნსდკჯფ ', 'ge', 1, 1),
