(9, 1525438074, '213.131.47.118', 1, 'შორენა ტორუა', 'nope', 'shtorua@hotmail.com', 'გამარჯობათ ქუთაისში ან ქობულეთში ხო არ გაქვთ ფილიალიი', 'ge', 1, 1),
(10, 1528853990, '31.146.93.135', 1, 'Tea', 'nope', 't.sibashvili@yahoo.com', 'გამარჯობათ.\n\n თქვენთან ისწავლება HR management? თუ ისწავლება რა დონეზე- ბაკალავრიატის, მაგისტრის თუ უბრალოდ სერტიფიცირებული კურსებია?\n\nასევე მაინტერესებს რა ღირს სწავლება HR Management პროგრამის და რამდენ ხანს გრძელდება?\n\n  მადლობთ\n \n', 'ge', 1, 1),
(11, 1530896546, '94.100.224.174', 1, 'სოფიკო ანსიანი', 'nope', 'sofia.ansiani@gmail.com', 'გთხოვთ გადმომიგზავნოთ ექსელის შემდეგი კურსების სილაბუსები, დაწყების თარიღი თუ არის ცნობილი, ღირებულება და რომელ საათებში ტარდება:\nმაღალი დონე- Advanced Level;\nVBA კურსი;\nბიზნეს მოდელირება და მონაცემთა ანალიზი ექსელში;', 'ge', 1, 1),
(12, 1537462022, '212.58.114.237', 1, 'გურამ საღრიშვილი', 'nope', 'gurami.sagrishvili@bk.ru', 'გამარჯობათ მე ვარ 13 წლის  თუ შეიძლება ჩემი ასაკის ადამიანისთვის თქვენთან ტრენინგებზე სიარული და თუკი შეიძლება რა ღირს', 'ge', 1, 1),
(13, 1540368942, '94.100.224.60', 1, 'ხათუნა ბოლქვაძე', 'nope', 'g.bolkvadze@yandex.ru', 'გამარჯობათ, მაინტერესებს სასტუმროს მენეჯმენტის კურსი, როდის დაიწყება მომდევნო ჯგუფის სწავლება და რა ტიპის სერტიფიკატს გასცემთ? არის თუ არა ორენოვანი? მადლობთ', 'ge', 1, 1),
(14, 1548268180, '93.177.181.100', 1, 'ბერტა ქობალია', 'nope', 'bkobalia@mail.ru', 'ვფლობ რუსულ და ინგლისურ ენებს კარგ დონეზე. ასევე კომპიუტერის საოფისე პროგრამებს. მაქვს სკოლაში მუშაობის გამოცდილება. ვმუშაოდბი ინგლისური ენის პედაგოგად. \nასევე ვმუშაობდი სხვადა სხვა ორგანიზაციაში კომპიუტერის კურსის ტრენერად.  ვიმუშავებდი რუსული ან ინგლისური ენის კურსის  ტრენერად, ან კომპიუტერის კურსის ტრენერად. \nუმორჩილესად გთხოვთ, თუ რამე ვაკანსია გექნებათ, გამომეხმაურეთ.\nწინასწარ გიხდით უზარმაზარ მადლობას.  T - 599 21 81 85.', 'ge', 1, 1),
(15, 1548659116, '93.177.181.100', 1, 'ბერტა ქობალია', 'nope', 'bkobalia@mail.ru', 'სასტუმროს მენეჯმენტის კურსზე ჩაწერა.\nჩემი მონაცემები.  \nსახელი: ბერტა, \nგვარი: ქობალია.\nT. - 599 21 81 85', 'ge', 1, 1),
(16, 1557425811, '37.215.14.172', 1, '', 'nope', 'tatiana.centr@yandex.ru', 'Добрый день! Я представляю «Центр охраны труда и промышленной безопасности». Это Беларусь, город Минск. Скажите, будут ли интересные мероприятия в Тбилиси, посвященные охране труда и промышленной безопасности,с 18 августа по 25 августа 2019 года? Это могут быть: семинары, выставки, тренинги, дебаты, обучение. Мы хотим отправить нашего специалиста в вашу прекрасную страну, с пользой для него', 'ge', 1, 1),
(17, 1559893157, '213.131.57.77', 1, 'ნინო მარტიაშვილი ', 'nope', 'nino.martiashvili.97@mail.ru', 'გამარჯობა , მაინტერესებს ამ ეტაპზე მიმდინარეობს თუ არა საოფისე პროგრამებზე რეგისტრაცია და  გადასახადის 2 ნაწილად გადახდა შეიძლება თუ არა . \nმადლობა.', 'ge', 1, 1),
(18, 1566240829, '37.232.64.14', 1, 'მანანა მახარაშვილი', 'nope', 'manana.makharashvili@gmail.com', 'გამარჯობა, \nმაინტერესებს, როდის იწყება მორიგი კურსი \"სამედიცინო ხარისხის კონტროლი\"?\nთუ არ შეგაწუხებთ, იქნებ ინფორმაცია სატელეფონო ზარით შემატყობინოთ 599 43 58 81\n\nწინასწარ დიდი მადლობა.', 'ge', 1, 1),
(19, 1578153424, '94.137.170.157', 1, 'ნიკა გუბელიძე', 'nope', 'nika.gubelidze@magticom.ge', 'მოგესალმებით , მაინტერესებს ისევ თუ გაქვთ c c++ კურსი ? ასევე კურსის ხანგრძლივობა თანხა და ვინ არის ლექტორი ? \nპატივისცემით , \n            ნიკა გუბელიძე ', 'ge', 1, 1),
(20, 1580203210, '109.172.207.110', 1, 'დიანა ბიგანაშვილი', 'nope', 'diana.biganashvili@yandex.ru', 'მიგესალმებით !\n\nმინდა თქვენთან გავიარო ტურ-ოპერატირის კურსები...ჯგუფში...მაწყობს საღამოს საათები...18:00 მერე...\n\n\nპატივისცემით, \n\n 593 71 22 71 დიანა \n\n', 'ge', 1, 0),
(21, 1580406420, '176.221.228.158', 1, 'nika dolidze', 'nope', 'n.dolidze97@gmail.com', 'გამარჯობა\nექსელის კურსები როდიდან ოწყება ?', 'ge', 1, 0),
(22, 1581432015, '91.184.107.171', 1, 'Maka Papiashvili', 'nope', 'makapapiashvili7@gmail.com', 'გამარჯობა, რა ჯდება თქვენთან ფარმაციის სრული კურსი ? ', 'ge', 1, 0),
(23, 1591393552, '31.146.226.206', 1, 'ნინო ბარამიძე', 'nope', 'ninibaramidze20@gmail.com', 'გამარჯობა, მჭირდება დახმარება სპსს-ით მონაცემების დამუშავება, ანალიზში, თუ გაქვთ თქვენ სერვისი, რომელიც დამიმუშავებს მონაცემებს, პატარა კვლევაა, არ ვიცი დამუშავება და მჭირდება :)', 'ge', 1, 1),
(24, 1597764591, '188.169.18.139', 1, 'ეკატერინე ყოლბაია', 'nope', 'ekayolbaia@gmail.com', 'მაინტერესებს როდიდან იწყება ფინანსური მენეჯმენტი IFRS for SMEs ის კურსები?', 'ge', 1, 0),
(25, 1600866557, '188.169.174.20', 1, 'tamuna kolbaia', 'nope', 'kolbaiatamuna1982@gmail.com', 'gamarjobat, tqveni gancxadeba vnaxe HR-ze HR ადამიანური რესურსების სტრატეგიული მართვის სასწავლო კურსი\nVIP Intellect Group da maainteresebs kvirashi ramdeni dgea swavleba? da ramdeni leqcia shedis 450 larshi?\ngmadlobt', 'ge', 1, 1),
(26, 1604770206, '212.58.121.217', 1, 'ივერი', 'nope', 'imdivnishvili47@gmail.com', 'მოგესალმებით, \n\nარის თუ არა დაგეგმილი ფარმაკოლოგიის კურსის ჩატარება წლის ბოლომდე, ან მომდევნო წელში?', 'ge', 1, 0),
(27, 1605715754, '176.221.253.71', 1, 'თორნიკე გაგოშიძე', 'nope', 'levanmghebrishvili@yahoo.com', 'გამარჯობა დედა ', 'ge', 1, 1),
