(49, 2, 1, 1523102602, 0, 'news', 'News', '<p>სიახლეები</p>', '<p>სიახლეები</p>', 'news', 'news', '', '', 'en', 1, 0, 0),
(2, 1, 0, 1504340572, 0, 'plugin', 'Home', '<p>Home Page</p>', '<p>Home Page</p>', 'home', 'false', '', '', 'en', 1, 0, 0),
(3, 1, 0, 1504340572, 0, 'plugin', 'მთავარი', '<p>შპს \"VIP Intellect Group\" გამორჩეული მრავალპროფილიანი სასწავლო ცენტრია საქართველოში, ჩვენი&nbsp;გუნდი უკვე&nbsp;21 წელია ატარებს ტრენინგებს სხვადასხვა მიმართულებით. უკვე ასობით ადგილობრივი თუ საერთაშორისო კომპანიის კადრი&nbsp;არის ჩვენი&nbsp;კურსდამთავრებული.</p>\n<p>ჩვენი მიზანია მივცეთ მსმენელებს პრაქტიკული უნარ-ჩვევები, რათა დამოუკიდებლად შეძლონ თავის დამკვიდრება სასურველ სფეროში!</p>\n<p>ჩვენთან მიღებული ცოდნის შედეგად კურსდამთავრებულები მნიშვნელოვნად აუმჯობესებენ საქმანობას სხვადასხვა სფეროში.</p>', '<p>მიზანი</p>', 'home', '', '', '', 'ge', 1, 0, 0),
(78, 16, 14, 1523108335, 0, 'text', 'ვებ გვერდების დამზადება', '<p>ვებ გვერდების დამზადება</p>', '<p><br />VIP Intellect Group-ის ვებ სტუდია გთავაზობთ პროფესიონალური დონის ვებ გვერდების დამზადებას!</p>\n<p>ჩვენი პროგრამისტების მიერ უკვე დამზადებულია მრავალი ვებ გვერდი სხვადასხვა წამყვანი კომპანიებისთვის!</p>\n<p>ვებ-გვერდი სულ უფრო მოთხოვნადი პროდუქტი ხდება მსოფლიო მასშტაბით, ვინაიდან წარმატებული ბიზნესი დღეს უკვე წარმოუდგენელია საკუთარი ვირტუალური სივრცის გარეშე, გსურთ გაზარდოთ თქვენი ორგანიზაციის იმიჯი და ინტერესი თქვენი კომპანიის და საქმიანობის მიმართ - Vip Intellect Group-is დიზაინერთა და ვებ-დეველოპერთა ჯგუფი გთავაზობთ პროფესიონალური დონის ვებ გვერდების შექმნას და განახლებას ხელმისაწვდომ ფასად. ჩვენი სპეციალისტები ხელმძღვანელობენ ყველა იმ ასპქეტით, რაც ქმნის საიტს საიმედოს, წარმატებულსა და საჭიროს. </p>\n<p>სერვისის სრული პაკეტი მოიცავს შემდეგ მომსახურებებს:<br /><strong>&bull; ვებ-გვერდების დამზადებას;</strong><br /><strong>&bull; ვებ-გვერდების მხარდაჭერას;</strong><br /><strong>&bull; ვებ-გვერდების შემდგომ განვითარებას.</strong></p>\n<p><strong>ვებ-გვერდის დამზადება</strong><br />ჩვენი ვებ დიზაინერები აკეთებენ ყველაფერს იმისათვის, რომ საიტის დიზაინი და პროგრამული კოდი პასუხობდეს მის წინაშე წაყენებულ ყველა მოთხოვნას და შეესაბამებოდეს დამკვეთის სურვილებთან სრულ შესაბამისობაში. გამოცდილება, მაღალი მოტივაცია და პროფესიონალიზმი გვაძლევს საშუალებას შევქმნათ წარმატებული ინტერნეტ-გვერდები.<br /><strong>ვებ-გვერდის მხარდაჭერა</strong><br />საიტის გამართული ფუნქციონირებისათვის აუცილებელია მისი პერმანენტული, კომპლექსური მხარდაჭერა რაც მოიცავს, როგორც სუფთა ტექნიკურ, როგორიცაა ტექნიკური აუდიტი, საიტის მუშაობის მონიტორინგი, ასევე მარკეტინგულ მომსახურებათა ერთობლიობას, როგორიცაა ბანერების დამზადება, საიტის ტექსტების მომზადება, განთავსება და ა.შ.<br /><strong>ვებ-გვერდის განვითარება</strong><br />ჩვენ გთავაზობთ ვებ-გვერდების განვითარების და ოპტიმიზაციის ისეთ მექანიზმებს, როგორებიცაა საძიებო ოპტიმიზაცია (SEO) და ინტერნეტ მარკეტინგი.</p>', 'consult-develop-website', '', '', '', 'ge', 2, 0, 0),
(77, 16, 14, 1523108335, 0, 'text', 'Web pages creation', '<p>ვებ გვერდების დამზადება</p>', '<p>ვებ გვერდების დამზადება</p>', 'consult-develop-website', 'false', '', '', 'en', 2, 0, 0),
(76, 15, 14, 1523108053, 0, 'text', 'საბუღალტრო მომსახურება', '<p>საბუღალტრო მომსახურება კონსულტაცია&nbsp;</p>', '<p>შპს ,,VIP Intellect Group&rdquo; პრაქტიკოს ბუღალტრებთან ერთად გთავაზობთ ბუღალტრულ მომსახურების სრულ სერვისს:</p>\n<p><br />&bull; თქვენი ბუღალტერიის წარმოებას პირველადი დოკუმეტაციების საფუძველზე.<br />&bull; დამწყები ბუღალტრებისთვის - ახალი ორგანიზაციის შექმნას და საწყისი ნაშთების შეყვანა-დალაგებას, ხელშეკრულებების, ინვოისების, ბრძანებების და აქტების წარმოებას. <br />&bull; კომპიუტერულ პროგრამაში: ორისი, 1C - ბუღალტერული მონაცემების წარმოება და დალაგებას. <br />&bull; ელექტრონული დეკლარაციების ყვეეთვიურ და წლიურ წარმოებას. <br />&bull; ერთჯერად კონსულტაციებს. <br />&bull; პატარა ორგანიზაციისთვის ექსელის გამოყენებით სპეციალური საბუღალტრო პროგრამის შექმნას, ადვილად რომ აწარმოოთ დოკუმენტაცია.</p>\n<p>მომსახურებას გაგიწევენ პრაქტიკოსი, კვალიფიციური ბუღალტრები!</p>', 'consult-account', '', '', '', 'ge', 1, 0, 0),
(247, 101, 14, 1524030291, 0, 'text', 'Financial services', '', '<p>ფინანსური მომსახურება</p>', 'finansial-service', 'contactdetails', '', '', 'en', 3, 0, 0),
(248, 101, 14, 1524030291, 0, 'text', 'ფინანსური მომსახურება', '<p>ფინანსური მომსახურება კონსულტაცია</p>', '<p><br />VIP Intellect Group-ის ვებ სტუდია გთავაზობთ პროფესიონალური დონის ფინანსურ მომსახურებას!</p>\n<p>ფინანსური ანგარიშგებების წარმოება<br />მოგება-ზარალის უწყისი<br />საბალანსო ანგარიშგება<br />ფულადი მოძრაობის ანგარიშგება<br />ფინანსური ანალიზი<br />ფინანსური რისკები<br />ნებისმიერი სხვა სახის ფინანსური კონსულტაცია</p>', 'finansial-service', '', '', '', 'ge', 3, 0, 0),
