INSERT INTO `navigation` (`id`, `idx`, `cid`, `date`, `nav_type`, `type`, `title`, `description`, `text`, `slug`, `usefull_type`, `cssclass`, `redirect`, `lang`, `position`, `visibility`, `status`) VALUES
(144, 49, 40, 1523699102, 0, 'text', 'სასაუბრო ინგლისური', '<p>general english სასაუბრო ინგლისური ინგლისურის შემსწავლელი კურსები ტრენინგ ცენტრი სასწავლო ცენტრი ინგლისური&nbsp;</p>', '<p>ლექციები მიმდინარეობს ინგლისურ ენაზე<br /><strong>General English</strong></p>\n<p><strong>მიზანი:</strong> მსმენელის მიერ შესაფერისი დონის ლექსიკისა და გრამატიკის დაუფლება, ასევე ინგლისური ენის ოთხი ძირითადი უნარის &ndash; კითხვა, საუბარი, წერა და მოსმენა &ndash; განვითარება.</p>\n<p><strong>კონკრეტული მიზნები:</strong><br />&bull; გრამატიკული კონსტრუქციების გაგება და სწორად გამოყენება პრაქტიკაში &ndash; ცოდნის გადატანა თეორიიდან რეალურ კომუნიკაციაში;<br />&bull; ლექსიკური მარაგის გაფართოება და განმტკიცება &ndash; ახალი სიტყვების აქტიურად გამოყენება სხვადასხვა ტიპის დავალებებში;</p>\n<p><strong>&nbsp;კომუნიკაციური უნარების განვითარება:</strong><br />&bull; საუბარი &ndash; თავისუფალი და დინამიკური დიალოგის წარმოება;<br />&bull; წერა &ndash; აზრის გამართული და სტრუქტურირებული გადმოცემა წერილობითი ფორმით;<br />&bull; მოსმენა &ndash; სმენითი აღქმის გაუმჯობესება სხვადასხვა აქცენტისა და სიჩქარის საუბრის გაგებით;<br />&bull; კითხვა &ndash; ტექსტის შინაარსისა და დეტალების სწორად გაგება.<br />&bull; თავდაჯერებულობის ამაღლება &ndash; შიშის, მორცხვობის, დაურწმუნებლობის დაძლევა; დაუფლებული ცოდნის თავისუფლად გამოყენება.</p>\n<p><strong>სწავლის ხანგრძლივობა - თვეში 8 ლექცია - კვირაში 2&ndash;ჯერ</strong><br /><strong>ლექციის ხანგრძლივობა - 1 სთ 30 წთ</strong></p>\n<p>ღირებულება თვეში:&nbsp;</p>\n<p><strong>3 კაციდან: 150 ლარი თვეში 8 ლექცია საათნახევრიანი - ყველა დონე</strong></p>\n<p><strong>წყვილში: 180 ლარი&nbsp; - ყველა დონე</strong></p>\n<p><strong>ინდივიდუალურად: ლექციის ხანგრძლივობა 1 საათი </strong><br /><strong>თვეში - 8 ლექცია , კვირაში 2 დღე</strong><br /><strong>ღირებულება 200 ლარი თვეში - დამწყები დონე</strong><br /><strong>240 ლარი თვეში - საშუალო დონე</strong><br /><strong>300 ლარი თვეში - მაღალი დონე</strong></p>\n<p>ჩვენი სერტიფიკატის მისაღებად აუცილებელი პირობაა დონის დასრულება და გამოცდის ჩაბარება.</p>\n<p>[registration]</p>', 'general-english', '', '', '', 'ge', 1, 0, 0),
(343, 149, 40, 1723710983, 0, 'text', 'ინგლისური ენა სკოლის მოსწავლეებისთვის', '<p>inglisuri bavSvebisTVis</p>', '<p>ინგლისური ენა სკოლის ასაკის ბავშვებისთვის მე-4 დან მე-12 კლასის ჩათვლით</p>\n<p>მეცადინეობები მიმდინარეობს როგორც ინდივიდუალურად, ასევე წყვილში და ჯგუფში</p>\n<p>ლექციები ჩატარდება კვირაში: 2 ჯერ</p>\n<p>ჯგუფში 1სთ 30წთ&nbsp; - ღირებულება - 80 ლარი</p>\n<p>ჯგუფი შედგება არანაკლებ 4 მონაწილისგან</p>\n<p>წყვილში&nbsp; - 150 ლარი</p>\n<p>ინდივიდუალურად - 200 ლარი</p>\n<p>აბიტურიენტების მომზადება</p>\n<p>ჯგუფში - 120 ლარი</p>\n<p>წყვილში - 160 ლარი</p>\n<p>ინდივიდუალურად: 220 ლარი</p>', 'eng ch', '', '', '', 'en', 6, 0, 0),
(332, 143, 140, 1694006597, 0, 'text', 'ხარისხის კონტროლის პრინციპები და HACCP-ის სისტემა', '<p><strong>ხარისხის კონტროლის პრინციპები და HACCP-ის სისტემა</strong></p>', '<p>პროგრამის სახელწოდება: ხარისხის კონტროლის პრინციპები და HACCP-ის სისტემა<br />პროგრამა განკუთვნილია:იმ პირებისთვის ვინც დასაქმებულია სურსათის საწარმოებსა და ობიექტებში, ან სურს საწარმო, სარეალიზაციო ობიექტის გახსნა, განახლება, კურსი ასევე განკუთვნილია პირებისთვის ვისაც სურს პერსონალის გადამზადება ხარისხის კონტროლის მიმართულებით.<br />კურსი მოიცავს: შეისწავლოთ ხარისხის კონტროლის მნიშვნელობა, მისი განსაზღვრა ნედლეულიდან მის საბოლოო პროდუქტამდე გარდა ამისა გექნებათ შესაძლებლობა შეისწავლოთ HACCP-ის სისტემის მნიშვნელობა მისი დანერგვისა და განხორციელებისათვის საჭირო დეტალები. <br />თემატიკა<br />&bull; სურსათის უვნებლობის მნიშვნელობა და მისი რეგულირების ძირითადი დებულებები<br />&bull; სურსათისა და სასურსათო ნედლეულის ძირითადი ქიმიური კომპონენტები. <br />&bull; სურსათის უვნებლობის პოლიტიკის ძირითადი საკითხები <br />&bull; სურსათის უვნებლობის პრინციპები საქართველოში.<br />&bull; სურსათისა და სასურსათო ნედლეულის ხარისხი, სურსათის დაბინძურების წყაროები <br />&bull; სურსათისა და სასურსათო ნედლეულის უვნებლობა.<br />&bull; სურსათისა და სასურსათო ნედლეულის ტექნიკური რეგულირება, სტანდარტიზაცია და სერტიფიკაცია.<br />&bull; სურსათისა და სასურსათო ნედლეულის საფრთხეები.<br />&bull; საფრთხის ანალიზისა და კრიტიკული საკონტროლო წერტილების სისტემა &ndash; HACCP. <br />&bull; მიკვლევადობის პრინციპები სურსათის უვნებლობაში. <br />&bull; HACCP-ის დანერგვამდე საჭირო წინასწარი პროგრამები GHP, GMP<br />&bull; HACCP ის სისტემის დანერგვის პრინციპები <br />&bull; HACCP-ის გეგმა და დოკუმენტაციის, ჩანაწერების წარმოება <br />კურსდამთავრებულის უპირატესობა: შეისწავლის სურსათის უვნებლობისათვის საჭირო არსებულ ძირითად მიმართულებებს, რომელიც პრაქტიკაში გამოიყენება, ასევე შეძლებენ თეორიული ცოდნის მიხედვით საწარმოებში, სურსათის წარმოების და რეალიზაციის დაწესებულებებში დაიცვან ხარისხის კონტროლი, შეძლებენ საჭირო დოკუმენტაციის სწორად წარმოებას.<br />სრული პროგრმის ხანგრძლივობა : 8 ლექცია<br />კვირაში ჩატარდება 2 ლექცია<br />ლექციის ხანგრძლივობა 1,5 სთ<br />კურსის ღირებულება ჯგუფში 3 კაციდან: 500<br />კურსის ღირებულება წყვილში: 650<br />კურსის ღირებულება ინდივიდუალურად:750<br />კურსის ბოლოს ჩატარდება დასკვნითი ტესტირება და გაიცემა სერთიფიკატი<br />კურსს უძღვება: ანჟელა ღაჭავა - 4 წლიანი გამოცდილების მქონე სურსათის ტექნოლოგი <br />მეღვინეობის მაგისტრი, ტრენერი.</p>\n<p>&nbsp;</p>', 'HACCP', '', '', '', 'ge', 1, 0, 1),
(145, 50, 7, 1523701856, 0, 'text', 'Health and pharmaceuticals', '', '<p>ჯანდაცვის მენეჯმენტი</p>', 'health', 'contactdetails', '', '', 'en', 5, 0, 0),
(146, 50, 7, 1523701856, 0, 'text', 'ჯანდაცვა და ფარმაკოლოგია', '<p>ჯანდაცვის და ფარმაკოლოგიის შემსწავლელი კურსები ტრენინგ ცენტრი სასწავლო ცენტრი&nbsp;</p>', '', 'health', '', '', '', 'ge', 5, 0, 0),
(155, 55, 9, 1523702431, 0, 'text', 'საბუღალტრო აღრიცხვა ', '', '', 'accounting', '', '', '', 'en', 1, 0, 1),
(147, 51, 50, 1523701929, 0, 'text', 'ჯანდაცვიც მენეჯმენტი', '', '<p>ჯანდაცვის მენეჯმენტის სასერთიფიკატო კურსი</p>', 'healths', '', '', '', 'en', 1, 0, 0),
(148, 51, 50, 1523701929, 0, 'text', ' ჯანდაცვის მენეჯმენტის აკრედიტირებული (რს-560) პროგრამა', '<p>ჯანდაცვის მენეჯმენტის სასერთიფიკატო კურსი ჯანდაცვის მენეჯმენტი ჯანდაცვის მენეჯმენტის შემსწავლელი კურსები ტრენინგ ცენტრი სასწავლო ცენტრი</p>', '<p><strong>კურსის მიზანია:</strong> კვალიფიციური ჯანდაცვის მენეჯერების მომზადება, რომლებიც ჯანდაცვის სფეროში მიმდინარე პროცესების ეფექტიან ადმინისტრირებას შეძლებენ. <br />მიზნობრივი ჯგუფები: ჯანდაცვის და სადაზღვევო ორგანიზაციების პერსონალი, ზოგადი სამედიცინო მენეჯერები, სექტორში სწრაფი კარიერული წინსვლით დაინტერესებული პირები, სტუდენტები, ამ სფეროებში დასაქმების მსურველები, რომელთაც სურთ იმუშაონ სამედიცინო დაწესებულებში მთავარ ექიმად, სამედიცინო ექსპერტად, პროგრამის კოორდინატორად, მენეჯერად, მითერად, ხარისხის კონტროლში, დაზღვევაში, სამედიცინო სოციალურ ექსპერტიზაში, ადამიანური რესურსების მართვა, რეცეფშენში, ქოლ ცენტრში...</p>\n<p><strong>მოდულირებული პროგრამა მოიცავს:</strong> თეორიულ სალექციო კურსს, პრაქტიკულ სავარჯიშოებს, ამოცანებს, ქეისების აქტიურ ანალიზს, მომზადებას და ტესტებს. <br />ტრენინგი დაფუძნებულია პრაქტიკაზე და მასში გათვალისწინებულია ჯანდაცვის სფეროში არსებული მოთხოვნები. <br />მსმენელები სრულად არიან უზრუნველყოფილნი აუცილებელი სასწავლო და მეთოდური მასალებით. <br />ლექციები მიმდინარეობს ქართულ ენაზე უახლესი ციფრული საპრეზენტაციო ტექნოლოგიების გამოყენებით. <br />კურსის მსვლელობისას მსმენელები შეიძენენ მნიშვნელოვან უნარ-ჩვევებს.</p>\n<p><strong>ტრენინგის მასალა:</strong><br />1. პროგრამის პრეზენტაცია (1სთ)&nbsp;<br />2. შესავალი ჯანდაცვის მენეჯმენტში (2სთ).&nbsp;<br />3. დაგეგმვა (2სთ). ლექცია<br />5. სამედიცინო სამართალი, კადრები და ხელშეკრულებები (კანონი პაციენტის უფლებების შესახებ). (2სთ)<br />6. სერვის პლუსი (2სთ).&nbsp;<br />7. სამედიცინო მარკეტინგი (2სთ).&nbsp;<br />8. ხარისხის კონტროლი (2სთ).&nbsp;<br />9. ხარისხის კონტროლი (2სთ).&nbsp;<br />10. საყოველთაო ჯანდაცვა (2სთ).<br />11. საყოველთაო ჯანდაცვა - შესრულებები (2სთ).<br />12. ჯანდაცვის მენეჯმენტი (იდეალური მენეჯერი, ლიდერობა, მოტივაცია, ორგანიზაციული კულტურა). (2სთ).&nbsp;<br />13. სადაზღვევო საქმე (ფრანშიზა, გადაზღვევა)(2სთ).<br />14. სადაზღვევო საქმე (case, ქართული ქეისი). (2სთ).&nbsp;<br />15. ონკოლოგია (138 - ლეიკემია, ფილტვის კიბო, ძუძუ, პროსტატა ...). (2სთ).<br />16. თავ-კისრის ონკოლოგია, სტომატოლოგიური და ონკოლოგიური კლინიკის მართვა. (2სთ).&nbsp;<br />17. კომუნიკაცია (2სთ).&nbsp;<br />18. სტრატეგია (2სთ).&nbsp;<br />19. ჯანდაცვის პოლიტიკა, შშს, ბიულეტენი (2სთ).<br />20. სიტუაცური ამოცანები case (ქართული ქეისი). (2სთ).<br />21. ეპიდემიოლოგია, ინფექციური დაავადებები (აცრების კალენდარი, დიარეა, წითელა...). (2სთ).&nbsp;<br />22. დაავადებების პრევენცია, არაინფექციური დაავადებები (გიდ, სასუნთქი, კნტ). (2სთ).&nbsp;</p>\n<p>პროგრამა ასახავს ჯანდაცვის სისტემაში თანამედროვე შრომის ბაზრის სპეციფიურობას, მისი მართვის უახლეს ტექნოლოგიებს და თანამედროვე მეთოდებს.</p>\n<p><strong>რატომ უნდა აირჩიოთ ჩვენი კურსი?</strong><br /><em>პროგრამა მსმენელს სთავაზობს:</em><br />&bull; ჯანდაცვის მენეჯმენტის აკრედიტირებული (რს-560) სერტიფიკატის მინიჭებას;<br />&bull; ინფორმაციას ჯანდაცვის სისტემაში თანამედროვე ტექნოლოგიების გამოყენების, კვლევის ძირითადი მეთოდების შესახებ, არსებული ინსიტიტუციების მართვასა და ლიდერობაში, ფინანსირება-ბიუჯეტირებაში, ჯანდაცვის გლობალურ და ეროვნულ პოლიტიკაში;<br />&bull; ტრენინგის სხვადასხვა საფეხურის კურსდამთავრებული შეიძენს მართვის ზოგად უნარ-ჩვევებს: სერვის პლუს, ძირითადი წინააღმდეგობების გადალახვა, მართვა კრიზის დროს, ეფექტური ურთიერთობა ორგანიზაციაში,<br />სამედიცინო პერსონალის მოტივაცია და ორგანიზაცია, დროის მართვის თანამედროვე მეთოდები, ადამიანური რესურსების ეფექტური მართვის მიმართულებები და ფუნქციები, კადრების შერჩევა, თანამშრომლების მოვალეობები და სუბორდინაცია, საშტატო გადაადგილების ეფექტური მართვა, ზოგადი ფსიქოლოგია, კადრების განვითარება და შესრულებული სამუშაოს კონტროლი, საქმიანი კომუნიკაცია, მოლაპარაკების უნარ-ჩვევები, გუნდური მუშაობის ტაქტიკა და ტექნიკა;<br />&bull; ჯანდაცვის მენეჯმენტის სრული კურსის გავლის შემდგომ&nbsp;საუკეთესო მსმენელებზე გაიცემა სარეკომენდაციო წერილი.</p>\n<p><strong>პროგრამის ხელმძღვანელი:</strong> ანა სხვიტარიძე MD. PHD. მედიცინის დოქტორი. პროფესორი. ჯანმრთელობის დაცვისა და განათლების ასოციაციის დამფუძნებელი - დირექტორი. QSCert საერთაშორისო სტანდარტი ISO აუდიტის სამედიცინო ექსპერტი. კლინიკა ,,სილკ მედიკალ\'\' ის მთავარი ექიმი</p>\n<p><strong>პროგრამის ხანგრძლივობა: 54 საათი</strong><br /><strong>კურსი მოიცავს: 2 თვე </strong><br /><strong>კვირაში ჩატარდება: 3 ლექცია.</strong><br /><strong>კურსის სრული ღირებულება 780 ლარი</strong></p>\n<p><strong>გადახდა ორ ეტაპად - თვეში: 390 ლარი</strong></p>\n<p>[registration]</p>', 'healths', '', '', '', 'ge', 1, 0, 0),
(149, 52, 50, 1523702159, 0, 'text', 'ფარმაკოლოგიის კურსი', '', '<p>ფარმაკოლოგია</p>', 'farmacy', '', '', '', 'en', 5, 0, 0),
(150, 52, 50, 1523702159, 0, 'text', 'ფარმაკოლოგიის კურსი-სტაჟირებით', '<p>ფარმაკოლოგიის შემსწავლელი კურსი farmacy ტრენინგ ცენტრი სასწავლო ცენტრი</p>', '<p><strong>ვისთვისაა კურსი გათვლილი?</strong><br />ფარმაკოლოგიით დაინტერესებულ ნებისმიერი მსურველისთვის, რომელსაც აქვს საშუალო ან უმაღლესი განათლება ფარმაციის ან სამედიცინო სფეროში, ასევე შესაბამისი სპეციალობის სტუდენტებისთვის. აგრეთვე პარაფარმაციით დაინტერესებული პირები შესაძლებელია იყვნენ არასამედიცინო განათლების მქონე.<br />ტრენინგ-კურსი მოიცავს თეორიულ და პრაქტიკულ ნაწილს და გათვალისწინებულია ისეთი მსმენელებისთვის, ვისაც სურს აფთიაქში მუშაობა ფარმაცევტად, ფარმაცევტის თანაშემწედ ან კონსულტანტად და სურს პროფესიული დონის ამაღლება.<br /><strong>კურსის მიზანია:</strong> კვალიფიკაციის ამაღლება და პრაქტიკული უნარ-ჩვევების გამომუშავება, რომელიც რეალურად შეწყობს ხელს კურსდამთავრებულს, რათა მიიღოს მეტი ცოდნა და დასაქმების შესაძლებლობა სხვადასხვა ფარმაცევტულ კომპანიებსა და აფთიაქებში.<br /><strong>კურსი მოიცავს:</strong> თეორიული და პრაქტიკულ ნაწილს.<br />თეორიული ნაწილში - მსმენელი გაეცნობა:<br />** სამკურნალო საშუალებების კლასიფიკაციას ფარმაკოლოგიური ჯგუფების მიხედვით. <br />** მედიკამენტთა თითოეული ჯგუფის განხილვა იმ დაავადებათა კლინიკასთან ერთად, რომლის დროსაც ინიშნება ეს მედიკამენტები, ასევე გაეცნობა აფთიაქის სტრუქტურას. <br />** სამკურნალო საშუალებების კლასიფიკაციას, ფარმაკოლოგიურ ჯგუფებს, მოქმედების მექანიზმებს, ჩვენებებს, გვერდით მოვლენებსა და უკუჩვენებებს;<br />** ფარმაცევტის სამუშაო პროგრამას;<br />** სარეცეპტო და არასარეცეპტო მედიკამენტების გაცემის წესებს;<br />** ეფექტური მომსახურებისა და გაყიდვების ტექნიკებს.<br />რამდენიმე ლექცია დაეთმობა პარაფარმაციას, ამ ტრეინინგის ქვეშ იგულისხმება: ბავშვთა კვება, ჰიგიენის და მოვლის საშუალებები, როგორც ბავშვებში ასევე ზრდასრულებში.<br />ტრეინინგის მსმენელები უზრუნველყოფილი იქნებიან სასწავლო მასალით. ტრენინგის მსვლელობისას გამოიყენება როლური თამაშები (აფთიაქის სიტუაციის სიმულირება).<br />ტესტირება ჩატარდება: ყოველ 3 სალექციო დღის განვლილ თეორიულ ნაწილზე.<br /><strong>ხოლო კურსის ბოლოს ჩატარდება შემაჯამებელი ტესტირება!</strong></p>\n<p><strong>კურსდამთავრებული სტაჟირებას გაივლის სრულიად უფასოდ პსპ-ს და ნეო ფარმას სააფთიაქო ქსელებში.</strong><br /><strong>პრაქტიკულ ნაწილში</strong> - სტაჟირების დროს გაეცნობა სააფთიაქო კომპიუტერულ პროგრამა - Apex-ს, აფთიაქში ყველა საჭირო დოკუმენტაციის წარმოების, ცვლის გადაბარების წესებს. შეისწავლის მომხმარებელთან ურთიერთობის უნარ-ჩვევებს, ეფექტურ მომსახურებას.<br />სტაჟირება სად და რა ინტენსივობით ჩატარდება: <br />კურსის დასრულების შემდეგ მსმენელები გაივლიან 1 თვიან უფასო სტაჟირებას <strong>\"PSP\"-ს</strong> და ,<strong>,იმპექსის</strong>\" სააფთიაქო ქსელებში, საუკეთესოებისთვის შემდგომი დასაქმების პერსპექტივით, როგორც თბილისში ასევე საქართველოს ნებისმიერ რეგიონში.<br /><strong>გაიცემა ორენოვანი სერტიფიკატი და სარეკომენდაციო წერილი.</strong> <br />აფთიაქში სტაჟირების მსვლელობის პერიოდში ჩატარდება სემინარები და განიხილება აფთიაქში ხშირად შექმნილი სხვადასხვა სიტუაცია.<br /><strong>თეორიული კურსი გრძელდება :&nbsp;2 თვე, კვირაში 3-ჯერ;</strong><br /><strong>სრული კურსის ღირებულება:&nbsp;500 ლარი;</strong><br /><br /></p>\n<p>[registration]</p>', 'farmacy', '', '', '', 'ge', 5, 0, 0),
(151, 53, 50, 1523702222, 0, 'text', 'სამედიცინო რეგისტრატორის მოსამზადებელი კურსი', '', '<p>რეგისტრატორი</p>', 'registratory', '', '', '', 'en', 4, 0, 0),
(152, 53, 50, 1523702222, 0, 'text', 'სამედიცინო რეგისტრატორის მოსამზადებელი კურსი', '<p>სამედიცინო რეგისტრატორის მოსამზადებელი კურსი ტრენინგ ცენტრი სასწავლო ცენტრი</p>', '<p><strong>კურსის შესახებ:</strong></p>\n<p>** კურსი ორიენტირებულია პრაქტიკული უნარ-ჩვევების გამომუშავებაზე. <br />** კურსდამთავრებულებს ექნებათ შესაბამისი თეორიული და პრაქტიკული ცოდნა იმისათვის, რომ კონკურენციის პირობებში მეტად მარტივად და კვალიფიციურად დასაქმდნენ სხვადასხვა წამყვან სამედიცინო ორგანიზაციაში, რეგისტრატორის პოზიციაზე.</p>\n<p><strong>კურსის მიზანია:</strong></p>\n<p>** მოლაპარაკების პრინციპების, ტექნიკისა და მართვის უნარების გამომუშავება. <br />** კურსის მსვლელობისას მსმენელები შეიძენენ მნიშვნელოვან უნარ-ჩვევებს. <br />** კურსი შედგება თეორიული და პრაქტიკული ნაწილისაგან, ასევე ქეისების აქტიური ანალიზი და მომზადება.</p>\n<p><strong>კურსის თემატიკა:</strong></p>\n<p>** ზოგადი თერაპიული უნარ-ჩვევები ავადმყოფობათა და ჯანმრთელობასთან დაკავშირებული პრობლემების საერთაშორისო სტატისტიკური კლასიფიკაცია <br />** ზოგადი ფსიქოლოგია ზოგადი თერაპია <br />** ზოგადი ქირურგია <br />** ზოგადი ფარმაკოლოგია <br />** ჯანმრთელობის დაზღვევა კორპორატიული დაზღვევა <br />** ჯანმრთელობის დაზღვევის სახელმწიფო პროგრამა საყოველთაო ჯანდაცვა დაზღვეული პაციენტის მომსახურება მოლაპარაკებების ძირითადი კომპონენტები <br />** მოლაპარაკების პროცესი გადაწყვეტილების მიღება <br />** მოლაპარკებების დროს სტრატეგიების სწორად გამოყენება <br />** მოლაპარაკების დროს ძირითადი წინააღმდეგობების გადალახვა სამედიცინო პროცესის კასკადის დაგეგმვა ინფორმაციის მიწოდება, რეგისტრაცია მონაცემების შეყვანა, როგორც სარეგისტრაციო ჟურნალში, ასევე, პროგრამაში ჯანდაცვის პორტალზე, e-mail-ის გაგზავნის ტექნიკა პაციენტის მომსახურების დაგეგმვა პაციენტის მოლოდინი პაციენტებთან ურთიერთობის ღირებულება პაციენტის კონსულტაცია გადამისამართება პრობლემების მართვა</p>\n<p><strong>კურსი მოიცავს:</strong></p>\n<p><strong>** სრული კურსის ხანგრძლივობა:&nbsp;12 ლექცია</strong></p>\n<p><strong>ლექციის ნაწილი თეორიულია, ხოლო ნაწილი პრაქტიკული სამედიცინო ამბოლატორიულ ცენტრში</strong><br /><strong>** კვირაში ჩატარდება: 3 ლექცია </strong><br /><strong>** ლექციის ხანგრძლივობა: 1სთ 30წთ&nbsp;</strong><br /><strong>** კურსის ღირებულება: 300 ლარი</strong></p>\n<p>[registration]</p>', 'registratory', '', '', '', 'ge', 4, 0, 0),
(153, 54, 50, 1523702279, 0, 'text', 'ხარისხის კონტროლი', '', '<p>ხარისხის კონტროლი</p>', 'control', '', '', '', 'en', 2, 0, 0),
(154, 54, 50, 1523702279, 0, 'text', 'სამედიცინო ხარისხის კონტროლი და მართვა', '<p>სამედიცინო ხარისხის მართვა სამედიცინო ხარისხის მართვის შემსწავლელი კურსები ტრენინგ ცენტრი სასწავლო ცენტრი</p>', '<p><strong>კურსის მიზანია:</strong> სამედიცინო ხარისხის კონტროლის სამსახურის მენეჯერების მომზადება, რომლებიც ჯანდაცვის სფეროს თანამედროვე მოთხოვნების პირობებში კვალიფიციურ ადმინისტრირებას შეძლებენ.<br /><strong>მიზნობრივი ჯგუფები:</strong> ჯანდაცვის, სადაზღვევო ორგანიზაციების და სამედიცინო დაწესებულებაში ხარისხის კონტროლის სამსახურის პერსონალი, ზოგადი სამედიცინო მენეჯერები, ექსპერტები, პროგრამის კოორდინატორები, სექტორში სწრაფი კარიერული წინსვლით დაინტერესებული პირები, სტუდენტები და ა.შ.<br /><strong>მოდულირებული პროგრამა მოიცავს:</strong>&nbsp;ტრენინგი დაფუძნებულია პრაქტიკაზე და მასში გათვალისწინებულია ჯანდაცვის სფეროში არსებული მოთხოვნები. სემინარი ,,სამედიცინო ხარისხის კონტროლი და მართვა&rsquo;&rsquo; მიმდინარეობს ქართულ ენაზე ციფრული საპრეზენტაციო ტექნოლოგიების გამოყენებით.<br />კურსის მსვლელობისას მსმენელები შეიძენენ მნიშვნელოვან უნარ-ჩვევებს. <br /><strong>მოდულში გაერთიანებულია:</strong><br />1. ჯანდაცვის მენეჯმენტის ზოგადი დებულებები და სამედიცინო ხარისხი: ხარისხის კონტროლის მიზანი; ხარისხის მართვის ერთეულის ფუნქციები; პერიოდული მონიტორინგი და კონტროლი; საზოგადოებრივი ჯანდაცვა; სანიტარიულ-ჰიგიენური და ეპიდსაწინააღმდეგო რეჟიმის უზრუნველყოფა; ნოზოკომიური ინფექციების კონტროლისა და აღრიცხვის პროცესის მართვა; ჰოსპიტალური ინფექციების პროფილაქტიკა; სამედიცინო სტატისტიკა; ხარისხის გაუმჯობესების და პაციენტთა უსაფრთხოების უზრუნველყოფის შეფასების შიდა (ხარისხის მართვის) სისტემა; პაციენტის და სამედიცინო პერსონალის კმაყოფილების შეფასება, მონიტორინგი და ანალიზი; ტესტირების კითხვარის შედგენა; პაციენტთა უსაფრთხოების წესების დაცვის შესწავლა; რეჰოსპიტალიზაციის და მრავალჯერადი ჰოსპიტალიზაციის; სამედიცინო მომსახურების ეფექტურობის მაჩვენებლების .<br />2. კლინიკის ადმინისტრირება, ჯანდაცვის კანონმდებლობა, სამედიცინო სოციალური ექსპერტიზა, სამედიცინო დოკუმენტაციის წარმოების ხარისხის შესწავლა, ფორმა 100, საავადმყოფო ფურცელი ... <br />3. ეთიკური საკითხების განხილვა: ლეტალური გამოსავალი; პაციენტის ჯანმთელობის მდგომარეობის მკვეთრი გაუარესება; სამედიცინო შეცდომა/სამედიცინო გადაცდომა; ნოზოკომიური ინფექცი(ებ)ის დადასტურებული შემთხვევა; პაციენტის/პაციენტის წარმომადგენლის საჩივარი;</p>\n<p><strong>პროგრამა ასახავს ჯანდაცვის სისტემაში თანამედროვე შრომის ბაზრის სპეციფიურობას, მისი მართვის უახლეს ტექნოლოგიებს და თანამედროვე მეთოდებს.</strong></p>\n<p><strong>რატომ უნდა აირჩიოთ ჩვენი კურსი?</strong><br />პროგრამა უმოკლეს ვადაში მსმენელს სთავაზობს:<br />სამედიცინო მომსახურების ხარისხის კონტროლის მენეჯერის კვალიფიკაციის სერტიფიკატის მინიჭებას;<br />ინფორმაციას სამედიცინო მომსახურების ხარისხის კონტროლის სამსახურის მოქმედების პრინციპები და კონცეფციები თანამედროვე მოთხოვნების პირობებში ჯანდაცვის სისტემაში თანამედროვე კონტროლის მეთოდების შესახებ, შესრულებული სამუშაოს კონტროლი, საქმიანი კომუნიკაცია, მოლაპარაკების უნარ-ჩვევები, გუნდური მუშაობის ტაქტიკა და ტექნიკა;</p>\n<p><strong>გაითვალისწინეთ:</strong> სრული კურსის გავლის შემდგომ ტესტირებაში უმაღლესი შეფასების მქონე მსმენელებზე გაიცემა სარეკომენდაციო წერილი.</p>\n<p>პროგრამის ხანგრძლივობა:&nbsp;</p>\n<p><strong>კურსი მოიცავს: 10 ლექცია</strong></p>\n<p><strong>ლექციის ხანგრძლივობა: 2 საათი</strong><br /><strong>კურსის ღირებულება:&nbsp;350 ლარი</strong></p>\n<p><strong>ტრენერი</strong> - ანა სხვიტარიძე MD. PHD. მედიცინის დოქტორი. პროფესორი. ჯანმრთელობის დაცვისა და განათლების ასოციაციის დამფუძნებელი - დირექტორი. QSCert საერთაშორისო სტანდარტი ISO აუდიტის სამედიცინო ექსპერტი. კლინიკა ,,სილკ მედიკალ\'\' ის მთავარი ექიმი.</p>\n<p><strong>[registration]</strong></p>', 'control', '', '', '', 'ge', 2, 0, 0),
