(158, 56, 9, 1523702520, 0, 'text', 'საბუღალტრო კომპიუტერული პროგრამები', '<p>1C ბუღალტერია ბუღალტერიის შემსწავლელი კურსები სტაჟირება კონსულტაცია საბუღალტრო კომპიუტერული პროგრამები საგადასახადო კანონმდებლობა</p>', '<p><strong>კომპიუტერული ბუღალტერია:</strong></p>\n<p>&nbsp;</p>\n<p><strong>ორისი - 6 ლექცია-1.30 წთ-იანი</strong></p>\n<p>250 ლარი ჯგუფში</p>\n<p>წყვილში - 350 ლარი</p>\n<p>ინდივიდუალურად -&nbsp;600 ლარი</p>\n<p>&nbsp;</p>\n<p><strong>ბალანსი&nbsp;</strong>-&nbsp;6&nbsp;ლექცია&nbsp;</p>\n<p>250 ლარი ჯგუფში</p>\n<p>წყვილში - 350 ლარი</p>\n<p>ინდივიდუალურად -&nbsp;600 ლარი</p>\n<p><strong>1C -ბუღალტერია</strong></p>\n<p>2-3 კაციან ჯგუფში - 8 საათი -&nbsp;350&nbsp; ლარი</p>\n<p>ინდივიდუალურად - 6 საათი-&nbsp;600 ლარი</p>\n<p>&nbsp;</p>\n<p>[registration]</p>', 'accouncting-programs', '', '', '', 'ge', 2, 0, 0),
(159, 57, 9, 1523702561, 0, 'text', 'სტაჟირება ბუღალტრებისთვის', '', '', 'accounting-stajior', '', '', '', 'en', 3, 0, 0),
(160, 57, 9, 1523702561, 0, 'text', 'სტაჟირება ბუღალტრებისთვის', '<p>ბუღალტერია ბუღალტერიის შემსწავლელი კურსები სტაჟირება ორისი კონსულტაცია ბანკინგი სტაჟირება ბუღალტრებისთვის ორისი 1С საბუღალტრო კომპიუტერული პროგრამები დასაქმება ტრენინგ ცენტრი სასწავლო ცენტრი ბუღალტერია დამწყებთათვის</p>', '<p>\"VIP Intellect Group\"-ის საბუღალტრო აღრიცხვისა და პრაქტიკული ბუღალტერიის კურსდამთავრებულები სტაჟირებას გაივლიან&nbsp; გამოცდილ და პროფესიონალ მთავარ ბუღალტრებთან.</p>\n<p>სტაჟირების დასრულების შემდეგ მოგეცემათ რეკომენდაცია როგორც ჩვენი სასწავლო ცენტრისგან, ასევე&nbsp;თავად ტრენერისგან!</p>\n<p>ეს იქნება რეალური პრაქტიკა, რომ შემდგომაც კურსდამთავრებულმა უნდა შეძლოს დამოუკიდებლად აწარმოოს საბუღალტრო საქმიანობა სხვადასხვა სფეროში!</p>\n<p><strong>სტაჟირებისას პრაქტიკანტს რეალურად ექნება შეხება:</strong></p>\n<p>1. მოქმედი, სხვადასხვა ორგანიზაციების რეალური დოკუმენტების დამუშავებასთან<br />2. კომპიუტერული პროგრამა ორისის პრაქტიკულად გამოყენება - რეალურ საბუთებზე დაყრდნობით<br />3. http://www.rs.ge-სთან მუშაობა<br />4. ინტერნეტ ბანკინგით სარგებლობა<br />5. საბუღალტრო დოკუმენტაციების დამუშავება ერთ საოპერაციო პერიოდში.</p>\n<p><strong>პრაქტიკის</strong>&nbsp;<strong>ხანგრძლივობა</strong><strong>:</strong><strong>&nbsp;</strong><strong>10 </strong><strong>შეხვედრა</strong></p>\n<p><strong>სტაჟირების</strong> <strong>ღირებულება</strong> <strong>ჯგუფში</strong><strong> :</strong>&nbsp;<strong>300</strong><strong>&nbsp;</strong><strong>ლარი</strong></p>\n<p><strong>სტაჟირების</strong> <strong>ღირებულება</strong> <strong>წყვილში: 500 ლარი</strong></p>\n<p><strong>სტაჟირების</strong> <strong>ღირებულება</strong> <strong>ინდივიდუალურად</strong><strong> :</strong><strong>&nbsp;</strong><strong>700</strong>&nbsp;<strong>ლარი</strong></p>\n<p>გაითვალისწინეთ: თქვენ პრაქტიკულ ბუღალტრულ საქმიანობას შეგასწავლიან ისეთი დონის ბუღალტრები, რომელთაც აქვთ დიდი ხნის მუშაობის გამოცდილება წარმოების, ვაჭრობის და მომსახურების სფეროს ყველანაირ ორგანიზაციაში!</p>\n<p>დამწყები ბუღალტრებისთვის გაგიწევთ საკონსულტაციო მომსახურებას, აგიწყობთ საბუღალტრო აღრიცხვიანობას პროგრამაში, დაგილაგებთ საბუღალტრო დოკუმენტაციას და მოგიწესრიგებთ პრობლემებს.</p>\n<p>&nbsp;</p>\n<p>[registration]</p>', 'accounting-stajior', '', '', '', 'ge', 3, 0, 0),
(161, 58, 9, 1523702594, 0, 'text', 'საგადასახადო კანონმდებლობის კურსი', '', '', 'tax', '', '', '', 'en', 4, 0, 1),
(162, 58, 9, 1523702594, 0, 'text', 'პრაქტიკული აუდიტი', '<p><strong>ტრენინგი</strong> <strong>პრაქტიკულ</strong> <strong>აუდიტში</strong></p>', '<p><strong>კურსის მიზანია:</strong> ბუღალტრებს, ფინანსისტებს წარმოდგენა შეუქმნას აუდიტის სფეროზე. აუდიტის დაგეგმვის ჩატარების ეტაპებზე, მეთოდებზე და მიდგომებზე. ცოდნა გაუღრმავოს როგორც თეორიულად ასევე პრაქტიკული მაგალითებით.</p>\n<p><strong>კურსის თემატიკა:</strong></p>\n<p>ფინანსური აუდიტის სფერო და არსი<br />აუდიტის პროგრამის პაკეტის თეორიული ციკლი<br />წინასწარი აუდიტორული პროცედურები<br />გარე და შიდა აუდიტის არსი მნიშვნელობა და განსხვავებები<br />აუდიტის ობიექტის შესწავლა<br />არსებითობის გაანგარიშება<br />შიდა კონტროლი და რისკები დაგეგმვის ეტაპზე<br />აუდიტის ტესტები<br />აუდიტორული შერჩევა<br />აუდიტორული მტკიცებულების მოპოვება<br />საქმიანობის დაწყება - საწყისი ნაშთები<br />აუდიტის დოკუმენტაციის პაკეტი<br />აუდიტის დასკვნა ფინანსური ანგარიშგების შესახებ სტრუქტურა<br />პრაქტიკული ქეისები რეალური კომპანიის მაგალითებზე.<br />დამუშავება ექსელში სხვადასხვა სფეროს კომპანიების, ბრუნვა ნაშთების და გატარებების გამოყენებით ფინანსური ანგარიშგების პაკეტის აწყობა.<br />რისკების იდენტიფიცირება და კონტროლის მექანიზმების შემუშავება აუდიტის შემდგომ დაგეგვის ეტაპისთვის.<br />აუდიტის შერჩევა და ტესტირება რწმუნების მოპოვება, დადოკუმენტირება.<br />ინფორმაციის თავმოყრა და ფლობა - აუდიტის დასკვნის მომზადებისთვის.<br />კურსში შეხვდებით აუდიტის გამოყენებულ ტერმინოლოგიებს როგორიც არის:</p>\n<p>ფინანსური ანგარიშგების სტანდარტები IFRS, IFRS for SME.<br />კონტროლის ღონისძიებები: შესაბამისი, თანმიმდევრულად განხორციელებადი, სრულყოფილი, დანახარჯების თვალსაზრისით ეფექტიანი კონტროლის მიზნებთან უშუალოდ დაკავშირებული.<br />აუდიტის რისკის სახეები:კონტროლის რისკი, თანდაყოლილი რისკი, შეუმჩნევლობის რისკი. <br />აუდიტორული მტკიცებულება:დათვალიერება, დაკვირვება, გარე დასტური, ხელახალი გამოთვლა, ხელახალი შესრულება, ანალიზური პროცედურები, გამოკითხვა.</p>\n<p><strong>კურსის ხანგრძლივობა: 8 ლექცია - 1.30 საათიანი</strong><br /><strong>კურსის ღირებულება ინდივიდუალურად: 800 ლარი</strong><br /><strong>ჯგუფში 3 და მეტი: 600 ლარი</strong></p>\n<p>[registration]</p>\n<p>&nbsp;</p>', 'tax', '', '', '', 'ge', 4, 0, 1),
(163, 59, 9, 1523702693, 0, 'text', 'ბუღალტერია უცხოელებისთვის', '', '', 'accounting-eng', '', '', '', 'en', 4, 0, 0),
(164, 59, 9, 1523702693, 0, 'text', 'ბუღალტერია უცხოელებისთვის', '<p>ბუღალტერია უცხოელებისთვის ბუღალტერია ინგლისურად ბუღალტერი ორისი სტაჟირება დასაქმება 1C ბუღალტერიის შემსწავლელი კურსები ბუღალტრული მომსახურება ტრენინგ ცენტრი სასწავლო ცენტრი&nbsp;</p>', '<p>ინგლისურენოვანი მსურველებისთვის ბუღალტერია ინდივდუალურად მოიცავს 12 სალექციო კურსს</p>\n<p>კურსის ღირებულება: 1200 ლარი</p>\n<p>ორ კაციანი ჯგუფისთვის ლექციის ღირებულება:&nbsp;800 ლარი</p>', 'accounting-eng', '', '', '', 'ge', 4, 0, 0),
(167, 61, 8, 1523702986, 0, 'text', 'გაძლიერებული ექსელის კურსები', '', '', 'advanced-excel', '', '', '', 'en', 2, 0, 0),
(168, 61, 8, 1523702986, 0, 'text', 'გაძლიერებული ექსელი', '<p>excel advanced excel&nbsp; გაძლიერებული ექსელი ექსელის შემსწავლელი კურსები საოფისე პროგრამები ექსელის ტრენინგი&nbsp;</p>', '<p>&nbsp;<strong>Basic Level:</strong></p>\n<p>განკუთვნილია დამწყებთათვის, რომელთაც არ ჰქონიათ შეხება ექსელთან.</p>\n<p>** Start<br />** ექსელის მომართვა:<br />** დოკუმენტის პარამეტრების მართვა:<br />** დოკუმენტის ფორმატირება:<br />** მონაცემების ტიპები<br />** ფორმულები: sum, average, count, max, min, if, if+if, sumif, countif, today, day 360, weekday, conditional formating</p>\n<p><strong>კურსის დასრულების შემდგომ:</strong></p>\n<p>** გექნებათ ექსელის საბაზისო შესაძლებლობების კარგი ცოდნა.<br />** თავს იგრძნობთ უფრო კომფორტულად ექსელის სამუშაო გარემოში და შეძლებთ ცხრილების/გრაფიკების აგებას და კორექტირებას.<br />** გეცოდინებათ საბაზისო ფორმულები, რომელიც დაგეხმარებათ უფრო პროდუქტიული იყოს თქვენი სამუშაო ცხრილები/გრაფიკები რომელთაც თქვენ შექმნით იქნება უფრო ეფექტური და პრეზენტაბელური.</p>\n<p><strong>პროგრამის ხანგრძლივობა შეადგენს: 6 ლექციას</strong><br /><strong>ღირებულება ინდივიდუალურად: 300 ლარი (დისტანციურად) 400&nbsp;ლარი (ადგილზე) ერთი მსმენელისთვის</strong><br /><br /><strong>2-4 კაციან ჯგუფში: 200 ლარი (დისტანციურად) - 250 ლარი (ადგილზე) ერთი მსმენელისთვის</strong></p>\n<p><strong>Intermediate Level:</strong></p>\n<p>განკუთვნილია მათთვის, ვინც უკვე იცის საბაზისო დონე და მუშაობს დიდი მონაცემთა ბაზებში.</p>\n<p>აღნიშნული კურსი დააინტერესებთ მათ, ვისაც უწევთ ფინანსური, სტატისტიკური ან სხვა საშედეგო ანალიზური ინფორმაციის დამუშავება-მომზადება Excel-ში, კურსის მიმდინარეობისას განვიხილავთ პრაქტიკულ ამოცანებს ფინანსური ანგარიშგებების, ფულადი ნაკადების და ხარჯთაღრიცხვის კუთხით, ასევე საწარმოო ბიუჯეტის დაგეგმარებას, ანალიზისა და საკონტროლო ცხრილების მექანიზმებს;</p>\n<p>გაითვალისწინეთ, რომ ამ კურსს ძირითადად ეუფლებიან სხვადასხვა წარმატებული ორგანიზაციების ფინანსური დირექტორები, მათ თანაშემწეები, ფინანსური და ბიზნეს ანალიტიკოსები, ასევე მენეჯერები, ბუღალტრები და საწყობის თანამშრომლები. ამიტომ პრაქტიკული ამოცანები ამ ორგანიზაციებში უკვე გადაჭრილი პრობლემების და მიმდინარე პროცესების მათემატიკური მოდელებია;</p>\n<p><strong>დიდი მოცულობის სამუშაო გვერდზე მუშაობა:</strong></p>\n<p>** ლოგიკურ ფუნქციებთან მუშაობა (If, Iferror, And, Or, True, False) Logical IF+IF; IF+AND+OR<br />** საძიებო ფორმულები: Vlookup, Hlookup, Lookup, index, indirect, match.<br />** სტატისტიკური ფორმულები: countif, averageif, countifs, averageifs, count A, count blank<br />** ტექსტური ფორმულები: left, right, mid, find, search, concatenate, rept, replace, proper, substitute, text;<br />** თარიღის და დროის ფუნქციები: Today, Now, Date, Day, Month , year, Hour, Minute, edate, eomonth, networkdays weeknum, workday<br />** Name Manager -თან მუშაობა (Name Box, Define Name, Create From Selection) ახალი სახელების შექმნა და მათი რედაქტირება;<br />** Data Validation: კრიტერიის დადგენა ტექსტის, თარიღის თუ რიცხვის შეზღუდვის დასაწესებლად, უჯრაში სიის შექმნა<br />** მათემატიკური ფუნქციები: Even, Odd\" Sumif , Sumifs , Subtotal; Sumproduct, Conditional Formulas and Formating<br />** გაფართოებული ფილტრი (Advanced Filter), ინფორმაციული ფუნქციები, ტექსტის დაშლა სვეტებად (Text To Column)<br />** ფორმულის შემოწმება და ხარვეზების პოვნა; სამუშაო წიგნის, სამუშაო გვერდის და არეალის დაცვა<br />** Table Format, Pivot table, Pivot chart , ფინანსური ფუნქციები: FV, pv ,pmt, ppmt, nper;</p>\n<p><strong>კურსის დასრულების შემდგომ:</strong></p>\n<p>** შეძლებთ სწრაფად დაამუშაოთ დიდი მონაცემთა ბაზები და განახორციელოთ მათზე მოქმედებები;<br />** შეძლეთ ვრცელი ცხრილების მარტივ და პრეზენტაბელურ რეპორტებად გარდაქმნას;<br />** ფორმულების და ფორმატირებების ცოდნა საშუალებას მოგცემთ აკონტროლოთ ვადები პროდუქციაზე, ასევე დებიტორთა თუ საკუთარი დავალიანებების გრაფიკი.<br />** შეძლებთ მონაცემთა ბაზების ერთმანეთთან დაკავშირებას ისე რომ ერთის განახლება იწვევდეს მეორის ავტომატურ განახლებას<br />** ფორმატინგის შეამცირებთ დიდ მონაცემებთან მუშაობისას ადამიანის მექანიკური შეცდომების მოხდენის ალბათობას<br />** შეძლებთ რთულ ფორმულებთან მუშაობას და თავად ჩაწერილი ფორმულის ანალიზს Error-ის შემთხვევებში; და ა.შ.</p>\n<p><strong>პროგრამის ხანგრძლივობა შეადგენს: 8 ლექცია</strong><br /><strong>ღირებულება ინდივიდუალურად - 400 ლარი (დისტანციურად) - 500 ლარი (ადგილზე) ერთი მსმენელისთვის;</strong><br /><strong>2-3 კაციან ჯგუფში: 300 ლარი (დისტანციურად) -&nbsp;350 ლარი (ადგილზე) - ერთი მსმენელისთვის;</strong><br /><br /></p>\n<p><strong>Advanced Level:</strong></p>\n<p>აღნიშნული კურსი განკუთვნილია: მათთვის, ვინც კარგად ფლობს წინა დონეებს და სურს გაეცნოს ექსელის უფრო რთულ და საინტერსო ფუნქციებს და შესაძლებლობებს და იყოს მეტად პროგრესული მონაცემთა ანალიზში.</p>\n<p><strong>პროგრამის აღწერა:</strong></p>\n<p>**ფილტრაცია, advanced filter, პირობითი დაფორმატება (Conditional Formatting), ავტოსიები,<br />**ჩადგმული IF-ები And და Or ფუნქციებთან კომბინაციები;შემდეგ ფუნქციებთან ერთად<br />**მათემატიკური ფუნქციები: (SQRT, Int, Abs, Sumifs, Product, Round, Roman, Randbetween, Trung, Large, Small);<br />**ტექსტური ფუნქციები: (Mid, Search, Find, Trim, Len, Left, Right, Concatenate, Upper, Proper, Lower) Text to Columns, Remove Dublicates,<br />**ინფორმაციული ფუნქციები: (ISBLANK, ISNUMBER, ISTEXT, ISEVEN, ISODD)<br />**Data validation: კრიტერიის დადგენა უჯრაში შეზღუდვის დასაწესებლად; Data table;<br />**ცხრილებისა და სიების დათვალიერება-დამუშავება: Lookup&amp;Reference (Vlookup, Hlookup, Index, Match), Hiperlink;<br />**დინამიური ცხრილები და მათი დიაგრამები (PivotTable, PivotChart), ოპტიმიზაციის და შეზღუდვების ამოცანები, პროგრამა Solver;</p>\n<p><strong>კურსის გავლის შემდგომ:</strong> გექნებათ აბსოლუტურად სრული წარმოდგენა და ცოდნა ექსელის უმაღლესი დონის ფუნქციებზე. შეძლებთ გამოიყენოთ ყველა ის შესაძლებლობა, რასაც ექსელი გაძლევთ თავისი ფორმულებით და ფუნქციებით, ასევე მონაცემთა ბაზების/ცხრილების მანიპულაციას Pivot Tables დახმარებით და Advanced ანალიზის ჩატარებას. შეძლებთ მაკროსების ჩაწერას რეკორდერის დახმარებით, რაც დაზოგავს თქვენს ყოველდღიურ რუტინაზე დასახარჯ დროს.</p>\n<p><strong>პროგრამის ხანგრძლივობა შეადგენს: 8 ლექცია</strong><br /><strong>ღირებულება ჯგუფში: 350 ლარი (დისტანციურად) - 400 ლარი (ადგილზე) - ერთი მსმენელისთვის</strong><br /><strong>2-3 კაციან ჯგუფში: 400 ლარი (დისტანციურად) - 450 ლარი (ადგილზე) - ერთი მსმენელისთვის;</strong><br /><strong>ინდივიდუალურად: 550 ლარი (დისტანციურად) - 600 ლარი (ადგილზე)</strong></p>\n<p><strong>ინგლისურ ენაზე ინდივიდუალურად: 800 ლარი</strong></p>\n<p>გაითვალისწინეთ, რომ კურსი მოიცავს პრაქტიკულ სამუშაოს და ყოველი გაკვეთილის შემდგომ რამდენიმე დავალებას, რომელიც ელექტრონული ფორმით მოგეცემათ და აუცილებლად უნდა შეასრულოთ, ყოველი დავალება იქნება თქვენი ათვისებული ცოდნისა და უნარ-ჩვევის გარკვეული მონიტორინგი, ამიტომ დავალებებზე იქნება მკაცრი კონტროლი;</p>\n<p>[registration]</p>\n<p>&nbsp;</p>', 'advanced-excel', '', '', '', 'ge', 2, 0, 0),
(302, 128, 9, 1625221281, 0, 'text', 'მეოთხე კატეგორიის საწარმოების ფინანსური ანგარიშგების სტანდარტი', '<p>მეოთხე კატეგორიის საწარმოების ფინანსური ანგარიშგების სტანდარტი</p>', '<p>მეოთხე კატეგორიის საწარმოების ფინანსური ანგარიშგების სტანდარტი<br />', 'მეოთხე კატეგორიის საწარმოების ფინანსური ანგარიშგების სტანდარტი ', '', '', '', 'ge', 7, 0, 1),
