(190, 72, 7, 1523783955, 0, 'text', 'ბიზნესის ადმინისტრირება', '<p>ბიზნეს ადმინისტრირება ბიზნეს ადმინისტრირების შემსწავლელი კურსები ტრენინგ ცენტრი სასწავლო ცენტრი</p>', '', 'bussines', '', '', '', 'ge', 6, 0, 0),
(191, 73, 72, 1523784072, 0, 'text', 'ეფექტური მენეჯმენტის ტექნიკები', '', '', 'management', '', '', '', 'en', 1, 0, 1),
(192, 73, 72, 1523784072, 0, 'text', 'ეფექტური მენეჯმენტის ტექნიკები', '<p>ეფექტური მენეჯმენტის ტექნიკები ეფექტური მენეჯმენტის შემსწავლელი კურსები ტრენინგ ცენტრი სასწავლო ცენტრი</p>', '<p>პროგრამის დასახელება: \"ეფექტური მართვის ტექნიკები\" თანამედროვე მენეჯერებისთვის!</p>\n<p>ვისთვის არის აღნიშნული პროგრამა? მოქმედი და დამწყები მენეჯერებისთვის, ვისაც სურს თანამედროვე მართვის ტექნიკები გაიზიაროს და ეფექტური გახადოს მართვის მეთოდები.</p>\n<p>კურსის შედეგი:</p>\n<p>** ტრენინგის მონაწილეები ისწავლიან, თუ როგორ მიაღწიონ დასახულ მიზანს და შეინარჩუნოს გუნდის კეთილგანწყობა.<br />** პროგრამა დაფუძნებულია სწავლების ინტერაქტიულ პრინციპზე: ცოდნის შეძენა (სემინარი, მცირე ლექცია), უნარების განვითარება (სავარჯიშოები, თამაშები) და ცვლილება დამოკიდებულებებში (განხილვები, დისკუსია, დებატები).</p>\n<p>ტრეინინგის თემატიკა:</p>\n<p>** ფასეულობების განსაზღვრა - 2 საათი<br />** გუნდის მართვა - 10 საათი<br />** ბიზნეს კომუნიკაცია - 8 საათი<br />** დროის მართვა - 2 საათი<br />** ორგანიზაციული კულტურა და ერთგულება - 2 სთ</p>\n<p>ფასეულობათა განსაზღვრა:</p>\n<p>** რა არის მენეჯმენტი და რა ფასეულობებს ქმნიან მენეჯერები?<br />** დავჩექინდეთ, სად ვართ ამჟამად?<br />** ლიდერი VS მენეჯერი<br />** ქეისების განხილვა<br />** შეჯამება: ახალი რა გავიგე, რასაც პრაქტიკაში გამოვიყენებ?</p>\n<p>გუნდის მართვა:</p>\n<p>** რა გვჭირდება გუნდის სწორად მართვისათვის?<br />** რა ძირითად ფაქტორებზეა დამოკიდებული პერსონალის კმაყოფილება/უკმაყოფილება<br />** სავარჯიშო - \"მოიპოვე მარკერი\"<br />** ფსიქოლოგიური ფაქტორები მართვის პროცესში: სუბიექტური აღქმა და რეალობა.<br />** პრაქტიკული სავარჯიშოები და ქეისების განხილვა.<br />** ორგანიზაციული კონფლიქტები და მისი მართვის გზები<br />** ერიკ ბერნის ტრანზაქციული ანალიზი და პრაქტიკული სავარჯიშო<br />** ქცევითი სტრატეგიები და კილმანის ტესტი.<br />** მოტივაცია: შინაარსობრივი და პროცესუალური თეორიები.<br />** მოტივაციის სავარჯიშო: \"3 ქეისი\"<br />** აქტივობა: გუნდების მიერ სამოტივაციო პოლიტიკის ჩამოყალიბება<br />** შესრულებული სამუშაოს შეფასება/ მეთოდები<br />** ფუნქციების დელეგირება: job description-ის წერა<br />** კადრების შესარჩევად სწორი გასაუბრების პროცესის წარმართვა<br />** გასაუბრება: მოდელირებული სიტუაციები<br />** ბიზნეს პროცესების კვარტალური დაგეგმარება - მენეჯმენტი მიზნების მიხედვით<br />** შეჯამება: ახალი რა გავიგე, რასაც პრაქტიკაში გამოვიყენებ?</p>\n<p>ბიზნეს კომუნიკაცია:</p>\n<p>** ეფექტური კომუნიკაციის ტიპები<br />** ბიზნეს მოლაპარაკების ტექნიკები<br />** სავარჯიშო: \" ფორთოხალი\"<br />** ეფექტური უკუკავშირის განხორციელება თანამშრომლებთან;<br />** როგორ ვისწავლოთ თანამშრომლების მოსმენა?<br />** ინტელექტის ორი მიმართულება: IQ და EQ (ზოგადი და ემოციური ინტელექტი)<br />** სხეულის ენა;</p>\n<p>დროის მართვა:</p>\n<p>** დროის მხარჯველების განსაზღვრა;<br />** პრიორიტეტების განსაზღვრა - საიდან დავიწყოთ?<br />** დროის მართვის ეფექტური მოდელი</p>\n<p>ტრეინინგის შეჯამება:</p>\n<p>** რატომ ვარ უკეთესი ლიდერი?<br />** რატომ შემიძლია გუნდის უკეთესად მართვა?<br />** რატომ შემიძლია უკეთესი ბიზნეს კომუნიკაციის წარმოება?</p>\n<p>სრული პროგრამის ხანგრძლივობა: 24 საათი<br />კურსის ღირებულება: 400 ლარი</p>\n<p>ტრენერი: 9 წლიანი პრაქტიკული მენეჯერული გამოცდილება, ბიზნეს და არასამთავრობო სექტორში. 5 წელია წარმატებით ისწავლება მისი საავტორო პროგრამა მოქმედი და მომავალი მენეჯერებისთვის სხვადასხვა ორგანიზაციაში.</p>\n<p>[registration]</p>', 'management', '', '', '', 'ge', 1, 0, 1),
(193, 74, 72, 1523784118, 0, 'text', 'ფინანსური მენეჯმენტი', '', '', 'finansial-management', '', '', '', 'en', 2, 0, 1),
(194, 74, 72, 1523784118, 0, 'text', 'ფინანსური მენეჯმენტი', '<p>ფინანსური მენეჯმენტი ფინანსური მენეჯმენტის შემსწავლელი კურსები finansial management ტრენინგ ცენტრი სასწავლო ცენტრი</p>', '<p>&nbsp;</p>\n<p>ფინანსური მენეჯმენტი IFRS-ის სტანდარტების გამოყენებით</p>\n<p><strong>ლექცია 1-8 ოპერაციებისა და მოვლენების აღრიცხვა</strong></p>\n<p>1. ბასს (IAS) 2 - სასაქონლო-მატერილური ფასეულობები <br />2. ბასს (IAS) 16 - ძირითადი საშუალებები<br />3. ბასს (IAS) 38 - არამატერიალური აქტივები<br />4. ბასს (IAS) 40 - საინვესტიციო ქონება <br />5. ბასს (IAS) 23 - სესხით სარგებლობასთან დაკავშირებული დანახარჯები<br />6. ფასს (IFRS) 15 - მომხმარებლებთან გაფორმებული ხელშეკრულებებიდან მიღებული ამონაგები <br /><strong>7. ბასს (IAS) 17 - იჯარა და ფასს (IFRS) 16 იჯარა</strong></p>\n<p><strong>ლექცია 9-11 შეფასებები</strong></p>\n<p>1. ფასს (IFRS) 13 - რეალური ღირებულების შეფასება <br />2. ბასს (IAS) 36 - აქტივების გაუფასურება <br />3. ბასს (IAS) 8 - სააღრიცხვო პოლიტიკა, ცვლილებები სააღრიცხვო შეფასებებში და შეცდომები <br />4. ფასს (IFRS) 1 - ფასს-ის პირველად გამოყენება</p>\n<p><strong>ლექცია 12 ანგარიშგება</strong></p>\n<p>1. ბასს (IAS) 1 - ფინანსური ანგარიშგების წარდგენა <br />2. ბასს (IAS) 7 - ფულადი ნაკადების ანგარიშგება</p>\n<p><br /><strong>მიხეილ მუმლაძე</strong></p>\n<p>მიხეილის პროფესიული კარიერა მოიცავს 10 წლიან სამუშაო გამოცდილებას ფინანსებში, ბუღალტერიაში, ბიზნესისა და საინფორმაციო ტექნოლოგიების კონსალტინგში. მიხეილი მუშაობდა სხვადასხვა ორგანიზაციებში და ასევე საჯარო სექტორში. მისი გამოცდილება მოიცავს მუშაობას წარმოების მიმართულებით ასევე ენერგეტიკის სექტორში. 2018 წლიდან მიხეილი კითხულობს სალექციო კურსს IFRS სტანდარტები პროფესიონალი ბუღალტრებისთვის და ფინანსების მართვას ბიზნესისა და ტექნოლოგიების უნივერსიტეტში. <br />მიხეილი ფლობს მაგისტრის ხარისხს ბიზნესის სისტემების ანალიზსა და დიზაინში - City University London. ასევე, ACCA-ის უმაღლეს დიპლომს აღრიცხვასა და ბიზნესის ადმინისტრირებაში.</p>\n<p>გაითვალისწინეთ: ლექციების მსვლელობისას განსაკუთრებული ყურადღება დაეთმობა პრაქტიკული მაგალითების და სიტუაციური ამოცანების განხილვას, როგორც მსოფლიო, ასევე ქართული კომპანიების დამახასიათებელ მნიშვნელოვან ნიუანსებს. მსმენელებს გადაეცემათ სასწავლო მასალები და პრაქტიკული სავარჯიშოები, გაიმართება დისკუსიები, თავად მსმენელებისთვის საინტერესო და პრობლემური სიტუაციური მაგალითების განხილვა და მისი თავიდან აცილების კვალიფიციური და სწორი მიდგომები.</p>\n<p>კურსდამთავრებულის უპირატესობანი: დამოუკიდებლად შეძლებენ ფინანსური მენეჯერის პოზიციაზე მუშაობას. ჩვენი კურსდამთავრებულები არიან საქართველოში არსებული წამყვანი კომპანიის მთავარი ბუღალტრები და ფინანსისტები, მენეჯერები, ბიზნესმენები.</p>\n<p><strong>პროგრამის ხანგრძლივობა: 12 ლექცია.</strong><br /><strong>პროგრამის საფასური: 500 ლარი - 4 კაცი და მეტი ჯგუფში.</strong><br /><strong>ორი ან მეტი მსმსნელის ერთი ორგანიზაციიდან დაინტერესების შემთხვევაში გადაიხდით 450 ლარს ნაცვლად 500 ლარის.</strong></p>\n<p>ჩვენს მიერ მომზადებულები არიან, როგორც ადგილობრივი, ასევე საერთაშორისო კომპანიის ბუღალტრები და ფინანსისტები, კომპანიის ხელმძღვანელები, მათ შორისაა: შპს \"ემბავუდ ჯორჯია\", შპს \"ფურშეტ ჯორჯია\", შპს \" გერმანიის საერთაშორისო თანამშრომლობის საზოგადოება\" და სხვა კომპანიების წარმომადგენლები.</p>\n<p>კორპორატიული ტრენინგის ჩატარების შემთხვევაში, ვითვალისწინებთ უშუალოდ თქვენს მოთხოვნებს და მხოლოდ თქვენი კადრებისთვის ჩატარდება სასწავლო კურსი!</p>\n<p>[registration]</p>', 'finansial-management', '', '', '', 'ge', 2, 0, 1),
(195, 75, 72, 1523784176, 0, 'text', 'HR ადამიანური რესურსების მართვის ტექნიკები ', '', '', 'hr', '', '', '', 'en', 2, 0, 1),
(196, 75, 72, 1523784176, 0, 'text', 'ადამიანური რესურსების სტრატეგიული მართვის სასწავლო კურსი', '<p>საჯარო და კერძო სექტორის HR ბიზნეს პარტნიორების სასწავლო კურსი</p>', '<p><strong>კურსს უძღვება: მედეა ჯინჯიხაძე</strong> - მრავალწლიანი სამუშაო გამოცდილების მქონე ექსპერტი ადამიანური რესურსების მართვისა და ბიზნეს კონსალტინგის სფეროში.</p>\n<p><strong>კურსის ზოგადი მიმოხილვა:</strong> თუ გსურთ გახდეთ სრულფასოვანი HR ბიზნეს პარტნიორი და თანამედროვე ადამიანური რესურსების მართვის ექსპერტი, მაშინ დროა დარეგისტრირდეთ ჩვენს მიერ შემოთავაზებულ სასწავლო კურსზე, სადაც შეძლებთ განივითაროთ შესაბამისი კომპეტენციები.</p>\n<p><strong>სამიზნე აუდიტორია:</strong> სასწავლო კურსი განკუთვნილია საშუალო და დაბალი რგოლის ადამიანური რესურსების მენეჯერებისათვის და სპეციალისტებისათვის. კურსი ასევე არის კარგი სტარტი დამწყები სპეციალისტებისთვის, ვისაც სურს კარიერა ადამიანური რესურსების მართვას დაუკავშირონ.</p>\n<p><strong>სასწავლო კურსის თემატიკა:</strong></p>\n<p>HR- როლი ორგანიზაციის განვითარებაში (2 საათი)<br />ადამიანური კაპიტალის დაგეგმვა, შერჩევა, ინტერვიუს თავისებურებები და დაშვებული შეცდომები (2 საათი)<br />ორგანიზაციული სტრუქტურა, სამუშაოს აღწერა და ანალიზი (4 საათი)<br />სტრატეგიის განსაზღვრა და სტრატეგიული გეგმის შემუშავება (2 საათი)<br />შრომის ორგანიზაციული სამართლებრივი ღირებულებები. შრომის კოდექსის ახალი რედაქციის განხილვა, სასამართლო პრაქტიკის გაზიარება და პრაქტიკული ქეისები (2 საათი)<br />8 კანონი, რომელიც HR-მა უნდა იცოდეს. (2 საათი)<br />ორგანიზაციული კულტურა, სამუშაო დისციპლინა და ზნეობრივი პრინციპების მნიშვნელობა (2 საათი)<br />შეფასების სისტემის შემუშავება და დანერგვა ორგანიზაციაში (2 საათი)<br />მოტივაციის სისტემის სახეები და მისი დანერგვა ორგანიზაციაში (2 საათი) კვლევითი სამუშაოების მნიშვნელობა<br />ციფრული ტექნოლოგიების როლი ადამიანური რესურსების მართვაში, HR ადმინისტრირება და HR ბრენდინგში (2 საათი)<br />სინერგია მენეჯმენტში და განსაკუთრებული უნარების გამომუშავება (2 საათი) გამოწვევები, დაშვბული შეცდომები და განვითარების სწორი გზები ქეისები. თანამშრომელთა ჩართულობა და სოციალური პასუხისმგებლობა.<br />ყველა ლექციის დროს განიხილება თემტიკის მიხედვით რამოდენიმე ქეისი.<br />პრეზენტაციების წარდგენა და სასწავლო კურსის დახურვა/შეჯამება;</p>\n<p><strong>კურსდამთავრებულის უპირატესობები:</strong>ადამიანური რესურსების მართვის პროცესების დეტალური და არა ფრაგმენტული გაცნობა;<br />შეხვედრებზე განხილული სასწავლო მასალები, რომელიც სასწავლო კურსში მონაწილე პირებს უსასყიდლოდ გადაეცემათ;<br />ადამიანური რესურსების საუკეთესო და თანამედროვე პრაქტიკების განხილვა;<br />ეთიკის და ქცევის თანამდეროვე სტანდარტების პრაქტიკული გამოყენების შესწავლა;<br />ტექნოლოგიების როლისა და გავლენის მნიშვნელობა ორგანიზაციებსა და ადამიანური კაპიტალის მართვაში;<br />ადამიანური რესურსების მართვის სრული ციკლის მართვის უნარების შეძენა/გაუმჯობესება;<br />პრაქტიკული სამუშაოები და სამუშაო ჯგუფის აქტიური ჩართულობა სასწავლო პროცესში.</p>\n<p><strong>კურსი მოიცავს: 24 საათს</strong></p>\n<p><strong>კურსის ღირებულება: 550 ლარი</strong></p>\n<p><strong>[registration]</strong></p>', 'hr', '', '', '', 'ge', 2, 0, 1),
(197, 76, 72, 1523784235, 0, 'text', 'მარკეტინგისი მენეჯმენტის ექსპრეს კურსი', '', '', 'marketing', '', '', '', 'en', 3, 0, 1),
(198, 76, 72, 1523784235, 0, 'text', 'მარკეტინგისი მენეჯმენტის ექსპრეს კურსი', '<p>მარკეტინგის მენეჯმენტის ექსპრეს კურსი მარკეტინგი მენეჯმენტი შემსწავლელი კურსები მარკეტინგის და მენეჯმენტის შემსწავლელი კურსები ტრენინგ ცენტრი სასწავლო ცენტრი</p>', '<p>[registration]</p>', 'marketing', '', '', '', 'ge', 3, 0, 1),
(199, 77, 72, 1523784285, 0, 'text', 'პრაქტიკული ლოგისტიკა', '', '', 'logistic-management', '', '', '', 'en', 2, 0, 0),
(200, 77, 72, 1523784285, 0, 'text', 'შესყიდვების მართვა და ლოგისტიკა', '<p>ლოგისტიკა, შესყიდვების მართვა შემსწავლელი კურსები ტრენინგ ცენტრი სასწავლო ცენტრი</p>', '<ol>\n<li><strong>შესყიდვების მართვა</strong></li>\n</ol>\n<p>კურსის მსმენელები მიიღებენ და გაიღმავებენ ცოდნას შესყიდვების მართვის და ასევე გაყიდვების პროგნოზირების (forecasting) მიმართულებით, რათა წარმატებით შეძლონ აღნიშნულ სფეროში მოღვაწეობა. კურსის თეორიული და პრაქტიკული ნაწილი მსმენელს აძლევს საშუალებას კრეატიულად და ინოვაციურად მიუდგეს ამ სფეროში არსებულ სხვადასხვა პრობლემებს და მონახოს მათი ეფექტურად გადაჭრის გზები.<br />შესყიდვების მართვის კურსი განკუთვნილია შესყიდვების და კატეგორიის მენეჯერების, ასევე ამ სფეროთი დაინტერესებული ნებისმიერი პირისთვის. <br /><strong>შესყიდვების მართვის პროგრამა მოიცავს შემდეგ საკითხებს:</strong><br />&bull; შესავალი შესყიდვებში და მისი მნიშვნელობა კომპანიებისათვის;<br />&bull; შესყიდვების ბაზრის ანალიზი;<br />&bull; მომწოდებლების შეფასება და შერჩევა;<br />&bull; შესყიდვების სტრატეგიები;<br />&bull; შეკვეთების დაგეგმვა მოთხოვნის გათვალისწინებით და კოორდინაცია მომწოდებლებთან;<br />&bull; საერთაშორისო შესყიდვების სპეციფიკა - ძირითადი ქვეყნების პრაქტიკის შედარება;<br />&bull; მოწოდების პირობები და ინკოტერმსი 2020;<br />&bull; შესყიდვის კონტრაქტები;<br />&bull; მოლაპარაკება შესყიდვების დროს;<br />&bull; პრაქტიკული ქეისები;</p>\n<p><strong>კურსი მოიცავს: 10 საათს</strong><br /><strong>სწავლის ღირებულება: 500 ლარი</strong></p>\n<p>[registration]</p>\n<p><strong>კურსის ბოლოს ჩატარდება ტესტირება!</strong><br />კურსდამთავრებულებს გადაეცემათ შესაბამისი სერტიფიკატი!</p>\n<p><strong>2. ლოგისტიკა:&nbsp;</strong></p>\n<p>ლოგისტიკის კურსი მიზნად ისახავს, მსმენელმა მიიღოს და გაიღრმაოს ცოდნა ტრანსპორტის და სასაწყობო ოპერაციების მიმართულებით, რათა წარმატებით შეძლონ აღნიშნულ სფეროში მოღვაწეობა. კურსის თეორიული და პრაქტიკული ნაწილი მსმენელს აძლევს საშუალებას კრეატიულად და ინოვაციურად მიუდგეს ამ სფეროში არსებულ სხვადასხვა პრობლემებს და მონახოს მათი ეფექტურად გადაჭრის გზები.<br /><strong>კურსდამთავრებული შეისწავლის შემდეგ საკითხებს:</strong><br />ტრანსპორტირების მართვა<br />საწყობის მართვა<br />მიწოდება<br /><strong>ლოგისტიკის პროგრამა მოიცავს:</strong><br />&bull; შესავალი ლოგისტიკაში, ლოგისტიკის მნიშვნელობა, მიზნები და<br />&bull; მათ შორის არსებული კონფლიქტები;<br />&bull; ტრანსპორტის სხვადასხვა სახეობები ანალიზი;<br />&bull; სატრანსპორტო საშუალებები და კომბინირებული ტრანსპორტი;<br />&bull; ტრანსპორტის დოკუმენტაცია;<br />&bull; გადამზიდავის შერჩევა;<br />&bull; ინკოტერმსი 2020 და დაზღვევა;<br />&bull; ტრანსპორტირების გეგმის შემუშავება;<br />&bull; შიდა ტრანსპორტის სახეობები;<br />&bull; ლოგისტიკური ცენტრები და სასაწყობო მეურნეობა;<br />&bull; საწყობის ცალკეული სახეობების შესწავლა და ოპტიმალური დაგეგმვა;<br />&bull; დისტრიბუციის ფუნქცია და სახეები;<br />&bull; სადისტრიბუციო მარშრუტების ოპტიმიზაცია;<br />&bull; შეფუთვის სახეები;<br />&bull; საავტომობილო პარკის მართვა;</p>\n<p><strong>კურსი მოიცავს:&nbsp;10 საათს</strong><br /><strong>სწავლის ღირებულება: 500 ლარი</strong></p>\n<p>[registration]</p>\n<p><strong>გაითვალისწინეთ: ორივე მოდულის შესწავლის შემთხვევაში კურსის ღირებულება იქნება 850 ლარი!</strong></p>\n<p><strong>ხოლო ლექციების რაოდენობა&nbsp; - 8/2 სთ-იანი</strong></p>\n<p>&nbsp;</p>\n<p>&nbsp;</p>', 'logistic-management', '', '', '', 'ge', 2, 0, 0),
(331, 143, 140, 1694006597, 0, 'text', 'ხარისხის კონტროლის პრინციპები და HACCP-ის სისტემა', '<p><strong>ხარისხის კონტროლის პრინციპები და HACCP-ის სისტემა</strong></p>', '<p>პროგრამის სახელწოდება: ხარისხის კონტროლის პრინციპები და HACCP-ის სისტემა<br />პროგრამა განკუთვნილია:იმ პირებისთვის ვინც დასაქმებულია სურსათის საწარმოებსა და ობიექტებში, ან სურს საწარმო, სარეალიზაციო ობიექტის გახსნა, განახლება, კურსი ასევე განკუთვნილია პირებისთვის ვისაც სურს პერსონალის გადამზადება ხარისხის კონტროლის მიმართულებით.<br />კურსი მოიცავს: შეისწავლოთ ხარისხის კონტროლის მნიშვნელობა, მისი განსაზღვრა ნედლეულიდან მის საბოლოო პროდუქტამდე გარდა ამისა გექნებათ შესაძლებლობა შეისწავლოთ HACCP-ის სისტემის მნიშვნელობა მისი დანერგვისა და განხორციელებისათვის საჭირო დეტალები. <br />თემატიკა<br />&bull; სურსათის უვნებლობის მნიშვნელობა და მისი რეგულირების ძირითადი დებულებები<br />&bull; სურსათისა და სასურსათო ნედლეულის ძირითადი ქიმიური კომპონენტები. <br />&bull; სურსათის უვნებლობის პოლიტიკის ძირითადი საკითხები <br />&bull; სურსათის უვნებლობის პრინციპები საქართველოში.<br />&bull; სურსათისა და სასურსათო ნედლეულის ხარისხი, სურსათის დაბინძურების წყაროები <br />&bull; სურსათისა და სასურსათო ნედლეულის უვნებლობა.<br />&bull; სურსათისა და სასურსათო ნედლეულის ტექნიკური რეგულირება, სტანდარტიზაცია და სერტიფიკაცია.<br />&bull; სურსათისა და სასურსათო ნედლეულის საფრთხეები.<br />&bull; საფრთხის ანალიზისა და კრიტიკული საკონტროლო წერტილების სისტემა &ndash; HACCP. <br />&bull; მიკვლევადობის პრინციპები სურსათის უვნებლობაში. <br />&bull; HACCP-ის დანერგვამდე საჭირო წინასწარი პროგრამები GHP, GMP<br />&bull; HACCP ის სისტემის დანერგვის პრინციპები <br />&bull; HACCP-ის გეგმა და დოკუმენტაციის, ჩანაწერების წარმოება <br />კურსდამთავრებულის უპირატესობა: შეისწავლის სურსათის უვნებლობისათვის საჭირო არსებულ ძირითად მიმართულებებს, რომელიც პრაქტიკაში გამოიყენება, ასევე შეძლებენ თეორიული ცოდნის მიხედვით საწარმოებში, სურსათის წარმოების და რეალიზაციის დაწესებულებებში დაიცვან ხარისხის კონტროლი, შეძლებენ საჭირო დოკუმენტაციის სწორად წარმოებას.<br />სრული პროგრმის ხანგრძლივობა : 8 ლექცია<br />კვირაში ჩატარდება 2 ლექცია<br />ლექციის ხანგრძლივობა 1,5 სთ<br />კურსის ღირებულება ჯგუფში 3 კაციდან: 500<br />კურსის ღირებულება წყვილში: 650<br />კურსის ღირებულება ინდივიდუალურად:750<br />კურსის ბოლოს ჩატარდება დასკვნითი ტესტირება და გაიცემა სერთიფიკატი<br />კურსს უძღვება: ანჟელა ღაჭავა - 4 წლიანი გამოცდილების მქონე სურსათის ტექნოლოგი <br />მეღვინეობის მაგისტრი, ტრენერი.</p>\n<p>&nbsp;</p>', 'HACCP', '', '', '', 'en', 1, 0, 1),
(201, 78, 9, 1523784420, 0, 'text', 'ბუღალტრეული აღრიცხვა დამწყებთათვის', '', '', 'accounting-course', '', '', '', 'en', 1, 0, 0),
(202, 78, 9, 1523784420, 0, 'text', 'ბუღალტრეული აღრიცხვა დამწყებთათვის', '<p>ბუღალტერია; ბუღალტერი; ბუღალტერიის შემსაწვლელი კურსები; ბუღალტრული აღრიცხვა დამწყებთათვის; ორისი; კონსულტაცია; საბუღალტრო კომპიუტერული პროგრამები; საგადასახადო კანონმდებლობა სტაჟირება; სუპერფინი, ინფო 1ც;</p>', '<p><strong>მიზნობრივი ჯგუფები:</strong> კომბინირებული ჯგუფები, როგორც დამწყები და მოქმედი ბუღალტრებისთვის, ასევე ნებისმიერი პროფესიის და განათლების მქონე პირთათვის.</p>\n<p><strong>კურსის აღწერა:</strong> პროგრამა შექმნილია კვალიფიციური გამოცდილი ბუღალტრებისა და აუდიტების ჯგუფის მიერ და ითვალისწინებს ფინანასური აღრიცხვის, საგადასახადო კოდექსის და საბუღალტრო კომპიუტერული პროგრამების კომპლექსურ შესწავლას, რის საფუძველზეც შეძლებთ კომლექსური ამოცანების გადაჭრას, რაც გულისხმობს, როგორც ფინანასური უწყისების, ასევე საგადასახადო დეკლარაციების მომზადებას და წარდგენას, რთულ ფინანასურ სიტუაციებში რჩევების მიცემას და საგადასახადო კანონების მორგებას და ლავირებას კომპანიის სასიკეთოთ.</p>\n<p>სწავლების მეთოდი: ლექციები, ინტერაქტივი, დისკუსია, პრაქტიკული ქეისები და სამუშაოები, თემატური გამოკითხვა, შეფასების ტესტები, მათი განხილვა და ანალიზი, კურსის განმავლობაში ჩატარდება შუალედური, ხოლო დასრულებისას სასერთიფიკატო გამოცდა.</p>\n<p><strong>შედეგი:</strong> პროგრამის სრულყოფილად დაუფლების შემდეგ თქვენ შეძლებთ დამოუკიდებლად აწარმოოთ ნებისმიერი ორგანიზაციული ფორმის საბუღალტრო საქმე და სრულყოფილად წარმართოთ საგადასახადო აღრიცხვიანობა, მოახდინოთ ანგარიშების ნაშთების კონტროლი და ყოველთვიური და ყოველწლიური დეკლარაციების დამოუკიდებლად მომზადება.</p>\n<p><strong>კურსს უძღვებიან</strong> - გამოცდილი პროფესიონალი სერტიფიცირებული, პრაქტიკოსი მთავარი ბუღალტრები.</p>\n<p>მსმენელებს უფასოდ გადაეცემათ სასწავლო ლიტერატურა, სხვადასხვა ქეისების მაგალითების დოკუმენტაციები.</p>\n<p><strong>კურსის დასრულების შემდეგ ჩატარდება ტესტირება და გაიცემა შესაბამისი ორენოვანი სერთიფიკატი.</strong></p>\n<p><strong>კურსის ხანგრძლივობა -&nbsp;ორი თვე</strong></p>\n<p><strong>ლექციის ხანგრძლივობა -1.30</strong></p>\n<p><strong>კურსის ღირებულება ოთხ კაცი და მეტი ჯგუფში:&nbsp;თვეში 250 ლარი</strong></p>\n<p><strong>3 კაციან ჯგუფში: თვეში 335 ლარი</strong></p>\n<p><strong>კურსის ღირებულება&nbsp;წყვილში - 450 ლარი</strong></p>\n<p>&nbsp;</p>\n<p>[registration]</p>', 'accounting-course', '', '', '', 'ge', 1, 0, 0),
(203, 79, 46, 1523784530, 0, 'text', 'საკომუნიკაციო რუსული', '', '', 'russen', '', '', '', 'en', 1, 0, 0),
(204, 79, 46, 1523784530, 0, 'text', 'საკომუნიკაციო რუსული', '<p>საკომუნიკაციო რუსულის შემსწავლელი კურსები რუსული ენის შემსწავლელი კურსები რუსული ენა სასაუბრო რუსული ტრენინგ ცენტრი სასწავლო ცენტრი russen</p>', '<p><strong>Элементарный уровень</strong><br />ელემენტარული დონე განკუთვნილია იმ მსმენელთათვის, ვინც იწყებს ენის შესწავლას თავიდან.ამ ეტაპის გადალახვის შემდეგმათ შეეძლებათ ურთიერთობა ენის მატარებლებთან ელემენტარულ-უბრალო საბაზისო სიტყვების გამოყენებით, საკომუნიკაციო სიტუაციაში. ელემენტარული კურსის გავლის შემდეგ მსმენელს შეუძლია დაეუფლოს საბაზო დონეს.<br /> <br />სახელმძღვანელოები: Станислав Чернышов, Поехали (начальный курс); Дорога в Россию. Учебник русского языка. - В. Е. Антонова, М. М. Нахабина, А. А. Толстых ; Видео-аудио записи<br /> <br />ელემენტარული დონე მოიცავს ერთვიან კურს (80-100 საათი)<br /> <br />სწავლობენ: Имя существительное: Род, число, падежные формы; Глагол: время; Личные местоимения. 400-480 слов<br /> <br />ლექციის რაოდენობა თვეში: კვირაში 2 ჯერ -1სთ. 30 წთ.<br />ღირებულება თვეში: 120 ლარი ჯგუფში 3-4 მოსწავლე.<br />ღირებულება თვეში:&nbsp;150 ლარი ჯგუფში 2 მოსწავლე.<br />ინდივიდუალურად: 200 ლარი<br /> <br /><strong>Базовый уровень</strong><br />ამ დონეზე კომუნიკაცია დაკავშირებულია საყოფაცხოვრებო, სოციალურ , კულტურულ და სასწავლო სფეროსთან.<br />საბაზო კურსი გულისხმობს საკმარის და საჭირო დონეს რუსული ენის სწავლის გასაგრძელებლად.<br /> <br />სახელმძღვანელოები: Станислав Чернышов, Поехали (II курс); Станислав Чернышов, Алла Чернышова, Поехали (базовый курс); Дорога в Россию. Учебник русского языка. - В. Е. Антонова, М. М. Нахабина, А. А. Толстых - (Базовый уровень )Видео-аудио записи.<br /> <br />საბაზო დონე მოიცავს ორთვიან კურს ( იმ შემთხვევაში თუ, ელემნტარული კურსი შესწავლილია) 160-180 საათი<br />ისწავლება: Все части речи. 1500 слов.<br /> <br />ლექციის რაოდენობა თვეში: კვირაში 2 ჯერ -1სთ. 30 წთ.<br />ღირებულება თვეში: 120 ლარი ჯგუფში 3-4 მოსწავლე.<br />ღირებულება თვეში: 150 ლარი ჯგუფში 2 მოსწავლე.<br />ინდივიდუალურად: 200 ლარი&nbsp;</p>\n<p>&nbsp;</p>\n<p>[registration]</p>', 'russen', '', '', '', 'ge', 1, 0, 0),
(205, 80, 46, 1523784641, 0, 'text', 'ბიზნეს რუსული', '', '', 'bussines-russian', '', '', '', 'en', 2, 0, 0),
(206, 80, 46, 1523784641, 0, 'text', 'ბიზნეს რუსული', '<p>bussines russian ბიზნეს რუსული ბიზნეს რუსულის შემსწავლელი კურსები რუსული ენის შემსწავლელი კურსები ტრენინგ ცენტრი სასწავლო ცენტრი</p>', '<p>ბიზნეს რუსულის შესწავლა მოიცავს:</p>\n<p>გრამატიკას, ბიზნეს ლექსიკას, ბიზნეს თემების დამუშავებას, დისკუსიას თემების ირგვლივ, სტატიების გარჩევას,ვიდეო ჩანაწერების გამოყენებას.<br /> <br />ამ კურსის გავლის შემდეგ მსმენელს შეეძლება საქმიანი წერილების მომზადება, სატელეფონო ურთიერთობები ბიზნეს პარტნიორებთან და წარმატებით მოღვაწეობა.<br />ბიზნეს რუსული მოიცავას ორთვიან კურს.<br /> <br /><strong>ლექციის რაოდენობა თვეში: კვირაში 2 ჯერ -1სთ. 30 წთ.</strong></p>\n<p><strong>ღირებულება თვეში:&nbsp;180 ლარი ჯგუფში მოსწავლე.</strong></p>\n<p><strong>წყვილში : 220 ლარი</strong></p>\n<p><strong>ინდივიდუალურად: 300 ლარი</strong><br /> <br /><br /></p>\n<p>[registration]</p>', 'bussines-russian', '', '', '', 'ge', 2, 0, 0),
(207, 81, 46, 1523784680, 0, 'text', 'რუსული ენა უცხოელებისთვის', '', '', 'ruusian-for-eng', '', '', '', 'en', 3, 0, 0),
(208, 81, 46, 1523784680, 0, 'text', 'რუსული ენა უცხოელებისთვის', '<p>რუსული ენა უცხოელებისთვის რუსული ენის შემსწავლელი კურსები ტრენინგ ცენტრი სასწავლო ცენტრი russian&nbsp;</p>', '<p>რუსული ენა ვასწავლოთ ინგლსურ ენოვან დაინტერესებულ პირებს!</p>\n<p><br />ლექციის ხანგრძლივობა - 1სთ. 30 წთ</p>\n<p>ჯგუფში-3 კაციდან - კვირაში 2 ჯერ-ღირებულება 180 ლარი;</p>\n<p>ჯგუფში - 2 კაცი- კვირაში 2 ჯერ-ღირებულება&nbsp;200 ლარი;</p>\n<p>ინდივიდუალურად: კვირაში 2 ჯერ-ღირებულება&nbsp;250 ლარი;</p>\n<p>&nbsp;</p>\n<p>[registration]</p>', 'ruusian-for-eng', '', '', '', 'ge', 3, 0, 0),
