(348, 151, 8, 1747918031, 0, 'text', 'ბიზნეს ანალიტიკის ტექნიკები ექსელის გამოყენებით', '<p>ბიზნეს ანალიტიკის ტექნიკები ექსელის გამოყენებით - Business Analytics with Excel<br />ტრენინგი შემუშავებულია Johns Hopkins University-მიერ</p>', '<p>ბიზნეს ანალიტიკის ტექნიკები ექსელის გამოყენებით - Business Analytics with Excel<br />ტრენინგი შემუშავებულია Johns Hopkins University-მიერ</p>\n<p>ვისთვის არის კურსი:<br />მენეჯერები &ndash; ოპერაციები | ლოჯისტიკა | კომერცია<br />ანალიტიკოსები &ndash; ფინანსური | საოპერაციო | კომერციული<br />კარიერული ზრდის მსურველები<br />Excel-ის მომხმარებლები ნებისმიერი გამოცდილებით<br />მონაწილეობის წინაპირობა-EXCEL საბაზო დონეზე ფლობა</p>\n<p>ისწავლება:<br />', 'Business Analytics with Excel', '', '', '', 'ge', 11, 0, 1),
(235, 95, 14, 1523817395, 0, 'text', 'ფინანსური მომსახურება', '', '', 'finansial service', '', '', '', 'en', 3, 0, 1),
(236, 95, 14, 1523817395, 0, 'text', 'ფინანსური მომსახურება', '', '', 'finansial service', '', '', '', 'ge', 3, 0, 1),
(237, 96, 7, 1523868182, 0, 'text', 'Geoinformation systems', '', '<p>გეოგრაფიული საინფორმაციო სისტემა არის კომპიუტერულ რუკებსა და მონაცემთა ბაზებზე დაფუძნებული საინფორმაციო სისტემა, რომელიც გამოიყენება სივრცეში განთავსებული მონაცემების შეგროვების, შენახვის, მართვისა და ანალიზისთვის.<br />ჩვენი კურსდამთავრებულები არიან: თელასის, საქართველოს რკინიგზის, ჯორჯიან ვოთერ ენდ ფაუერის, საჯარო რეესტრის, კაუკასუს ონლაინის, იუსტიციის სახლის, სხვადასხვა მუნიციპალიტეტების და სხვა ცნობილი კომპანიების კადრები!</p>\n<p>ხორციელდება კორპორატიული მომხმარებლებისთვის მსემენელთა მომზადება, როგორც ჩვენს ოფისში, ასევე ადგილზე მოსვლით, სპეციალურად თქვენი მოთხოვნებიდან გამომდინარე, შეიქმნება სპეციალიზირებული პროგრამა.</p>\n<p>გეოინფორმაციული სისტემები რამდენიმე ძირითადი მიმართულებისგან შედგება</p>', 'geoinformacional-systems', 'contactdetails', '', '', 'en', 7, 0, 1),
(238, 96, 7, 1523868182, 0, 'text', 'გეოინფრომაციული სისტემები', '<p>გეოინფორმაციული სისტემები გეოინფორმაციული სისტემების შემსწავლელი კურსები geoinformacional systems ტრენინგ ცენტრი სასწავლო ცენტრი</p>', '', 'geoinformacional-systems', '', '', '', 'ge', 7, 0, 1),
(239, 97, 96, 1523868605, 0, 'text', 'გეოინფორმაციული სისტემები ArcGIS 10.4', '', '', 'ArcGIS 10.4', '', '', '', 'en', 1, 0, 0),
(240, 97, 96, 1523868605, 0, 'text', 'გეოინფორმაციული სისტემები - ArcGIS 10.4', '<p>გისის კურსი გეოინფორმაციული სისტემები და ბაზები არკ გისი&nbsp;გეოინფორმაციული სისტემები - ArcGIS 10.4</p>', '<p>გეოგრაფიული საინფორმაციო სისტემა არის კომპიუტერულ რუკებსა და მონაცემთა ბაზებზე დაფუძნებული საინფორმაციო სისტემა, რომელიც გამოიყენება სივრცეში განთავსებული მონაცემების შეგროვების, შენახვის, მართვისა და ანალიზისთვის.<br />ჩვენი კურსდამთავრებულები არიან: თელასის, საქართველოს რკინიგზის, ჯორჯიან ვოთერ ენდ ფაუერის, საჯარო რეესტრის, კაუკასუს ონლაინის, იუსტიციის სახლის, სხვადასხვა მუნიციპალიტეტების და სხვა ცნობილი კომპანიების კადრები!</p>\n<p>ხორციელდება კორპორატიული მომხმარებლებისთვის მსემენელთა მომზადება, როგორც ჩვენს ოფისში, ასევე ადგილზე მოსვლით, სპეციალურად თქვენი მოთხოვნებიდან გამომდინარე, შეიქმნება სპეციალიზირებული პროგრამა.</p>\n<p>გეოინფორმაციული სისტემები რამდენიმე ძირითადი მიმართულებისგან შედგება.</p>\n<p>სად შეუძლია GIS-ის სპეციალისტს მუშაობა?<br />ნებისმიერ სახელმწიფო თუ კერძო დაწესებულებაში, რომელთაც აქვთ სივრცით ინფორმაციასთან საქმე. კერძოდ:</p>\n<p>** თავდაცვის სფეროში<br />** შინაგან საქმეთა უწყებაში<br />** საჯარო რეესტრში<br />** საჯარო რეესტრის ავტორიზებულ კერძო ამზომველ კომპანიებში<br />** მერიის დაქვემდებარების უწყებებში<br />** ტურიზმის დეპარტამენტში<br />** თელასში<br />** თბილგაზში<br />** თბილისის წყალში<br />** არქიტექტურულ სამსახურებში<br />** სამშენებლო კომპანიებში<br />** სასწავლო-სამეცნერო დაწესებულებებში<br />** სკოლებში<br />** მსხვილ კორპორაციებში (გაზისა და ნავთობის, ელექტროკავშირი და სხვა).</p>\n<p>გაკვეთილი 1. ზოგადი საკითხები<br />გაკვეთილი 2. გის-ის მონაცემთა სახეები<br />გაკვეთილი 3. გის-ის ვექტორული თემატური ფენების დიგიტალიზაცია (აციფრვა)<br />გაკვეთილი 4. მონაცემთა ატრიბუტული ცხრილები<br />გაკვეთილი 5. მონაცემთა მონიშვნა (Selection)<br />გაკვეთილი 6. მონაცემთა ვიზუალიზაცია<br />გაკვეთილი 7. წარწერებთან მუშაობა<br />გაკვეთილი 8. ციფრული რუკის კომპოზიცია <br />გაკვეთილი 9. სხვადასხვა ტიპის ციფრული რუკების გენერირება<br />გაკვეთილი 10. სასარგებლო ინსტრუმენტები და უნარ-ჩვევები</p>\n<p><br />სწავლის ხანგრძლივობა 10 - 2 სთ-იანი ლექცია - სამ-ოთხკაციან ჯგუფში - 700 ლარი <br />სწავლის ხანგრძლივობა 10 - 2 სთ-იანი ლექცია - ხუთ-ათ კაციან ჯგუფში - 600 ლარი</p>\n<p>&nbsp;[registration]</p>', 'ArcGIS-10.4', '', '', '', 'ge', 1, 0, 0),
(243, 99, 96, 1523869097, 0, 'text', 'ლანდშაფტების 3D მოდელირება', '', '', 'ArcGIS 3D Analyst', '', '', '', 'en', 3, 0, 0),
(241, 98, 96, 1523868701, 0, 'text', 'გეომონაცემთა ბაზები და პროგრამირება (პროგრამირება ArcGIS-ის გარემოში)', '', '', 'arcgis proggraming', '', '', '', 'en', 2, 0, 0),
(242, 98, 96, 1523868701, 0, 'text', 'გეომონაცემთა ბაზები და პროგრამირება', '<p>გეომონაცემთა ბაზები და პროგრამირება გეოინფორმაციული ბაზების და პროგრამირების შემსწავლელი კურსები arcgis proggraming ტრენინგ ცენტრი სასწავლო ცენტრი</p>', '<p>პროგრამირება ArcGIS-ის გარემოში</p>\n<p>ArcGIS-ის დაპროგრამების საშუალებები (VBA) და ArcObjects-ის მოდელი (2 სთ)<br />2. გეომონაცემების გამოყენება (მონაცემთა მწკრივები და ფენები. მათი ატრიბუტები, დამუშავება, გარდაქმნა და საკოორდინატო სისტემებთან მიბმა) (2-3 სთ)<br />3. მონაცემთა გამოსახვა (2 სთ)<br />4. ArcObjects-ის მოდელის გამოყენება გეომონაცემთა შესწავლისას (2 სთ)<br />5. ოპერაციები ვექტორულ მონაცემებზე (1.5-2 სთ)<br />6. ოპერაციები რასტრულ მონაცემებზე (1.5-2 სთ)<br />7. ArcObjects-ის გამოყენება ადგილობრივი რუკების შექმნისას და სივრცული ინტერპოლაციის დროს (2-3 სთ)</p>\n<p>&nbsp;</p>\n<p>სწავლის ხანგრძლივობა 7 - 2 სთ-იანი ლექცია - სამ-ოთხ კაციან ჯგუფში - 600 ლარი <br />სწავლის ხანგრძლივობა 7 - 2 სთ-იანი ლექცია - ხუთ-ათ კაციან ჯგუფში - 500 ლარი</p>\n<p>[registration]</p>', 'arcgis-proggraming', '', '', '', 'ge', 2, 0, 0),
(244, 99, 96, 1523869097, 0, 'text', 'ლანდშაფტების 3D მოდელირება', '<p>ლანდშაფტების 3D მოდელირება ტრენინგ ცენტრი სასწავლო ცენტრი ArcGIS 3D Analyst ლანდშაფტის 3D მოდელირების შემსწავლელი კურსები</p>', '<p>ArcGIS 3D Analyst - სამგანზომილებიანი გეოსაინფორმაციო სისტემა</p>\n<p>ArcGIS 3D Analyst-ის შესაძლებლობები და გამოყენება (1 სთ)</p>\n<p>შესავალი კურსი (2 სთ)<br />2. ზედაპირების სამგანზომილებიანი მოდელების (მაგ., TIN da DEM) შექმნა (2 სთ)<br />3. სამგანზომლებიანი მონაცემების მართვა (2 სთ)<br />4. ზედაპირების გამოსახვა (2 სთ)<br />5. ზედაპირების ანალიზი (2 სთ)<br />6. 3D ვიზუალიზაცია (2 სთ)<br />7. 3D ანიმაცია (2 სთ).</p>\n<p><br />სწავლის ხანგრძლივობა 7 - 2 სთ-იანი ლექცია - სამ-ოთხ კაციან ჯგუფში - 600 ლარი <br />სწავლის ხანგრძლივობა 7 - 2 სთ-იანი ლექცია - ხუთ-ათ კაციან ჯგუფში - 500 ლარი</p>\n<p>[registration]</p>', 'ArcGIS-3D-Analyst', '', '', '', 'ge', 3, 0, 0),
(245, 100, 96, 1523869468, 0, 'text', 'გამოყენებითი კარტოგარფიის და გეოდეზიის საფუძვლები', '', '', 'Applied cartography and geodesy basics', '', '', '', 'en', 4, 0, 0),
(246, 100, 96, 1523869468, 0, 'text', 'გამოყენებითი კარტოგარფიის და გეოდეზიის საფუძვლები', '<p>გამოყენებითი კარტოგრაფიის და გეოდეზიის საფუძვლები გამოყენებითი კარტოგრაფიის და გეოდეზიის საფუძვლების შემსწავლელი კურსები გეოდეზი კარტოგრაფი ტრენინგ ცენტრი სასწავლო ცენტრი</p>', '<p>GIS-ის სპეციალისტებისა და საჯარო რეესტრის ავტორიზებული ამზომველი ორგანიზაციებისათვის</p>\n<p>1. რუკა და მისი ელემენტები<br />2. რუკის მათემატიკური საფუძვლები<br />3. რუკის გეოდეზიური საფუძველი<br />4. ტოპოგრაფიული რუკა და გეგმა<br />5. დამატებითი მასალა</p>\n<p><br />სწავლის ხანგრძლივობა 5 - 1,5 სთ-იანი ლექცია - სამ-ოთხ კაციან ჯგუფში - 500 ლარი <br />სწავლის ხანგრძლივობა 5 - 1,5 სთ-იანი ლექცია - ხუთ-ათ კაციან ჯგუფში - 400 ლარი</p>\n<p>[registration]</p>', 'Applied-cartography-and-geodesy-basics', '', '', '', 'ge', 4, 0, 0),
(268, 111, 40, 1576066862, 0, 'text', 'სამართლებრივი (იურიდიული) ', '<p>სამართლებრივი (იურიდიული) ინგლისურის კურსი</p>', '<p><strong>კურსის მიზანია:</strong> დაეხმაროს სტუდენტებს, პრაქტიკოს იურისტებს, ადვოკატებს, კერძო კომპანიებისა და საჯარო დაწესებულებების იურისტებს სამართლებრივი ტერმინოლოგიის დაუფლებაში, რათა მათ შეძლონ ინგლისურ ენაზე სამართლებრივი საქმიანობის, როგორც წერილობით, ისე ზეპირად წარმართვა.</p>\n<p><strong>კურსი მოიცავს შემდეგ საკითხებს:</strong></p>\n<p>- ზოგადი სამართლებრივი და დარგობრივი ტერმინოლოგიის შესწავლა (სამოქალაქო, შრომის, ბიზნეს, საკორპორაციო, სამშენებლო, საჯარო, სისხლის, საერთაშორისო სამართალი და ა. შ.);<br />- სხვადასხვა სახის სამართლებრივი დოკუმენტების შედგენა (საკორპორაციო დოკუმენტების, ხელშეკრულებების, მემორანდუმების, სამართლებრივი დასკვნების და ა. შ.);<br />- ინგლისურ ენაზე სამართლებრივი სპეციფიკის მქონე, როგორც წერილობითი, ისე ზეპირი კომუნიკაციის წარმოება;<br />- პრაქტიკული სამუშაოები, ზეპირი განხილვები და იმიტირებული პრაქტიკული სიტუაციები.</p>\n<p><strong>კურსის ხანგრძლივობა:</strong> (2 ან 3 თვე)<br />დამოკიდებულია მსმენელის მიერ ინგლისური ენის ცოდნის დონეზე</p>\n<p><strong>კვირაში ორი დღე - თვეში 8 ლექცია</strong><br />(1 საათი ინდივიდუალურად, ჯგუფში - საათნახევარი).<br />ღირებულება 3-5 კაციან ჯგუფში: 160 ლარი<br />ღირებულება წყვილში: 240 ლარი<br />ინდივიდუალურად: 300 ლარი</p>\n<p><strong>კვირაში სამი დღე - თვეში 12 ლექცია</strong><br />(1 საათი ინდივიდუალურად, ჯგუფში - საათნახევარი).<br />ღირებულება 3-5 კაციან ჯგუფში: 240 ლარი<br />ღირებულება წყვილში: 360 ლარი<br />ინდივიდუალურად: 450 ლარი</p>\n<p><strong>გაითვალისწინეთ! მსურველთა ინგლისურის ცოდნა უნდა აკმაყოფილებდეს მინიმუმ B1 დონეს.</strong></p>\n<p><strong>კურსის დასრულების შემდეგ</strong>: თქვენ შეძლებთ სამართლებრივი ტერმინოლოგიის შემცველ დოკუმენტებზე მუშაობას, სამართლებრივი დოკუმენტების თავად შედგენას, კლიენტებთან და ბიზნეს-პარტნიორებთან ზეპირ და წერილობით კომუნიკაციას, სხვადასხვა პირებთან მოლაპარაკების წარმოებას.</p>\n<p>კურსის დასრულების შემდეგ გაიცემა სერტიფიკატი.</p>\n<p><strong>კურსს უძღვება:</strong> თორნიკე ამილახვარი - ადვოკატი, შპს &bdquo;ღვინაძე და პარტნიორების&ldquo; უფროსი იურისტი.</p>\n<p>[registration]</p>', 'english-law', '', '', '', 'ge', 5, 0, 1),
(253, 104, 0, 1524474956, 1, 'text', 'Socar Georgia Gaz', '<p>test</p>', '<p>aksjd akjsdn ajksnd akjsnd kjasnd jkasd njkasn dkjasnd kjasd l;asd ,askjd aslkd akjsd nkjasnd kjasd</p>', 'socar-georgia-gaz', '', '', '', 'en', 4, 0, 0),
(254, 104, 0, 1524474956, 1, 'text', 'Socar Georgia Gaz', '<p>test</p>', '<p>aksjd akjsdn ajksnd akjsnd kjasnd jkasd njkasn dkjasnd kjasd l;asd ,askjd aslkd akjsd nkjasnd kjasd</p>', 'socar-georgia-gaz', '', '', '', 'ge', 4, 0, 0),
(326, 140, 7, 1682000552, 0, 'text', 'მეღვინეობა, მევენახეობა, დეგუსტაცია', '<p>მეღვინეობის და მევენახეობის და დეგუსტაციის საბაზო კურსები</p>', '<pre class=\"tw-data-text tw-text-large tw-ta\" dir=\"ltr\" data-placeholder=\"თარგმანი\"><span class=\"Y2IQFc\" lang=\"en\"><strong>მეღვინეობის საბაზო კურსი</strong><br /><br />პროგრამა განკუთვნილია: იმ პირებისთვის, ვისაც სურს იმუშაოს ღვინის წარმოებაში ტექნოლოგიურ ხაზებში და ჩაატაროს დეგუსტაცია ან განავითაროს საკუთარი ღვინის<br />წარმოება.ამ პოზიციებზე სამუშაოდ საჭიროა გაიარონ თეორიული და პრაქტიკული ცოდნა.<br /><br /><strong>კურსი მოიცავს:</strong><br />მეღვინეობაში არსებული ტერმინოლოგიას, ღვინის წარმოების სრული ტექნოლოგიებს, დეგუსტაციის პრინციპებს, ღვინოებს შორის განსხვავებას, მათი ხარისხის განსაზღვრას<br /><br /><strong>თემატიკა:</strong><br />&bull; კანონი ვაზის და ღვინის შესახებ<br />&bull; ქართული ღვინის ისტორია და კულტურა<br />&bull; დანადგარების, ხელსაწყოების აგებულება და მათი ფუნქციები<br />&bull; ყურძნის მიღება- დამუშავება<br />&bull; ყურძნის ტკბილის შემადგენელი ნივთიერებები, და მათი განსაზღვრა<br />&bull; ალკოჰოლური დუღილი და მოქმედი ფაქტორები;<br />&bull; თეთრი ღვინის წარმოება<br />&bull; ვარდისფერი ღვინის წარმოება<br />&bull; წითელი ღვინის წარმოება<br />&bull; ცქრიალა ღვინოების წარმოება<br />&bull; ბიო-ორგანული ღვინოების წარმოება<br />&bull; ღვინოების შედარება ადგილმდებარეობის მიხედვით<br />&bull; ფიზიკურ-ქიმიური პარამეტრების განსაზღვრა<br />&bull; ღვინოში დამხმარე მასალების შეტანა<br />&bull; პირველადი და მეორეული დუღილის მნიშვნელობა<br />&bull; ღვინის სეგმენტაცია<br />&bull; ღვინის სტაბილიზაცია<br />&bull; ღვინის ჩამოსხმა<br />&bull; ღვინის დაავადებები<br />&bull; ღვინის მოვლა<br />&bull; ღვინის დეგუსტაცია<br /><br /><strong>კურსდამთავრებულის უპირატესობა:</strong> <br />შეისწავლის მეღვინეობაში არსებულ ძირითად მიმართულებებს, რომელიც პრაქტიკაში გამოიყენება, ასევე შეძლებენ ტექნოლოგიების გამოყენებით შექმნან საკუთარი წარმოების ღვინო და შეაფასონ ღვინის ხარისხი. ღვინის მარნებში და ღვინის საწარმოებში დანერგონ სწორი მიმართულება.<br /><br /><strong>სრული პროგრმის ხანგრძლივობა:12 ლექცია</strong><br /><strong>კვირაში ჩატარდება 2 ლექცია</strong><br /><strong>ლექციის ხანგრძლივობა 1სთ 30წთ - 2სთ</strong><br /><strong>კურსის ღირებულება ჯგუფში 3 კაციდან:500 ლარი</strong><br /><strong>კურსის ღირებულება წყვილში:650 ლარი</strong><br /></span></pre>\n<pre class=\"tw-data-text tw-text-large tw-ta\" dir=\"ltr\" data-placeholder=\"თარგმანი\"><span class=\"Y2IQFc\" lang=\"en\"><strong>პრაქტიკული:</strong> ღვინის ლაბორატორიაში ან ღვინის ცენტრში - წარმობის დათვალიერება ადგილობრივი მეღვინის თანხლებით, დეგუსტაცია.<br /></span><span class=\"Y2IQFc\" lang=\"en\"><br />[registration]<br /><br /></span></pre>\n<pre class=\"tw-data-text tw-text-large tw-ta\" dir=\"ltr\" data-placeholder=\"თარგმანი\"><span class=\"Y2IQFc\" lang=\"en\"><strong>მევენახეობის საბაზო კურსი</strong><br /><br />პროგრამა განკუთვნილია:პირებისთვის, ვისაც სურს იმუშაოს მევენახეობის მიმართულებით, გააშენონ ვენახი სწორად, გაეცნონ ამპელოგრაფიულ მახასიათებლებს<strong> <br /><br />კურსი მოიცავს: </strong>მევენახეობაში არსებული ტერმინოლოგიას, გაშენებას და მოვლის ხერხებს.<strong><br /><br /></strong>● მევენახეობის მნიშვნელობა და ბიოლოგიური თავისებურებები<br />● სანერგისათვის ადგილის შერჩევის წესი;<br />● ვაზის ჯიშების განსხვავება,<br />● ვაზის აგებულება ბიოლოგიური-მორფოლოგიური განსხვავებები<br />● ზრდა განვითარების და მსხმოიარობის პრინციპები<br />● მევენახეობის ძირითადი ზონები<br />● ვაზის საკვირტე მასალის წარმოება მისი დამზადება და ვადები, ვაზის მყნობა მათი<br />ვადები<br />● სანერგის მოვლა და მათი წესები, ამოღება, დახარისხება, შენახვა.<br />● ვენახის დაპროექტების თავისებურებები და მათი განსაზღვრა<br />●ვაზისათვის შესაბამისი ადგილმდებარეობის შერჩევა , რიგების განსაზღვრა<br />● ვენახის ძირითადი ტიპები და გაშენების სქემა<br />● ვაზის სელექცია მათი სახეობები<br />● ვაზის ჯიშების სხვლა ფორმირბის ძირითადი სისტემა და შერჩევა<br />● ნიადაგის მოვლის, განოყიერების ზოგადი პრინციპები<br />● ვაზის მცენარის დაცვის პრინციპები და საშუალებები<br />● მავნებელ-დაავადებათა ბრძოლა, პრევენცია<br />● ვენახში გამოყენებული მანქანა დანადგარები და მათი მუშაობის პრინციპები<br />● სარწყავი სისტემები და მორწყვის პრინციპები<br />● ვაზის მოსავლის კრეფა და განსაზღვრული დრო<br />● ყურძნის შენახვაზე მოქმედი ფაქტორები<br />● შრომის უსაფრთხოების წესების დაცვა<strong><br /><br />კურსდამთავრებულის უპირატესობა: </strong>შეისწავლის მევენახეობაში არსებული ძირითადი მიმართულებები რომელიც პრაქტიკაში გამოიყენება და ასევე შეძლებენ საკუთარი პროფესიის სწორად რეალიზებას.<strong> <br /><br />ლექციის ხანგრძლივობა 1სთ 30წთ - 2სთ<br />კურსის ღირებულება ჯგუფში 3 კაციდან:500 ლარი<br />კურსის ღირებულება წყვილში:650 ლარი<br /><br />პრაქტიკული: ვენახის დათვალიერება და მისი აღწერა<br />კურსის ბოლოს ჩატარდება დასკვნითი ტესტირება და გაიცემა სერთიფიკატი<br /><br />კურსს უძღვება: ანჟელა ღაჭავა - 8 წლიანი გამოცდილების მქონე მევენახე-<br />მეღვინეობის მაგისტრი, მეღვინე, ტრენერი. პროფესიული განათლების მასწავლებელი მევენახეობა-მეღვინეობის მიმართულებით</strong><br /><br />თითოეული კურსის ბოლოს ჩატარდება დასკვნითი ტესტირება და გაიცემა სერთიფიკატი<br /><br />[registration]<br /><br /><br /><strong>ღვინის დეგუსტაციის კურსი</strong><br /></span></pre>\n<p><strong>პროგრამა განკუთვნილია:</strong>&nbsp;იმ პირებისთვის, ვისაც სურს შეისწავლოს ღვინის ორგანოლეპტიკური მახასიათებლების განსაზღვრა, ღვინის შემადგენლობა, დეგუსტაციის ჩატარებისათვის აუცილებელი მოთხოვნები, ან განავითაროს ღვინის შეფასების უნარები</p>\n<p><strong>კურსი მოიცავს</strong>: მეღვინეობაში არსებული ტერმინოლოგიის შესწავლას, ღვინის<br />წარმოების ტექნოლოგიებს, დეგუსტაციის პრინციპებს, ღვინოებს შორის<br />განსხვავებას, მათი ხარისხის განსაზღვრას, ღვინის დეგუსტაციის პრინციპებს.<br /><br />1 ღვინის შემადგენლობა და მისი ხარისხის შემოწმება<br />2 ღვინის ორგანოლეპტიკური მახასიათებლები<br />3 ღვინის დაავადებების სახეობები<br />4 დეგუსტაციის ჩატარებისათვის აუცილებებლი პირობები<br />5 ღვინის არომატები: თეთრ, ვარდისფერ და წითელ ღვინოებში<br />6 ღვინის არომატების განსაზღვრა<br />7 შეფასების ტერმინოლოგია DLG-ის ხუთქულიანი სისტემის მიხედვით<br />8 პროფესიული დეგუსტაციის პირობები<br />9 ღვინის ნიმუშების მომზადების პრინციპები<br />10 პროფესიონალი დეგუსტატორის (სენსორული ექსპერტის) მიმართ არსებული მოთხოვნები<br />11 ღვინის შეხამება კერძებთან<br />12 ღვინის არომატების აღქმა<br />13 დეგუსტაციის ჩატარების სახეები</p>\n<p><strong>კურსდამთავრებულის უპირატესობა:</strong>&nbsp;შეისწავლის მეღვინეობაში არსებულ ძირითად მიმართულებებს ღვინის დახასიათების და შეფასების მიმართულებით. შეძლებთ ღვინის მარნებში და ღვინის საწარმოებში დანერგოთ სწორი შეფასების კრიტერიუმები ხარისხიანი პროდუქტისათვის. მიღებული პრაქტიკა კი მოგცემთ საშუალებას დეგუსტაციის მოთხოვნები სრულად შეისწვლოთ.<br /><strong>სრული პროგრმის ხანგრძლივობა : 8 ლექცია</strong></p>\n<p><strong>კურსის ღირებულება ჯგუფში: 400 ლარი</strong></p>\n<p><strong>წყვილში: 500 ლარი</strong></p>\n<p><strong>ინდივიდუალურად: 650 ლარი</strong></p>\n<p><strong>პრაქტიკული ნაწილი:</strong>&nbsp;ღვინის სადეგუსტაციო სივრცეში დააგემოვნებთ ღვინოების სხვადასხვა სახეობებს.</p>\n<p>კურსის ბოლოს ჩატარდება დასკვნითი ტესტირება და გაიცემა სერთიფიკატი!</p>\n<p><strong>კურსს უძღვება:</strong>&nbsp;ანჟელა ღაჭავა - 8 წლიანი გამოცდილების მქონე მევენახე-<br />მეღვინეობის მაგისტრი, მეღვინე, ტრენერი. პროფესიული განათლების მასწავლებელი<br />მევენახეობა-მეღვინეობის მიმართულებით.</p>\n<pre id=\"tw-target-text\" class=\"tw-data-text tw-text-large tw-ta\" dir=\"ltr\" data-placeholder=\"თარგმანი\"><span class=\"Y2IQFc\" lang=\"en\">[registration]</span></pre>\n<pre id=\"tw-target-text\" class=\"tw-data-text tw-text-large tw-ta\" dir=\"ltr\" data-placeholder=\"თარგმანი\"><span class=\"Y2IQFc\" lang=\"en\">&nbsp;</span></pre>', 'winemaking', '', '', '', 'ge', 7, 0, 0),
(349, 152, 8, 1747918957, 0, 'text', 'ბიზნეს ანალიტიკის ტექნიკები ექსელის გამოყენებით', '<p><em>ბიზნეს ანალიტიკის ტექნიკები ექსელის გამოყენებით - Business Analytics with Excel<br />ტრენინგი შემუშავებულია Johns Hopkins University-მიერ</em></p>', '<p>ბიზნეს ანალიტიკის ტექნიკები ექსელის გამოყენებით - Business Analytics with Excel<br />ტრენინგი შემუშავებულია Johns Hopkins University-მიერ</p>\n<p>ვისთვის არის კურსი:<br />მენეჯერები &ndash; ოპერაციები | ლოჯისტიკა | კომერცია<br />ანალიტიკოსები &ndash; ფინანსური | საოპერაციო | კომერციული<br />კარიერული ზრდის მსურველები<br />Excel-ის მომხმარებლები ნებისმიერი გამოცდილებით<br />მონაწილეობის წინაპირობა-EXCEL საბაზო დონეზე ფლობა</p>\n<p>ისწავლება:<br />', 'Business Analytics with Excel', '', '', '', 'en', 3, 0, 0),
(335, 145, 8, 1698322995, 0, 'text', 'AutoCAD', '<p>AutoCAD-ის ზოგადი კურსი</p>\n<p>&nbsp;</p>', '<p><strong>კურსის მიზნები:</strong><br />&bull; კურსის მიზანია შესწავლოს სტუდენტებს 2D/3D გეომეტრიული მოდელირების ზოგადი პრინციპები AutoCAD-ის ბაზაზე. სტუდენტი შეისწავლის სტანდარტული და არასტანდარტული სამგანზომილებიანი კომპიუტერული მოდელის შექმნას და მოდიფიცირებას, 3D მოდელიდან ნახაზის შექმნის საფუძვლებს</p>\n<p><strong>გამოყენების სფეროები:</strong><br />&bull; მშენებლობა, არქიტექტურა, წარმოება, დიზაინი (ავეჯი და ა.შ.)<br /><strong>კურსის ძირითადი თემები:</strong><br />1. რა არის 2D/3D მოდელირება?<br />2. 2D/3D მოდელირების პრინციპები AutoCAD-ში<br />3. სტანდარტული და არასტანდარტული 2D/3D მოდელების შექმნა AutoCAD-ში<br />4. ტექნიკური ნახაზების შექმნის საფუძვლები</p>\n<p><strong>კურსის შინაარსი:</strong><br /><strong>ლექცია I: შესავალი</strong><br />&bull; 2D/3D მოდელირების პრინციპები<br />&bull; 2D/3D მოდელირების პლატფორმები და გამოყენების სფეროები<br />&bull; AutoCAD-ის ინსტალაცია<br />&bull; მომხმარებლის ინტერფეისი<br />&bull; სამუშაო გარემოს მოწყობა <br />&bull; სანავიგაციო ფუნქციები<br /><strong>ლექცია II: 2D მოდელირება</strong><br />&bull; AutoCAD-ის მუშაობის პრინციპი (ბრძანებები)<br />&bull; Grid და Snap გამოყენება<br />&bull; ორგანზომილებიანი მოდელირების ინსტრუმენტების პარამეტრები (ფერი, სისქე ...)<br />&bull; ორგანზომილებიანი მოდელირების ინსტრუმენტები:<br />- Lines<br />- Rectangles<br />- Circles<br /><strong>ლექცია III: 2D მოდელირება</strong><br />&bull; კონსტრეინტები<br />&bull; ორგანზომილებიანი მოდელირების ინსტრუმენტები:<br />- Ellipses<br />- Arcs<br />- Polygons<br />- Polylines<br /><strong>ლექცია IV: ორგანომილებიანი მოდელების რედაქტირების საშუალებები</strong><br />&bull; ორგანზომილებიანი მოდელების რედაქტირება:<br />- Move<br />- Copy<br />- Rotate<br />- Scale<br />- Trim<br />- Extend<br />- Fillet<br />- Chamfer<br />- Mirror<br /><strong>ლექცია V: პრაქტიკული სამუშაო</strong><br /><strong>&bull; სხვადასხვა სახის ორგანზომილებიანი მოდელის შექმნა AutoCAD-ში შესწავლილი ინსტრუმენტების გამოყენებით</strong><br /><strong>ლექცია VI: შუალედური ტესტირება</strong><br /><strong>ლექცია VII: 3D მოდელირება</strong><br />&bull; სამგანზომილებიანი მოდელირების გარემო<br />&bull; სამგანზომილებიანი მოდელირების პრინციპები AutoCAD-ში<br />&bull; კოორდინატთა სისტემის შექმნა<br />&bull; სტანდარტული სამგანზომილებიანი პრიმიტივები:<br />- Cylinder<br />- Box<br />- Cones<br />- Pyramid<br /><strong>ლექცია VIII: 3D მოდელირება - არასტანდარტული სამგანზომილებიანი პრიმიტივები:</strong><br />- Sphere<br />- Torus<br />- Wedge<br />ლექცია IX: 3D მოდელირება - არასტანდარტული სამგანზომილებიანი პრიმიტივები<br />- Polysolid<br />- Extrude<br />- Loft<br /><strong>ლექცია X: 3D მოდელირება - არასტანდარტული სამგანზომილებიანი პრიმიტივები</strong><br />- Revolve<br />- Sweep<br />- Presspull<br />- Helix<br /><strong>ლექცია XI: 3D მოდელირება - რთული ობიექტების შექმნა Boolean ოპერატორის გამოყენებით</strong><br />- Subtraction<br />- Union<br />- Intersection</p>\n<p><strong>ლექცია XII: 3D მოდელირება - სამგანზომილებიანი ობიექტების ტრანზაქციის ოპერაციები:</strong><br />- Move<br />- Rotate<br />- Array<br />- Align<br />- Mirror</p>\n<p><strong>ლექცია XIII: 3D მოდელირება - სამგანზომილებიანი ობიექტების რედაქტირება</strong><br />- Fillet<br />- Taper<br />- Offset<br />- Shell<br />- Chamfer<br />- Section</p>\n<p><strong>ლექცია XIV: სამგანზომილებიანი მოდელებიდან ნახაზების შექმნა</strong><br />- Base View<br />- Projected View<br />- Section Views<br />- Section View Style<br />- Full Section View<br />- Detailed View</p>\n<p><strong>ლექცია XV: პრაქტიკული სამუშაო</strong><br />&bull; სხვადასხვა სახის სამგანზომილებიანი მოდელის შექმნა AutoCAD-ში შესწავლილი ინსტრუმენტების გამოყენებით</p>\n<p><strong>ლექცია XVI: დასკვნითი გამოცდა</strong></p>\n<p><strong>კურსის ხანგძლივობა:<br />&bull; სრული კურსი გრძელდება - 2 თვე<br />&bull; კვირაში 2 ლექცია<br />&bull; 1 ლექციის ხანგძლივობა 2 აკადემიური საათი</strong></p>\n<p><strong>კურსის ღირებულება: ინდივიდუალურად -&nbsp; 700 ლარი თვეში&nbsp;</strong></p>\n<p><strong>წყვილში: 550 ლარი თვეში</strong></p>\n<p><strong>ჯგუფში: 400 ლარი თვეში&nbsp;</strong></p>\n<p>&nbsp;</p>', 'AUTOCAD', '', '', '', 'en', 10, 0, 0),
(313, 134, 39, 1654259585, 0, 'text', 'თურქული ენა', '<p>თურქული ენის შემსწავლელი კურსების&nbsp;ფართო არჩევანი - უფროსებისთვის</p>', '<p>საკომუნიკაციო თურქული ენა დონეების მიხედვით</p>\n<p>&nbsp;</p>', 'Turkish language', '', '', '', 'en', 3, 0, 1),
(281, 118, 17, 1579259465, 0, 'text', 'სტაჟირება პსპ-ში', '<p>სტაჟირება აფთიაქში</p>', '<p>ფარმაკოლოგიის კურსის დასრულების შემდეგ მსმენელები გაივლიან 1 თვიან უფასო სტაჟირებას \"PSP\" -ს სხვადასხვა აფთიაქებში, საუკეთესოებისთვის შემდგომი დასაქმების პერსპექტივით, როგორც თბილისში ასევე საქართველოს ნებისმიერ რეგიონში.<br />გაიცემა ორენოვანი სერტიფიკატი და სარეკომენდაციო წერილი.<br /><br />აფთიაქში სტაჟირების მსვლელობის პერიოდში ჩატარდება სემინარები და განიხილება აფთიაქში ხშირად შექმნილი სხვადასხვა სიტუაცია.</p>', 'stajireba-sps', '', '', '', 'en', 4, 0, 0),
(271, 113, 72, 1577111887, 0, 'text', 'სამოქალაქო სამართლის პრაქტიკული კურსი ', '<p><strong>სამოქალაქო სამართლის პრაქტიკული კურსი&nbsp;</strong></p>', '<p><strong>სამოქალაქო სამართლის პრაქტიკული კურსი </strong><strong>!</strong></p>\n<p><strong>კურსს</strong> <strong>უძღვება</strong><strong>:</strong>&nbsp;მაია თურქია - ს.ს.ო.პ. საქართველოს ადვოკატთა ასოციაციის წევრი&nbsp; ადვოკატი.</p>\n<p><strong>კურსის</strong> <strong>მიზანია</strong><strong>:</strong>&nbsp;</p>\n<p>დაეხმაროს სამართლის ფაკულტეტის სტუდენტებს და სამართლის კურსდამთავრებულებს სამოქალაქო სპეციალიზაციით სამართლებრივი საქმიანობის დამოუკიდებლად&nbsp; წარმართვაში.</p>\n<p><strong>კურსი</strong><strong>ს მოიცავს:</strong></p>\n<ol>\n<li>კანონით დადგენილი ყველა სახის ხელშეკრულებების შედგენა.</li>\n<li>სამოქალაქო და ადმინისტრაციული სარჩელის შედგენა .</li>\n<li>სააპელალაციო და საკასაციო სარჩელის შედგენა.</li>\n<li>კერძო საჩივრის და სხვადასხვა სახის განცხადებების შედგენა ყველა ინსტანციის სასამართლოში.</li>\n<li>განქორწინება და ალიმენტი</li>\n<li>მეუღლეთა თანაცხოვრების მანძილზე შეძენილი ქონების გაყოფა.</li>\n<li>მემკვიდრეობის მიღებასთან დაკავშირებული საკითხები.</li>\n<li>სასამართლო პროცესებზე დასწრება.</li>\n<li>9. იმიტირებული პრაქტიკული სიტუაციები.</li>\n</ol>\n<p><strong>&nbsp;</strong></p>\n<p><strong>კურსის</strong> <strong>ხანგრძლივობა</strong><strong>:</strong>&nbsp;<strong>3 </strong><strong>თვე</strong></p>\n<p><strong>კვირაში</strong> <strong>ორი</strong> <strong>დღე</strong><strong> - </strong><strong>თვეში</strong><strong>&nbsp; </strong><strong>8 </strong><strong>ლექცია</strong></p>\n<p><strong>კურსის ღირებულება თვეში: 300 ლარი ჯგუფში</strong></p>\n<p><strong>360 ლარი&nbsp; 2 კაციან ჯგუფში</strong></p>\n<p><strong>540 ლარი ინდივიდუაურად</strong></p>\n<p><br /> <strong>კურსის</strong> <strong>დასრულების</strong> <strong>შემდეგ</strong>: თქვენ შეძლებთ სამართლებრივი შემცველ დოკუმენტებზე მუშაობას, სამართლებრივი დოკუმენტების თავად შედგენას, კლიენტებთან&nbsp; ურთიერთობას.</p>\n<p><strong>კურსის</strong> <strong>დასრულების</strong> <strong>შემდეგ</strong> <strong>გაიცემა</strong> <strong>სერტიფიკატი</strong><strong>.</strong></p>\n<p>&nbsp;</p>\n<p>&nbsp;</p>', 'Law course', '', '', '', 'en', 8, 0, 1),
(267, 111, 40, 1576066862, 0, 'text', 'სამართლებრივი (იურიდიული) ', '<p>სამართლებრივი (იურიდიული) ინგლისურის კურსი</p>', '<p><strong>კურსის მიზანია:</strong> დაეხმაროს სტუდენტებს, პრაქტიკოს იურისტებს, ადვოკატებს, კერძო კომპანიებისა და საჯარო დაწესებულებების იურისტებს სამართლებრივი ტერმინოლოგიის დაუფლებაში, რათა მათ შეძლონ ინგლისურ ენაზე სამართლებრივი საქმიანობის, როგორც წერილობით, ისე ზეპირად წარმართვა.</p>\n<p><strong>კურსი მოიცავს შემდეგ საკითხებს:</strong></p>\n<p>- ზოგადი სამართლებრივი და დარგობრივი ტერმინოლოგიის შესწავლა (სამოქალაქო, შრომის, ბიზნეს, საკორპორაციო, სამშენებლო, საჯარო, სისხლის, საერთაშორისო სამართალი და ა. შ.);<br />- სხვადასხვა სახის სამართლებრივი დოკუმენტების შედგენა (საკორპორაციო დოკუმენტების, ხელშეკრულებების, მემორანდუმების, სამართლებრივი დასკვნების და ა. შ.);<br />- ინგლისურ ენაზე სამართლებრივი სპეციფიკის მქონე, როგორც წერილობითი, ისე ზეპირი კომუნიკაციის წარმოება;<br />- პრაქტიკული სამუშაოები, ზეპირი განხილვები და იმიტირებული პრაქტიკული სიტუაციები.</p>\n<p><strong>კურსის ხანგრძლივობა:</strong> (2 ან 3 თვე)<br />დამოკიდებულია მსმენელის მიერ ინგლისური ენის ცოდნის დონეზე</p>\n<p><strong>კვირაში ორი დღე - თვეში 8 ლექცია</strong><br />(1 საათი ინდივიდუალურად, ჯგუფში - საათნახევარი).<br />ღირებულება 3-5 კაციან ჯგუფში: 160 ლარი<br />ღირებულება წყვილში: 240 ლარი<br />ინდივიდუალურად: 300 ლარი</p>\n<p><strong>კვირაში სამი დღე - თვეში 12 ლექცია</strong><br />(1 საათი ინდივიდუალურად, ჯგუფში - საათნახევარი).<br />ღირებულება 3-5 კაციან ჯგუფში: 240 ლარი<br />ღირებულება წყვილში: 360 ლარი<br />ინდივიდუალურად: 450 ლარი</p>\n<p><strong>გაითვალისწინეთ! მსურველთა ინგლისურის ცოდნა უნდა აკმაყოფილებდეს მინიმუმ B1 დონეს.</strong></p>\n<p><strong>კურსის დასრულების შემდეგ</strong>: თქვენ შეძლებთ სამართლებრივი ტერმინოლოგიის შემცველ დოკუმენტებზე მუშაობას, სამართლებრივი დოკუმენტების თავად შედგენას, კლიენტებთან და ბიზნეს-პარტნიორებთან ზეპირ და წერილობით კომუნიკაციას, სხვადასხვა პირებთან მოლაპარაკების წარმოებას.</p>\n<p>კურსის დასრულების შემდეგ გაიცემა სერტიფიკატი.</p>\n<p><strong>კურსს უძღვება:</strong> თორნიკე ამილახვარი - ადვოკატი, შპს &bdquo;ღვინაძე და პარტნიორების&ldquo; უფროსი იურისტი.</p>', 'english law', '', '', '', 'en', 5, 0, 1),
(308, 131, 4, 1648463968, 0, 'text', 'ჩვენი გუნდი', '<p>შოთა ნიორაძე - გაძ₾იერებული ექსელის და ფინანსების ტრენერი:</p>', '<p><strong>ბიზნეს მოდელირება და მონაცემთა ანალიზი ექსელში;&nbsp;</strong></p>\n<p><strong>ფინანსური ანალიზი ექსელში;</strong></p>\n<p>&nbsp;</p>\n<p><strong>პრაქტიკული აუდიტი, პრაქტიკული ბუღალტერი,&nbsp;</strong></p>\n<p>&nbsp;</p>', 'https://vipintellect.ge/ge/staff', '', '', 'https://vipintellect.ge/ge/staff', 'ge', 1, 0, 1),
(255, 105, 72, 1525777634, 0, 'text', 'სამშენებლო პროექტების მენეჯმენტი', '', '<p>პროგრამის დასახელება: სამშენებლო პროექტების მენეჯმენტი</p>\n<p><br />ვისთვის არის აღნიშნული პროგრამა:<br />პროგრამის მიზანია კვალიფიკაცის ამაღლება და პროფსეიონალური უნარების შესწავლა, მათთვის ვისაც სურს ცოდნის შეძენა უძრავ ქონების მენეჯმენტში, განვითარების კუთხით, ვისაც მენეჯერული უნარები გააჩნია და უნდა დაეუფლოს სამშენებლო ბაზარზე უძრავი ქონების ტექნიკური მართვის პროექტების სპეციფიკაციებს, ტექნოლოგიებს, მართვის უნარებს და სრულად მართოს სხვადასხვა სამშენებლო პროექტები დროში, სივრცეში და საბაზრო მოთხოვნების შესაბამისად.<br />ტრეინინგის თემატიკა: <br />სამშენებლო პროექტის მენეჯერის თვისებების, პრინციპების და მეთოდოლოგის შესწავლა, ასევე სამშენებლო პროექტების მართვის უნარების დახვეწას და მის კრიატიულ ასპექტში აყვანას, ასევე სამშენებლო ოპერაციების თანმიმდევრობის და ტექნოლოგიების შესწავლას სრულად.<br />ტრეინინგის შეჯამება:<br />ტრენინგის გავლის შემდგომ სრულად შეიძლება მართოს სამშენებლო ობექტები, კერძოდ მშენებლობა, მისი ადმინისტრაციული მხარე, მშენებლობის ტექნლოგიური მხარე, მშენებლობის ფინანსური მხარე - მენეჯმენტის რგოლის არეალში, ასევე შეძლებენ სამშენებლო პროექტების დადეგმას და შედეგების ანალიზების განხორცელებას. მომავალი პროექტების თეორიულ და პრაქტიკულ შეფასებას წინასწარ. სამშენებლო ბიზნეს პროექტების შექმნას.<br />კურსდამთავრებულის უპირატესობანი:<br />დამოუკიდებლად შეძლებს სამშებენლო პროექტის მენეჯერად, საპროექტო ორგანიზაციის მენეჯერად, სამშენებლო ობექტის საქმეთა მწარმობლად, სამშენებლო სასაწყობო მენეჯერად, ასევე სამშენებლო ლოჯისტიკის მენეჯერად, სამშენებლო კომპანიებში ადმინისტაციულ, ტექნიკურ რგოლში მუშაობას.<br />სრული პროგრამის ხანგრძლივობა: 24 საათი<br />კურსის ღირებულება: 500 ლარი</p>\n<p>შეავსე სარეგისტრაციო ფორმა და დარეგისტრირდი ჯგუფში: vipintellect.ge/ge/register<br />აგრეთვე გთავაზობთ პროგრამა MS Project-ის შესწავლას!</p>\n<p>მოდული 1. პროექტების მართვის საწყისები, MS Project-ის ინტერფეისი<br />მოდული 2. დაგეგმვა. პროექტის თვისებების ინიციალიზაცია, დავალებათა იერარქიული სტრუქტურის შექმნა<br />მოდული 3. სამუშაო დროის მენეჯმენტი<br />მოდული 4. დაგეგმვა. კრიტიკული გზის მეთოდი<br />მოდული 5. დაგეგმვა, სხვა თვისებები<br />მოდული 6. პროექტის რესურსების დაგეგმვა<br />მოდული 7. პროექტის ოპტიმიზაცია<br />მოდული 8. პროექტის მიმდინარეობის შემოწმება.<br />მოდული 9. პარამეტრების შერჩევა, ვიზუალური თვისებები<br />მოდული 10. სპეციალური პარამეტრები<br />მოდული 11. მულტიპროექტი</p>\n<p>სრული პროგრამის ხანგრძლივობა: 10 საათი<br />კურსის ღირებულება: 300 ლარი<br />500 ლარი ინდივიდუალურად</p>\n<p>გაითვალისწინეთ! ხორციელდება კორპორატიული ტრეინინგის ჩატარება, სპეციალურად თქვენი მოთხოვნებიდან გამომდინარე, შეიქმნება სპეციალიზირებული პროგრამა!<br />შეავსე სარეგისტრაციო ფორმა და დარეგისტრირდი ჯგუფში: vipintellect.ge/ge/register</p>', 'building management', '', '', '', 'en', 3, 0, 0),
(256, 105, 72, 1525777634, 0, 'text', 'სამშენებლო პროექტების მართვა', '', '<p><strong>ვისთვის არის აღნიშნული პროგრამა:</strong></p>\n<p>პროგრამის მიზანია კვალიფიკაცის ამაღლება და პროფსეიონალური უნარების შესწავლა, მათთვის ვისაც სურს ცოდნის შეძენა უძრავ ქონების მენეჯმენტში განვითარების კუთხით. ასევე ვისაც მენეჯერული უნარები გააჩნია და უნდა დაეუფლოს სამშენებლო ბაზარზე უძრავი ქონების ტექნიკური მართვის პროექტების სპეციფიკაციებს, ტექნოლოგიებს, მართვის უნარებს და მართოს სხვადასხვა სამშენებლო პროექტები დროში, სივრცეში და საბაზრო მოთხოვნების შესაბამისად.</p>\n<p><strong>ტრეინინგის თემატიკა</strong><strong>: </strong></p>\n<p><strong>მშენებლობის ორგანიზაციის პროექტი, რას შეიცავს, როდის გვჭირდება.</strong></p>\n<p><strong>სამშენებლო გრაფიკი.&nbsp; 4სთ</strong></p>\n<p><strong>პროექტის რეალიზაციის ვადის განსაზღვრა.</strong></p>\n<p><strong>არქიტექტურული კონცეფცია.</strong></p>\n<p><strong>სამშენებლო ობიექტის ნულოვანი სამუშაოები.</strong></p>\n<p><strong><em><u>არსებული პროექტების ( პატარა და დიდი) შედგენილი სამუშაო გრაფიკის გავლა.</u></em></strong></p>\n<p><strong>ქვაბულის ექსკავაცია, ხიმინჯების მოწყობა . 2სთ</strong></p>\n<p><strong>მოსამზადებელი ფენის და ჰიდროიზოლაციის სამუშაოები . 2სთ</strong></p>\n<p><strong>მონოლითური სამუშაოები . 6სთ</strong></p>\n<p><strong>ბლოკის სამუშაოები . 2სთ</strong></p>\n<p><strong>ხარისხის კონტროლი. 2სთ</strong></p>\n<p><strong>&nbsp;სველი პროცესები. 2სთ</strong></p>\n<p>პრაქტიკაში არსებული შეცდომების განხილვა.</p>\n<p><strong>მენეჯმენტი და მშენებლობის თვითღირებულება.</strong></p>\n<p><strong>კურსდამთავრებულის უპირატესობანი:</strong></p>\n<p>სამშენებლო ობექტები, კერძოდ მშენებლობა, მისი ადმინისტრაციული მხარე, მშენებლობის ტექნლოგიური მხარე, მშენებლობის ფინანსური მხარე - მენეჯმენტის რგოლის არეალში, ასევე შეძლებენ სამშენებლო პროექტების დაგეგმვას და შედეგების ანალიზების განხორცელებას. მომავალი პროექტების თეორიულ და პრაქტიკულ შეფასებას წინასწარ. სამშენებლო ბიზნეს პროექტების შექმნას.</p>\n<p><strong>სრული პროგრამის ხანგრძლივობა</strong><strong>: </strong><strong>12 ლექცია</strong></p>\n<p><strong>კვირაში ჩატარდება 2/2 საათიანი ლექცია</strong></p>\n<p><strong>ღირებულება: 800 ლარი</strong></p>\n<p><strong>აქედან 2 ლექცია ჩატარდება გასვლითი პრაქტიკული სახის - საწარმოო ობიექტზე!</strong></p>\n<p><strong>კურსის ბოლოს ჩატარდება დასკვნითი ტესტირება და გაიცემა სერთიფიკატი!</strong></p>\n<p><strong>საუკეთესო კურსდამთავრებულებს გავუწევთ რეკომენდაციებს და მოთხოვნის შესაბამისად ხელს შევუწყოთ დასაქმებაში!</strong></p>\n<p><strong>კურსს უძღვებიან: შოთა კოხრეიძე - </strong>პრაქტიკოსი ტრენერი, მშენებელი 20 წლიანი გამოცდილებით.</p>\n<p><strong>შეავსე სარეგისტრაციო ფორმა და დარეგისტრირდი ჯგუფში:</strong></p>\n<p>[registration]</p>\n<p>&nbsp;</p>\n<p>&nbsp;</p>', 'building-management', '', '', '', 'ge', 3, 0, 0),
(257, 106, 9, 1527937220, 0, 'text', 'ფინანსური მენეჯმენტი', '<p>IFRS ფინანსური მენეჯმენტი</p>', '<p>ფინანსური მენეჯმენტი IFRS-ის სტანდარტების გამოყენებით</p>\n<p>ლექცია 1-8 ოპერაციებისა და მოვლენების აღრიცხვა</p>\n<p>1. ბასს (IAS) 2 - სასაქონლო-მატერილური ფასეულობები <br />2. ბასს (IAS) 16 - ძირითადი საშუალებები<br />3. ბასს (IAS) 38 - არამატერიალური აქტივები<br />4. ბასს (IAS) 40 - საინვესტიციო ქონება <br />5. ბასს (IAS) 23 - სესხით სარგებლობასთან დაკავშირებული დანახარჯები<br />6. ფასს (IFRS) 15 - მომხმარებლებთან გაფორმებული ხელშეკრულებებიდან მიღებული ამონაგები <br />7. ბასს (IAS) 17 - იჯარა და ფასს (IFRS) 16 იჯარა</p>\n<p>ლექცია 9-11 შეფასებები</p>\n<p>1. ფასს (IFRS) 13 - რეალური ღირებულების შეფასება <br />2. ბასს (IAS) 36 - აქტივების გაუფასურება <br />3. ბასს (IAS) 8 - სააღრიცხვო პოლიტიკა, ცვლილებები სააღრიცხვო შეფასებებში და შეცდომები <br />4. ფასს (IFRS) 1 - ფასს-ის პირველად გამოყენება</p>\n<p>ლექცია 12 ანგარიშგება</p>\n<p>1. ბასს (IAS) 1 - ფინანსური ანგარიშგების წარდგენა <br />2. ბასს (IAS) 7 - ფულადი ნაკადების ანგარიშგება</p>\n<p><br />მიხეილ მუმლაძე</p>\n<p>მიხეილის პროფესიული კარიერა მოიცავს 10 წლიან სამუშაო გამოცდილებას ფინანსებში, ბუღალტერიაში, ბიზნესისა და საინფორმაციო ტექნოლოგიების კონსალტინგში. მიხეილი მუშაობდა სხვადასხვა ორგანიზაციებში და ასევე საჯარო სექტორში. მისი გამოცდილება მოიცავს მუშაობას წარმოების მიმართულებით ასევე ენერგეტიკის სექტორში. 2018 წლიდან მიხეილი კითხულობს სალექციო კურსს IFRS სტანდარტები პროფესიონალი ბუღალტრებისთვის და ფინანსების მართვას ბიზნესისა და ტექნოლოგიების უნივერსიტეტში. <br />მიხეილი ფლობს მაგისტრის ხარისხს ბიზნესის სისტემების ანალიზსა და დიზაინში - City University London. ასევე, ACCA-ის უმაღლეს დიპლომს აღრიცხვასა და ბიზნესის ადმინისტრირებაში.</p>', 'financial management', '', '', '', 'en', 5, 0, 0),
(258, 106, 9, 1527937220, 0, 'text', 'გადასახადების აღრიცხვა და დეკლარციების შევსება', '<p>გადასახადების აღრიცხვა და დეკლარციების შევსება</p>', '<p><strong>კურსი მოიცავს:</strong><strong><br />შპს-ს ყოველწლიური და ყოველთვიური საშემოსავლო დეკლარაციის შევსების წესი</strong></p>\n<p><strong>საშემოსავლო გადასახდის აღრიცხვა და დეკლარაციის შევსება<br />მოგების გადასახადი და დეკლარაციის შევსება<br />დღგ-ის გადასახადის აღიცხვა და დეკლარაციის შევსება<br />ქონების გადასახდის აღიცხვა და დეკლარაციის შევსება</strong></p>\n<p><strong> კურსის ხანგრძლივობა: 8 საათი - 4 ლექცია</strong><br /><strong>კურსის ღირებულება ჯგუფში 3 კაციდან: 160 ლარი</strong><br /><strong>წყვილში: 240 ლარი</strong><br /><strong>ინდივიდუალურად: 400 ლარი</strong></p>\n<p><strong>ინდმეწარმის და მცირე მეწარმის შემთხვევაში 2 საათი&nbsp;</strong></p>\n<p>კორპორატიული ტრენინგის ჩატარების შემთხვევაში, ვითვალისწინებთ უშუალოდ თქვენს მოთხოვნებს და მხოლოდ თქვენი კადრებისთვის ჩატარდება სასწავლო კურსი!</p>\n<p><strong>შეავსე</strong> <strong>სარეგისტრაციო</strong> <strong>ფორმა</strong> <strong>და</strong> <strong>დარეგისტრირდი</strong> <strong>ჯგუფში</strong><strong>:</strong></p>\n<p>[registration]</p>\n<p><strong>&nbsp;</strong></p>\n<p>&nbsp;</p>\n<p><strong>&nbsp;</strong></p>', 'financial-management', '', '', '', 'ge', 5, 0, 0);
INSERT INTO `navigation` (`id`, `idx`, `cid`, `date`, `nav_type`, `type`, `title`, `description`, `text`, `slug`, `usefull_type`, `cssclass`, `redirect`, `lang`, `position`, `visibility`, `status`) VALUES
(270, 112, 41, 1576159165, 0, 'text', 'შემომყვანი ტურ-ოპერატორი', '<p>შემომყვანი ტურ ოპერატორის პრაქტიკული კურსი</p>', '<p><strong>კურსის მიზანი:</strong></p>\n<p>მოამზადოს დაინტერესებული იმ საჭირო უნარ-ჩვევებით, რომლებიც უშუალოდ პრაქტიკულ საქმიანობაში დასჭირდება ტურ-ოპერატორს. თითოეული კურსი დაგეგმილია მონაწილეთა ჩართულობით, რათა კონკრეტული მაგალითების მეშვეობით მოხდეს იმ მეთოდოლოგიის პრეზენტაცია, რაც შემომყვან ტურ ოპერატორს ესაჭიროება, საქმიანობის განხორციელებისას. <br />ტურისტული პაკეტის შედგენა<br /><strong>ლექცია 1</strong> <br />ძირითადი სერვისის ტიპები <br />სტატიკური <br />&bull; საცხოვრებელი ადგილი (სასტუმრო)<br />&bull; კვების ობიექტები<br />&bull; ტურისტული ლოკაციები<br />დინამიური<br />&bull; ტრანსპორტი<br />&bull; ადგილობრივი გიდის მომსახურება<br />პროგრამის შედგენა (პრაქტიკული სამუშაოები: დავალება ერთ დღიანი პროგრამის შედგენა, ძველი თბილისის ტური)<br />&bull; პროგრამის ზოგადი მნიშვნელობა<br />&bull; ერთ-დღიანი ტურის პროგრამის შედგენა <br />&bull; დროის დაგეგმვა და პროგრამულად გაწერა <br />&bull; ტურის ბიუჯეტი <br /><strong>ლექცია 2</strong> <br />&bull; პროგრამის ვიზუალური მხარე/პრეზენტაცია<br />&bull; პრეზენტაციის ტექსტის შედგენა<br />&bull; პრეზენტაციის პლატფორმები <br />&bull; დავალება: ერთ დღიანი ტურის პრეზენტაციის აწყობა <br /><strong>ლექცია 3</strong> <br />მრავალდღიანი პროგრამის შედგენა <br />&bull; მრავალდღიანი პროგრამის შედგენისთვის აუცილებელი ცვლადები (ტურისტული ლოკაციები; ტრანსპორტის ტიპი; დროის მენეჯმენტი)<br />&bull; ტურისტული ლოკაციების მონაცემთა ბაზის მნიშვნელობა გეოგრაფიული მდებარეობის მიხედვით (ინტერნეტი; ინფოტური) <br />&bull; პრაქტიკული სამუშაოები: ძირითადი ტურისტული ლოკაციების მონაცემთა ბაზის შედგენა <br />&bull; პრაქტიკული სამუშაო: სასტუმროების და კვების ობიექტების მონაცემთა ბაზის შედგენა<br /><strong>ლექცია 4</strong><br />&bull; ტრანსპორტი (ტრანსპორტის შესაბამისობა ჯგუფის მოცულობასთან; სასტუმროს ჯავშნებთან) <br />&bull; დროის დაგეგმვა მრავალდღიანი ტურის შედგენისას<br /><strong>ლექცია 5</strong><br />&bull; მრავალდღიანი ტურის ბიუჯეტი (ინდივიდუალური ხარჯები და ზოგადი ხარჯები) <br />&bull; გასაყიდი ფასების განსაზღვრა <br /><strong>ლექცია 6</strong> <br />ტურის გაყიდვა (ონლაინ პლატფორმები)<br />ვებ დეველოპერთან კომუნიკაცია<br />&bull; ვებ გვერდის მნიშვნელობა და ტიპები (ვიქსი; ვორდპრესი; კოდით დაწერილი) <br />&bull; ვებ-დომენის ყიდვა <br />&bull; საიტმეფის გაწერა<br /><strong>ლექცია 7</strong><br />&bull; ვებ-ადმინისტრირების მნიშვნელობა<br />&bull; სოც ქსელები <br />&bull; დარეკლამება და &bdquo;ბუსთი&ldquo;<br /><strong>ლექცია 8</strong><br />&bull; კლიენტებთან და მესამე მხარესთან კორესპოდენცია/კომუნიკაცია (პრაქტიკული სამუშაოები, კომუნიკაციის სიმულაცია) <br />&bull; კორპორატიული ელ-ფოსტა <br /><strong>ლექცია 9</strong><br />რეზერვაციები: გაყიდული ტურისთვის საჭირო სერვისების დაჯავშნა<br />&bull; საცხოვრებელი ადგილის ჯავშანი<br />&bull; კვების ობიექტების ჯავშანი<br /><strong>ლექცია 10</strong><br />&bull; ტრანსპორტის ჯავშანი (რისკების პრევენცია)<br />&bull; გიდის ჯავშანი (კერძო პირი VS მცირე მეწარმე) (რისკების პრევენცია) <br />&bull; ტურის მართვა<br />&bull; გადარიცხვები <br /><strong>ლექცია 11</strong><br />ბიუროკრატია/იურიდიული მხარე<br />&bull; შპს-ს რეგისტრაციისას გასათვალისწინებელი დეტალები (პრაქტიკული მხარე, საჯარო უწყებებთან კომუნიკაცია) <br />&bull; შპს-ს წესდება <br />&bull; საბანკო ანგარიშის გახსნა<br /><strong>ლექცია 12</strong><br />&bull; საჭირო თანამშრომლები (სტაფი)<br />&bull; ხელშეკრულებები <br />&bull; მიღება-ჩაბარების აქტები</p>\n<p><strong>კურსი</strong> <strong>მოიცავს</strong><strong>: 1</strong><strong>2</strong> <strong>ლექციას</strong></p>\n<p><strong>კვირასი</strong> <strong>ჩატარდება</strong> <strong>3</strong> <strong>ლექცია</strong><br /> <strong>კურსის</strong> <strong>ღირებულება ჯგუფში</strong><strong>: </strong><strong>45</strong><strong>0 </strong><strong>ლარი</strong></p>\n<p><strong>კურსის ღირებულება წყვილში: 600 ლარი</strong></p>\n<p><strong>კურსის ღირებულება ინდივიდუალურად: 850 ლარი</strong></p>\n<p><strong>შეავსე</strong>&nbsp;<strong>სარეგისტრაციო</strong>&nbsp;<strong>ფორმა</strong>&nbsp;<strong>და</strong>&nbsp;<strong>დარეგისტრირდი</strong>&nbsp;<strong>ჯგუფში</strong><strong>:</strong></p>\n<p>[registration]</p>\n<p>&nbsp;</p>', 'tour-operator', '', '', '', 'ge', 1, 0, 0),
(259, 107, 0, 1541409129, 0, 'text', 'ტრენინგ კურსი - სარემონტო პროექტის ეფექტური მართვა', '<p>ტრენინგ კურსი - სარემონტო პროექტის ეფექტური მართვა!</p>', '<p><strong>კურსი განკუთვნილია:</strong></p>\n<p>დამწყები დიზაინერებისათვის, არქიტექტორებისთვის და ყველასთვის - ვისაც სურს შეაფასოს, პრაქტიკულად შეისწავლოს და მართოს შენობის ინტერიერის სარემონტო სამუშაოები. კომპანიებისთვის, ვინც დაკავებულია სამშენებლო-სარემონტო ბიზნესით და სურს გააღრმავოს და გააფართოვოს ცოდნის არიალი რემონტის მართვის სფეროში, შესაბამისად დამკვეთს შესთავაზოს სარემონტო პროექტის მართვის ეფექტური სერვისი.<br />მიზანი: შეძლო ოპტიმალურად დაგეგმო და მართო რემონტთან დაკავშირებული დრო, რესურსები, ხარჯები და ხარისხი.</p>\n<p><strong>კურსის შემადგენლობა:</strong> <br />&bull; მენეჯერის როლი რემონტის მსვლელობაში;<br />&bull; გეგმარების პროცესი - პროექტის შემადგენელი ნახაზები და ვიზუალები;<br />&bull; სარემონტო სივრცის ანალიზი, დათვალიერება-შეფასება; <br />&bull; ტექნოლოგიური ნაწილი - სამუშაოთა ჩამონათვალის შედგენა და თანმიმდევრობის განსაზღვრა; <br />&bull; ბაზრის კვლევა, ანალიზი, მასალების შერჩევა და სპეციფიკაცია - მასალების შესყიდვა - მომარაგება;<br />&bull; ბიუჯეტის განსაზღვრა და ხარჯთაღრიცხვის მომზადება; <br />&bull; რემონტისათვის საჭირო ადამიანური რესურსები - მოძიება და მართვა;<br />&bull; დროის დაგეგმარება - გეგმა-გრაფიკის მომზადება; <br />&bull; ხელოსნებთან ურთიერთობის პრინციპები და მიდგომები;<br />&bull; ხარისხისა და დროის კონტროლის მექანიზმები;<br />&bull; შესრულებული სამუშაოების შემოწმება-ჩაბარება;<br />&bull; დუკუმენტაცია;<br />&bull; პროექტის მართვის ფსიქოლოგიური მიდგომები;<br />&bull; უსაფრთხოება ობიექტზე.</p>\n<p><strong>კურსდამთავრებულის უპირატესობა:</strong><br />კურსდამთავრებული შეძლებს რემონტთან დაკავთირებული დროის ხარჯების და რესურსების მართვას ოპტიმალურად.<br />სრული პროგრამის ხანგრძლივობა: 12 ლექცია<br />ლექციის ხანგრძლივობა: არანაკლებ საათნახევრი<br />კურსის ღირებულება ჯგუფში: 500 ლარი</p>\n<p><strong>კურსს უძღვება:</strong> სოფო ახვლედიანი - 12 წლიანი წარმატებული სამუშაო გამოცდილება მოიცავს მრავალფეროვანი კომერციული და საცხოვრებელი ობიექტების პროექტების ხელმძღვანელობას საქართველოს მასშტაბით. <br />მას როგორც თანამშრომელს, ასევე მოწვეულ სპეციალისტ-დიზაინერს ნამუშევარი აქვს სასტუმროებზე, მაღაზიებზე, საქართველოს წამყვან ბანკებზე (პროკრედიტი, რესპუბლიკა, თიბისი ბანკი ...) და სხვადასხვა ტიპის ობიექტებზე. ამჟამად, მეხუთე წელია &ldquo;სამედიცინო ველნეს კურორტ ბიოლში&ldquo; დიზაინერია, ასრულებს საინტერესო დიზაინერულ სამუშაოებს და უშუალოდ მართავს სარემონტო-სამშენებლო პროცესებს.<br />უმაღლესი განათლება ინტერიერის დიზაინის სპეციალობით მიიღო არაბეთის გაერთიანებულ საემიროებში, ამერიკულ უნივესიტეტში - AUD (American University in Dubai) და დაამთავრა უმაღლესი ქულებით. არის არაერთი დიზაინის კონკურსის გამარჯვებული. აღსანიშნავია &ldquo;Association of Professional Interior Designers&rdquo; (APID)-ის მიერ ორგანიზებული &ldquo;Annual Hotel Furniture Design Competition&rdquo; კონკურსი, სადაც ცნობილი დიზაინერის, კარიმ რაშიდის მიერ პირადად დაჯილდოვდა სასტუმროს საუკეთესო დიზაინისთვის.<br />გაითვალისწინეთ! ხორციელდება კორპორატიული ტრეინინგის ჩატარება, სპეციალურად თქვენი მოთხოვნებიდან გამომდინარე, შეიქმნება სპეციალიზირებული პროგრამა!</p>\n<p>&nbsp;</p>', 'temon', '', '', 'remont', 'en', 8, 0, 1),
(260, 107, 0, 1541409129, 0, 'text', 'ტრენინგ კურსი - სარემონტო პროექტის ეფექტური მართვა', '<p>ტრენინგ კურსი - სარემონტო პროექტის ეფექტური მართვა!</p>', '<p><strong>კურსი განკუთვნილია:</strong></p>\n<p>დამწყები დიზაინერებისათვის, არქიტექტორებისთვის და ყველასთვის - ვისაც სურს შეაფასოს, პრაქტიკულად შეისწავლოს და მართოს შენობის ინტერიერის სარემონტო სამუშაოები. კომპანიებისთვის, ვინც დაკავებულია სამშენებლო-სარემონტო ბიზნესით და სურს გააღრმავოს და გააფართოვოს ცოდნის არიალი რემონტის მართვის სფეროში, შესაბამისად დამკვეთს შესთავაზოს სარემონტო პროექტის მართვის ეფექტური სერვისი.<br />მიზანი: შეძლო ოპტიმალურად დაგეგმო და მართო რემონტთან დაკავშირებული დრო, რესურსები, ხარჯები და ხარისხი.</p>\n<p><strong>კურსის შემადგენლობა:</strong> <br />&bull; მენეჯერის როლი რემონტის მსვლელობაში;<br />&bull; გეგმარების პროცესი - პროექტის შემადგენელი ნახაზები და ვიზუალები;<br />&bull; სარემონტო სივრცის ანალიზი, დათვალიერება-შეფასება; <br />&bull; ტექნოლოგიური ნაწილი - სამუშაოთა ჩამონათვალის შედგენა და თანმიმდევრობის განსაზღვრა; <br />&bull; ბაზრის კვლევა, ანალიზი, მასალების შერჩევა და სპეციფიკაცია - მასალების შესყიდვა - მომარაგება;<br />&bull; ბიუჯეტის განსაზღვრა და ხარჯთაღრიცხვის მომზადება; <br />&bull; რემონტისათვის საჭირო ადამიანური რესურსები - მოძიება და მართვა;<br />&bull; დროის დაგეგმარება - გეგმა-გრაფიკის მომზადება; <br />&bull; ხელოსნებთან ურთიერთობის პრინციპები და მიდგომები;<br />&bull; ხარისხისა და დროის კონტროლის მექანიზმები;<br />&bull; შესრულებული სამუშაოების შემოწმება-ჩაბარება;<br />&bull; დუკუმენტაცია;<br />&bull; პროექტის მართვის ფსიქოლოგიური მიდგომები;<br />&bull; უსაფრთხოება ობიექტზე.</p>\n<p><strong>კურსდამთავრებულის უპირატესობა:</strong><br />კურსდამთავრებული შეძლებს რემონტთან დაკავთირებული დროის ხარჯების და რესურსების მართვას ოპტიმალურად.<br />სრული პროგრამის ხანგრძლივობა: 12 ლექცია<br />ლექციის ხანგრძლივობა: არანაკლებ საათნახევრი<br />კურსის ღირებულება ჯგუფში: 500 ლარი</p>\n<p><strong>კურსს უძღვება:</strong> სოფო ახვლედიანი - 12 წლიანი წარმატებული სამუშაო გამოცდილება მოიცავს მრავალფეროვანი კომერციული და საცხოვრებელი ობიექტების პროექტების ხელმძღვანელობას საქართველოს მასშტაბით. <br />მას როგორც თანამშრომელს, ასევე მოწვეულ სპეციალისტ-დიზაინერს ნამუშევარი აქვს სასტუმროებზე, მაღაზიებზე, საქართველოს წამყვან ბანკებზე (პროკრედიტი, რესპუბლიკა, თიბისი ბანკი ...) და სხვადასხვა ტიპის ობიექტებზე. ამჟამად, მეხუთე წელია &ldquo;სამედიცინო ველნეს კურორტ ბიოლში&ldquo; დიზაინერია, ასრულებს საინტერესო დიზაინერულ სამუშაოებს და უშუალოდ მართავს სარემონტო-სამშენებლო პროცესებს.<br />უმაღლესი განათლება ინტერიერის დიზაინის სპეციალობით მიიღო არაბეთის გაერთიანებულ საემიროებში, ამერიკულ უნივესიტეტში - AUD (American University in Dubai) და დაამთავრა უმაღლესი ქულებით. არის არაერთი დიზაინის კონკურსის გამარჯვებული. აღსანიშნავია &ldquo;Association of Professional Interior Designers&rdquo; (APID)-ის მიერ ორგანიზებული &ldquo;Annual Hotel Furniture Design Competition&rdquo; კონკურსი, სადაც ცნობილი დიზაინერის, კარიმ რაშიდის მიერ პირადად დაჯილდოვდა სასტუმროს საუკეთესო დიზაინისთვის.<br />გაითვალისწინეთ! ხორციელდება კორპორატიული ტრეინინგის ჩატარება, სპეციალურად თქვენი მოთხოვნებიდან გამომდინარე, შეიქმნება სპეციალიზირებული პროგრამა!</p>\n<p>&nbsp;</p>', 'temon', '', '', 'remont', 'ge', 8, 0, 1),
(261, 108, 72, 1541409268, 0, 'text', 'ტრენინგ კურსი - სარემონტო პროექტის ეფექტური მართვა', '', '<p>ტრენინგ კურსი - სარემონტო პროექტის ეფექტური მართვა!<br />კურსი განკუთვნილია: დამწყები დიზაინერებისათვის, არქიტექტორებისთვის და ყველასთვის - ვისაც სურს შეაფასოს, პრაქტიკულად შეისწავლოს და მართოს შენობის ინტერიერის სარემონტო სამუშაოები. კომპანიებისთვის, ვინც დაკავებულია სამშენებლო-სარემონტო ბიზნესით და სურს გააღრმავოს და გააფართოვოს ცოდნის არიალი რემონტის მართვის სფეროში, შესაბამისად დამკვეთს შესთავაზოს სარემონტო პროექტის მართვის ეფექტური სერვისი.<br />მიზანი: შეძლო ოპტიმალურად დაგეგმო და მართო რემონტთან დაკავშირებული დრო, რესურსები, ხარჯები და ხარისხი.<br />კურსის შემადგენლობა: <br />&bull; მენეჯერის როლი რემონტის მსვლელობაში;<br />&bull; გეგმარების პროცესი - პროექტის შემადგენელი ნახაზები და ვიზუალები;<br />&bull; სარემონტო სივრცის ანალიზი, დათვალიერება-შეფასება; <br />&bull; ტექნოლოგიური ნაწილი - სამუშაოთა ჩამონათვალის შედგენა და თანმიმდევრობის განსაზღვრა; <br />&bull; ბაზრის კვლევა, ანალიზი, მასალების შერჩევა და სპეციფიკაცია - მასალების შესყიდვა - მომარაგება;<br />&bull; ბიუჯეტის განსაზღვრა და ხარჯთაღრიცხვის მომზადება; <br />&bull; რემონტისათვის საჭირო ადამიანური რესურსები - მოძიება და მართვა;<br />&bull; დროის დაგეგმარება - გეგმა-გრაფიკის მომზადება; <br />&bull; ხელოსნებთან ურთიერთობის პრინციპები და მიდგომები;<br />&bull; ხარისხისა და დროის კონტროლის მექანიზმები;<br />&bull; შესრულებული სამუშაოების შემოწმება-ჩაბარება;<br />&bull; დუკუმენტაცია;<br />&bull; პროექტის მართვის ფსიქოლოგიური მიდგომები;<br />&bull; უსაფრთხოება ობიექტზე.<br />კურსდამთავრებულის უპირატესობა:<br />კურსდამთავრებული შეძლებს რემონტთან დაკავთირებული დროის ხარჯების და რესურსების მართვას ოპტიმალურად.<br />სრული პროგრამის ხანგრძლივობა: 12 ლექცია<br />ლექციის ხანგრძლივობა: არანაკლებ საათნახევრი<br />კურსის ღირებულება ჯგუფში: 500 ლარი</p>\n<p>კურსს უძღვება: სოფო ახვლედიანი - 12 წლიანი წარმატებული სამუშაო გამოცდილება მოიცავს მრავალფეროვანი კომერციული და საცხოვრებელი ობიექტების პროექტების ხელმძღვანელობას საქართველოს მასშტაბით. <br />მას როგორც თანამშრომელს, ასევე მოწვეულ სპეციალისტ-დიზაინერს ნამუშევარი აქვს სასტუმროებზე, მაღაზიებზე, საქართველოს წამყვან ბანკებზე (პროკრედიტი, რესპუბლიკა, თიბისი ბანკი ...) და სხვადასხვა ტიპის ობიექტებზე. ამჟამად, მეხუთე წელია &ldquo;სამედიცინო ველნეს კურორტ ბიოლში&ldquo; დიზაინერია, ასრულებს საინტერესო დიზაინერულ სამუშაოებს და უშუალოდ მართავს სარემონტო-სამშენებლო პროცესებს.<br />უმაღლესი განათლება ინტერიერის დიზაინის სპეციალობით მიიღო არაბეთის გაერთიანებულ საემიროებში, ამერიკულ უნივესიტეტში - AUD (American University in Dubai) და დაამთავრა უმაღლესი ქულებით. არის არაერთი დიზაინის კონკურსის გამარჯვებული. აღსანიშნავია &ldquo;Association of Professional Interior Designers&rdquo; (APID)-ის მიერ ორგანიზებული &ldquo;Annual Hotel Furniture Design Competition&rdquo; კონკურსი, სადაც ცნობილი დიზაინერის, კარიმ რაშიდის მიერ პირადად დაჯილდოვდა სასტუმროს საუკეთესო დიზაინისთვის.<br />გაითვალისწინეთ! ხორციელდება კორპორატიული ტრეინინგის ჩატარება, სპეციალურად თქვენი მოთხოვნებიდან გამომდინარე, შეიქმნება სპეციალიზირებული პროგრამა!<br />შეავსე სარეგისტრაციო ფორმა და დარეგისტრირდი ჯგუფში: vipintellect.ge/ge/register<br /><br /></p>', 'remont management', '', '', '', 'en', 7, 0, 1),
(262, 108, 72, 1541409268, 0, 'text', 'სარემონტო პროექტის ეფექტური მართვა', '', '<p><strong>კურსი განკუთვნილია:</strong> დამწყები დიზაინერებისათვის, არქიტექტორებისთვის და ყველასთვის - ვისაც სურს შეაფასოს, პრაქტიკულად შეისწავლოს და მართოს შენობის ინტერიერის სარემონტო სამუშაოები. კომპანიებისთვის, ვინც დაკავებულია სამშენებლო-სარემონტო ბიზნესით და სურს გააღრმავოს და გააფართოვოს ცოდნის არიალი რემონტის მართვის სფეროში, შესაბამისად დამკვეთს შესთავაზოს სარემონტო პროექტის მართვის ეფექტური სერვისი.</p>\n<p><strong>მიზანი:</strong> შეძლო ოპტიმალურად დაგეგმო და მართო რემონტთან დაკავშირებული დრო, რესურსები, ხარჯები და ხარისხი.</p>\n<p><strong>კურსის შემადგენლობა:</strong> <br />&bull; მენეჯერის როლი რემონტის მსვლელობაში;<br />&bull; გეგმარების პროცესი - პროექტის შემადგენელი ნახაზები და ვიზუალები;<br />&bull; სარემონტო სივრცის ანალიზი, დათვალიერება-შეფასება; <br />&bull; ტექნოლოგიური ნაწილი - სამუშაოთა ჩამონათვალის შედგენა და თანმიმდევრობის განსაზღვრა; <br />&bull; ბაზრის კვლევა, ანალიზი, მასალების შერჩევა და სპეციფიკაცია - მასალების შესყიდვა - მომარაგება;<br />&bull; ბიუჯეტის განსაზღვრა და ხარჯთაღრიცხვის მომზადება; <br />&bull; რემონტისათვის საჭირო ადამიანური რესურსები - მოძიება და მართვა;<br />&bull; დროის დაგეგმარება - გეგმა-გრაფიკის მომზადება; <br />&bull; ხელოსნებთან ურთიერთობის პრინციპები და მიდგომები;<br />&bull; ხარისხისა და დროის კონტროლის მექანიზმები;<br />&bull; შესრულებული სამუშაოების შემოწმება-ჩაბარება;<br />&bull; დუკუმენტაცია;<br />&bull; პროექტის მართვის ფსიქოლოგიური მიდგომები;<br />&bull; უსაფრთხოება ობიექტზე.</p>\n<p><strong>კურსდამთავრებულის უპირატესობა:</strong><br />კურსდამთავრებული შეძლებს რემონტთან დაკავთირებული დროის ხარჯების და რესურსების მართვას ოპტიმალურად.</p>\n<p><strong>სრული პროგრამის ხანგრძლივობა: 12 ლექცია</strong><br /><strong>ლექციის ხანგრძლივობა: არანაკლებ საათნახევრი</strong><br /><strong>კურსის ღირებულება ჯგუფში: 700 ლარი</strong></p>\n<p><strong>კურსს უძღვება:</strong> სოფო ახვლედიანი - 12 წლიანი წარმატებული სამუშაო გამოცდილება მოიცავს მრავალფეროვანი კომერციული და საცხოვრებელი ობიექტების პროექტების ხელმძღვანელობას საქართველოს მასშტაბით. <br />მას როგორც თანამშრომელს, ასევე მოწვეულ სპეციალისტ-დიზაინერს ნამუშევარი აქვს სასტუმროებზე, მაღაზიებზე, საქართველოს წამყვან ბანკებზე (პროკრედიტი, რესპუბლიკა, თიბისი ბანკი ...) და სხვადასხვა ტიპის ობიექტებზე. ამჟამად, მეხუთე წელია &ldquo;სამედიცინო ველნეს კურორტ ბიოლში&ldquo; დიზაინერია, ასრულებს საინტერესო დიზაინერულ სამუშაოებს და უშუალოდ მართავს სარემონტო-სამშენებლო პროცესებს.<br />უმაღლესი განათლება ინტერიერის დიზაინის სპეციალობით მიიღო არაბეთის გაერთიანებულ საემიროებში, ამერიკულ უნივესიტეტში - AUD (American University in Dubai) და დაამთავრა უმაღლესი ქულებით. არის არაერთი დიზაინის კონკურსის გამარჯვებული. აღსანიშნავია &ldquo;Association of Professional Interior Designers&rdquo; (APID)-ის მიერ ორგანიზებული &ldquo;Annual Hotel Furniture Design Competition&rdquo; კონკურსი, სადაც ცნობილი დიზაინერის, კარიმ რაშიდის მიერ პირადად დაჯილდოვდა სასტუმროს საუკეთესო დიზაინისთვის.<br />გაითვალისწინეთ! ხორციელდება კორპორატიული ტრეინინგის ჩატარება, სპეციალურად თქვენი მოთხოვნებიდან გამომდინარე, შეიქმნება სპეციალიზირებული პროგრამა!</p>\n<p>შეავსე სარეგისტრაციო ფორმა და დარეგისტრირდი ჯგუფში:</p>\n<p>[registration]</p>', 'remont-management', '', '', '', 'ge', 7, 0, 1),
(327, 141, 72, 1686041748, 0, 'text', 'სამშენებლო ხარჯთაღრიცხვის შემსწავლელი კურსი', '', '<p>პროგრამის მიზანი: პროფესიონალური უნარების შესწავლა, მათთვის ვისაც სურს ცოდნის შეძენა სამშენებლო ხარჯთაღრიცხვის მიმართულებით.<br />დაინტერესებული პირი უნდა ფლობდეს: ექსელის საბაზო დონეს და შეეძლოს ელემენტარული მათემატიკური აზროვნება.</p>\n<p>ტრეინინგის თემატიკა:<br />&bull; მშენებლობის პროცესების და ეტაპების განხილვა <br />&bull; AUTOCAD და ARCHICAD პროგრამების საბაზისო შესწავლა მოცულობების ამოსათვლელად.<br />&bull; სამუშაოს მოცულობების დათვლა სამშენებლო ნახაზების საფუძველზე.<br />&bull; სამშენებლო ხარჯთაღრიცხვის შედგენა სამშენებლო ნორმებისა და წესების გათვალისწინებით<br />&bull; შესრულებული სამუშაოს ფორმა 2 ის შედგენა ხარჯთაღრიცხვის საფუძველზე.</p>\n<p>სრული პროგრამის ხანგრძლივობა: 16 ლექცია<br />კვირაში ჩატარდება 2/2 საათიანი ლექცია<br />ღირებულება: 1250 ლარი<br />კურსის ბოლოს ჩატარდება დასკვნითი ტესტირება და გაიცემა სერთიფიკატი!</p>\n<p>საუკეთესო კურსდამთავრებულებს გავუწევთ რეკომენდაციებს და მოთხოვნის შესაბამისად ხელს შევუწყოთ დასაქმებაში!</p>\n<p>კურსს უძღვება: გიორგი ბუკია - პრაქტიკოსი ტრენერი, რომელსაც გააჩნია სამშენებლო ხარჯთამღრიცხველის პოზიციაზე მუშაობის მრავალწლიანი გამოცდილება.</p>\n<p>შეავსე სარეგისტრაციო ფორმა და დარეგისტრირდი ჯგუფში:</p>', 'https://vipintellect.ge/ge/bussines', '', '', 'cost estimate', 'en', 6, 0, 1),
(314, 134, 39, 1654259585, 0, 'text', 'თურქული ენა', '<p>თურქული ენის შემსწავლელი კურსების&nbsp;ფართო არჩევანი - უფროსებისთვის</p>', '<p><strong>A1- A2 დონე: შეისწავლება წერა-კითხვა, გრამატიკის საფუძვლები, სიტყვების სწორად გამოთქმა, მარტივი წინადადებების აგება და მარტივი საკომუნიკაციო ენა.</strong></p>\n<p>კურსის ხანგრძილობა A1-A2 დონისთვის - 3 თვე</p>\n<p><strong>თვეში ჩატარდება: 8 ლექცია<br /> კურსის ღირებულება:<br /> </strong></p>\n<p><strong>ინდივიდუალურად: 200 ლარი<br /> წყვილში: 150 ლარი<br /> 3 კაციან ჯგუფებში: 100 ლარი</strong><br /> <br /> B1- B2 დონე: შეისწავლება გრამატიკის სრული კურსი, დამოუკიდებლად საუბარი ნებისმიერ სიტუაციაში, ზოგადი სამეცნიერო თემატიკა, პრესისა და მედიის აღქმა-გაანალიზება და თარგმანი, ენისთვის დამახასიათებელი დიალექტების დახვეწა.</p>\n<p><strong>კურსის ხანგრძლივობა:2 თვე<br /> თვეში ჩატარდება: 8 ლექცია<br /> კურსის ღირებულება:<br /> </strong></p>\n<p><strong>ინდივიდუალურად: 250 ლარი<br /> წყვილში: 200 ლარი<br /> 3 კაციან ჯგუფებში: 150 ლარი</strong></p>\n<p>C1- C2 დონე: შეისწავლება პროფესიონალურ დონეზე თურქულ ენაზე საუბარი, რთული სამეცნიერო ტერმინოლოგიის დახვეწა, ნებისმიერი დიალოგისა და ტექსტის თარგმნა.</p>\n<p><strong>კურსის ხანგრძლივობა:2 თვე<br /> თვეში ჩატარდება: 8 ლექცია<br /> კურსის ღირებულება:<br /> </strong></p>\n<p><strong>ინდივიდუალურად: 250 ლარი<br /> წყვილში: 200 ლარი<br /> 3 კაციან ჯგუფებში: 150 ლარი</strong></p>\n<p>[registration]</p>\n<p><strong>კურსის ბოლოს ჩატარდება ტესტირება!</strong><br />კურსდამთავრებულებს გადაეცემათ შესაბამისი სერტიფიკატი!</p>', 'Turkish-language', '', '', '', 'ge', 3, 0, 1),
(283, 119, 72, 1580137497, 0, 'text', 'ოფის - მენეჯერის კომპეტენციები', '<p>ოფის მენეჯრის კომპეტენციების კურსი სტაჟირებით&nbsp;</p>', '<p>&nbsp;</p>\n<p>კურსის მსვლელობისას ჩატარდება:</p>\n<p>საოფისე კომპიუტერული უნარების გასაუმჯობესებელი ლექციები</p>\n<p>ბიზნეს ინგლისურის აუცილებელი ტერმინოლოგია</p>\n<p>კურსი გრძელდება: 2 თვე</p>\n<p>კვირაში ჩატარდება: 2 ლექცია</p>\n<p>კურსის ღირებულება: 400 ლარი</p>', 'office manager', '', '', '', 'en', 1, 0, 0),
(284, 119, 72, 1580137497, 0, 'text', 'ოფის - მენეჯერის პრაქტიკული კურსი', '<p>ოფის მენეჯრის&nbsp;პრაქტიკული კურსი სტაჟირებით&nbsp;</p>', '<p><strong>კურსის სამიზნე აუდიტორია:</strong> ყველა დაინტერესებული პირი, ვისაც სურს ოფისის მენეჯერაად მუშაობის დაწყება და არ გააჩნია შესაბამის კვალიფიკაციას!</p>\n<p><strong>კურსის მიზანი:</strong> მსმენელს გამოუმუშავდეს ყველა ის პრაქტიკული უნარი და ჩვევა, რაც ოფი-მენეჯერს მოეთხოვება.</p>\n<p><strong>კურსი მოიცავს:</strong></p>\n<p>მენეჯმენტის წარმოშობა, არსი, მიზანი;<br />ოფისის მენეჯმენტის კომპეტენციები, ქცევის მენეჯმენტი და ვიზუალიზაცია;<br />დროის მენეჯმენტი, მოლაპარაკების მენეჯმენტი;<br />სამუშაოს დაგეგმვა, ორგანიზება, კონტროლი;<br />ოფისის მოწყობა, უსაფრთხოება;<br />საქმიანი შეხვედრები, პრეზენტაციების მომზადება; საქმიანი მიმოწერა; სატელეფონო საუბრის ტექნიკები;<br />საქმის წარმოება, კომპიუტერული უნარები, ელექტრონული ოფისი;<br />პროფორმების მომზადება - ინვოისი, ხელშეკრულება, ბრძანება, მემორანდუმი, აქტი ოქმი;<br />სალარო, rs.ge-სთან და ბანკთან მუშაობა; მარაგები; ინვენტარიზაცია;<br />მედია და ინტერნეტ განაცხადების მომზადება;</p>\n<p><strong>კურსდამთავრებულის უპირატესობანი:</strong></p>\n<p>დამოუკიდებლად შეძ₾ოს ოფის-მენეჯერად მუშაობა ნებისმიერ საოფისე სივრცეში!</p>\n<p><strong>კურსი გრძელდება: 12 ლექცია</strong><br /><strong>კურსის ღირებულება: ჯგუფში:&nbsp; 450 ლარი </strong></p>\n<p><strong>წყვილში: 550 ლარი</strong></p>\n<p><strong>ინდივიდუალურად: 700 ლარი</strong></p>\n<p><strong>კურსს უძღვება:</strong> ნინო მღებრიშვილი - 17 წლიანი გამოცდილების მქონე მენეჯერი, ამჟამად შპს ,,ვიაიპ ინტელექტ გრუპის\" - დამფუძნებელი, დირექტორი!</p>\n<p>[registration]</p>', 'office-manager', '', '', '', 'ge', 1, 0, 0),
(265, 110, 41, 1560427672, 0, 'text', 'საშუალო და მცირე ზომის სასტუმროს მართვის სასერთიფიკატო კურსი', '', '<p>&nbsp;</p>\n<p><strong>პროგრამის მიზანი:</strong> ტურიზმი დღეისათვის ყველაზე პერსპექტიული და მოთხოვნადი მიმართულებაა განსაკუთრებით ჩვენს ქვეყანაში, ტურიზმის განვითარებასთან ერთად იზრდება მოთხოვნა სასტუმროს მენეჯმენტის კვალიფიციურ და პრაქტიკოს სპეციალისტებზე, სწორედ ამ მოთხოვნების შესაბამისად, მოქმედი სასტუმროს მენეჯერებთან ერთად შეიქმნა სპეციალიზირებული პროგრამა, რომელიც აკმაყოფილებს თანამედროვე სასტუმროს ბიზნესის ყველა მოთხოვნას. თქვენ გეძლევათ რეალური შანსი, რომ მიიღოთ კვალიფიციური ცოდნა და შესაბამისად დასაქმდეთ&nbsp; ამ პერსპექტიულ და განვითარებად სფეროში.</p>\n<p><strong>პროგრამა განკუთვნილია:</strong> ყველა იმ დაინტერესებული პირისთვის, ვისი სურვილიცაა დაიმკვიდროს თავი სასტუმროს ბიზნესში წამყვან თანამდებობებზე ან ვისაც სურს საკუთარი სასტუმროს ბიზნეს იდეის განხორციელება.</p>\n<p><strong>კურსის სწავლის მეთოდები :</strong></p>\n<ul>\n<li>სასტუმროს მოწყობის მინიმალური სტანდარტი</li>\n<li>სასტუმროების მარკეტინგი და გაყიდვები</li>\n<li>სასტუმროს უსაფრთხოების ნორმები</li>\n<li>მცირე და საშუალო ზომის სასტუმროების ფასწარმოქმნა</li>\n<li>საშუალო და მცირე ზომის სასტუმროს მომსახურების (სრვისების) დაგეგმვა.</li>\n<li>მცირე და საშუალო ზომის სასტუმროს კადრების ადმინისტრირება, უფლება-მოალეობები და სახელფასო ფონდი.</li>\n<li>მცირე და საშალო ზომის სასტუმროს ადმინისტრაციული დოკუმენტაციის წარმოება.</li>\n</ul>\n<p><strong>კურსის მსვლელობისას გადმოგეცემათ:</strong> სასწავლო მასალის ელექტრონული ვერსია და სამუშაო დოკუმენტაციის მზა ფორმები.</p>\n<p><strong>სრული კურსის შემდეგ თქვენ შეძლებთ:</strong>&nbsp;&nbsp; მცირე და საშუალო ზომის სასტუმროს მართვას,&nbsp; ასევე&nbsp; გამოიმუშავებთ&nbsp; იმ უნარ-ჩვევებს რაც აუცილებელია&nbsp; სასტუმროს მენეჯერისთვის, მიეჩვევით გუნდური მუშაობის პრონციპებს .</p>\n<p><strong>ინტერაქციული ლექციების ხანგრძლივობა: 18 საათი </strong></p>\n<p><strong>სალექციო კურსის ღირებულება ჯგუფში: 300 ლარი</strong></p>\n<p><strong>კურსს წარუძღვება: დარინა ხუბაევი.&nbsp; </strong></p>\n<p>სასტუმროს ბიზნესში ცხრა წლიანი გამოცდილების მქონე პრაქტიკოსი ტრენერი, მისი სამუშაო გამოცდილება მოიცავს, როგორც ადგილობრივ ბრენდებთან (Bazaleti Palace, Archi group, Fund Hotel, hotel 27), ასევე სასტუმროს საერთაშორისო ქსელებთან&nbsp;&nbsp; ურთიერთობას (Starwood Hotels Group, Accor Hotels Group).</p>\n<p><strong>გაითვალისწინეთ! </strong>&nbsp;ჩვენი საუკეთესო კურსდამთავრებულები, ჩვენი რეკომენდაციით წარმატებით აგრძელებენ მცირე და საშუალო ზომის სასტუმროში მუშაობას!</p>\n<p>აგრეთვე, ჩვენი კურსდამთავრებული თავისუფლად შეძლებს საკუთარი მცირე და საშუალო ზომის სასტუმროს ბიზნესის დაწყებასა და მართვას!</p>\n<p>ასევე გაგიწევთ საკონსულტაიო მომსახურებას, მათ ვისაც&nbsp; გსურთ სასტუმროს ბიზნესში საქმიანობა და საკუთარი ბიზნესის შექმნა ან სხვის ბიზნესში მენეჯერულ პოზიციაზე მუშაობა, გარდა ამისა დაგეხმარებით კვალიფიციური კადრების მოძიებაში, თქვენი ბიზნესის პოპულარიზაციისთვის მარკეტინგული ღონისძიებების დაგეგმვაში, რეკლამირებასა და გაყიდვების გაზრდაში!</p>\n<p><strong>კურსზე რეგისტრაციისთია შეავსეთ სარეგისტრაციო ფორმა: </strong></p>\n<p><strong>vipintellect.ge/ge/register</strong></p>\n<p>&nbsp;</p>', 'small hotel management', '', '', 'small hotel management', 'en', 7, 0, 0),
(263, 109, 41, 1560427350, 0, 'text', ',სასტუმროს ადმინისტრატორის მოსამზადებელი სასერტიფიკატო კურსი!', '<p>&nbsp;</p>\n<p>&nbsp;</p>', '<p>&nbsp;</p>\n<p><strong>კურსი</strong><strong> განკუთვნილია:</strong> მათთვის, ვისაც სურს სასტუმროში ადმინისტრატორის პოზიციაზე დასაქმება.</p>\n<p><strong>დასაქმების რეალური შესაძლებლობა!</strong></p>\n<p>გაითვალისწინეთ, წლებია ვთანამშრომლოთ სხვადასხვა ტიპის სასტუმროსთან, როგორც თბილისში ასევე რეგიონებში. არსებული სასტუმროები სისტემატურად გვაწვდიან ვაკანსიებს და ითხოვენ ჩვენგან კვალიფიციურ კადრებს.</p>\n<p>დავასაქმეთ, არა ერთი&nbsp; ჩვენი კურსდამთავრებულები, ისინი დღემდე წარმატებით მოღვაწეობენ ტურიზმის სფეროში საშუალო და ზედა რგოლის მენეჯერებად. &nbsp;</p>\n<p>მხოლოდ წარმატებულ კურსდამთავრებულებს აქვთ საშუალება გამოიყენონ ეს შანსი და ჩვენი რეკომენდაციით თავი დაიმკვიდრონ სასტუმროს ბიზნესში.</p>\n<p><strong>კურსის</strong><strong> თემატიკა :</strong></p>\n<ol>\n<li>განთავსების ობიექტის ტიპები და ოთახების კატეგორიები</li>\n<li>დიდი, საშუალო და მცირე ზომის სასტუმროს ორგანიზაციული სტრუქტურა და უფლება-მოვალეობები</li>\n<li>მიღება-განთავსების (რეცეფციის, ადმინისტრაციის )სამსახურის ურთიერთ თანამშრომლობა სასტუმროს სხვა დეპარტამენტებთან</li>\n<li>მირება განთავსების დეპარტამენტის თანამშრომლები და მათი ფუნქცია მოვალეობები</li>\n<li>ადმინისტრატორის (რეცეფციონისტის) სამუშაო აღწერილობა, პროფესიული უნარჩვევები; სამუშაო ბაზრის მოთხოვნები და პრაქტიკაში გავრცელებული სამუშაო პირობები</li>\n<li>სასტუმროს სამუშაო პროგრამები; სასტუმროს სამუშაო პროგრამაში მუშაობის პრაქტიკული ნაწილი.</li>\n<li>სასტუმროში ანგარიშსწორების წესი და პირობები, თანმდევი დოკუმენტაცია;</li>\n<li>სტუმართან ურთიერთობის ეთიკის ნორმები და ადმინისტრაციის შენაგანაწესი</li>\n<li>ფორსმაჟორული სიტუაციების მართვა</li>\n<li>დაჯავშნის სამსახურის უფლება-მოვალეობები, სამუშაო დოკუმენტაცია და სტუმართან კომუნიკაციის ეტიკეტი; ჯავშნის მიღება და პროგრამაში ასახვა</li>\n</ol>\n<p><strong>კურსის ხანგრძლივობა: 20 საათი</strong></p>\n<p><strong>კურსის ღირებულება: 400 ლარი</strong></p>\n<p><strong>კურსის ფორმატში ჩატარდება ინფო</strong><strong> - </strong><strong>ტური</strong><strong> 5,4 </strong><strong>ვარსკვლავიან</strong><strong>, </strong><strong>საოჯახო</strong> <strong>და</strong> <strong>ჰოსტელის</strong> <strong>ტიპის</strong> <strong>სასტუმროებში</strong><strong>.</strong></p>\n<p><strong>კურსდამთ</strong><strong>ავრებულის უპირატესობანი:</strong></p>\n<p>სრული კურსის შემდეგ თქვენ შეძლებთ სასტუმროში ადმინისტრატორის პოზიციაზე დასაქმებას, გამოიმუშავებთ იმ უნარ-ჩვევებს რაც აუცილებელია სასტუმროს ადმინისტრატორისთვის, დაეუფლებით გუნდური მუშაობის პრინციპებს.&nbsp;</p>\n<p><strong>კურსის</strong> <strong>ხელმძღვენელი</strong><strong>&nbsp;&nbsp; - &nbsp;</strong><strong>დარინა</strong> <strong>ხუბაევი</strong><strong>.&nbsp;</strong></p>\n<p>ტურიზმის ექსპერტი, სასტუმროს ბიზნესში 10+ წლიანი გამოცდილების მქონე პრაქტიკოსი ტრენერი, მისი სამუშაო გამოცდილება მოიცავს, როგორც ადგილობრივ ბრენდებთან (Bazaleti Palace, Archi group, Fund Hotel, hotel 27, ჰოტელ ამსერი,), ასევე სასტუმროს საერთაშორისო ქსელებთან ურთიერთობას (Starwood Hotels Group, Accor Hotels Group).</p>\n<p><strong>ვითვალისწინებთ რა ზაფხულის სეზონს ლექციები ჩატარდება ინტენსიურად!</strong></p>\n<p><strong>შეავსე სარეგისტრაციო ფორმა და დარეგისტრირდი ჯგუფში: vipintellect.ge/ge/register</strong></p>\n<p>&nbsp;</p>\n<p>&nbsp;</p>', 'hotel admin', '', '', 'hotel admin', 'en', 6, 0, 0),
(264, 109, 41, 1560427350, 0, 'text', 'სასტუმროს ადმინისტრატორის მოსამზადებელი სასერტიფიკატო კურსი', '<p>&nbsp;</p>\n<p>&nbsp;</p>', '<p><strong>კურსი</strong><strong> განკუთვნილია:</strong> მათთვის, ვისაც სურს სასტუმროში ადმინისტრატორის პოზიციაზე დასაქმება.</p>\n<p><strong>დასაქმების რეალური შესაძლებლობა!</strong></p>\n<p>გაითვალისწინეთ, წლებია ვთანამშრომლოთ სხვადასხვა ტიპის სასტუმროსთან, როგორც თბილისში ასევე რეგიონებში. არსებული სასტუმროები სისტემატურად გვაწვდიან ვაკანსიებს და ითხოვენ ჩვენგან კვალიფიციურ კადრებს.</p>\n<p>დავასაქმეთ, არა ერთი&nbsp; ჩვენი კურსდამთავრებულები, ისინი დღემდე წარმატებით მოღვაწეობენ ტურიზმის სფეროში საშუალო და ზედა რგოლის მენეჯერებად. &nbsp;</p>\n<p>მხოლოდ წარმატებულ კურსდამთავრებულებს აქვთ საშუალება გამოიყენონ ეს შანსი და ჩვენი რეკომენდაციით თავი დაიმკვიდრონ სასტუმროს ბიზნესში.</p>\n<p><strong>კურსის</strong><strong> თემატიკა :</strong></p>\n<p>განთავსების ობიექტის ტიპები და ოთახების კატეგორიები<br />დიდი, საშუალო და მცირე ზომის სასტუმროს ორგანიზაციული სტრუქტურა და უფლება-მოვალეობები<br />მიღება-განთავსების (რეცეფციის, ადმინისტრაციის) სამსახურის ურთიერთ თანამშრომლობა სასტუმროს სხვა დეპარტამენტებთან<br />მიღება განთავსების დეპარტამენტის თანამშრომლები და მათი ფუნქცია მოვალეობები<br />ადმინისტრატორის (რეცეფციონისტის) სამუშაო აღწერილობა, პროფესიული უნარჩვევები; სამუშაო ბაზრის მოთხოვნები და პრაქტიკაში გავრცელებული სამუშაო პირობები<br />სასტუმროს სამუშაო პროგრამები; სასტუმროს სამუშაო პროგრამაში მუშაობის პრაქტიკული ნაწილი.<br />სასტუმროში ანგარიშსწორების წესი და პირობები, თანმდევი დოკუმენტაცია;<br />სტუმართან ურთიერთობის ეთიკის ნორმები და ადმინისტრაციის შენაგანაწესი<br />ფორსმაჟორული სიტუაციების მართვა<br />დაჯავშნის სამსახურის უფლება-მოვალეობები, სამუშაო დოკუმენტაცია და სტუმართან კომუნიკაციის ეტიკეტი; ჯავშნის მიღება და პროგრამაში ასახვა</p>\n<p><strong>კურსის ხანგრძლივობა: 10 ლექცია - 20 საათი</strong></p>\n<p><strong>კურსის ღირებულება: 550 ლარი - მცირე რიცხვოვან ჯგუფში</strong></p>\n<p><strong>კურსის ხანგრძლივობა: ინდივიდუალურად - 8 ლექცია / 16 საათი</strong></p>\n<p><strong>კურსის ღირებულება: 950 ლარი&nbsp;</strong></p>\n<p><strong>კურსის ფორმატში ჩატარდება ინფო</strong><strong> - </strong><strong>ტური</strong><strong> 5,4 </strong><strong>ვარსკვლავიან</strong><strong>, </strong><strong>საოჯახო</strong> <strong>და</strong> <strong>ჰოსტელის</strong> <strong>ტიპის</strong> <strong>სასტუმროებში</strong><strong>.</strong></p>\n<p><strong>კურსდამთ</strong><strong>ავრებულის უპირატესობანი:</strong></p>\n<p>სრული კურსის შემდეგ თქვენ შეძლებთ სასტუმროში ადმინისტრატორის პოზიციაზე დასაქმებას, გამოიმუშავებთ იმ უნარ-ჩვევებს რაც აუცილებელია სასტუმროს ადმინისტრატორისთვის, დაეუფლებით გუნდური მუშაობის პრინციპებს.&nbsp;</p>\n<p><strong>შეავსე სარეგისტრაციო ფორმა და დარეგისტრირდი ჯგუფში: [registration]</strong></p>\n<p>&nbsp;</p>\n<p>&nbsp;</p>', 'hotel-admin', '', '', 'hotel admin', 'ge', 6, 0, 0),
(266, 110, 41, 1560427672, 0, 'text', 'საშუალო და მცირე ზომის სასტუმროს მართვის სასერთიფიკატო კურსი', '', '<p><strong>პროგრამის მიზანი:</strong> ტურიზმი დღეისათვის ყველაზე პერსპექტიული და მოთხოვნადი მიმართულებაა განსაკუთრებით ჩვენს ქვეყანაში, ტურიზმის განვითარებასთან ერთად იზრდება მოთხოვნა სასტუმროს მენეჯმენტის კვალიფიციურ და პრაქტიკოს სპეციალისტებზე, სწორედ ამ მოთხოვნების შესაბამისად, მოქმედი სასტუმროს მენეჯერებთან ერთად შეიქმნა სპეციალიზირებული პროგრამა, რომელიც აკმაყოფილებს თანამედროვე სასტუმროს ბიზნესის ყველა მოთხოვნას. თქვენ გეძლევათ რეალური შანსი, რომ მიიღოთ კვალიფიციური ცოდნა და შესაბამისად დასაქმდეთ&nbsp; ამ პერსპექტიულ და განვითარებად სფეროში.</p>\n<p><strong>პროგრამა განკუთვნილია:</strong> ყველა იმ დაინტერესებული პირისთვის, ვისი სურვილიცაა დაიმკვიდროს თავი სასტუმროს ბიზნესში წამყვან თანამდებობებზე ან ვისაც სურს საკუთარი სასტუმროს ბიზნეს იდეის განხორციელება.</p>\n<p><strong>კურსის სწავლის მეთოდები :</strong></p>\n<ul>\n<li>სასტუმროს მოწყობის მინიმალური სტანდარტი</li>\n<li>სასტუმროების მარკეტინგი და გაყიდვები</li>\n<li>სასტუმროს უსაფრთხოების ნორმები</li>\n<li>მცირე და საშუალო ზომის სასტუმროების ფასწარმოქმნა</li>\n<li>საშუალო და მცირე ზომის სასტუმროს მომსახურების (სრვისების) დაგეგმვა.</li>\n<li>მცირე და საშუალო ზომის სასტუმროს კადრების ადმინისტრირება, უფლება-მოალეობები და სახელფასო ფონდი.</li>\n<li>მცირე და საშალო ზომის სასტუმროს ადმინისტრაციული დოკუმენტაციის წარმოება.</li>\n</ul>\n<p><strong>კურსის მსვლელობისას გადმოგეცემათ:</strong> სასწავლო მასალის ელექტრონული ვერსია და სამუშაო დოკუმენტაციის მზა ფორმები.</p>\n<p><strong>სრული კურსის შემდეგ თქვენ შეძლებთ:</strong>&nbsp;&nbsp; მცირე და საშუალო ზომის სასტუმროს მართვას,&nbsp; ასევე&nbsp; გამოიმუშავებთ&nbsp; იმ უნარ-ჩვევებს რაც აუცილებელია&nbsp; სასტუმროს მენეჯერისთვის, მიეჩვევით გუნდური მუშაობის პრონციპებს .</p>\n<p><strong>ინტერაქციული ლექციების ხანგრძლივობა: 18 საათი </strong></p>\n<p><strong>სალექციო კურსის ღირებულება ჯგუფში:&nbsp;400 ლარი</strong></p>\n<p><strong>ინდივიდუალურად:&nbsp;6 საათი</strong></p>\n<p><strong>ღირებულება: 750 ლარი</strong></p>\n<p><strong>კურსს წარუძღვება:&nbsp;ნინო დანელია</strong></p>\n<p>ტურიზმის ექსპერტი, სასტუმროს ბიზნესში 10+ წლიანი გამოცდილების მქონე პრაქტიკოსი ტრენერი, მისი სამუშაო გამოცდილება მოიცავს, როგორც ადგილობრივ ბრენდებთან, ასევე სასტუმროს საერთაშორისო ქსელებთან ურთიერთობას.</p>\n<p><strong>გაითვალისწინეთ! </strong>&nbsp;ჩვენი საუკეთესო კურსდამთავრებულები, ჩვენი რეკომენდაციით წარმატებით აგრძელებენ მცირე და საშუალო ზომის სასტუმროში მუშაობას!</p>\n<p>აგრეთვე, ჩვენი კურსდამთავრებული თავისუფლად შეძლებს საკუთარი მცირე და საშუალო ზომის სასტუმროს ბიზნესის დაწყებასა და მართვას!</p>\n<p>ასევე გაგიწევთ საკონსულტაიო მომსახურებას, მათ ვისაც&nbsp; გსურთ სასტუმროს ბიზნესში საქმიანობა და საკუთარი ბიზნესის შექმნა ან სხვის ბიზნესში მენეჯერულ პოზიციაზე მუშაობა, გარდა ამისა დაგეხმარებით კვალიფიციური კადრების მოძიებაში, თქვენი ბიზნესის პოპულარიზაციისთვის მარკეტინგული ღონისძიებების დაგეგმვაში, რეკლამირებასა და გაყიდვების გაზრდაში!</p>\n<p><strong>შეავსე სარეგისტრაციო ფორმა და დარეგისტრირდი ჯგუფში:&nbsp;[registration]</strong></p>\n<p>&nbsp;</p>', 'small-hotel-management', '', '', 'small hotel management', 'ge', 7, 0, 0),
(269, 112, 41, 1576159165, 0, 'text', 'ტურ-ოპერატორის მოსამზადებელი კურსი', '<p>ტურ ოპერატორების შემსწავლელი კურსი</p>', '<p><strong>პროგრამა</strong> <strong>განკუთვნილია</strong><strong>:</strong>&nbsp;ყველა იმ დაინტერესებული პირისთვის, ვისაც სურვილი აქვს იმუშაოს ტურიზმის მენეჯერად ან ტურ ოპერატორად, ან შექმნას საკუთარი ტურისტული კომპანია.</p>\n<p>', 'tour-operator', '', '', '', 'en', 1, 0, 0),
(272, 113, 72, 1577111887, 0, 'text', 'სამოქალაქო სამართლის პრაქტიკული კურსი ', '<p><strong>სამოქალაქო სამართლის პრაქტიკული კურსი&nbsp;</strong></p>', '<p><strong>კურსს</strong> <strong>უძღვება</strong><strong>:</strong>&nbsp;მაია თურქია - ს.ს.ო.პ. საქართველოს ადვოკატთა ასოციაციის წევრი&nbsp; ადვოკატი.</p>\n<p><strong>კურსის</strong> <strong>მიზანია</strong><strong>:</strong>&nbsp;</p>\n<p>დაეხმაროს სამართლის ფაკულტეტის სტუდენტებს და სამართლის კურსდამთავრებულებს სამოქალაქო სპეციალიზაციით სამართლებრივი საქმიანობის დამოუკიდებლად&nbsp; წარმართვაში.</p>\n<p><strong>კურსი</strong><strong>ს მოიცავს:</strong></p>\n<ol>\n<li>კანონით დადგენილი ყველა სახის ხელშეკრულებების შედგენა.</li>\n<li>სამოქალაქო და ადმინისტრაციული სარჩელის შედგენა .</li>\n<li>სააპელალაციო და საკასაციო სარჩელის შედგენა.</li>\n<li>კერძო საჩივრის და სხვადასხვა სახის განცხადებების შედგენა ყველა ინსტანციის სასამართლოში.</li>\n<li>განქორწინება და ალიმენტი</li>\n<li>მეუღლეთა თანაცხოვრების მანძილზე შეძენილი ქონების გაყოფა.</li>\n<li>მემკვიდრეობის მიღებასთან დაკავშირებული საკითხები.</li>\n<li>სასამართლო პროცესებზე დასწრება.</li>\n<li>9. იმიტირებული პრაქტიკული სიტუაციები.</li>\n</ol>\n<p><strong>&nbsp;</strong></p>\n<p><strong>კურსის</strong> <strong>ხანგრძლივობა</strong><strong>:</strong>&nbsp;<strong>3 </strong><strong>თვე</strong></p>\n<p><strong>კვირაში</strong> <strong>ორი</strong> <strong>დღე</strong><strong> - </strong><strong>თვეში</strong><strong>&nbsp; </strong><strong>8 </strong><strong>ლექცია</strong></p>\n<p><strong>კურსის ღირებულება თვეში: 300 ლარი ჯგუფში</strong></p>\n<p><strong>360 ლარი&nbsp; 2 კაციან ჯგუფში</strong></p>\n<p><strong>540 ლარი ინდივიდუაურად</strong></p>\n<p><br /> <strong>კურსის</strong> <strong>დასრულების</strong> <strong>შემდეგ</strong>: თქვენ შეძლებთ სამართლებრივი შემცველ დოკუმენტებზე მუშაობას, სამართლებრივი დოკუმენტების თავად შედგენას, კლიენტებთან&nbsp; ურთიერთობას.</p>\n<p><strong>კურსის</strong> <strong>დასრულების</strong> <strong>შემდეგ</strong> <strong>გაიცემა</strong> <strong>სერტიფიკატი</strong><strong>.</strong></p>\n<p>&nbsp;</p>\n<p>&nbsp;</p>', 'Law-course', '', '', '', 'ge', 8, 0, 1),
(275, 115, 7, 1577112540, 0, 'text', 'სამოქალაქო სამართლის პრაქტიკული კურსი ', '<p><strong>სამოქალაქო სამართლის პრაქტიკული კურსი </strong></p>', '<p><strong>კურსის</strong> <strong>მიზანია</strong><strong>:</strong>&nbsp;</p>\n<p>დაეხმაროს სამართლის ფაკულტეტის სტუდენტებს და სამართლის კურსდამთავრებულებს სამოქალაქო სპეციალიზაციით სამართლებრივი საქმიანობის დამოუკიდებლად&nbsp; წარმართვაში.</p>\n<p><strong>კურსს</strong> <strong>უძღვება</strong><strong>:</strong>&nbsp;მაია თურქია - ს.ს.ო.პ. საქართველოს ადვოკატთა ასოციაციის წევრი&nbsp; ადვოკატი.</p>\n<p><strong>კურსი</strong><strong>ს მოიცავს:</strong></p>\n<ol>\n<li>კანონით დადგენილი ყველა სახის ხელშეკრულებების შედგენა.</li>\n<li>სამოქალაქო და ადმინისტრაციული სარჩელის შედგენა .</li>\n<li>სააპელალაციო და საკასაციო სარჩელის შედგენა.</li>\n<li>კერძო საჩივრის და სხვადასხვა სახის განცხადებების შედგენა ყველა ინსტანციის სასამართლოში.</li>\n<li>განქორწინება და ალიმენტი</li>\n<li>მეუღლეთა თანაცხოვრების მანძილზე შეძენილი ქონების გაყოფა.</li>\n<li>მემკვიდრეობის მიღებასთან დაკავშირებული საკითხები.</li>\n<li>სასამართლო პროცესებზე დასწრება.</li>\n<li>9. იმიტირებული პრაქტიკული სიტუაციები.</li>\n</ol>\n<p><strong>კურსის</strong> <strong>ხანგრძლივობა</strong><strong>:</strong>&nbsp;<strong>3 </strong><strong>თვე</strong></p>\n<p><strong>კვირაში</strong> <strong>ორი</strong> <strong>დღე</strong><strong> - </strong><strong>თვეში</strong><strong>&nbsp; </strong><strong>8 </strong><strong>ლექცია</strong></p>\n<p><strong>კურსის ღირებულება თვეში: 300 ლარი ჯგუფში</strong></p>\n<p><strong>360 ლარი&nbsp; 2 კაციან ჯგუფში</strong></p>\n<p><strong>540 ლარი ინდივიდუაურად</strong></p>\n<p><strong>კურსის</strong> <strong>დასრულების</strong> <strong>შემდეგ</strong>: თქვენ შეძლებთ სამართლებრივი შემცველ დოკუმენტებზე მუშაობას, სამართლებრივი დოკუმენტების თავად შედგენას, კლიენტებთან&nbsp; ურთიერთობას.</p>\n<p><strong>კურსის</strong> <strong>დასრულების</strong> <strong>შემდეგ</strong> <strong>გაიცემა</strong> <strong>სერტიფიკატი</strong><strong>.</strong></p>\n<p>&nbsp;</p>', 'low course', '', '', '', 'en', 8, 0, 1),
(273, 114, 7, 1577112068, 0, 'text', 'სამოქალაქო სამართლის პრაქტიკული კურსი ', '<p><strong>სამოქალაქო სამართლის პრაქტიკული კურსი </strong></p>', '<p><strong>კურსს</strong> <strong>უძღვება</strong><strong>:</strong>&nbsp;მაია თურქია - ს.ს.ო.პ. საქართველოს ადვოკატთა ასოციაციის წევრი&nbsp; ადვოკატი.</p>\n<p><strong>კურსის</strong> <strong>მიზანია</strong><strong>:</strong>&nbsp;</p>\n<p>დაეხმაროს სამართლის ფაკულტეტის სტუდენტებს და სამართლის კურსდამთავრებულებს სამოქალაქო სპეციალიზაციით სამართლებრივი საქმიანობის დამოუკიდებლად&nbsp; წარმართვაში.</p>\n<p><strong>კურსი</strong><strong>ს მოიცავს:</strong></p>\n<ol>\n<li>კანონით დადგენილი ყველა სახის ხელშეკრულებების შედგენა.</li>\n<li>სამოქალაქო და ადმინისტრაციული სარჩელის შედგენა .</li>\n<li>სააპელალაციო და საკასაციო სარჩელის შედგენა.</li>\n<li>კერძო საჩივრის და სხვადასხვა სახის განცხადებების შედგენა ყველა ინსტანციის სასამართლოში.</li>\n<li>განქორწინება და ალიმენტი</li>\n<li>მეუღლეთა თანაცხოვრების მანძილზე შეძენილი ქონების გაყოფა.</li>\n<li>მემკვიდრეობის მიღებასთან დაკავშირებული საკითხები.</li>\n<li>სასამართლო პროცესებზე დასწრება.</li>\n<li>9. იმიტირებული პრაქტიკული სიტუაციები.</li>\n</ol>\n<p><strong>კურსის</strong> <strong>ხანგრძლივობა</strong><strong>:</strong>&nbsp;<strong>3 </strong><strong>თვე</strong></p>\n<p><strong>კვირაში</strong> <strong>ორი</strong> <strong>დღე</strong><strong> - </strong><strong>თვეში</strong><strong>&nbsp; </strong><strong>8 </strong><strong>ლექცია</strong></p>\n<p><strong>კურსის ღირებულება თვეში: 300 ლარი ჯგუფში</strong></p>\n<p><strong>360 ლარი&nbsp; 2 კაციან ჯგუფში</strong></p>\n<p><strong>540 ლარი ინდივიდუაურად</strong></p>\n<p><strong>კურსის</strong> <strong>დასრულების</strong> <strong>შემდეგ</strong>: თქვენ შეძლებთ სამართლებრივი შემცველ დოკუმენტებზე მუშაობას, სამართლებრივი დოკუმენტების თავად შედგენას, კლიენტებთან&nbsp; ურთიერთობას.</p>\n<p><strong>კურსის</strong> <strong>დასრულების</strong> <strong>შემდეგ</strong> <strong>გაიცემა</strong> <strong>სერტიფიკატი</strong><strong>.</strong></p>', 'low course', '', '', '', 'en', 8, 0, 1),
(274, 114, 7, 1577112068, 0, 'text', 'სამოქალაქო სამართლის პრაქტიკული კურსი ', '<p><strong>სამოქალაქო სამართლის პრაქტიკული კურსი </strong></p>', '<p><strong>კურსს</strong> <strong>უძღვება</strong><strong>:</strong>&nbsp;მაია თურქია - ს.ს.ო.პ. საქართველოს ადვოკატთა ასოციაციის წევრი&nbsp; ადვოკატი.</p>\n<p><strong>კურსის</strong> <strong>მიზანია</strong><strong>:</strong>&nbsp;</p>\n<p>დაეხმაროს სამართლის ფაკულტეტის სტუდენტებს და სამართლის კურსდამთავრებულებს სამოქალაქო სპეციალიზაციით სამართლებრივი საქმიანობის დამოუკიდებლად&nbsp; წარმართვაში.</p>\n<p><strong>კურსი</strong><strong>ს მოიცავს:</strong></p>\n<ol>\n<li>კანონით დადგენილი ყველა სახის ხელშეკრულებების შედგენა.</li>\n<li>სამოქალაქო და ადმინისტრაციული სარჩელის შედგენა .</li>\n<li>სააპელალაციო და საკასაციო სარჩელის შედგენა.</li>\n<li>კერძო საჩივრის და სხვადასხვა სახის განცხადებების შედგენა ყველა ინსტანციის სასამართლოში.</li>\n<li>განქორწინება და ალიმენტი</li>\n<li>მეუღლეთა თანაცხოვრების მანძილზე შეძენილი ქონების გაყოფა.</li>\n<li>მემკვიდრეობის მიღებასთან დაკავშირებული საკითხები.</li>\n<li>სასამართლო პროცესებზე დასწრება.</li>\n<li>9. იმიტირებული პრაქტიკული სიტუაციები.</li>\n</ol>\n<p><strong>კურსის</strong> <strong>ხანგრძლივობა</strong><strong>:</strong>&nbsp;<strong>3 </strong><strong>თვე</strong></p>\n<p><strong>კვირაში</strong> <strong>ორი</strong> <strong>დღე</strong><strong> - </strong><strong>თვეში</strong><strong>&nbsp; </strong><strong>8 </strong><strong>ლექცია</strong></p>\n<p><strong>კურსის ღირებულება თვეში: 300 ლარი ჯგუფში</strong></p>\n<p><strong>360 ლარი&nbsp; 2 კაციან ჯგუფში</strong></p>\n<p><strong>540 ლარი ინდივიდუაურად</strong></p>\n<p><strong>კურსის</strong> <strong>დასრულების</strong> <strong>შემდეგ</strong>: თქვენ შეძლებთ სამართლებრივი შემცველ დოკუმენტებზე მუშაობას, სამართლებრივი დოკუმენტების თავად შედგენას, კლიენტებთან&nbsp; ურთიერთობას.</p>\n<p><strong>კურსის</strong> <strong>დასრულების</strong> <strong>შემდეგ</strong> <strong>გაიცემა</strong> <strong>სერტიფიკატი</strong><strong>.</strong></p>', 'low course', '', '', '', 'ge', 8, 0, 1),
(276, 115, 7, 1577112540, 0, 'text', 'სამოქალაქო სამართლის პრაქტიკული კურსი ', '<p><strong>სამოქალაქო სამართლის პრაქტიკული კურსი </strong></p>', '<p><strong>კურსის</strong> <strong>მიზანია</strong><strong>:</strong>&nbsp;</p>\n<p>დაეხმაროს სამართლის ფაკულტეტის სტუდენტებს და სამართლის კურსდამთავრებულებს სამოქალაქო სპეციალიზაციით სამართლებრივი საქმიანობის დამოუკიდებლად&nbsp; წარმართვაში.</p>\n<p><strong>კურსს</strong> <strong>უძღვება</strong><strong>:</strong>&nbsp;მაია თურქია - ს.ს.ო.პ. საქართველოს ადვოკატთა ასოციაციის წევრი&nbsp; ადვოკატი.</p>\n<p><strong>კურსი</strong><strong>ს მოიცავს:</strong></p>\n<ol>\n<li>კანონით დადგენილი ყველა სახის ხელშეკრულებების შედგენა.</li>\n<li>სამოქალაქო და ადმინისტრაციული სარჩელის შედგენა .</li>\n<li>სააპელალაციო და საკასაციო სარჩელის შედგენა.</li>\n<li>კერძო საჩივრის და სხვადასხვა სახის განცხადებების შედგენა ყველა ინსტანციის სასამართლოში.</li>\n<li>განქორწინება და ალიმენტი</li>\n<li>მეუღლეთა თანაცხოვრების მანძილზე შეძენილი ქონების გაყოფა.</li>\n<li>მემკვიდრეობის მიღებასთან დაკავშირებული საკითხები.</li>\n<li>სასამართლო პროცესებზე დასწრება.</li>\n<li>9. იმიტირებული პრაქტიკული სიტუაციები.</li>\n</ol>\n<p><strong>კურსის</strong> <strong>ხანგრძლივობა</strong><strong>:</strong>&nbsp;<strong>3 </strong><strong>თვე</strong></p>\n<p><strong>კვირაში</strong> <strong>ორი</strong> <strong>დღე</strong><strong> - </strong><strong>თვეში</strong><strong>&nbsp; </strong><strong>8 </strong><strong>ლექცია</strong></p>\n<p><strong>კურსის ღირებულება თვეში: 300 ლარი ჯგუფში</strong></p>\n<p><strong>360 ლარი&nbsp; 2 კაციან ჯგუფში</strong></p>\n<p><strong>540 ლარი ინდივიდუაურად</strong></p>\n<p><strong>კურსის</strong> <strong>დასრულების</strong> <strong>შემდეგ</strong>: თქვენ შეძლებთ სამართლებრივი შემცველ დოკუმენტებზე მუშაობას, სამართლებრივი დოკუმენტების თავად შედგენას, კლიენტებთან&nbsp; ურთიერთობას.</p>\n<p><strong>კურსის</strong> <strong>დასრულების</strong> <strong>შემდეგ</strong> <strong>გაიცემა</strong> <strong>სერტიფიკატი</strong><strong>.</strong></p>\n<p><strong>[registration]</strong></p>\n<p>&nbsp;</p>', 'low-course', '', '', '', 'ge', 8, 0, 1),
(277, 116, 40, 1578489933, 0, 'text', 'იურიდიული ინგლისური', '<p>იურიდიული ინგლისური</p>', '<p><strong>კურსის მიზანია:</strong> დაეხმაროს სტუდენტებს, პრაქტიკოს იურისტებს, ადვოკატებს, კერძო კომპანიებისა და საჯარო დაწესებულებების იურისტებს სამართლებრივი ტერმინოლოგიის დაუფლებაში, რათა მათ შეძლონ ინგლისურ ენაზე სამართლებრივი საქმიანობის, როგორც წერილობით, ისე ზეპირად წარმართვა.</p>\n<p>&nbsp;</p>\n<p><strong>კურსი მოიცავს შემდეგ საკითხებს:</strong></p>\n<p>&nbsp;</p>\n<ul>\n<li>ზოგადი სამართლებრივი და დარგობრივი ტერმინოლოგიის შესწავლა (სამოქალაქო, შრომის, ბიზნეს, საკორპორაციო, სამშენებლო, საჯარო, სისხლის, საერთაშორისო სამართალი და ა. შ.);</li>\n<li>სხვადასხვა სახის სამართლებრივი დოკუმენტების შედგენა (საკორპორაციო დოკუმენტების, ხელშეკრულებების, მემორანდუმების, სამართლებრივი დასკვნების და ა. შ.);</li>\n<li>ინგლისურ ენაზე სამართლებრივი სპეციფიკის მქონე, როგორც წერილობითი, ისე ზეპირი კომუნიკაციის წარმოება;</li>\n<li>პრაქტიკული სამუშაოები, ზეპირი განხილვები და იმიტირებული პრაქტიკული სიტუაციები.</li>\n</ul>\n<p>&nbsp;</p>\n<p><strong>კურსის ხანგრძლივობა:</strong> &nbsp;(2 ან 3 თვე)</p>\n<p>დამოკიდებულია მსმენელის მიერ ინგლისური ენის ცოდნის დონეზე</p>\n<p>&nbsp;</p>\n<p><strong>კვირაში ორი დღე - თვეში 8 ლექცია</strong></p>\n<p>ლექციის ხანგრილობა:</p>\n<p>1 საათი ინდივიდუალურად, ჯგუფში - საათნახევარი</p>\n<p>ღირებულება 3-5 კაციან ჯგუფში: 160 ლარი</p>\n<p>ღირებულება წყვილში: 240 ლარი</p>\n<p>ინდივიდუალურად: 300 ლარი</p>\n<p>&nbsp;</p>\n<p><strong>კვირაში სამი&nbsp; დღე - თვეში 12 ლექცია</strong></p>\n<p>ლექციის ხანგრილობა:</p>\n<p>1 საათი ინდივიდუალურად, ჯგუფში - საათნახევარი</p>\n<p>ღირებულება 3-5 კაციან ჯგუფში: 240 ლარი</p>\n<p>ღირებულება წყვილში: 360 ლარი</p>\n<p>ინდივიდუალურად: 450 ლარი</p>\n<p><br /> <strong>გაითვალისწინეთ! </strong><strong>მსურველთა</strong> <strong>ინგლისურის</strong> <strong>ცოდნა</strong> <strong>უნდა</strong> <strong>აკმაყოფილებდეს</strong> <strong>მინიმუმ</strong><strong> B1 </strong><strong>დონეს</strong><strong>.</strong></p>\n<p>&nbsp;</p>\n<p><strong>კურსის დასრულების შემდეგ</strong>: თქვენ შეძლებთ სამართლებრივი ტერმინოლოგიის შემცველ დოკუმენტებზე მუშაობას, სამართლებრივი დოკუმენტების თავად შედგენას, კლიენტებთან და ბიზნეს-პარტნიორებთან ზეპირ და წერილობით კომუნიკაციას, სხვადასხვა პირებთან მოლაპარაკების წარმოებას.</p>\n<p>&nbsp;</p>\n<p><strong>კურსის დასრულების შემდეგ გაიცემა სერტიფიკატი.</strong></p>\n<p><strong>&nbsp;</strong></p>\n<p><strong>კურსს უძღვება:</strong> თორნიკე ამილახვარი - ადვოკატი, შპს &bdquo;ღვინაძე და პარტნიორების&ldquo; უფროსი იურისტი.</p>', 'englis law', '', '', '', 'en', 5, 0, 1);
INSERT INTO `navigation` (`id`, `idx`, `cid`, `date`, `nav_type`, `type`, `title`, `description`, `text`, `slug`, `usefull_type`, `cssclass`, `redirect`, `lang`, `position`, `visibility`, `status`) VALUES
(278, 116, 40, 1578489933, 0, 'text', 'იურიდიული ინგლისური', '<p>იურიდიული ინგლისური</p>', '<p><strong>კურსის მიზანია:</strong> დაეხმაროს სტუდენტებს, პრაქტიკოს იურისტებს, ადვოკატებს, კერძო კომპანიებისა და საჯარო დაწესებულებების იურისტებს სამართლებრივი ტერმინოლოგიის დაუფლებაში, რათა მათ შეძლონ ინგლისურ ენაზე სამართლებრივი საქმიანობის, როგორც წერილობით, ისე ზეპირად წარმართვა.</p>\n<p>&nbsp;<strong>კურსი მოიცავს შემდეგ საკითხებს:</strong></p>\n<ul>\n<li>ზოგადი სამართლებრივი და დარგობრივი ტერმინოლოგიის შესწავლა (სამოქალაქო, შრომის, ბიზნეს, საკორპორაციო, სამშენებლო, საჯარო, სისხლის, საერთაშორისო სამართალი და ა. შ.);</li>\n<li>სხვადასხვა სახის სამართლებრივი დოკუმენტების შედგენა (საკორპორაციო დოკუმენტების, ხელშეკრულებების, მემორანდუმების, სამართლებრივი დასკვნების და ა. შ.);</li>\n<li>ინგლისურ ენაზე სამართლებრივი სპეციფიკის მქონე, როგორც წერილობითი, ისე ზეპირი კომუნიკაციის წარმოება;</li>\n<li>პრაქტიკული სამუშაოები, ზეპირი განხილვები და იმიტირებული პრაქტიკული სიტუაციები.</li>\n</ul>\n<p><strong>კურსის ხანგრძლივობა:</strong> &nbsp;(2 ან 3 თვე)</p>\n<p>დამოკიდებულია მსმენელის მიერ ინგლისური ენის ცოდნის დონეზე</p>\n<p><strong>კვირაში ორი დღე - თვეში 8 ლექცია</strong></p>\n<p>ლექციის ხანგრილობა:</p>\n<p>1 საათი ინდივიდუალურად, ჯგუფში - საათნახევარი</p>\n<p>ღირებულება 3-5 კაციან ჯგუფში: 160 ლარი</p>\n<p>ღირებულება წყვილში: 240 ლარი</p>\n<p>ინდივიდუალურად: 300 ლარი</p>\n<p><strong>კვირაში სამი&nbsp; დღე - თვეში 12 ლექცია</strong></p>\n<p>ლექციის ხანგრილობა:</p>\n<p>1 საათი ინდივიდუალურად, ჯგუფში - საათნახევარი</p>\n<p>ღირებულება 3-5 კაციან ჯგუფში: 240 ლარი</p>\n<p>ღირებულება წყვილში: 360 ლარი</p>\n<p>ინდივიდუალურად: 450 ლარი<br /> <strong>გაითვალისწინეთ! </strong><strong>მსურველთა</strong> <strong>ინგლისურის</strong> <strong>ცოდნა</strong> <strong>უნდა</strong> <strong>აკმაყოფილებდეს</strong> <strong>მინიმუმ</strong><strong> B1 </strong><strong>დონეს</strong><strong>.</strong></p>\n<p><strong>კურსის დასრულების შემდეგ</strong>: თქვენ შეძლებთ სამართლებრივი ტერმინოლოგიის შემცველ დოკუმენტებზე მუშაობას, სამართლებრივი დოკუმენტების თავად შედგენას, კლიენტებთან და ბიზნეს-პარტნიორებთან ზეპირ და წერილობით კომუნიკაციას, სხვადასხვა პირებთან მოლაპარაკების წარმოებას.</p>\n<p>&nbsp;</p>\n<p><strong>კურსის დასრულების შემდეგ გაიცემა სერტიფიკატი.</strong></p>\n<p><strong>&nbsp;</strong></p>\n<p><strong>კურსს უძღვება:</strong> თორნიკე ამილახვარი - ადვოკატი, შპს &bdquo;ღვინაძე და პარტნიორების&ldquo; უფროსი იურისტი.</p>', 'englis-law', '', '', '', 'ge', 5, 0, 1),
(279, 117, 40, 1578671867, 0, 'text', 'TOEFL,  IELTS გამოცდებისთვის მოსამზადებელ სასერთიფიკატო კურსები', '<p>VIP Intellect Group გთავაზობთ TOEFL (Test of English as a Foreign Language) - ამერიკული უნივერსიტეტებისათვის და IELTS (International English Language Testing System) საერთაშორისო ინგლისური ენის გამოცდებისთვის მოსამზადებელ კურსებს.</p>', '<p>TOEFL და IELTS ინგლისური ენის სასერტიფიკატო გამოცდებია, რომლების ტარდება კონკრეტული უნარ-ჩვევების შესამოწმებლად:</p>\n<ul>\n<li>საუბარი - Speaking</li>\n<li>მოსმენა - Listening</li>\n<li>წაკითხულის გააზრება- Reading</li>\n<li>წერა - Writing</li>\n</ul>\n<p><strong>პროგრამაზე სწავლის დასაწყებად აუცილებელია:</strong></p>\n<p>სასაუბრო ინგლისურის მინიმუმ B2 დონეზე ფლობა.</p>\n<p>&nbsp;</p>\n<p>პროგრამის რეკომენდირებული ხანგრძლივობა 8-16 კვირა (დამოკიდებულია მსმენელის მიერ ინგლისური ენის ცოდნის დონეზე).</p>\n<ul>\n<li>კვირაში ჩატარდება სამი შეხვედრა</li>\n<li>გაკვეთილის ხანგძლივობა 1:30</li>\n</ul>\n<p><strong>კურსის ღირებულება თვეში:</strong></p>\n<ul>\n<li>მცირერიცხოვან ჯგუფებში (3-4 კაცი) &ndash; 200 ლარი;</li>\n<li>წყვილში - 250 ლარი;</li>\n<li>ინდივიდუალურად - 350 ლარი;</li>\n</ul>\n<p>&nbsp;</p>', 'eng -TOEFL,  IELTS', '', '', '', 'en', 5, 0, 0),
(280, 117, 40, 1578671867, 0, 'text', 'TOEFL IBT/TOEFL CBT, IELTS; FCA  სასერთიფიკატო კურსები', '<p>TOEFL (Test of English as a Foreign Language) - ამერიკული უნივერსიტეტებისათვის და IELTS (International English Language Testing System) ევროპული საერთაშორისო ინგლისური ენის გამოცდებისთვის&nbsp;FCE - CAMBRIDGE First certificate of English&nbsp; სამაგისტო გამოცდებისთვის მოსამზადებელ კურსებს.</p>', '<p>საერთაშორისო ინგლისური ენის გამოცდებისთვის მოსამზადებელი კურსები!</p>\n<p>TOEFL IBT/TOEFL CBT (Test of English as a Foreign Language) - ამერიკული უნივერსიტეტებისათვის&nbsp;</p>\n<p>IELTS (International English Language Testing System) ევროპული უნივერსიტეტებისთვის</p>\n<p>FCA -&nbsp;CAMBRIDGE First certificate of English - სამაგისტრო გამოცდებისთვის</p>\n<p>TOEFL IBT/TOEFL CBT&nbsp;და IELTS და&nbsp; FCA&nbsp; ინგლისური ენის სასერტიფიკატო გამოცდებია, რომლების ტარდება კონკრეტული უნარ-ჩვევების შესამოწმებლად:</p>\n<ul>\n<li>საუბარი - Speaking</li>\n<li>მოსმენა - Listening</li>\n<li>წაკითხულის გააზრება- Reading</li>\n<li>წერა - Writing</li>\n</ul>\n<p><strong>პროგრამაზე სწავლის დასაწყებად აუცილებელია:</strong></p>\n<p>სასაუბრო ინგლისურის მინიმუმ B/-B2 დონეზე ფლობა.</p>\n<p>პროგრამის რეკომენდირებული ხანგრძლივობა 3 თვე&nbsp;(დამოკიდებულია მსმენელის მიერ ინგლისური ენის ცოდნის დონეზე).</p>\n<ul>\n<li>კვირაში ჩატარდება&nbsp;ორი შეხვედრა</li>\n<li>გაკვეთილის ხანგძლივობა არანაკლებ 1:30</li>\n</ul>\n<p><strong>კურსის ღირებულება თვეში:</strong></p>\n<ul>\n<li>მცირერიცხოვან ჯგუფებში (2-4 კაცი) &ndash; 250 ლარი;</li>\n</ul>\n<ul>\n<li>ინდივიდუალურად -&nbsp;400 ლარი;</li>\n</ul>\n<p><strong>კუსებს უძღვება:&nbsp;</strong>მრავალწლიანი გამოცდილების მქონე CELTA- სერთიფიცირებული, ლონდონის უნივერსიტეტის კურსდამთავრებული საერთაშორისო დონის ტრენერი!</p>\n<p>&nbsp;[registration]</p>', 'eng--TOEFL,--IELTS', '', '', '', 'ge', 5, 0, 0),
(282, 118, 17, 1579259465, 0, 'text', 'სტაჟირება პსპ-ში', '<p>სტაჟირება აფთიაქში</p>', '<p>ფარმაკოლოგიის კურსის დასრულების შემდეგ მსმენელები გაივლიან 1 თვიან უფასო სტაჟირებას \"PSP\" -ს სხვადასხვა აფთიაქებში, საუკეთესოებისთვის შემდგომი დასაქმების პერსპექტივით, როგორც თბილისში ასევე საქართველოს ნებისმიერ რეგიონში.<br />გაიცემა ორენოვანი სერტიფიკატი და სარეკომენდაციო წერილი.<br /><br />აფთიაქში სტაჟირების მსვლელობის პერიოდში ჩატარდება სემინარები და განიხილება აფთიაქში ხშირად შექმნილი სხვადასხვა სიტუაცია.</p>', 'stajireba-sps', '', '', '', 'ge', 4, 0, 0),
(285, 120, 8, 1586173380, 0, 'text', 'მონაცემთა ანალიზი პითონის გამოყენებით', '<p>მონაცემთა ანალიზი პითონის გამოყენებით</p>', '<p>კურსი განკუთვნილია მსმენელთათვის ვისაც აქვს გავლილი <br /><strong>1. სტატისტიკის საბაზისო კურსი ან/და</strong><br /><strong>2. გააჩნია მონაცემთა ანალიზის უნარჩვევები EXCEL-ის, SPSS-ის ან STATA-ს გამოყენებით</strong><br />და სურს გაიღრმავოს ცოდნა მონაცემთა ანალიზის, მანქანური სწავლებისა და ხელოვნური ინტელექტის მიმართულებით პითონის პროგრამირების ენის გამოყენებით.<br />კურსის გავლის შემდეგ, მსმენელი შეძლებს მონაცემების ანალიზსა და ვიზუალიზაციას, რეგრესიულ და კლასიფიკაციის მოდელებთან მუშაობას, ბუნებრივი ენისა და ფოტო მასალის ავტომატურ დამუშავებას. ასევე ნეირონულ ქსელებთან მუშაობას.</p>\n<p>კურსი წარიმართება 5 მოდულად. თითოეული მოდულის ხანგრძლივობაა 4 გაკვეთილი. გაკვეთილის ხანგრძლივობაა საათნახევარი.<br />მოდულები:<br />1. პითონზე პროგრამირება - numpy და pandas ბიბლიოთეკებთან მუშაობა.<br />2. მონაცემთა ვიზუალიზაცია - matplotlib და bokeh ბიბლიოთეკებთან მუშაობა.<br />3. რეგრესიულ და კლასიფიკაციის მოდელებთან მუშაობა - sklearn და xgboost ბიბლიოთეკებთან მუშაობა.<br />4. ბუნებრივი ენის დამუშავება - spaCy და NLTK ბიბლიოთეკებთან მუშაობა.<br />5. ნეირონულ ქსელებთან მუშაობა, სურათზე ობიექტის ამოცნობა - TensorFlow, PyTorch ბიბლიოთეკებთან მუშაობა.</p>\n<p><strong>კურსი არის ინდივიდუალური.</strong><br /><strong>კურსის ხანგრძლივობა 20 დღე.</strong><br /><strong>კურსის ღირებულება 800 ლარი.</strong></p>\n<p><br /><em><strong>შესაძლებელია კურსის გარკვეული მოდულების არჩევა.</strong></em></p>', 'python', '', '', '', 'en', 8, 0, 1),
(286, 120, 8, 1586173380, 0, 'text', 'მონაცემთა ანალიზი პითონის გამოყენებით', '<p>მონაცემთა ანალიზი პითონის გამოყენებით</p>', '<p>კურსი განკუთვნილია მსმენელთათვის ვისაც აქვს გავლილი <br /><strong>1. სტატისტიკის საბაზისო კურსი ან/და</strong><br /><strong>2. გააჩნია მონაცემთა ანალიზის უნარჩვევები EXCEL-ის, SPSS-ის ან STATA-ს გამოყენებით</strong><br />და სურს გაიღრმავოს ცოდნა მონაცემთა ანალიზის, მანქანური სწავლებისა და ხელოვნური ინტელექტის მიმართულებით პითონის პროგრამირების ენის გამოყენებით.<br />კურსის გავლის შემდეგ, მსმენელი შეძლებს მონაცემების ანალიზსა და ვიზუალიზაციას, რეგრესიულ და კლასიფიკაციის მოდელებთან მუშაობას, ბუნებრივი ენისა და ფოტო მასალის ავტომატურ დამუშავებას. ასევე ნეირონულ ქსელებთან მუშაობას.</p>\n<p><strong>კურსი წარიმართება 5 მოდულად.</strong></p>\n<p><strong>თითოეული მოდულის ხანგრძლივობაა 4 გაკვეთილი.</strong></p>\n<p><strong>გაკვეთილის ხანგრძლივობაა საათნახევარი.</strong></p>\n<p><strong>მოდულები:</strong><br />1. პითონზე პროგრამირება - numpy და pandas ბიბლიოთეკებთან მუშაობა.<br />2. მონაცემთა ვიზუალიზაცია - matplotlib და bokeh ბიბლიოთეკებთან მუშაობა.<br />3. რეგრესიულ და კლასიფიკაციის მოდელებთან მუშაობა - sklearn და xgboost ბიბლიოთეკებთან მუშაობა.<br />4. ბუნებრივი ენის დამუშავება - spaCy და NLTK ბიბლიოთეკებთან მუშაობა.<br />5. ნეირონულ ქსელებთან მუშაობა, სურათზე ობიექტის ამოცნობა - TensorFlow, PyTorch ბიბლიოთეკებთან მუშაობა.</p>\n<p><strong>კურსი არის ინდივიდუალური</strong><br /><strong>კურსის ხანგრძლივობა 20 დღე</strong><br /><strong>კურსის ღირებულება 1000 ლარი ინდივიდუალურად</strong></p>\n<p><strong>კურსის ღირებულება 600 ლარი ჯგუფში</strong><br /><em><strong>შესაძლებელია კურსის გარკვეული მოდულების არჩევა.</strong></em></p>\n<p><em><strong>[registration]</strong></em></p>', 'python', '', '', '', 'ge', 8, 0, 1),
(287, 121, 72, 1590422073, 0, 'text', 'სახელმწიფო შესყიდვების კურსი', '<p><strong>სახელმწიფო შესყიდვების კურსი</strong></p>', '<p><strong>კურსის</strong> <strong>მიზნები</strong><strong>, </strong><strong>ამოცანები</strong><strong>, </strong><strong>შედეგები</strong></p>\n<ul>\n<li>მსმენელები მოისმენენ და პრაქტიკული სავარჯიშოებით გაიღრმავებენ ცოდნას, სახელმწიფო შესყიდვების განხორციელების პროცედურებთან დაკავშირებით - შესყიდვების დაგეგმვიდან განხორციელებული შესყიდვების ანალიზის (თვითშეფასების) ჩათვლით. ტრენინგ-კურსში წარმოდგენილი იქნება შემსყიდველი ორგანიზაციის მიერ შესყიდვების განხორციელების პროცესების მართვის თანამედროვე პრინციპები და მსოფლიო გამოცდილება აღნიშნული მიმართულებით;</li>\n<li>ტრენინგ-კურსში წარმოდგენილი და განხილული იქნება საერთაშორისო სივრცეში აღიარებული უახლესი მიდგომები და პრაქტიკული რჩევები შემსყიდველთათვის; ასევე თანამედროვე გამოცდილება, რომელიც დაეხმარება სახელმწიფო და ადგილობრივი თვითმმართველობის ორგანოებში დასაქმებულ მოსამსახურეებს სახელმწიფო შესყიდვების კანონშესაბამის განხორციელებაში, რაც გულისხმობს, სახელმწიფო ბიუჯეტის გამჭვირვალედ ხარჯვას, კონკურენტუნარიანი გარემოს შექმნას სახელმწიფო შესყიდვების პროცედურებში მონაწილე ნებისმიერი პირისთვის.</li>\n<li>ტრენინგ-კურსი ითვალისწინებს ორგანიზაციაში შესყიდვებთან დაკავშირებული პრობლემების იდენტიფიცირებას, პრობლემების გამომწვევი კონკრეტული მიზეზების გამოვლენას, პრობლემის გადაჭრის გენერირებას, პრინციპების შერჩევას, კონკრეტული ქმედებების დაგეგმვას და ა.შ.</li>\n</ul>\n<p><strong>სწავლების</strong> <strong>მეთოდები</strong><strong>:</strong></p>\n<p>სწავლების პროცესში განსაკუთრებული ყურადღება მიექცევა თეორიული ცოდნის გადაცემას, მონაწილეთა ჩართულობას, გამოცდილების ურთიერთგაზიარებას, დისკუსია-სემინარის, პრობლემური სიტუაციის ანალიზისა (&ldquo;Case-study&rdquo;) და საქმიანი თამაშის (&ldquo;Brain-Storm&rdquo;) მეთოდების გამოყენებას, როგორც პრობლემების ეფექტურად და ოპერატიულად გადაჭრის უნარ-ჩვევების გამომუშავების პირობას. შედგება ინდივიდუალური, პარტნიორული და ჯგუფური მუშაობა. კურსის სასწავლო პროგრამით გათვალისწინებული პრაქტიკული მეცადინეობების დანიშნულებაა შესყიდვების რთულ და საპასუხისმგებლო პროცესებზე ზემოქმედი ფაქტორების ანალიზისა და ობიექტური შეფასების, გადაწყვეტილებების მომზადება- მიღების, პრაქტიკული უნარ-ჩვევების გამომუშავება.</p>\n<p><strong>სწავლების</strong> <strong>პროცესში</strong> <strong>მსმენელთა</strong> <strong>ცოდნის</strong> <strong>სისტემატიზება</strong> <strong>მოხდება</strong> <strong>ისეთ</strong> <strong>საკვანძო</strong> <strong>საკითხებზე</strong><strong>, </strong><strong>როგორიცაა</strong><strong>:</strong></p>\n<ul>\n<li>სახელმწიფო შესყიდვების ზოგადი მიმოხილვა: სახელმწიფო შესყიდვების არსი და მოქმედების სფერო;</li>\n<li>რელევანტური ნორმატიული აქტები. ადმინისტრაციულ სამართალდარღვევათა განხილვა; სახელმწიფო შესყიდვების მარეგულირებელი კანონმდებლობა, სხვა აქტები და მათი ურთიერთკავშირი სახელმწიფო შესყიდვებთან;</li>\n<li>დღგ-ს ფაქტორი სახელმწიფო შესყიდვების პროცესში;</li>\n<li>შესყიდვის საშუალებების ზოგადი მიმოხილვა;</li>\n<li>სახელმწიფო შესყიდვის სრული პროცესი;</li>\n<li>სახელწიფო შესყიდვების დაგეგმვა და ერთგვაროვნების დადგენის წესი;</li>\n<li>ერთგვაროვნების დადგენა (Common Procurement Vocabulary &ndash; CPV კოდები);</li>\n<li>სახელმწიფო შესყიდვების ელექტრონული სისტემა და სააგენტოს ოფიციალური ვებ-გვერდი;</li>\n<li>შესყიდვის დაგეგმვა, ბაზრის კვლევა/სავარაუდო ღირებულების განსაზღვრა, გეგმის რეგისტრაცია - ePLAN მოდულში, მონეტარული ზღვრები, სახელმწიფო შესყიდვების გეგმის შესაბამისობის დადგენა ბიუჯეტთან,შესყიდვების გეგმის კორექტირება;</li>\n<li>გამარტივებული შესყიდვა და ხელშეკრულება სახელმწიფო შესყიდვის შესახებ;</li>\n<li>შესყიდვები ხელშეკრულებით - ხელშეკრულების პირობები, ცვლილება ხელშეკრულებაში, ინტერესთა კონფლიქტი, ხელშეკრულების შესრულების უზრუნველყოფის გარანტია და საავანსო ანგარიშსწორება, საჯარიმო სანქციები;</li>\n<li>შესყიდვები ხელშეკრულების დადების გარეშე - ხელშეკრულების ჩანაცვლება შესყიდვის დამადასტურებელი დოკუმენტით (ინტერნეტ-გამოწერა, წარმომადგენლობითი და სხვა შემთხვევები);  ანგარიშგება - CMR მოდულის გამოყენება და ანგარიში ხელშეკრულების მიმდინარეობის თაობაზე.</li>\n<li>სატენდერო კომისიისა და სატენდერო კომისიის აპარატის შექმნა, მისი ფუნქციები, მოვალეობები;</li>\n<li>შესყიდვის ობიექტის სპეციფიკის გათვალისწინებით მოთხოვნების განსაზღვრა;</li>\n<li>სატენდერო დოკუმენტაციის, სატენდერო განცხადების შედგენა და საკვალიფიკაციო მოთხოვნები, ცვლილებები, ტენდერის გამოცხადება;</li>\n<li>ტენდერის განსაკუთრებული შემთხვევა, ერთობლივი, ორ ეტაპიანი ტენდერები და ალტერნატიული ტენდერი;</li>\n<li>სატენდერო წინადადების წარდგენა, ვადები, ელექტრონული ვაჭრობა;</li>\n<li>ოქმების/შეტყობინებების შედგენა/სტატუსების მინიჭება, ხელშეკრულების გაფორმება, ხელშეკრულების მიმდინარეობის თაობაზე ანგარიშის წარდგენა;</li>\n<li>შავი და თეთრი სია;</li>\n<li>კონსოლიდირებული ტენდერი;</li>\n<li>კონკურსის მომზადება - საკონკურსო განცხადებისა და დოკუმენტაციის მომზადება, გამოცხადება, შედეგების განხილვა და ხელშეკრულების გაფორმება;</li>\n<li>დავების საბჭო, მისი ფუნქციები, მოვალეობები, განხილვის პროცედურები და გადაწყვეტილებები;</li>\n<li>გამარტივებული შესყიდვის განხორციელების შეთანხმება სააგენტოსთან;</li>\n</ul>\n<p><strong>✔</strong><strong>️</strong><strong>კურსის</strong> <strong>ხანგრძლივობა</strong> <strong>ინდივიდუალურად</strong><strong>: 3 </strong><strong>ლექცია</strong><strong> - 2</strong><strong>სთ</strong><strong>-</strong><strong>იანი</strong><strong><br /> </strong><strong>✔</strong><strong>️</strong><strong>ღირებულება</strong><strong>: 500 </strong><strong>ლარი</strong><strong><br /> </strong><strong>✔</strong><strong>️</strong><strong>კურსის</strong> <strong>ხანგრძლივობა</strong> <strong>წყვილში</strong><strong>: 3 </strong><strong>ლექცია</strong><strong> - 2</strong><strong>სთ</strong><strong>-</strong><strong>იანი</strong><strong><br /> </strong><strong>✔</strong><strong>️</strong><strong>ღირებულება</strong><strong>: 350 </strong><strong>ლარი</strong><strong><br /> </strong><strong>✔</strong><strong>️</strong><strong>კურსის</strong> <strong>ხანგრძლივობა</strong> <strong>ჯგუფში</strong><strong>: 4 </strong><strong>ლექცია</strong><strong> - 2</strong><strong>სთ</strong><strong>-</strong><strong>იანი</strong><strong><br /> </strong><strong>✔</strong><strong>️</strong><strong>ღირებულება</strong><strong>: 250 </strong><strong>ლარი</strong></p>', 'tender', '', '', '', 'en', 6, 0, 1),
(288, 121, 72, 1590422073, 0, 'text', 'სახელმწიფო შესყიდვების კურსი', '<p><strong>სახელმწიფო შესყიდვების კურსი</strong></p>', '<p><strong>კურსის მიზნები, ამოცანები, შედეგები</strong></p>\n<p>მსმენელები მოისმენენ და პრაქტიკული სავარჯიშოებით გაიღრმავებენ ცოდნას, სახელმწიფო შესყიდვების განხორციელების პროცედურებთან დაკავშირებით - შესყიდვების დაგეგმვიდან განხორციელებული შესყიდვების ანალიზის (თვითშეფასების) ჩათვლით. ტრენინგ-კურსში წარმოდგენილი იქნება შემსყიდველი ორგანიზაციის მიერ შესყიდვების განხორციელების პროცესების მართვის თანამედროვე პრინციპები და მსოფლიო გამოცდილება აღნიშნული მიმართულებით;<br />ტრენინგ-კურსში წარმოდგენილი და განხილული იქნება საერთაშორისო სივრცეში აღიარებული უახლესი მიდგომები და პრაქტიკული რჩევები შემსყიდველთათვის; ასევე თანამედროვე გამოცდილება, რომელიც დაეხმარება სახელმწიფო და ადგილობრივი თვითმმართველობის ორგანოებში დასაქმებულ მოსამსახურეებს სახელმწიფო შესყიდვების კანონშესაბამის განხორციელებაში, რაც გულისხმობს, სახელმწიფო ბიუჯეტის გამჭვირვალედ ხარჯვას, კონკურენტუნარიანი გარემოს შექმნას სახელმწიფო შესყიდვების პროცედურებში მონაწილე ნებისმიერი პირისთვის.<br />ტრენინგ-კურსი ითვალისწინებს ორგანიზაციაში შესყიდვებთან დაკავშირებული პრობლემების იდენტიფიცირებას, პრობლემების გამომწვევი კონკრეტული მიზეზების გამოვლენას, პრობლემის გადაჭრის გენერირებას, პრინციპების შერჩევას, კონკრეტული ქმედებების დაგეგმვას და ა.შ.</p>\n<p><strong>სწავლების მეთოდები:</strong>სწავლების პროცესში განსაკუთრებული ყურადღება მიექცევა თეორიული ცოდნის გადაცემას, მონაწილეთა ჩართულობას, გამოცდილების ურთიერთგაზიარებას, დისკუსია-სემინარის, პრობლემური სიტუაციის ანალიზისა (&ldquo;Case-study&rdquo;) და საქმიანი თამაშის (&ldquo;Brain-Storm&rdquo;) მეთოდების გამოყენებას, როგორც პრობლემების ეფექტურად და ოპერატიულად გადაჭრის უნარ-ჩვევების გამომუშავების პირობას. შედგება ინდივიდუალური, პარტნიორული და ჯგუფური მუშაობა. კურსის სასწავლო პროგრამით გათვალისწინებული პრაქტიკული მეცადინეობების დანიშნულებაა შესყიდვების რთულ და საპასუხისმგებლო პროცესებზე ზემოქმედი ფაქტორების ანალიზისა და ობიექტური შეფასების, გადაწყვეტილებების მომზადება- მიღების, პრაქტიკული უნარ-ჩვევების გამომუშავება.</p>\n<p><strong>სწავლების პროცესში მსმენელთა ცოდნის სისტემატიზება მოხდება ისეთ საკვანძო საკითხებზე, როგორიცაა:</strong></p>\n<p><strong>სახელმწიფო შესყიდვების ზოგადი მიმოხილვა:</strong> სახელმწიფო შესყიდვების არსი და მოქმედების სფერო;<br />რელევანტური ნორმატიული აქტები. ადმინისტრაციულ სამართალდარღვევათა განხილვა; სახელმწიფო შესყიდვების მარეგულირებელი კანონმდებლობა, სხვა აქტები და მათი ურთიერთკავშირი სახელმწიფო შესყიდვებთან;<br />დღგ-ს ფაქტორი სახელმწიფო შესყიდვების პროცესში;<br />შესყიდვის საშუალებების ზოგადი მიმოხილვა;<br />სახელმწიფო შესყიდვის სრული პროცესი;<br />სახელწიფო შესყიდვების დაგეგმვა და ერთგვაროვნების დადგენის წესი;<br />ერთგვაროვნების დადგენა (Common Procurement Vocabulary &ndash; CPV კოდები);<br />სახელმწიფო შესყიდვების ელექტრონული სისტემა და სააგენტოს ოფიციალური ვებ-გვერდი;<br />შესყიდვის დაგეგმვა, ბაზრის კვლევა/სავარაუდო ღირებულების განსაზღვრა, გეგმის რეგისტრაცია - ePLAN მოდულში, მონეტარული ზღვრები, სახელმწიფო შესყიდვების გეგმის შესაბამისობის დადგენა ბიუჯეტთან,შესყიდვების გეგმის კორექტირება;<br />გამარტივებული შესყიდვა და ხელშეკრულება სახელმწიფო შესყიდვის შესახებ;<br />შესყიდვები ხელშეკრულებით - ხელშეკრულების პირობები, ცვლილება ხელშეკრულებაში, ინტერესთა კონფლიქტი, ხელშეკრულების შესრულების უზრუნველყოფის გარანტია და საავანსო ანგარიშსწორება, საჯარიმო სანქციები;<br />შესყიდვები ხელშეკრულების დადების გარეშე - ხელშეკრულების ჩანაცვლება შესყიდვის დამადასტურებელი დოკუმენტით (ინტერნეტ-გამოწერა, წარმომადგენლობითი და სხვა შემთხვევები);  ანგარიშგება - CMR მოდულის გამოყენება და ანგარიში ხელშეკრულების მიმდინარეობის თაობაზე.<br />სატენდერო კომისიისა და სატენდერო კომისიის აპარატის შექმნა, მისი ფუნქციები, მოვალეობები;<br />შესყიდვის ობიექტის სპეციფიკის გათვალისწინებით მოთხოვნების განსაზღვრა;<br />სატენდერო დოკუმენტაციის, სატენდერო განცხადების შედგენა და საკვალიფიკაციო მოთხოვნები, ცვლილებები, ტენდერის გამოცხადება;<br />ტენდერის განსაკუთრებული შემთხვევა, ერთობლივი, ორ ეტაპიანი ტენდერები და ალტერნატიული ტენდერი;<br />სატენდერო წინადადების წარდგენა, ვადები, ელექტრონული ვაჭრობა;<br />ოქმების/შეტყობინებების შედგენა/სტატუსების მინიჭება, ხელშეკრულების გაფორმება, ხელშეკრულების მიმდინარეობის თაობაზე ანგარიშის წარდგენა;<br />შავი და თეთრი სია;<br />კონსოლიდირებული ტენდერი;<br />კონკურსის მომზადება - საკონკურსო განცხადებისა და დოკუმენტაციის მომზადება, გამოცხადება, შედეგების განხილვა და ხელშეკრულების გაფორმება;<br />დავების საბჭო, მისი ფუნქციები, მოვალეობები, განხილვის პროცედურები და გადაწყვეტილებები;<br />გამარტივებული შესყიდვის განხორციელების შეთანხმება სააგენტოსთან;<br /><strong>✔️კურსის ხანგრძლივობა ინდივიდუალურად: 3 ლექცია - 2სთ-იანი</strong><br /><strong>✔️ღირებულება: 500 ლარი</strong><br /><strong>✔️კურსის ხანგრძლივობა წყვილში: 3 ლექცია - 2სთ-იანი</strong><br /><strong>✔️ღირებულება: 350 ლარი</strong><br /><strong>✔️კურსის ხანგრძლივობა ჯგუფში: 4 ლექცია - 2სთ-იანი</strong><br /><strong>✔️ღირებულება: 250 ლარი</strong></p>', 'tender', '', '', '', 'ge', 6, 0, 1),
(289, 122, 2, 1608643138, 0, 'text', 'გთავაზობთ საშობაო ფასდაკლებას 10-იდან 30%-მდე ჩვენთან არსებულ ყველა კურსზე!', '<p>ეპიდემიის გავცელების მიზნით ყველა კურსი ტარდება დისტანციურად!</p>', '<p>', 'https://vipintellect.ge/ge/news', '', '', '', 'en', 1, 0, 1),
(290, 122, 2, 1608643138, 0, 'text', 'გთავაზობთ საშობაო ფასდაკლებას 10-იდან 30%-მდე ჩვენთან არსებულ ყველა კურსზე!', '<p>ეპიდემიის გავცელების მიზნით ყველა კურსი ტარდება დისტანციურად!</p>', '<p>', 'https://vipintellect.ge/ge/news', '', '', '', 'ge', 1, 0, 1),
(317, 136, 50, 1662375769, 0, 'text', 'სამედიცინო წარმომადგენლის მოსამზადებელი კურსი', '<p>სამედიცინო წარმომადგენელი</p>', '<p><strong>ტრენინგი განკუთვნილია:</strong> უმაღლესი სამედიცინო განათლების მქონე პირებისთვის<br /> <br /><strong>კურსის მიზანია:</strong> სამედიცინო წარმომადგენლების გადამზადება</p>\n<p><strong>კურსი მოიცავს:</strong><br />1 კომუნიკაციის საფუძვლები და ფსიქოლოგია, მოსმენა კომუნიკაციის ბარიერი <br />2 პიროვნების ფსიქოტიპები და თვისებები <br />3 კომუნიკაცია სხვა და სხვა ფსიქოტიპებთან <br />4 კომპეტენციის დონეები, პოტენციალი, ვიზიტის ეტაპები <br />5 ლოგიკური და მოტივირებული მოთხოვნები, პრეზენტაცია, შეთანხმება <br />6 სიტუაციური ამოცანები, ტესტირება</p>\n<p><strong>კურსი მოიცავს: 6 ლექციას</strong><br /><strong>კურსის ღირებულება: 250 ლარი</strong></p>', 'health', '', '', '', 'en', 5, 0, 1),
(291, 123, 8, 1612446447, 0, 'text', 'VBA-Visual Basic For Application', '<p>პროგრამირების ენა Microsoft-ის პროდუქტებისთვის რომელიც საშუალებას გაძლევთ წეროთ ავტომატიზირებული პროცედურები, შექმნათ ფუნქციები და პროგრამები. VBA-ის შესწავლა ექსელში საკმარისია იმისთვის, რომ შეძლოთ მისი გამოყენება სხვა საოფისე აპლიკაციებისთვის.</p>', '<p>პროგრამირების ენა Microsoft-ის პროდუქტებისთვის რომელიც საშუალებას გაძლევთ წეროთ ავტომატიზირებული პროცედურები, შექმნათ ფუნქციები და პროგრამები. VBA-ის შესწავლა ექსელში საკმარისია იმისთვის, რომ შეძლოთ მისი გამოყენება სხვა საოფისე აპლიკაციებისთვის.</p>\n<p><strong>აღნიშნული კურსი განკუთვნილია მათთვის:</strong></p>\n<p>ვინც ფლობს ექსელს მაღალ დონეზე და საერთოდ არ გააჩნია პროგრამირების ცოდნა ან აქვს ექსელში მაკროსებთან მუშაობის გარკვეული გამოცდილება.<br />კურსი აგებულია Microsoft ის ოფიციალური ტრეინინგ პროგრამის საფუძველზე და საშუალებას მოგცემთ შეისწავლოთ VBA-ის პროგრამირების ენა ნულიდან.</p>\n<p><strong>პროგრამის დაუფლების შემდეგ:</strong></p>\n<p>** გექნებათ კოდის ჩაწერის და რედაქტირების საფუძვლიანი ცოდნა;<br />** ფორმებით თქვენ შეძლებთ საკუთარი პროგრამების, ფუნქციების და ფორმების შექმნას; რეპორტინგის ავტომატიზაციას;<br />** საოფისე პროგრამებთან ერთად მუშაობას;<br />** ასევე სხვა ექსელის მრავალფეროვანი შესაძლებლობების გამოყენებას.</p>\n<p>კურსის განმავლობაში თქვენ გადმოგეცემათ მზა კოდების ნიმუშები, ასევე დავალებების სახით თავად შექმნით ტრენერის დახმარებით თქვენთვის სასურველ პროდუქტებს.</p>\n<p>პროგრამის ხანგრძლივობა შეადგენს: 12 საათნახევრიან ლექციას.</p>\n<p>ღირებულება:</p>\n<p><strong>ჯგუფში 4 კაცი და მეტი: 350 ლარი - ერთი მსმენელისთვის</strong><br /><strong>ორ-სამ კაციან ჯგუფში: 450 ლარი - ერთი მსმენელისთვის</strong><br /><strong>ინდივიდუალურად: 560 ლარი</strong></p>', 'https://vipintellect.ge/ge/advanced-excel', '', '', '', 'en', 13, 0, 1),
(325, 140, 7, 1682000552, 0, 'text', 'მეღვინეობა', '<p>მეღვინეობის საბაზო კურსი</p>', '<pre id=\"tw-target-text\" class=\"tw-data-text tw-text-large tw-ta\" dir=\"ltr\" data-placeholder=\"თარგმანი\"><span class=\"Y2IQFc\" lang=\"en\">პროგრამა განკუთვნილია: იმ პირებისთვის, ვისაც სურს იმუშაოს ღვინის წარმოებაში ტექნოლოგიურ ხაზებში და ჩაატაროს დეგუსტაცია ან განავითაროს საკუთარი ღვინის<br />წარმოება.ამ პოზიციებზე სამუშაოდ საჭიროა გაიარონ თეორიული და პრაქტიკული ცოდნა.<br /><strong>კურსი მოიცავს:</strong><br />მეღვინეობაში არსებული ტერმინოლოგიას, ღვინის წარმოების სრული ტექნოლოგიებს, დეგუსტაციის პრინციპებს, ღვინოებს შორის განსხვავებას, მათი ხარისხის განსაზღვრას<br /><strong>თემატიკა:</strong><br />&bull; კანონი ვაზის და ღვინის შესახებ<br />&bull; ქართული ღვინის ისტორია და კულტურა<br />&bull; დანადგარების, ხელსაწყოების აგებულება და მათი ფუნქციები<br />&bull; ყურძნის მიღება- დამუშავება<br />&bull; ყურძნის ტკბილის შემადგენელი ნივთიერებები, და მათი განსაზღვრა<br />&bull; ალკოჰოლური დუღილი და მოქმედი ფაქტორები;<br />&bull; თეთრი ღვინის წარმოება<br />&bull; ვარდისფერი ღვინის წარმოება<br />&bull; წითელი ღვინის წარმოება<br />&bull; ცქრიალა ღვინოების წარმოება<br />&bull; ბიო-ორგანული ღვინოების წარმოება<br />&bull; ღვინოების შედარება ადგილმდებარეობის მიხედვით<br />&bull; ფიზიკურ-ქიმიური პარამეტრების განსაზღვრა<br />&bull; ღვინოში დამხმარე მასალების შეტანა<br />&bull; პირველადი და მეორეული დუღილის მნიშვნელობა<br />&bull; ღვინის სეგმენტაცია<br />&bull; ღვინის სტაბილიზაცია<br />&bull; ღვინის ჩამოსხმა<br />&bull; ღვინის დაავადებები<br />&bull; ღვინის მოვლა<br />&bull; ღვინის დეგუსტაცია<br /><strong>კურსდამთავრებულის უპირატესობა:</strong> <br />შეისწავლის მეღვინეობაში არსებულ ძირითად მიმართულებებს, რომელიც პრაქტიკაში გამოიყენება, ასევე შეძლებენ ტექნოლოგიების გამოყენებით შექმნან საკუთარი წარმოების ღვინო და შეაფასონ ღვინის ხარისხი. ღვინის მარნებში და ღვინის საწარმოებში დანერგონ სწორი მიმართულება.<br /><strong>სრული პროგრმის ხანგრძლივობა : 12 ლექცია</strong><br /><strong>კვირაში ჩატარდება 2 ლექცია</strong><br /><strong>ლექციის ხანგრძლივობა 2სთ</strong><br /><strong>კურსის ღირებულება ჯგუფში 3 კაციდან: 480 ლარი</strong><br /><strong>კურსის ღირებულება წყვილში: 580 ლარი</strong><br /><strong>კურსის ღირებულება ინდივიდუალურად: 800 ლარი</strong><br /><strong>პრაქტიკული:</strong> საწარმოში წარმობის დათვალიერება ადგილობრივი მეღვინის თანხლებით, დეგუსტაცია.<br />კურსის ბოლოს ჩატარდება დასკვნითი ტესტირება და გაიცემა სერთიფიკატი<br /><strong>კურსს უძღვება:</strong> ანჟელა ღაჭავა - 4 წლიანი გამოცდილების მქონე მევენახე-მეღვინეობის მაგისტრი, პრაქტიკოსი მეღვინე, ტრენერი.<br /></span></pre>', 'winemaking', '', '', '', 'en', 7, 0, 0),
(292, 123, 8, 1612446447, 0, 'text', 'VBA', '<p>პროგრამირების ენა Microsoft-ის პროდუქტებისთვის რომელიც საშუალებას გაძლევთ წეროთ ავტომატიზირებული პროცედურები, შექმნათ ფუნქციები და პროგრამები. VBA-ის შესწავლა ექსელში საკმარისია იმისთვის, რომ შეძლოთ მისი გამოყენება სხვა საოფისე აპლიკაციებისთვის.</p>', '<p>პროგრამირების ენა Microsoft-ის პროდუქტებისთვის რომელიც საშუალებას გაძლევთ წეროთ ავტომატიზირებული პროცედურები, შექმნათ ფუნქციები და პროგრამები. VBA-ის შესწავლა ექსელში საკმარისია იმისთვის, რომ შეძლოთ მისი გამოყენება სხვა საოფისე აპლიკაციებისთვის.</p>\n<p><strong>აღნიშნული კურსი განკუთვნილია მათთვის:</strong></p>\n<p>ვინც ფლობს ექსელს მაღალ დონეზე და საერთოდ არ გააჩნია პროგრამირების ცოდნა ან აქვს ექსელში მაკროსებთან მუშაობის გარკვეული გამოცდილება.<br />კურსი აგებულია Microsoft ის ოფიციალური ტრეინინგ პროგრამის საფუძველზე და საშუალებას მოგცემთ შეისწავლოთ VBA-ის პროგრამირების ენა ნულიდან.</p>\n<p><strong>პროგრამის დაუფლების შემდეგ:</strong></p>\n<p>** გექნებათ კოდის ჩაწერის და რედაქტირების საფუძვლიანი ცოდნა;<br />** ფორმებით თქვენ შეძლებთ საკუთარი პროგრამების, ფუნქციების და ფორმების შექმნას; რეპორტინგის ავტომატიზაციას;<br />** საოფისე პროგრამებთან ერთად მუშაობას;<br />** ასევე სხვა ექსელის მრავალფეროვანი შესაძლებლობების გამოყენებას.</p>\n<p>კურსის განმავლობაში თქვენ გადმოგეცემათ მზა კოდების ნიმუშები, ასევე დავალებების სახით თავად შექმნით ტრენერის დახმარებით თქვენთვის სასურველ პროდუქტებს.</p>\n<p>პროგრამის ხანგრძლივობა შეადგენს: 12 საათნახევრიან ლექციას.</p>\n<p>ღირებულება:</p>\n<p><strong>ჯგუფში 4 კაცი და მეტი: 350 ლარი - ერთი მსმენელისთვის</strong><br /><strong>ორ-სამ კაციან ჯგუფში: 450 ლარი - ერთი მსმენელისთვის</strong><br /><strong>ინდივიდუალურად: 560 ლარი</strong></p>', 'https://vipintellect.ge/ge/advanced-excel', '', '', '', 'ge', 13, 0, 1),
(293, 124, 8, 1612446744, 0, 'text', 'VBA-Visual Basic For Application', '<p>პროგრამირების ენა Microsoft-ის პროდუქტებისთვის რომელიც საშუალებას გაძლევთ წეროთ ავტომატიზირებული პროცედურები, შექმნათ ფუნქციები და პროგრამები. VBA-ის შესწავლა ექსელში საკმარისია იმისთვის, რომ შეძლოთ მისი გამოყენება სხვა საოფისე აპლიკაციებისთვის.</p>', '<p><strong>აღნიშნული კურსი განკუთვნილია მათთვის:</strong></p>\n<p>ვინც ფლობს ექსელს მაღალ დონეზე და საერთოდ არ გააჩნია პროგრამირების ცოდნა ან აქვს ექსელში მაკროსებთან მუშაობის გარკვეული გამოცდილება.<br />კურსი აგებულია Microsoft ის ოფიციალური ტრეინინგ პროგრამის საფუძველზე და საშუალებას მოგცემთ შეისწავლოთ VBA-ის პროგრამირების ენა ნულიდან.</p>\n<p><strong>პროგრამის დაუფლების შემდეგ:</strong></p>\n<p>** გექნებათ კოდის ჩაწერის და რედაქტირების საფუძვლიანი ცოდნა;<br />** ფორმებით თქვენ შეძლებთ საკუთარი პროგრამების, ფუნქციების და ფორმების შექმნას; რეპორტინგის ავტომატიზაციას;<br />** საოფისე პროგრამებთან ერთად მუშაობას;<br />** ასევე სხვა ექსელის მრავალფეროვანი შესაძლებლობების გამოყენებას.</p>\n<p>კურსის განმავლობაში თქვენ გადმოგეცემათ მზა კოდების ნიმუშები, ასევე დავალებების სახით თავად შექმნით ტრენერის დახმარებით თქვენთვის სასურველ პროდუქტებს.</p>\n<p>პროგრამის ხანგრძლივობა შეადგენს: 12 საათნახევრიან ლექციას.</p>\n<p>ღირებულება:</p>\n<p><strong>ჯგუფში 4 კაცი და მეტი: 350 ლარი - ერთი მსმენელისთვის</strong><br /><strong>ორ-სამ კაციან ჯგუფში: 450 ლარი - ერთი მსმენელისთვის</strong><br /><strong>ინდივიდუალურად: 560 ლარი</strong></p>', 'VBA-Visual Basic For Application', '', '', '', 'en', 5, 0, 0),
(294, 124, 8, 1612446744, 0, 'text', 'Python პროგრამირების ენის საბაზისო კურსი', '<p>კურსის მიზანია მსმენელს საფუძვლიანად შეასწავლოს Python-ის პროგრამირების ენის საფუძვლები.</p>', '<p><strong>კურსის მიზანია: მსმენელს&nbsp;შეასწავლოს Python-ის პროგრამირების ენის&nbsp;საფუძვლები</strong>.</p>\n<p><strong>კურსი მოიცავს:</strong> როგორც თეორიულ ცოდნას, ასევე ინტენსიურ პრაქტიკულ სავარჯიშოებს.</p>\n<p><strong>კურსი განიხილავს:</strong> Python-ის ყველა მთავარ კონცეპტს, დაწყებული ცვლადებიდან და მონაცემთა ტიპებიდან, დამთავრებული ობიექტზე ორიენტირებული პროგრამირებით და გარე ბიბლიოთეკების გამოყენებით მარტივი აპლიკაციების შექმნით.</p>\n<p><strong>კვირა 1</strong><br /><strong>თემა: Python &ndash; ზოგადი მიმოხილვა და საბაზისო სინტაქსი</strong></p>\n<p>Python-ის გამოყენების სფეროები<br />Python-ის ინსტალაცია (Windows / macOS)<br />IDE-ის ინსტალაცია/გამოყენება (PyCharm)<br />პირველი პროგრამის დაწერა (Hello, World)<br />Python-ის სინტაქსის თავისებურებები<br />ცვლადები (variables) და მონაცემთა ტიპები (int, float, str, bool)<br />ფუნქციები print, input, len<br />მონაცემთა ტიპის ცვლილება<br />ოპერატორები: არითმეტიკული, ლოგიკური, შედარების</p>\n<p><strong>კვირა 2</strong><br /><strong>თემა: პროგრამის მართვის სტრუქტურები (Control Flow)</strong></p>\n<p>პირობითი ოპერატორები: if, elif, else<br />ლოგიკური პირობების აგება<br />ციკლები: while, for<br />range() ფუნქციის გამოყენება<br />break, continue, pass<br />ციკლების გამოყენება მონაცემთა დამუშავებაში</p>\n<p><strong>კვირა 3</strong><br /><strong>თემა: ფუნქციის შექმნა Python-ში</strong></p>\n<p>ფუნქციების განსაზღვრა (def)<br />ფუნქციის გამოძახება<br />პარამეტრები და არგუმენტები<br />დაბრუნებული მნიშვნელობები (return)<br />ცვლადების მოქმედების არეალი (local / global scope)<br />Lambda ფუნქციები<br />კოდის რეფაქტორინგი ფუნქციების გამოყენებით</p>\n<p><strong>კვირა 4</strong><br /><strong>თემა: მონაცემთა სტრუქტურები</strong></p>\n<p>სიები (Lists): ინდექსირება, slicing, list comprehensions<br />Tuple და მისი გამოყენება<br />Dictionaries: key-value სტრუქტურა, მონაცემთა სწრაფი მოძიება<br />Sets: უნიკალური მონაცემების დამუშავება<br />მონაცემთა სტრუქტურების კომბინირება</p>\n<p><strong>კვირა 5</strong><br /><strong>თემა: ობიექტზე ორიენტირებული პროგრამირების საფუძვლები</strong></p>\n<p>OOP-ის კონცეფცია, კლასები და ობიექტები<br />__init__ მეთოდი<br />ატრიბუტები და მეთოდები<br />კლასის მაგალითების შექმნა</p>\n<p><strong>კვირა 6</strong><br /><strong>თემა: OOP-ის ძირითადი პრინციპები</strong></p>\n<p>მემკვიდრეობითობა (Inheritance)<br />პოლიმორფიზმი<br />ინკაფსულაცია<br />აბსტრაქცია<br />კოდის ხელახალი გამოყენება</p>\n<p><strong>კვირა 7</strong><br /><strong>თემა: გარე ბიბლიოთეკები და მოდულები</strong></p>\n<p>Python მოდულების სტრუქტურა<br />import მექანიზმი<br />pip-ის გამოყენება<br />ფაილებთან სამუშაოდ შესაბამისი ბიბლიოთეკების გაცნობა: os, json, csv</p>\n<p><strong>კვირა 8</strong><br /><strong>თემა: მარტივი აპლიკაციის აწყობა</strong></p>\n<p>პროექტის სტრუქტურის დაგეგმვა<br />ფუნქციებისა და კლასების კომბინირება<br />მონაცემთა შეყვანა/გამოტანა<br />პროგრამის ლოგიკის ორგანიზება<br />კონსოლური Python აპლიკაციის შექმნა</p>\n<p><strong>კვირა 9</strong><br /><strong>თემა: პროექტის დაგეგმვა და GitHub</strong></p>\n<p>GitHub-ის ანგარიშის შექმნა<br />Git-ის ძირითადი ბრძანებები<br />რეპოზიტორიის შექმნა<br />პროექტის იდეის ჩამოყალიბება<br />PYQT5, Kivy ან pygame მოდულის გამოყენება</p>\n<p><strong>კვირა 10</strong><br /><strong>თემა: ფინალური პროექტი &ndash; ნაწილი I</strong></p>\n<p>კოდის არქიტექტურის დაგეგმვა<br />მოდულებად დაყოფა<br />ფუნქციებისა და კლასების იმპლემენტაცია</p>\n<p><strong>კვირა 11</strong><br /><strong>თემა: ფინალური პროექტი &ndash; ნაწილი II</strong></p>\n<p>შეცდომების პოვნა და აგსწორება (debugging)<br />ტესტირება<br />კოდის დოკუმენტირება (docstrings, comments)<br />პროექტის დასრულება</p>\n<p><strong>კვირა 12</strong><br /><strong>თემა: პროექტის პრეზენტაცია და GitHub</strong></p>\n<p>README ფაილის შექმნა<br />პროექტის ატვირთვა GitHub-ზე<br />კოდის პრეზენტაცია<br />პორტფოლიოს ფორმირება</p>\n<p><strong>კურსის ბოლოს</strong> მსმენელები იმუშავებენ ინდივიდუალურ პროექტებზე, წარადგენენ მათ და მიიღებენ ცოდნის დამადასტურებელ სერტიფიკატს. ისინი დამოუკიდებლად შეძლებენ საშუალო სირთულის პროექტების შექმნასა და საკუთარი პორტფოლიოს GitHub-ზე განთავსებას.</p>\n<p>ლექციების ჩატარება შესაძლებელია, როგორც დისტანციურად, ასევე ტრენინგ ცენტრში ან კორპორატიული დაკვეთის შემთხვევაში დამკვეთი კომპანიის სივრცეში!<strong><br /></strong></p>\n<p><strong>სასწავლო კურსის შესწავლის წინაპირობები:<br />მათემატიკის საბაზისო ცოდნა.<br />კომპიუტერული საბაზისო ცოდნა და ლოგიკური აზროვნების უნარი.<br />პროგრამირებისადმი ინტერესი და მოტივაცია.<br /></strong></p>\n<p><strong>კურსის ხანგრძლივობა: 3 თვე&nbsp;<br />შეხვედრების სიხშირე: კვირაში 2 შეხვედრა<br /></strong></p>\n<p><strong>შეხვედრის ხანგრძლივობა: 1.5 საათი<br /></strong></p>\n<p><strong>ღირებულება ჯგუფში 4 კაციდან: თვეში</strong></p>\n<p><strong>ადგილზე: 600 ლარი&nbsp;ერთი მონაწილისთვის</strong></p>\n<div dir=\"auto\"><strong>დისტანციურად: 480 ლარი ერთი მონაწილისთვის</strong></div>\n<p>&nbsp;</p>\n<p><strong>[registration]</strong></p>\n<p>&nbsp;</p>', 'VBA-Visual-Basic-For-Application', '', '', '', 'ge', 5, 0, 0),
(295, 125, 8, 1613467593, 0, 'text', 'Microsoft Project ', '<p><strong>Microsoft Project Professional 2016</strong></p>', '<p>** მოდული 1. პროექტების მართვის საწყისები, MS Project-ის ინტერფეისი<br />** მოდული 2. დაგეგმვა. პროექტის თვისებების ინიციალიზაცია, დავალებათა იერარქიული სტრუქტურის შექმნა<br />** მოდული 3. სამუშაო დროის მენეჯმენტი<br />** მოდული 4. დაგეგმვა. კრიტიკული გზის მეთოდი<br />** მოდული 5. დაგეგმვა, სხვა თვისებები<br />** მოდული 6. პროექტის რესურსების დაგეგმვა<br />** მოდული 7. პროექტის ოპტიმიზაცია<br />** მოდული 8. პროექტის მიმდინარეობის შემოწმება.<br />** მოდული 9. პარამეტრების შერჩევა, ვიზუალური თვისებები<br />** მოდული 10. სპეციალური პარამეტრები<br />** მოდული 11. მულტიპროექტი</p>\n<p><strong>ჯგუფში 10 საათი: 250 ლარი ერთი მსმენელისთვის</strong></p>\n<p><strong>ორ კაციანი ჯგუფი: 10 საათი-ღირებულება: 300 ლარი</strong><br /><strong>ინდივიდუალურად - 8 საათი: 400 ლარი</strong></p>\n<p>ლექციები ჩატარდება როგორც ქართულ, ასევე ინგლისურ ენაზე. გთავაზობთ კორპორატიულ ტრენინგებს!</p>', 'https://vipintellect.ge/ge/Ms-Office', '', '', '', 'en', 14, 0, 1),
(296, 125, 8, 1613467593, 0, 'text', 'Microsoft Project ', '<p><strong>Microsoft Project Professional 2016</strong></p>', '<p>** მოდული 1. პროექტების მართვის საწყისები, MS Project-ის ინტერფეისი<br />** მოდული 2. დაგეგმვა. პროექტის თვისებების ინიციალიზაცია, დავალებათა იერარქიული სტრუქტურის შექმნა<br />** მოდული 3. სამუშაო დროის მენეჯმენტი<br />** მოდული 4. დაგეგმვა. კრიტიკული გზის მეთოდი<br />** მოდული 5. დაგეგმვა, სხვა თვისებები<br />** მოდული 6. პროექტის რესურსების დაგეგმვა<br />** მოდული 7. პროექტის ოპტიმიზაცია<br />** მოდული 8. პროექტის მიმდინარეობის შემოწმება.<br />** მოდული 9. პარამეტრების შერჩევა, ვიზუალური თვისებები<br />** მოდული 10. სპეციალური პარამეტრები<br />** მოდული 11. მულტიპროექტი</p>\n<p><strong>ჯგუფში 10 საათი: 250 ლარი ერთი მსმენელისთვის</strong></p>\n<p><strong>ორ კაციანი ჯგუფი: 10 საათი-ღირებულება: 300 ლარი</strong><br /><strong>ინდივიდუალურად - 8 საათი: 400 ლარი</strong></p>\n<p>ლექციები ჩატარდება როგორც ქართულ, ასევე ინგლისურ ენაზე. გთავაზობთ კორპორატიულ ტრენინგებს!</p>', 'https://vipintellect.ge/ge/Ms-Office', '', '', '', 'ge', 14, 0, 1),
(297, 126, 8, 1613467844, 0, 'text', 'Microsoft Project Professional 2016/2013. პროექტების მართვა', '<p><strong>Microsoft Project Professional 2016/2013. პროექტების მართვა:</strong></p>', '<p>** მოდული 1. პროექტების მართვის საწყისები, MS Project-ის ინტერფეისი<br />** მოდული 2. დაგეგმვა. პროექტის თვისებების ინიციალიზაცია, დავალებათა იერარქიული სტრუქტურის შექმნა<br />** მოდული 3. სამუშაო დროის მენეჯმენტი<br />** მოდული 4. დაგეგმვა. კრიტიკული გზის მეთოდი<br />** მოდული 5. დაგეგმვა, სხვა თვისებები<br />** მოდული 6. პროექტის რესურსების დაგეგმვა<br />** მოდული 7. პროექტის ოპტიმიზაცია<br />** მოდული 8. პროექტის მიმდინარეობის შემოწმება.<br />** მოდული 9. პარამეტრების შერჩევა, ვიზუალური თვისებები<br />** მოდული 10. სპეციალური პარამეტრები<br />** მოდული 11. მულტიპროექტი</p>\n<p><strong>ჯგუფში 10 საათი: 250 ლარი ერთი მსმენელისთვის</strong></p>\n<p><strong>ორ კაციანი ჯგუფი: 10 საათი-ღირებულება: 300 ლარი</strong><br /><strong>ინდივიდუალურად - 8 საათი: 400 ლარი</strong></p>', 'Microsoft Project Professional 2016/2013. პროექტების მართვა', '', '', '', 'en', 14, 0, 1),
(298, 126, 8, 1613467844, 0, 'text', 'Microsoft Project Professional ', '<p><strong>Microsoft Project Professional 2016/2013. პროექტების მართვა:</strong></p>', '<p>** მოდული 1. პროექტების მართვის საწყისები, MS Project-ის ინტერფეისი<br />** მოდული 2. დაგეგმვა. პროექტის თვისებების ინიციალიზაცია, დავალებათა იერარქიული სტრუქტურის შექმნა<br />** მოდული 3. სამუშაო დროის მენეჯმენტი<br />** მოდული 4. დაგეგმვა. კრიტიკული გზის მეთოდი<br />** მოდული 5. დაგეგმვა, სხვა თვისებები<br />** მოდული 6. პროექტის რესურსების დაგეგმვა<br />** მოდული 7. პროექტის ოპტიმიზაცია<br />** მოდული 8. პროექტის მიმდინარეობის შემოწმება.<br />** მოდული 9. პარამეტრების შერჩევა, ვიზუალური თვისებები<br />** მოდული 10. სპეციალური პარამეტრები<br />** მოდული 11. მულტიპროექტი</p>\n<p><strong>ჯგუფში 10 საათი: 250 ლარი ერთი მსმენელისთვის</strong></p>\n<p><strong>ორ კაციანი ჯგუფი: 10 საათი-ღირებულება: 300 ლარი</strong><br /><strong>ინდივიდუალურად - 8 საათი: 400 ლარი</strong></p>', 'Microsoft-Project-Professional-2016/2013.-პროექტების-მართვა', '', '', '', 'ge', 14, 0, 1),
(301, 128, 9, 1625221281, 0, 'text', 'მეოთხე კატეგორიის საწარმოების ფინანსური ანგარიშგების სტანდარტი', '<p>მეოთხე კატეგორიის საწარმოების ფინანსური ანგარიშგების სტანდარტი</p>', '<p>მეოთხე კატეგორიის საწარმოების ფინანსური ანგარიშგების სტანდარტი<br />', 'მეოთხე კატეგორიის საწარმოების ფინანსური ანგარიშგების სტანდარტი ', '', '', '', 'en', 7, 0, 1),
(299, 127, 41, 1621424983, 0, 'text', 'გამყვანი ტურიზმი', '<p>ტურიზმის მენეჯმენტი, გამყყვან ტურიზმის პრაქტიკული კურსი</p>', '<p>გამყვანი ტურიზმი</p>\n<p>1. ტურიზმის ისტორიის მცირე მიმოხილვა, ტურიზმის სახეობები, მათი საერთო და განმასხვავებელი ნიშნები. ( საკურორტო ტურიზმი, სამედიცინო ტურიზმი ,სასწავლო ტურიზმი და ა. შ. ) <br />2. ტურიზმის როლი ქართულ ეკონომიკაში , პრობლემები რომლებსაც ტურ- ოპერატორად მუშაობისას ვაწყდებით , სირთულეები და საყურადღებო საკითხები. <br />3. გამყვანი ტურიზმი , მისი შემადგენელი ძირითადი ერთეულები : ავიაბილეთი,განთავსება , დაზღვევა, ტრანსფერი და დამატებითი მომსახურებები იგივე VIP სერვისები. ინვოისი : მისი ფორმა და შინაარსი . ანგარიშსწორების ფორმები. <br />4. განთავსების ობიექტების ტიპები , ნომრების კატეგორიები , CHECK INN, CHECK OUT, EARLY CHECK INN, LATE CHECK OUT .<br />5. საქართველოს ბაზარზე არსებული განთავსების ობიექტების დასაჯავშნი ყველა ხელმისაწვდომი სისტემა. ზოგადი მიმოხილვა იმისა სად რა შეგვიძლია დავჯავშნოთ. <br />კომუნიკაციის როლი გამყვან ტურიზმში : როგორ შევარჩიოთ მომხმარებლისთვის საინტერესო განთავსების ობიექტი, რა უნდა გავითვალისწინოთ მისი მოძიებისას და რა ინფორმაცია დაგვჭირდება მომხმარებლისგან. <br />6. პრაქტიკული ნაწილი : როგორ ვიმუშაოთ განთავსების ობიექტების დაჯავშნის სისტემებთან : NOVATOUR ; PEGAS TOURISTICS <br />7. პრაქტიკული ნაწილი : Ratehawk ; CTH<br />8. ავიაბილეთები, მათი სახეობები და ჯავშნის სისტემები - იატა , ამადეუსი, პეგასუსი, ვიზ ეარი , ონლაინ ჯავშნის სისტემები <br />9. პრაქტიკული ნაწილი : ავიაბილეთის დაჯავშნა WIZZ AIR , გამოსყიდვა, ბილეთის გაუქმება , საბარგო პოლიტიკა . <br />10. დაზღვევა: საქართველოს ბაზარზე არსებული სადაზღვეო კომპანიების მიერ შემოთავაზებული სადაზღვეო პაკეტები გამყვანი ტურიზმისათვის : ჯიპიაი, იმედი ელ , თიბისი დაზღვევა და ა. შ. ( პრაქტიკული ნაწილი: დაზღვევის გამოწერა )<br />11. ცალკეული ელემენტებით ტურის აკინძვა , ღირებულების დათვლა და რეალიზაცია. (პრაქტიკულ ნაწილთან ერთად) შექმნილი პროდუქტის რეკლამირება : რა გზით მივაწოდოთ პროდუქტი მომხმარებელს , რას მივაქციოთ ყურადღება და როგორ გავაკეთოთ სარეკლამო პოსტი. ( დავალება შემაჯამებელი ლექციისათვის )<br />12. შემაჯამებელი ლექცია : ჩემ მიერ დავალებული ტურების სათითაოდ განხილვა. პრობლემების გაანალიზება , ახსნა, შეჯამება . <br /> <br />შემაჯამებელი ტესტირება</p>\n<p>კურსი მოიცავს: 12 საათს<br />კურსის ღირებულება: 500 ლარი ინდივიდუაურად</p>', 'tour ', '', '', '', 'en', 2, 0, 0),
(305, 130, 40, 1638267210, 0, 'text', 'სამართლებრივი - იურიდიული ინგლისური', '<p>იურიდიული ინგლისური</p>', '<p><strong>კ</strong><strong>ურსი განკუთვნილია:</strong></p>\n<p>სამართლის სტუდენტებისა და პრაქტიკოსი იურისტებისთვის, რომლებსაც აქვთ Intermediate (B1) ან უფრო მაღალი დონე ინგლისურ ენაში. იმ შემთხვევაში, თუ პიროვნება არ ფლობს ინგლისური ენის ზემოთ ხსენებულ დონეს, ვთავაზობთ კომბინირებულ მეთოდს, რომელიც ითვალისწინებს სამართლებრივი და სასაუბრო ინგლისურის პარალელურ რეჟიმში შესწავლას. ამ შემთხვევაში სწავლების ხანგრძლივობა, რასაკვირველია, იზრდება.</p>\n<p><strong>კურსი ითვალისწინებს&nbsp; შემდეგი თემების შესწავლას:</strong></p>\n<p>Contract Law;</p>\n<p>Employment Law;</p>\n<p>Company Law;</p>\n<p>Real Property Law;</p>\n<p>Litigation and Arbitration.</p>\n<p><strong>კურსის ხანგრძლივობა:</strong><strong>2 თვე</strong></p>\n<p><strong>თვეში ჩატარდება:&nbsp;</strong><strong>8&nbsp;</strong><strong>ლექცია</strong></p>\n<p><strong>კურსის ღირებულება:</strong></p>\n<p><strong>ინდივიდუალურად:</strong><strong>&nbsp;&nbsp;300 ლარი</strong></p>\n<p><strong>წყვილში: 240 ლარი</strong></p>\n<p><strong>3 კაციან&nbsp; ჯგუფებში:</strong><strong>&nbsp;180 ლარი</strong></p>\n<p><strong>კურსის დასრულების შემდეგ</strong>&nbsp;თქვენ შეძლებთ სამართლებრივი &nbsp;დოკუმენტების წაკითხვასა და მათ შედგენას (მათ შორის, ხელშეკრულებისა და განცხადების შედგენას), ასევე, ოფიციალური სამართლებრივი კორესპონდენციის წარმოებას.</p>\n<p><strong>სახელმძღვანელოები:</strong></p>\n<p>Introduction to International Legal English &ndash; Amy Krois-Lindner, Matt Firth</p>\n<p>International Legal English - Amy Krois-Lindner</p>', 'lower english', '', '', '', 'en', 6, 0, 1),
(300, 127, 41, 1621424983, 0, 'text', 'გამყვანი ტურ ოპერატორი', '<p>გამყყვანი ტურ&nbsp;ოპერატორის პრაქტიკული კურსი</p>', '<p>კურსი გათვალისწინებულია: პირებისთვის, ვისაც სურს იმუშაოს ტურისტულ სააგენოტებში ტურ-ოპერატორად ან მენეჯერად, ან შექმნას საკუთარი ტურისტული კომპანია, რომელიც ორიენტირებული იქნება გამყვან ტურებზე.</p>\n<p><strong>პროგრამა მოიცავს:</strong></p>\n<p>შესავალი სპეციალობაში.<br />ტურიზმის განვითარები ისტორია, არსი, ტერმინები, კონცეფცია.<br />ტურიზმის სახეები და ძირითადი მიმართულება.<br />ტურისტული ინდუსტრია.<br />ტურიზმის იურიდიული - სამართლებრივი ბაზა და ტურიზმის სახელმწიფოებრივი რეგულირება. თანამშრომლობის ფორმები, ხელშეკრულებები ინვოისები და ურთიერთობები პარტნიორებთან.<br />ტურის დაგეგმვა. ტურისტული ტერმინოლოგია. ტუტისტული პაკეტის შესადგენად საჭირო ყველა ელემენტის<br />განხილვა და დახასიათება.<br />სასტუმროები, ავიაბილეთები ,დაზღვევა,ავტობუსის და მატარებლის ბილეთები.დამატებითი მომსახურებები.<br />ამჟამად არსებული საჯავშნი სისტემების ზოგადი მიმოხილვა ( Ratehawk, Pegasus, Coral, Nova Tour, Voyager Group, CTh, Iati, Amadeus, Wizz Air, Imedi l)<br />მოთხოვნის შესაბამისი ტურის დაგეგმვა. კომუნიკაცია მომხმარებელთან. როგორ და რა ფორმით შევთავაზოთ მომხმარებელს ის რაც სურს. როგორ მივიღოთ სასურველი ინფორმაცია მომხმარებლისგან.<br />მოთხოვნის დამუშავება, ტურის მარშრუტის აწყობა,ფასის დათვლა. ჩარტერული რეისები, მზა ტურისტული პაკეტები და მათი დაჯავშნის თავისებურებები (Nova Tour,CTh, Coral)<br />ტურისტული პროდუქტების მომზადება, პრეზენტაცია. რეკლამა და მისი მნიშვნელობა ტურიზმის განვითარებისათვის. ჩვენთვის ხელმისაწვდომი პლატფორმები რეკლამის განთავსებისთვის და ტურის რეალიზაციისთვის.<br />მიღებული ცოდნის გამოყენებით ტურის შერჩევა, განფასება,რეკლამის მომზადება და მომხმარებლისთვის შეთავაზება .<br />შეცდომების განხილვა. დისკუსია (Ratehawk, Pegasus, CTh, Wizz Air, Iati Dდა ა. შ)<br />საერთაშორისო რეისები . ევროპის ტურის მომზადება. Fფრენებისა და სასტუმროების მოძიება . განფასება, შეთავაზების მომზადება. სირთულეები და თავისებურებები, რომლებიც შესაძლოა შეგვხვდეს და მათი გადაჭრის გზები. სასტუმროებისა და ავიაბილეთების დასაჯავშნი სისტემები.<br />ევროპის რომელიმე მიმართულების შერჩევა. ტურის მომზადება, განფასება,დამუშავება და მომხმარებლისთვის შეთავაზება. სასტუმროს დაჯავშნა,გაუქმება. ავიაბილეთების დაჯავშნა, გამოსყიდვა. რეისის ცვლილება. ბარგის დამატება ბილეთების გამოსყიდვის შემდეგ.<br />ყველა საკითხის ზოგადი მიმოხილვა. რა გაგვიჭირდა. რა იყო გაუგებარი. განვიხილოთ შეცდომები, დისკუსია.<br />შეჯამება.</p>\n<p><strong>კურსის ბოლოს ჩატარდება შემაჯამებელი ტესტირება და გაიცემა სერტიფიკატი!</strong></p>\n<p><strong>კურსი მოიცავს: 10 ლექციას</strong><br /><strong>კვირაში ჩატარდება 2-3 ლექცია</strong><br /><strong>კურსის ღირებულება ჯგუფში : 550 ლარი</strong></p>\n<p><strong>კურსის&nbsp;კურსის ღირებულება წყვილში:650 ლარი</strong></p>\n<p><strong>ინდივიდუალურად:850 ლარი</strong></p>\n<p>ლექციებს უძღვება პრაქტიკოსი, მრავალწლიანი გამოცდილების მქონე ტურიზმის მენეჯერი, <strong>ტრენერი: თეონა ტყეშელაშვილი</strong>!</p>\n<p><strong>შეავსე სარეგისტრაციო ფორმა და დარეგისტრირდი ჯგუფში:</strong></p>\n<p>[registration]</p>', 'tour-', '', '', '', 'ge', 2, 0, 0),
(307, 131, 4, 1648463968, 0, 'text', 'ჩვენი გუნდი', '<p>შოთა ნიორაძე - გაძ₾იერებული ექსელის და ფინანსების ტრენერი:</p>', '<p><strong>ბიზნეს მოდელირება და მონაცემთა ანალიზი ექსელში;&nbsp;</strong></p>\n<p><strong>ფინანსური ანალიზი ექსელში;</strong></p>\n<p>&nbsp;</p>\n<p><strong>პრაქტიკული აუდიტი, პრაქტიკული ბუღალტერი,&nbsp;</strong></p>\n<p>&nbsp;</p>', 'https://vipintellect.ge/ge/staff', '', '', 'https://vipintellect.ge/ge/staff', 'en', 1, 0, 1),
(306, 130, 40, 1638267210, 0, 'text', 'სამართლებრივი - იურიდიული ინგლისური', '<p>იურიდიული ინგლისური</p>', '<p><strong>კ</strong><strong>ურსი განკუთვნილია:</strong></p>\n<p>სამართლის სტუდენტებისა და პრაქტიკოსი იურისტებისთვის, რომლებსაც აქვთ Intermediate (B1) ან უფრო მაღალი დონე ინგლისურ ენაში. იმ შემთხვევაში, თუ პიროვნება არ ფლობს ინგლისური ენის ზემოთ ხსენებულ დონეს, ვთავაზობთ კომბინირებულ მეთოდს, რომელიც ითვალისწინებს სამართლებრივი და სასაუბრო ინგლისურის პარალელურ რეჟიმში შესწავლას. ამ შემთხვევაში სწავლების ხანგრძლივობა, რასაკვირველია, იზრდება.</p>\n<p><strong>კურსი ითვალისწინებს&nbsp; შემდეგი თემების შესწავლას:</strong></p>\n<p>Contract Law;</p>\n<p>Employment Law;</p>\n<p>Company Law;</p>\n<p>Real Property Law;</p>\n<p>Litigation and Arbitration.</p>\n<p><strong>კურსის ხანგრძლივობა:</strong><strong>2 თვე</strong></p>\n<p><strong>თვეში ჩატარდება:&nbsp;</strong><strong>8&nbsp;</strong><strong>ლექცია</strong></p>\n<p><strong>კურსის ღირებულება:</strong></p>\n<p><strong>ინდივიდუალურად:</strong><strong>&nbsp;&nbsp;300 ლარი</strong></p>\n<p><strong>წყვილში: 240 ლარი</strong></p>\n<p><strong>3 კაციან&nbsp; ჯგუფებში:</strong><strong>&nbsp;180 ლარი</strong></p>\n<p><strong>კურსის დასრულების შემდეგ</strong>&nbsp;თქვენ შეძლებთ სამართლებრივი &nbsp;დოკუმენტების წაკითხვასა და მათ შედგენას (მათ შორის, ხელშეკრულებისა და განცხადების შედგენას), ასევე, ოფიციალური სამართლებრივი კორესპონდენციის წარმოებას.</p>\n<p><strong>სახელმძღვანელოები:</strong></p>\n<p>Introduction to International Legal English &ndash; Amy Krois-Lindner, Matt Firth</p>\n<p>International Legal English - Amy Krois-Lindner</p>\n<p>[registration]</p>', 'lower-english', '', '', '', 'ge', 6, 0, 1),
(309, 132, 4, 1648463968, 0, 'text', 'ჩვენი გუნდი', '<p>შოთა ნიორაძე - გაძ₾იერებული ექსელის და ფინანსების ტრენერი:</p>', '<p><strong>ბიზნეს მოდელირება და მონაცემთა ანალიზი ექსელში;&nbsp;</strong></p>\n<p><strong>ფინანსური ანალიზი ექსელში;</strong></p>\n<p>&nbsp;</p>\n<p><strong>პრაქტიკული აუდიტი, პრაქტიკული ბუღალტერი,&nbsp;</strong></p>\n<p>&nbsp;</p>', 'https://vipintellect.ge/ge/staff', '', '', 'https://vipintellect.ge/ge/staff', 'en', 1, 0, 1),
(310, 132, 4, 1648463968, 0, 'text', 'ჩვენი გუნდი', '<p>შოთა ნიორაძე - გაძ₾იერებული ექსელის და ფინანსების ტრენერი:</p>', '<p><strong>ბიზნეს მოდელირება და მონაცემთა ანალიზი ექსელში;&nbsp;</strong></p>\n<p><strong>ფინანსური ანალიზი ექსელში;</strong></p>\n<p>&nbsp;</p>\n<p><strong>პრაქტიკული აუდიტი, პრაქტიკული ბუღალტერი,&nbsp;</strong></p>\n<p>&nbsp;</p>', 'https://vipintellect.ge/ge/staff', '', '', 'https://vipintellect.ge/ge/staff', 'ge', 1, 0, 1);
INSERT INTO `navigation` (`id`, `idx`, `cid`, `date`, `nav_type`, `type`, `title`, `description`, `text`, `slug`, `usefull_type`, `cssclass`, `redirect`, `lang`, `position`, `visibility`, `status`) VALUES
(316, 135, 134, 1655721951, 0, 'text', 'თურქული ენის კურსი', '<p><strong>თურქული</strong> <strong>ენის</strong> <strong>ზოგადი </strong><strong>კურსი</strong> <strong>&nbsp;- </strong><strong>დონეების</strong> <strong>მიხედვით</strong></p>', '<p>A1- A2 დონე: შეისწავლება წერა-კითხვა, გრამატიკის საფუძვლები, სიტყვების სწორად გამოთქმა, მარტივი წინადადებების აგება და მარტივი საკომუნიკაციო ენა.</p>\n<p>კურსის ხანგრძილობა A1-A2 დონისთვის - 3 თვე</p>\n<p><strong>თვეში ჩატარდება: 8 ლექცია<br /> კურსის ღირებულება:<br /> </strong></p>\n<p><strong>ინდივიდუალურად: 200 ლარი<br /> წყვილში: 150 ლარი<br /> 3 კაციან ჯგუფებში: 100 ლარი</strong><br /> <br /> B1- B2 დონე: შეისწავლება გრამატიკის სრული კურსი, დამოუკიდებლად საუბარი ნებისმიერ სიტუაციაში, ზოგადი სამეცნიერო თემატიკა, პრესისა და მედიის აღქმა-გაანალიზება და თარგმანი, ენისთვის დამახასიათებელი დიალექტების დახვეწა.</p>\n<p><strong>კურსის ხანგრძლივობა:2 თვე<br /> თვეში ჩატარდება: 8 ლექცია<br /> კურსის ღირებულება:<br /> </strong></p>\n<p><strong>ინდივიდუალურად: 250 ლარი<br /> წყვილში: 200 ლარი<br /> 3 კაციან ჯგუფებში: 150 ლარი</strong><br /> <br /> C1- C2 დონე: შეისწავლება პროფესიონალურ დონეზე თურქულ ენაზე საუბარი, რთული სამეცნიერო ტერმინოლოგიის დახვეწა, ნებისმიერი დიალოგისა და ტექსტის თარგმნა.</p>\n<p><strong>კურსის ხანგრძლივობა:2 თვე<br /> თვეში ჩატარდება: 8 ლექცია<br /> კურსის ღირებულება:<br /> </strong></p>\n<p><strong>ინდივიდუალურად: 250 ლარი<br /> წყვილში: 200 ლარი<br /> 3 კაციან ჯგუფებში: 150 ლარი</strong></p>', 'https://vipintellect.ge/ge/Turkish-language', '', '', '', 'ge', 1, 0, 1),
(318, 136, 50, 1662375769, 0, 'text', 'სამედიცინო წარმომადგენლის მოსამზადებელი კურსი', '<p>სამედიცინო წარმომადგენელი</p>', '<p>medical representativemedical representativemedical representativemedical representativemedical representative</p>', 'health', '', '', '', 'ge', 5, 0, 1),
(319, 137, 50, 1662376137, 0, 'text', 'სამედიცინო წარმომადგენელის სასერთიფიკატო კურსი', '<p>სამედიცინო წარმომადგენელი</p>', '<p><strong>ტრენინგი განკუთვნილია:</strong> უმაღლესი სამედიცინო განათლების მქონე პირებისთვის<br /> <br /><strong>კურსის მიზანია:</strong> სამედიცინო წარმომადგენლების გადამზადება</p>\n<p><strong>კურსი მოიცავს:</strong><br />1 კომუნიკაციის საფუძვლები და ფსიქოლოგია, მოსმენა კომუნიკაციის ბარიერი <br />2 პიროვნების ფსიქოტიპები და თვისებები <br />3 კომუნიკაცია სხვა და სხვა ფსიქოტიპებთან <br />4 კომპეტენციის დონეები, პოტენციალი, ვიზიტის ეტაპები <br />5 ლოგიკური და მოტივირებული მოთხოვნები, პრეზენტაცია, შეთანხმება <br />6 სიტუაციური ამოცანები, ტესტირება</p>\n<p><strong>კურსი მოიცავს: 6 ლექციას</strong><br /><strong>კურსის ღირებულება: 250 ლარი</strong></p>', 'medical representative', '', '', '', 'en', 5, 0, 1),
(320, 137, 50, 1662376137, 0, 'text', 'სამედიცინო წარმომადგენელის სასერთიფიკატო კურსი', '<p>სამედიცინო წარმომადგენელი</p>', '<p><strong>ტრენინგი განკუთვნილია:</strong> უმაღლესი სამედიცინო განათლების მქონე პირებისთვის<br /> <br /><strong>კურსის მიზანია:</strong> სამედიცინო წარმომადგენლების გადამზადება</p>\n<p><strong>კურსი მოიცავს:</strong><br />1 კომუნიკაციის საფუძვლები და ფსიქოლოგია, მოსმენა კომუნიკაციის ბარიერი <br />2 პიროვნების ფსიქოტიპები და თვისებები <br />3 კომუნიკაცია სხვა და სხვა ფსიქოტიპებთან <br />4 კომპეტენციის დონეები, პოტენციალი, ვიზიტის ეტაპები <br />5 ლოგიკური და მოტივირებული მოთხოვნები, პრეზენტაცია, შეთანხმება <br />6 სიტუაციური ამოცანები, ტესტირება</p>\n<p><strong>კურსი მოიცავს: 6 ლექციას</strong><br /><strong>კურსის ღირებულება: 250 ლარი</strong></p>', 'medical-representative', '', '', '', 'ge', 5, 0, 1),
(321, 138, 50, 1662376340, 0, 'text', 'სამედიცინო წარმომადგენელის სასერთიფიკატო კურსი', '', '', 'health', '', '', '', 'en', 5, 0, 1),
(322, 138, 50, 1662376340, 0, 'text', 'სამედიცინო წარმომადგენელის სასერთიფიკატო კურსი', '', '', 'health', '', '', '', 'ge', 5, 0, 1),
(323, 139, 50, 1662376556, 0, 'text', 'სამედიცინო წარმომადგენელი', '<p>სამედიცინო წარმომადგენლის მოსამზადებელი სასერთიფიკატო კურსი</p>', '<p>ტრენინგი განკუთვნილია უმაღლესი სამედიცინო განათლების მქონე პირებისთვის<br /> <br />კურსის მიზანია: სამედიცინო წარმომადგენლების გადამზადება</p>\n<p>კურსი მოიცავს:<br />1 კომუნიკაციის საფუძვლები და ფსიქოლოგია, მოსმენა კომუნიკაციის ბარიერი <br />2 პიროვნების ფსიქოტიპები და თვისებები <br />3 კომუნიკაცია სხვა და სხვა ფსიქოტიპებთან <br />4 კომპეტენციის დონეები, პოტენციალი, ვიზიტის ეტაპები <br />5 ლოგიკური და მოტივირებული მოთხოვნები, პრეზენტაცია, შეთანხმება <br />6 სიტუაციური ამოცანები, ტესტირება</p>\n<p>კურსი მოიცავს: 6 ლექციას<br />კურსის ღირებულება: 250 ლარი</p>', 'health-medical representative', '', '', '', 'en', 3, 0, 0),
(324, 139, 50, 1662376556, 0, 'text', 'სამედიცინო წარმომადგენლის სასერთიფიკატო კურსი', '<p>სამედიცინო წარმომადგენლის მოსამზადებელი სასერთიფიკატო კურსი</p>', '<p><strong>ტრენინგი განკუთვნილია:</strong> უმაღლესი სამედიცინო განათლების მქონე პირებისთვის<br /> <br /><strong>კურსის მიზანია:</strong> სამედიცინო წარმომადგენლების&nbsp;მომზადება, რომ უპირატესობა ქონდეს დასაქმების პირობებში</p>\n<p><strong>კურსი მოიცავს:</strong><br />1. კომუნიკაციის საფუძვლები და ფსიქოლოგია, მოსმენა კომუნიკაციის ბარიერი <br />2. პიროვნების ფსიქოტიპები და თვისებები <br />3. კომუნიკაცია სხვა და სხვა ფსიქოტიპებთან <br />4. კომპეტენციის დონეები, პოტენციალი, ვიზიტის ეტაპები <br />5. ლოგიკური და მოტივირებული მოთხოვნები, პრეზენტაცია, შეთანხმება <br />6. სიტუაციური ამოცანები, ტესტირება</p>\n<p><strong>კურსი მოიცავს: 6 ლექციას</strong><br /><strong>კურსის ღირებულება მცირე რიცხოვან ჯგუფში: 250 ლარი</strong></p>\n<p><strong>წყვილში: 300 ლარი</strong></p>\n<p><strong>ინდივიდუალურად: 400 ლარი</strong></p>\n<p><strong>[registration]</strong></p>', 'health-medical-representative', '', '', 'medical representative', 'ge', 3, 0, 0),
(328, 141, 72, 1686041748, 0, 'text', 'სამშენებლო ხარჯთაღრიცხვის შემსწავლელი კურსი', '', '<p>პროგრამის მიზანი: პროფესიონალური უნარების შესწავლა, მათთვის ვისაც სურს ცოდნის შეძენა სამშენებლო ხარჯთაღრიცხვის მიმართულებით.<br />დაინტერესებული პირი უნდა ფლობდეს: ექსელის საბაზო დონეს და შეეძლოს ელემენტარული მათემატიკური აზროვნება.</p>\n<p>ტრეინინგის თემატიკა:<br />&bull; მშენებლობის პროცესების და ეტაპების განხილვა <br />&bull; AUTOCAD და ARCHICAD პროგრამების საბაზისო შესწავლა მოცულობების ამოსათვლელად.<br />&bull; სამუშაოს მოცულობების დათვლა სამშენებლო ნახაზების საფუძველზე.<br />&bull; სამშენებლო ხარჯთაღრიცხვის შედგენა სამშენებლო ნორმებისა და წესების გათვალისწინებით<br />&bull; შესრულებული სამუშაოს ფორმა 2 ის შედგენა ხარჯთაღრიცხვის საფუძველზე.</p>\n<p>სრული პროგრამის ხანგრძლივობა: 16 ლექცია<br />კვირაში ჩატარდება 2/2 საათიანი ლექცია<br />ღირებულება: 1250 ლარი<br />კურსის ბოლოს ჩატარდება დასკვნითი ტესტირება და გაიცემა სერთიფიკატი!</p>\n<p>საუკეთესო კურსდამთავრებულებს გავუწევთ რეკომენდაციებს და მოთხოვნის შესაბამისად ხელს შევუწყოთ დასაქმებაში!</p>\n<p>კურსს უძღვება: გიორგი ბუკია - პრაქტიკოსი ტრენერი, რომელსაც გააჩნია სამშენებლო ხარჯთამღრიცხველის პოზიციაზე მუშაობის მრავალწლიანი გამოცდილება.</p>\n<p>შეავსე სარეგისტრაციო ფორმა და დარეგისტრირდი ჯგუფში:</p>', 'https://vipintellect.ge/ge/bussines', '', '', '', 'ge', 6, 0, 1),
(329, 142, 72, 1686042076, 0, 'text', 'სამშენებლო ხარჯთაღრიცხვის კურსი', '<p>სამშენებლო ხარჯთაღიცხვის შემსწავლელი კურსი</p>', '<p>პროგრამის მიზანი: პროფესიონალური უნარების შესწავლა, მათთვის ვისაც სურს ცოდნის შეძენა სამშენებლო ხარჯთაღრიცხვის მიმართულებით.<br />დაინტერესებული პირი უნდა ფლობდეს: ექსელის საბაზო დონეს და შეეძლოს ელემენტარული მათემატიკური აზროვნება.</p>\n<p>ტრეინინგის თემატიკა:<br />&bull; მშენებლობის პროცესების და ეტაპების განხილვა <br />&bull; AUTOCAD და ARCHICAD პროგრამების საბაზისო შესწავლა მოცულობების ამოსათვლელად.<br />&bull; სამუშაოს მოცულობების დათვლა სამშენებლო ნახაზების საფუძველზე.<br />&bull; სამშენებლო ხარჯთაღრიცხვის შედგენა სამშენებლო ნორმებისა და წესების გათვალისწინებით<br />&bull; შესრულებული სამუშაოს ფორმა 2 ის შედგენა ხარჯთაღრიცხვის საფუძველზე.</p>\n<p>სრული პროგრამის ხანგრძლივობა: 16 ლექცია<br />კვირაში ჩატარდება 2/2 საათიანი ლექცია<br />ღირებულება: 1250 ლარი<br />კურსის ბოლოს ჩატარდება დასკვნითი ტესტირება და გაიცემა სერთიფიკატი!</p>\n<p>საუკეთესო კურსდამთავრებულებს გავუწევთ რეკომენდაციებს და მოთხოვნის შესაბამისად ხელს შევუწყოთ დასაქმებაში!</p>\n<p>კურსს უძღვება: გიორგი ბუკია - პრაქტიკოსი ტრენერი, რომელსაც გააჩნია სამშენებლო ხარჯთამღრიცხველის პოზიციაზე მუშაობის მრავალწლიანი გამოცდილება.</p>\n<p>შეავსე სარეგისტრაციო ფორმა და დარეგისტრირდი ჯგუფში:</p>', 'cost estimate', '', '', '', 'en', 5, 0, 0),
(330, 142, 72, 1686042076, 0, 'text', 'სამშენებლო ხარჯთაღრიცხვის კურსი', '<p>სამშენებლო ხარჯთაღიცხვის შემსწავლელი კურსი</p>', '<p><strong>ლექცია 1. ხარჯთაღრიცხველი როგორც კონტროლის ფიგურა</strong><br />&bull; რა როლი აქვს ხარჯთაღმრიცხველს რეალურ პროექტზე?<br />&bull; რატომ არის ხარჯთაღრიცხვა კონტროლის მთავარი ინსტრუმენტი?<br />&bull; როგორ უნდა წავიკითხოთ სხვისი ხარჯთაღრიცხვა კრიტიკულად?<br />&bull; დამკვეთი, შემსრულებელი, ზედამხედველი &mdash; სად დგას ხარჯთაღმრიცხველი?<br />სავარჯიშო: არსებული ხარჯთაღრიცხვის სწრაფი ანალიზი და რისკების გამოვლენა.</p>\n<p><strong>ლექცია 2. ხარჯთაღრიცხვის ლოგიკა და სტრუქტურა</strong><br />&bull; როგორ იშლება ხარჯთაღრიცხვა სწორად?<br />&bull; პირდაპირი და არაპირდაპირი ხარჯები ქართულ პრაქტიკაში<br />&bull; სარეზერვო ფონდი &mdash; როდის აუცილებელია და როდის გადაჭარბებული?<br />&bull; მოგების მარჟა: როგორ დავიცვათ ციფრები კონტრაქტში?<br />სავარჯიშო: ხარჯთაღრიცხვის სტრუქტურის აწყობა ნულიდან.</p>\n<p><strong>ლექცია 3. დოკუმენტაცია და ფორმები (№2, №3, №4)</strong><br />&bull; ფორმა №2 &mdash; როგორ იკითხება და როგორ მოწმდება?<br />&bull; ფორმა №3 &mdash; რა ამტკიცებს და რა არა?<br />&bull; ფარული სამუშაოების აქტები &mdash; ყველაზე ხშირად დავიწყებული დოკუმენტი<br />&bull; სად იწყება და სად მთავრდება პასუხისმგებლობა?<br />სავარჯიშო: შესრულებული სამუშაოების გადამოწმება ფორმა №3-ზე.</p>\n<p><strong>ლექცია 4. მოცულობების ამოთვლა ნახაზებიდან</strong><br />&bull; არქიტექტურული და კონსტრუქციული ნახაზების კითხვა<br />&bull; სად ხდება ყველაზე ხშირი შეცდომები მოცულობებში?<br />&bull; დიზაინ&ndash;პროექტიდან მასალების დათვლა<br />&bull; AutoCAD / ArchiCAD / BIM &mdash; პრაქტიკული გამოყენება ხარჯთაღრიცხვაში<br />სავარჯიშო: ფასადის და შიდა ფართობების ამოთვლა ნახაზიდან.</p>\n<p><strong>ლექცია 5. სამშენებლო მასალების ხარჯთაღრიცხვა</strong><br />&bull; მასალების კლასიფიკაცია და კოდირება<br />&bull; როგორ ვამოწმებთ ფასების რეალურობას ქართულ ბაზარზე?<br />&bull; ინფლაცია, ვალუტა, სეზონურობა &mdash; როგორ აისახება სმეტაზე?<br />&bull; როგორ ავირიდოთ არარეალური ფასები?<br />სავარჯიშო: ფასების შედარება (ბეტონი, არმატურა, ფილა).</p>\n<p><strong>ლექცია 6. შრომითი ხარჯები რეალურ პირობებში</strong><br />&bull; მუშახელის ანაზღაურების მოდელები<br />&bull; შრომის ნორმები და დროის ბალანსი<br />&bull; სოციალური და საგადასახადო ხარჯები<br />&bull; რატომ &bdquo;იფანტება&ldquo; შრომის ბიუჯეტი?<br />სავარჯიშო: კედლის წყობის შრომის ხარჯის დეტალური დათვლა.</p>\n<p><strong>ლექცია 7. ტექნიკის ხარჯები</strong><br />&bull; ძირითადი სამშენებლო ტექნიკა და მისი როლი ბიუჯეტში<br />&bull; ქირაობა vs საკუთრება<br />&bull; საათობრივი და დღიური ტარიფები<br />&bull; ტექნიკის ფარული ხარჯები<br />სავარჯიშო: ექსკავატორის ხარჯის გამოთვლა 1 კვირაზე.</p>\n<p><strong>ლექცია 8. ზედნადები ხარჯები და რეალური პროცენტები</strong><br />&bull; ადმინისტრაციული ხარჯების სტრუქტურა<br />&bull; ტრანსპორტი, ენერგია, კომუნიკაცია<br />&bull; საერთაშორისო 10&ndash;20% vs ქართული რეალობა<br />&bull; როდის არის ზედნადები გადაჭარბებული?<br />სავარჯიშო: მცირე ობიექტის ზედნადების გამოთვლა.</p>\n<p><strong>ლექცია 9. Excel ხარჯთაღრიცხველისთვის</strong><br />&bull; პროფესიული Excel&ndash;სტრუქტურა<br />&bull; ფორმულები, ლოგიკა, ავტომატიზაცია<br />&bull; შეცდომების კონტროლი<br />&bull; როგორ შევქმნათ სამუშაო შაბლონი?<br />სავარჯიშო: Excel ხარჯთაღრიცხვის შაბლონის აწყობა.</p>\n<p><strong>ლექცია 10. კალენდარული სმეტა და გეგმა&ndash;ფაქტი</strong><br />&bull; რა არის კალენდარული სმეტა?<br />&bull; სამუშაოების ეტაპებად დაყოფა<br />&bull; გეგმა&ndash;ფაქტის შედარება<br />&bull; გადახრების დროული აღმოჩენა<br />სავარჯიშო: კალენდარული სმეტის შედგენა.</p>\n<p><strong>ლექცია 11. ფასების კორექტირება და მოლაპარაკება</strong><br />&bull; რატომ იცვლება ხარჯთაღრიცხვა?<br />&bull; ინდექსაცია (FIDIC და პრაქტიკული მოდელები)<br />&bull; როგორ დავიცვათ ფასი დამკვეთთან?<br />&bull; მოლაპარაკების სტრატეგია ხარჯთაღმრიცხველისთვის<br />სავარჯიშო: ფასის დაცვის სცენარი მოლაპარაკების დროს.</p>\n<p><strong>ლექცია 12. ტიპური ქართული შეცდომები და ვორქშოფი</strong><br />&bull; ყველაზე ხშირი შეცდომები ქართულ ობიექტებზე<br />&bull; როგორ &bdquo;ატყუებენ&ldquo; სმეტით?<br />&bull; როგორ დავიცვათ თავი?<br />&bull; სრულმასშტაბიანი პროექტის ხარჯთაღრიცხვა<br />სავარჯიშო: სრული პროექტი + პრეზენტაცია.</p>\n<p><strong>კურსის დასრულების შემდეგ მონაწილეები შეძლებენ:</strong><br />&bull; დამოუკიდებლად შეადგინონ პროფესიული ხარჯთაღრიცხვები<br />&bull; აკონტროლონ შემსრულებლები და ზედამხედველები<br />&bull; იმუშაონ Excel, AutoCAD და ArchiCAD მონაცემებით<br />&bull; მართონ კალენდარული სმეტები<br />&bull; დაიცვან ფასი და პოზიცია დამკვეთთან მოლაპარაკებისას<br />&bull; ამოიცნონ და აირიდონ ტიპური ქართული შეცდომები</p>\n<p><strong>კურსი მოიცავს: 12/2 საათიან შეხვედრას</strong></p>\n<p><strong>კურსის ღირებულება: 1200 ლარი</strong></p>\n<p><strong>შეავსე სარეგისტრაციო ფორმა და დარეგისტრირდი ჯგუფში:</strong></p>\n<p>[registration]</p>\n<p>&nbsp;</p>', 'cost-estimate', '', '', 'https://vipintellect.ge/ge//cost estimate', 'ge', 5, 0, 0),
(333, 144, 7, 1694006957, 0, 'text', 'ხარისხის კონტროლის პრინციპები და HACCP-ის სისტემა', '<p><strong>ხარისხის კონტროლის პრინციპები და HACCP-ის სისტემა</strong></p>', '<p>პროგრამის სახელწოდება: ხარისხის კონტროლის პრინციპები და HACCP-ის სისტემა<br />პროგრამა განკუთვნილია:იმ პირებისთვის ვინც დასაქმებულია სურსათის საწარმოებსა და ობიექტებში, ან სურს საწარმო, სარეალიზაციო ობიექტის გახსნა, განახლება, კურსი ასევე განკუთვნილია პირებისთვის ვისაც სურს პერსონალის გადამზადება ხარისხის კონტროლის მიმართულებით.<br />კურსი მოიცავს: შეისწავლოთ ხარისხის კონტროლის მნიშვნელობა, მისი განსაზღვრა ნედლეულიდან მის საბოლოო პროდუქტამდე გარდა ამისა გექნებათ შესაძლებლობა შეისწავლოთ HACCP-ის სისტემის მნიშვნელობა მისი დანერგვისა და განხორციელებისათვის საჭირო დეტალები.<br />თემატიკა<br />&bull; სურსათის უვნებლობის მნიშვნელობა და მისი რეგულირების ძირითადი დებულებები<br />&bull; სურსათისა და სასურსათო ნედლეულის ძირითადი ქიმიური კომპონენტები.<br />&bull; სურსათის უვნებლობის პოლიტიკის ძირითადი საკითხები<br />&bull; სურსათის უვნებლობის პრინციპები საქართველოში.<br />&bull; სურსათისა და სასურსათო ნედლეულის ხარისხი, სურსათის დაბინძურების წყაროები<br />&bull; სურსათისა და სასურსათო ნედლეულის უვნებლობა.<br />&bull; სურსათისა და სასურსათო ნედლეულის ტექნიკური რეგულირება, სტანდარტიზაცია და სერტიფიკაცია.<br />&bull; სურსათისა და სასურსათო ნედლეულის საფრთხეები.<br />&bull; საფრთხის ანალიზისა და კრიტიკული საკონტროლო წერტილების სისტემა &ndash; HACCP.<br />&bull; მიკვლევადობის პრინციპები სურსათის უვნებლობაში.<br />&bull; HACCP-ის დანერგვამდე საჭირო წინასწარი პროგრამები GHP, GMP<br />&bull; HACCP ის სისტემის დანერგვის პრინციპები<br />&bull; HACCP-ის გეგმა და დოკუმენტაციის, ჩანაწერების წარმოება<br />კურსდამთავრებულის უპირატესობა: შეისწავლის სურსათის უვნებლობისათვის საჭირო არსებულ ძირითად მიმართულებებს, რომელიც პრაქტიკაში გამოიყენება, ასევე შეძლებენ თეორიული ცოდნის მიხედვით საწარმოებში, სურსათის წარმოების და რეალიზაციის დაწესებულებებში დაიცვან ხარისხის კონტროლი, შეძლებენ საჭირო დოკუმენტაციის სწორად წარმოებას.<br />სრული პროგრმის ხანგრძლივობა : 8 ლექცია<br />კვირაში ჩატარდება 2 ლექცია<br />ლექციის ხანგრძლივობა 1,5 სთ<br />კურსის ღირებულება ჯგუფში 3 კაციდან: 500<br />კურსის ღირებულება წყვილში: 650<br />კურსის ღირებულება ინდივიდუალურად:750<br />კურსის ბოლოს ჩატარდება დასკვნითი ტესტირება და გაიცემა სერთიფიკატი<br />კურსს უძღვება: ანჟელა ღაჭავა - 4 წლიანი გამოცდილების მქონე სურსათის ტექნოლოგი<br />მეღვინეობის მაგისტრი, ტრენერი.</p>', 'HACCP', '', '', '', 'en', 8, 0, 0),
(334, 144, 7, 1694006957, 0, 'text', 'სურსათი და ღვინის ხარისხის კონტროლის პრინციპები და HACCP-ის სისტემა', '<p><strong>სურსათის და ღვინის ხარისხის კონტროლის პრინციპები და HACCP-ის სისტემა</strong></p>', '<p><strong>პროგრამის სახელწოდება</strong>: ხარისხის კონტროლის პრინციპები და HACCP-ის სისტემა</p>\n<p>პროგრამა განკუთვნილია:იმ პირებისთვის ვინც დასაქმებულია სურსათის საწარმოებსა და ობიექტებში, ან სურს საწარმო, სარეალიზაციო ობიექტის გახსნა, განახლება, კურსი ასევე განკუთვნილია პირებისთვის ვისაც სურს პერსონალის გადამზადება ხარისხის კონტროლის მიმართულებით.<br />კურსი მოიცავს: შეისწავლოთ ხარისხის კონტროლის მნიშვნელობა, მისი განსაზღვრა ნედლეულიდან მის საბოლოო პროდუქტამდე გარდა ამისა გექნებათ შესაძლებლობა შეისწავლოთ HACCP-ის სისტემის მნიშვნელობა მისი დანერგვისა და განხორციელებისათვის საჭირო დეტალები.</p>\n<p><strong>თემატიკა</strong><br />&bull; სურსათის უვნებლობის მნიშვნელობა და მისი რეგულირების ძირითადი დებულებები<br />&bull; სურსათისა და სასურსათო ნედლეულის ძირითადი ქიმიური კომპონენტები.<br />&bull; სურსათის უვნებლობის პოლიტიკის ძირითადი საკითხები<br />&bull; სურსათის უვნებლობის პრინციპები საქართველოში.<br />&bull; სურსათისა და სასურსათო ნედლეულის ხარისხი, სურსათის დაბინძურების წყაროები<br />&bull; სურსათისა და სასურსათო ნედლეულის უვნებლობა.<br />&bull; სურსათისა და სასურსათო ნედლეულის ტექნიკური რეგულირება, სტანდარტიზაცია და სერტიფიკაცია.<br />&bull; სურსათისა და სასურსათო ნედლეულის საფრთხეები.<br />&bull; საფრთხის ანალიზისა და კრიტიკული საკონტროლო წერტილების სისტემა &ndash; HACCP.<br />&bull; მიკვლევადობის პრინციპები სურსათის უვნებლობაში.<br />&bull; HACCP-ის დანერგვამდე საჭირო წინასწარი პროგრამები GHP, GMP<br />&bull; HACCP ის სისტემის დანერგვის პრინციპები<br />&bull; HACCP-ის გეგმა და დოკუმენტაციის, ჩანაწერების წარმოება</p>\n<p><strong>კურსდამთავრებულის უპირატესობა:</strong> შეისწავლის სურსათის უვნებლობისათვის საჭირო არსებულ ძირითად მიმართულებებს, რომელიც პრაქტიკაში გამოიყენება, ასევე შეძლებენ თეორიული ცოდნის მიხედვით საწარმოებში, სურსათის წარმოების და რეალიზაციის დაწესებულებებში დაიცვან ხარისხის კონტროლი, შეძლებენ საჭირო დოკუმენტაციის სწორად წარმოებას.</p>\n<p><strong>სრული პროგრმის ხანგრძლივობა : 8 ლექცია</strong><br /><strong>კვირაში ჩატარდება 2 ლექცია</strong><br /><strong>ლექციის ხანგრძლივობა 1,5 სთ</strong><br /><strong>კურსის ღირებულება ჯგუფში 3 კაციდან: 450</strong><br /><strong>კურსის ღირებულება წყვილში: 600</strong><br /><strong>კურსის ღირებულება ინდივიდუალურად:700</strong></p>\n<p><strong>კურსის ბოლოს ჩატარდება დასკვნითი ტესტირება და გაიცემა სერთიფიკატი</strong></p>\n<p><strong>კურსს უძღვება: ანჟელა ღაჭავა</strong> -&nbsp;8 წლიანი გამოცდილების მქონე სურსათის ტექნოლოგი<br />მეღვინეობის მაგისტრი, ტრენერი.</p>\n<p>[registration]</p>\n<p><strong>2. ღვინის ხარისხის კონტროლის HACCP-ის კურსი - პრაქტიკით ღვინის ლაბორატორიაში</strong><br />პროგრამა განკუთვნილია:იმ პირებისთვის ვისაც სურს ხარისხიანი ღვინის წარმოება და საწარმოს სწორი მოწყობა, გარდა ამისა საშუალება ექნება გაეცნოს ლაბორატორიულ საკითხებს რაც დაეხმარება ღვინის საწარმოში ხარისხის სწორად შეფასებაში, შეძლებთ მარნებში სრული პროცესები აკონტროლოთ, ჩაატაროთ ზედამხედველობა და იყოთ ღვინის ხარისხის კონტროლის განმახორციელებელი.</p>\n<p><strong>კურსი მოიცავს:</strong> ხარისხის კონტროლის განვითარებისთვის საჭირო საკითხებს, HACCP-ის დანერგვისათვის მოსამზადებელ დეტალებს, დოკუმენტაციის ჩათვლით, გარდა ამისა ლაბორატორიული ნიმუშების აღწერას და დაავადებების შესწავლას.<br />გარდა ამისა კურსი მოიცავს პრაქტიკულ ნაწილს, რომელიც ჩატარდება შპს ,,ირმა ჭანტურიას სახელობის ღვინის ლაბორატორიაში,, სადაც შესაძლებლობა გექნებათ ჩაერთოთ ღვინის ნიმუშების შემოწმების და ხარისხის დადგენის პროცესში.<br />ღვინის ხარისხის კონტროლი<br />კანონმდებლობა ვაზის და ღვინის შესახებ<br />ვენახის ხარისხის კონტროლი<br />კახური ღვინის ტექნოლოგიის ხარისხის კონტროლი<br />ევროპული ღვინის ტექნოლოგიის ხარისხის კონტროლი<br />სურსათის უვნებლობის მართვის სისტემა მიდგომა &bdquo;ფერმიდან სუფრამდე&ldquo;<br />საფრთხის ანალიზისა და კრიტიკული საკონტროლო წერტილების სისტემა &ndash; HACCP.<br />HACCP-ის დანერგვამდე საჭირო წინასწარი პროგრამები GHP, GMP ღვინის საწარმოში<br />HACCP-ის მნიშვნელობა და დანერგვის წესები ღვინის საწარმოში<br />HACCP-ის მოთხოვნების დადგენა და დოკუმენტაციის შედგენა<br />ღვინის მოვლა და დამუშავება<br />ღვინის მიკრობიოლოგიური დაავადებები<br />ღვინის დაავადებების გადაჭრის გზები<br />ღვინის ლაბორატორიის მოწყობა და მისი მნიშვნელობა<br />ლაბორატორიაში ღვინის ნიმუშების მიღება და კვლევა<br />დანადგარების ქიმიური რეცხვის ტექნიკა. <br />სრული საწარმოო კონტროლი მეღვინეობაში</p>\n<p><strong>კურსდამთავრებულის უპირატესობა:</strong> შეისწავლის ღვინის ხარისხისათვის საჭირო ძირითად მიმართულებებს, რომელიც პრაქტიკაში აქტიურად გამოიყენება, ასევე შეძლებენ თეორიული და პრაქტიკული ცოდნის მიხედვით საწარმოებში ღვინის წარმოების და რეალიზაციის პროცესში დაიცვან ხარისხის კონტროლი, შეძლებენ საჭირო დოკუმენტაციის სწორად წარმოებას და შეძლებენ ლაბორატორიაში დამოუკიდებლად ჩართვას.<br /><strong>სრული პროგრამის ხანგრძლივობა : 6 ლექცია - 2 საათიანი</strong><br /><strong>საწარმოო პრაქტიკა ღვინის ლაბორატორიაში</strong><br /><strong>კვირაში ჩატარდება 2 ლექცია</strong></p>\n<p><strong>კურსის ღირებულება ჯგუფში 3 კაციდან: 550</strong></p>\n<p><strong>კურსის ღირებულება წყვილში: 700</strong></p>\n<p>კურსის ბოლოს ჩატარდება დასკვნითი ტესტირება და გაიცემა სერთიფიკატი<br />კურსს უძღვება: ანჟელა ღაჭავა -&nbsp;8 წლიანი გამოცდილების მქონე მევენახე-<br />მეღვინეობის მაგისტრი, მეღვინე, ტრენერი. პროფესიული განათლების მასწავლებელი<br />მევენახეობა-მეღვინეობის მიმართულებით</p>\n<p>[registration]</p>', 'HACCP', '', '', '', 'ge', 8, 0, 0),
(336, 145, 8, 1698322995, 0, 'text', 'AutoCAD; ArchiCAD -ის კურსები', '<p>AutoCAD-ის ArchiCAD -ის ზოგადი კურსი</p>\n<p>&nbsp;</p>', '<p><strong>AutoCAD-ის&nbsp;კურსის მიზნები:</strong><br />&bull; კურსის მიზანია შესწავლოს სტუდენტებს 2D/3D გეომეტრიული მოდელირების ზოგადი პრინციპები AutoCAD-ის ბაზაზე. სტუდენტი შეისწავლის სტანდარტული და არასტანდარტული სამგანზომილებიანი კომპიუტერული მოდელის შექმნას და მოდიფიცირებას, 3D მოდელიდან ნახაზის შექმნის საფუძვლებს</p>\n<p><strong>გამოყენების სფეროები:</strong><br />&bull; მშენებლობა, არქიტექტურა, წარმოება, დიზაინი (ავეჯი და ა.შ.)<br /><strong>კურსის ძირითადი თემები:</strong><br />1. რა არის 2D/3D მოდელირება?<br />2. 2D/3D მოდელირების პრინციპები AutoCAD-ში<br />3. სტანდარტული და არასტანდარტული 2D/3D მოდელების შექმნა AutoCAD-ში<br />4. ტექნიკური ნახაზების შექმნის საფუძვლები<strong>კურსის შინაარსი:</strong><br /><strong>ლექცია I: შესავალი</strong><br />&bull; 2D/3D მოდელირების პრინციპები<br />&bull; 2D/3D მოდელირების პლატფორმები და გამოყენების სფეროები<br />&bull; AutoCAD-ის ინსტალაცია<br />&bull; მომხმარებლის ინტერფეისი<br />&bull; სამუშაო გარემოს მოწყობა <br />&bull; სანავიგაციო ფუნქციები<br /><strong>ლექცია II: 2D მოდელირება</strong><br />&bull; AutoCAD-ის მუშაობის პრინციპი (ბრძანებები)<br />&bull; Grid და Snap გამოყენება<br />&bull; ორგანზომილებიანი მოდელირების ინსტრუმენტების პარამეტრები (ფერი, სისქე ...)<br />&bull; ორგანზომილებიანი მოდელირების ინსტრუმენტები:<br />- Lines<br />- Rectangles<br />- Circles<br /><strong>ლექცია III: 2D მოდელირება</strong><br />&bull; კონსტრეინტები<br />&bull; ორგანზომილებიანი მოდელირების ინსტრუმენტები:<br />- Ellipses<br />- Arcs<br />- Polygons<br />- Polylines<br /><strong>ლექცია IV: ორგანომილებიანი მოდელების რედაქტირების საშუალებები</strong><br />&bull; ორგანზომილებიანი მოდელების რედაქტირება:<br />- Move<br />- Copy<br />- Rotate<br />- Scale<br />- Trim<br />- Extend<br />- Fillet<br />- Chamfer<br />- Mirror<br /><strong>ლექცია V: პრაქტიკული სამუშაო</strong><br /><strong>&bull; სხვადასხვა სახის ორგანზომილებიანი მოდელის შექმნა AutoCAD-ში შესწავლილი ინსტრუმენტების გამოყენებით</strong><br /><strong>ლექცია VI: შუალედური ტესტირება</strong><br /><strong>ლექცია VII: 3D მოდელირება</strong><br />&bull; სამგანზომილებიანი მოდელირების გარემო<br />&bull; სამგანზომილებიანი მოდელირების პრინციპები AutoCAD-ში<br />&bull; კოორდინატთა სისტემის შექმნა<br />&bull; სტანდარტული სამგანზომილებიანი პრიმიტივები:<br />- Cylinder<br />- Box<br />- Cones<br />- Pyramid<br /><strong>ლექცია VIII: 3D მოდელირება - არასტანდარტული სამგანზომილებიანი პრიმიტივები:</strong><br />- Sphere<br />- Torus<br />- Wedge<br />ლექცია IX: 3D მოდელირება - არასტანდარტული სამგანზომილებიანი პრიმიტივები<br />- Polysolid<br />- Extrude<br />- Loft<br /><strong>ლექცია X: 3D მოდელირება - არასტანდარტული სამგანზომილებიანი პრიმიტივები</strong><br />- Revolve<br />- Sweep<br />- Presspull<br />- Helix<br /><strong>ლექცია XI: 3D მოდელირება - რთული ობიექტების შექმნა Boolean ოპერატორის გამოყენებით</strong><br />- Subtraction<br />- Union<br />- Intersection</p>\n<p><strong>ლექცია XII: 3D მოდელირება - სამგანზომილებიანი ობიექტების ტრანზაქციის ოპერაციები:</strong><br />- Move<br />- Rotate<br />- Array<br />- Align<br />- Mirror</p>\n<p><strong>ლექცია XIII: 3D მოდელირება - სამგანზომილებიანი ობიექტების რედაქტირება</strong><br />- Fillet<br />- Taper<br />- Offset<br />- Shell<br />- Chamfer<br />- Section</p>\n<p><strong>ლექცია XIV: სამგანზომილებიანი მოდელებიდან ნახაზების შექმნა</strong><br />- Base View<br />- Projected View<br />- Section Views<br />- Section View Style<br />- Full Section View<br />- Detailed View</p>\n<p><strong>ლექცია XV: პრაქტიკული სამუშაო</strong><br />&bull; სხვადასხვა სახის სამგანზომილებიანი მოდელის შექმნა AutoCAD-ში შესწავლილი ინსტრუმენტების გამოყენებით</p>\n<p><strong>ლექცია XVI: დასკვნითი გამოცდა</strong></p>\n<p><strong>კურსის ხანგძლივობა:<br />&bull; სრული კურსი გრძელდება - 2 თვე<br />&bull; კვირაში 2 ლექცია<br />&bull; 1 ლექციის ხანგძლივობა 2 აკადემიური საათი</strong></p>\n<p><strong>კურსის ღირებულება: </strong></p>\n<p><strong>ინდივიდუალურად ადგილზე შესწავლა -&nbsp;850 ლარი თვეში&nbsp;</strong></p>\n<p><strong>წყვილში: 650 ლარი თვეში</strong></p>\n<p><strong>ჯგუფში: 550 ლარი თვეში&nbsp;</strong></p>\n<p><strong>ლექციების ჩატარება შესაძლებელია, როგორც ადგილზე ტრენინგ ცენტრში, ასევე დისტანციურად.</strong></p>\n<p><strong>[registration]</strong></p>\n<p>&nbsp;</p>\n<p><strong>ArchiCAD-ის ზოგადი კურსის&nbsp;მიზნები</strong>:<br />&bull; კურსის მიზანია შესწავლოს სტუდენტებს, შენობების დაპროექტებისთვის საჭირო უნარები და ინსტრუმენტები, კონცეპტუალური ეტაპიდან მშენებლობის ფაზამდე. კომპიუტერული პროგრამა ArchiCAD-ის გამოყენებით.</p>\n<p><strong>გამოყენების სფეროები:</strong><br />&bull; მშენებლობა, არქიტექტურა, ინტერიერის და ექსტერიერის დიზაინი<br /><strong>კურსის ძირითადი თემები:</strong><br />1. იუზერის ინტერფეისი<br />2. 2D/3D მოდელირების პრინციპები ArchiCAD-ში<br />3. შენობის ძირითადი კომპონენტები: კედელი, სახურავი, კიბე ფანჯარა და ა.შ<br />4. სამგანზომილებიანი კომპიუტერული მოდელებიდან ფოტორეალისტური გამოსახულების გენერაცია<br /><strong>კურსის შინაარსი:</strong><br /><strong>ლექცია I: შესავალი</strong><br />&bull; Archicad-ის ინსტალაცია <br />&bull; Archicad-ის ვერსიები<br />&bull; რატომ Archicad?<br /><strong>ლექცია II: იუზერის ინტერფეისი</strong><br />&bull; დახმარება<br />&bull; ხელსაწყოების ყუთი<br />&bull; ინფორმაციის ველი<br />&bull; მენიუ<br />&bull; Toolbars<br />&bull; Palettes<br />&bull; პროექტის რუქა<br />&bull; სამუშაო გარემო<br /><strong>ლექცია III: პროექტის პარამეტრები</strong><br />&bull; ერთეულების სისტემა<br />&bull; ზომები<br />&bull; პროექტზე ინფორმაცია<br />&bull; გაანგარიშების ერთეულები და წესები<br /><strong>ლექცია IV: თვისებები</strong><br />&bull; ლეიერები<br />&bull; ხაზის ტიპები<br />&bull; დაფარვის ტიპები<br />&bull; შენობის მასალები<br />&bull; სიბრტყეები<br />&bull; თვისებების მართვა<br /><strong>ლექცია V: სხვადასხვა ხელსაწყოები ArchiCAD-ში</strong><br />&bull; Drawing tool<br />&bull; External content<br />&bull; Virtual trace<br />&bull; Line tool<br />&bull; Polyline tool<br />ლექცია VI: დიზაინი<br />&bull; კედელი<br />&bull; ფანჯარა<br />&bull; კარი<br />&bull; კიბე<br />&bull; სახურავი<br />&bull; სვეტი<br />&bull; კოლონა</p>\n<p><strong>ლექცია VII დიზაინი</strong><br />&bull; Objects<br />&bull; Zones<br />&bull; Meshes<br />&bull; Composites<br />&bull; Priorities<br />&bull; MEP<br />&bull; Stairs<br />&bull; Railings<br /><strong>ლექცია VIII პრაქტიკული სამუშაო</strong> <br />&bull; პრაქტიკული პროექტი<br /><strong>ლექცია IX პრაქტიკული პროექტი</strong><br />&bull; პრაქტიკული პროექტი<br /><strong>ლექცია X: პროექტის განვითარება</strong><br />&bull; დოკუმენტის ხელსაწყოები<br />&bull; მოდელის ხედები<br />&bull; განათება<br />&bull; კამერა<br />&bull; ვიზუალიზაცია</p>\n<p><strong>ლექცია XI: პრაქტიკული პროექტი</strong></p>\n<p><strong>ლექცია XII: პრაქტიკული პროექტი</strong></p>\n<p><strong>ლექცია XIII: პრაქტიკული პროექტი</strong></p>\n<p><strong>ლექცია XIV: პრაქტიკული პროექტი</strong></p>\n<p><strong>ლექცია XV: პრაქტიკული პროექტი</strong></p>\n<p><strong>ლექცია XVI: პრაქტიკული პროექტის დასრულება</strong></p>\n<p><strong>კურსის ხანგძლივობა:<br />&bull; სრული კურსი გრძელდება - 2 თვე<br />&bull; კვირაში 2 ლექცია<br />&bull; 1 ლექციის ხანგძლივობა 2 აკადემიური საათი</strong></p>\n<p><strong>ინდივიდუალურად ადგილზე შესწავლა -&nbsp;850 ლარი თვეში</strong></p>\n<p><strong>დისტანციურად: 700 ლარი&nbsp;</strong></p>\n<p><strong>წყვილში: 650 ლარი თვეში</strong></p>\n<p><strong>ჯგუფში: 550 ლარი თვეში&nbsp;</strong></p>\n<p><strong>ლექციების ჩატარება შესაძლებელია, როგორც ადგილზე ტრენინგ ცენტრში, ასევე დისტანციურად.</strong></p>\n<p><strong>[registration]</strong></p>\n<p>&nbsp;</p>\n<p>&nbsp;</p>', 'AUTOCAD', '', '', '', 'ge', 10, 0, 0),
(337, 146, 72, 1707738111, 0, 'text', 'ღვინის დეგუსტაციის კურსი', '', '<p>პროგრამა განკუთვნილია: იმ პირებისთვის, ვისაც სურს შეისწავლოს ღვინის ორგანოლეპტიკური მახასიათებლების განსაზღვრა, ღვინის შემადგენლობა, დეგუსტაციის ჩატარებისათვის აუცილებელი მოთხოვნები, ან განავითაროს ღვინის შეფასების უნარები</p>\n<p>კურსი მოიცავს: მეღვინეობაში არსებული ტერმინოლოგიის შესწავლას, ღვინის<br />წარმოების ტექნოლოგიებს, დეგუსტაციის პრინციპებს, ღვინოებს შორის<br />განსხვავებას, მათი ხარისხის განსაზღვრას, ღვინის დეგუსტაციის პრინციპებს.<br /> <br />1 ღვინის შემადგენლობა და მისი ხარისხის შემოწმება<br />2 ღვინის ორგანოლეპტიკური მახასიათებლები<br />3 ღვინის დაავადებების სახეობები <br />4 დეგუსტაციის ჩატარებისათვის აუცილებებლი პირობები<br />5 ღვინის არომატები: თეთრ, ვარდისფერ და წითელ ღვინოებში<br />6 ღვინის არომატების განსაზღვრა<br />7 შეფასების ტერმინოლოგია DLG-ის ხუთქულიანი სისტემის მიხედვით<br />8 პროფესიული დეგუსტაციის პირობები<br />9 ღვინის ნიმუშების მომზადების პრინციპები<br />10 პროფესიონალი დეგუსტატორის (სენსორული ექსპერტის) მიმართ არსებული მოთხოვნები<br />11 ღვინის შეხამება კერძებთან<br />12 ღვინის არომატების აღქმა<br />13 დეგუსტაციის ჩატარების სახეები</p>\n<p>კურსდამთავრებულის უპირატესობა: შეისწავლის მეღვინეობაში არსებულ ძირითად მიმართულებებს ღვინის დახასიათების და შეფასების მიმართულებით. შეძლებთ ღვინის მარნებში და ღვინის საწარმოებში დანერგოთ სწორი შეფასების კრიტერიუმები ხარისხიანი პროდუქტისათვის. მიღებული პრაქტიკა კი მოგცემთ საშუალებას დეგუსტაციის მოთხოვნები სრულად შეისწვლოთ.<br />სრული პროგრმის ხანგრძლივობა : 8 ლექცია</p>\n<p>პრაქტიკული ნაწილი: ღვინის სადეგუსტაციო სივრცეში დააგემოვნებთ ღვინოების სხვადასხვა სახეობებს.<br /> <br />კურსის ბოლოს ჩატარდება დასკვნითი ტესტირება და გაიცემა სერთიფიკატი!</p>\n<p>კურსს უძღვება: ანჟელა ღაჭავა - 5 წლიანი გამოცდილების მქონე მევენახე-<br />მეღვინეობის მაგისტრი, მეღვინე, ტრენერი. პროფესიული განათლების მასწავლებელი<br />მევენახეობა-მეღვინეობის მიმართულებით.</p>', 'https://vipintellect.ge/ge/bussines/Wine tasting', '', '', '', 'en', 7, 0, 1),
(338, 146, 72, 1707738111, 0, 'text', 'ღვინის დეგუსტაციის კურსი', '', '<p>პროგრამა განკუთვნილია: იმ პირებისთვის, ვისაც სურს შეისწავლოს ღვინის ორგანოლეპტიკური მახასიათებლების განსაზღვრა, ღვინის შემადგენლობა, დეგუსტაციის ჩატარებისათვის აუცილებელი მოთხოვნები, ან განავითაროს ღვინის შეფასების უნარები</p>\n<p>კურსი მოიცავს: მეღვინეობაში არსებული ტერმინოლოგიის შესწავლას, ღვინის<br />წარმოების ტექნოლოგიებს, დეგუსტაციის პრინციპებს, ღვინოებს შორის<br />განსხვავებას, მათი ხარისხის განსაზღვრას, ღვინის დეგუსტაციის პრინციპებს.<br /> <br />1 ღვინის შემადგენლობა და მისი ხარისხის შემოწმება<br />2 ღვინის ორგანოლეპტიკური მახასიათებლები<br />3 ღვინის დაავადებების სახეობები <br />4 დეგუსტაციის ჩატარებისათვის აუცილებებლი პირობები<br />5 ღვინის არომატები: თეთრ, ვარდისფერ და წითელ ღვინოებში<br />6 ღვინის არომატების განსაზღვრა<br />7 შეფასების ტერმინოლოგია DLG-ის ხუთქულიანი სისტემის მიხედვით<br />8 პროფესიული დეგუსტაციის პირობები<br />9 ღვინის ნიმუშების მომზადების პრინციპები<br />10 პროფესიონალი დეგუსტატორის (სენსორული ექსპერტის) მიმართ არსებული მოთხოვნები<br />11 ღვინის შეხამება კერძებთან<br />12 ღვინის არომატების აღქმა<br />13 დეგუსტაციის ჩატარების სახეები</p>\n<p>კურსდამთავრებულის უპირატესობა: შეისწავლის მეღვინეობაში არსებულ ძირითად მიმართულებებს ღვინის დახასიათების და შეფასების მიმართულებით. შეძლებთ ღვინის მარნებში და ღვინის საწარმოებში დანერგოთ სწორი შეფასების კრიტერიუმები ხარისხიანი პროდუქტისათვის. მიღებული პრაქტიკა კი მოგცემთ საშუალებას დეგუსტაციის მოთხოვნები სრულად შეისწვლოთ.<br />სრული პროგრმის ხანგრძლივობა : 8 ლექცია</p>\n<p>პრაქტიკული ნაწილი: ღვინის სადეგუსტაციო სივრცეში დააგემოვნებთ ღვინოების სხვადასხვა სახეობებს.<br /> <br />კურსის ბოლოს ჩატარდება დასკვნითი ტესტირება და გაიცემა სერთიფიკატი!</p>\n<p>კურსს უძღვება: ანჟელა ღაჭავა - 5 წლიანი გამოცდილების მქონე მევენახე-<br />მეღვინეობის მაგისტრი, მეღვინე, ტრენერი. პროფესიული განათლების მასწავლებელი<br />მევენახეობა-მეღვინეობის მიმართულებით.</p>', 'https://vipintellect.ge/ge/bussines/Wine tasting', '', '', '', 'ge', 7, 0, 1),
(339, 147, 140, 1707738447, 0, 'text', 'ღვინის დეგუსტაციის კურსი', '', '<p>&nbsp;</p>\n<p>პროგრამა განკუთვნილია: იმ პირებისთვის, ვისაც სურს შეისწავლოს ღვინის ორგანოლეპტიკური მახასიათებლების განსაზღვრა, ღვინის შემადგენლობა, დეგუსტაციის ჩატარებისათვის აუცილებელი მოთხოვნები, ან განავითაროს ღვინის შეფასების უნარები <br />კურსი მოიცავს: მეღვინეობაში არსებული ტერმინოლოგიის შესწავლას, ღვინის<br />წარმოების ტექნოლოგიებს, დეგუსტაციის პრინციპებს, ღვინოებს შორის<br />განსხვავებას, მათი ხარისხის განსაზღვრას, ღვინის დეგუსტაციის პრინციპებს.<br /> <br />1 ღვინის შემადგენლობა და მისი ხარისხის შემოწმება<br />2 ღვინის ორგანოლეპტიკური მახასიათებლები<br />3 ღვინის დაავადებების სახეობები <br />4 დეგუსტაციის ჩატარებისათვის აუცილებებლი პირობები<br />5 ღვინის არომატები: თეთრ, ვარდისფერ და წითელ ღვინოებში<br />6 ღვინის არომატების განსაზღვრა<br />7 შეფასების ტერმინოლოგია DLG-ის ხუთქულიანი სისტემის მიხედვით<br />8 პროფესიული დეგუსტაციის პირობები<br />9 ღვინის ნიმუშების მომზადების პრინციპები<br />10 პროფესიონალი დეგუსტატორის (სენსორული ექსპერტის) მიმართ არსებული მოთხოვნები<br />11 ღვინის შეხამება კერძებთან<br />12 ღვინის არომატების აღქმა<br />13 დეგუსტაციის ჩატარების სახეები</p>\n<p>კურსდამთავრებულის უპირატესობა: შეისწავლის მეღვინეობაში არსებულ ძირითად მიმართულებებს ღვინის დახასიათების და შეფასების მიმართულებით. შეძლებთ ღვინის მარნებში და ღვინის საწარმოებში დანერგოთ სწორი შეფასების კრიტერიუმები ხარისხიანი პროდუქტისათვის. მიღებული პრაქტიკა კი მოგცემთ საშუალებას დეგუსტაციის მოთხოვნები სრულად შეისწვლოთ.<br />სრული პროგრმის ხანგრძლივობა : 8 ლექცია</p>\n<p>პრაქტიკული ნაწილი: ღვინის სადეგუსტაციო სივრცეში დააგემოვნებთ ღვინოების სხვადასხვა სახეობებს.<br /> <br />კურსის ბოლოს ჩატარდება დასკვნითი ტესტირება და გაიცემა სერთიფიკატი!</p>\n<p>კურსს უძღვება: ანჟელა ღაჭავა - 5 წლიანი გამოცდილების მქონე მევენახე-<br />მეღვინეობის მაგისტრი, მეღვინე, ტრენერი. პროფესიული განათლების მასწავლებელი<br />მევენახეობა-მეღვინეობის მიმართულებით.</p>', 'Wine tasting', '', '', '', 'en', 1, 0, 1),
(340, 147, 140, 1707738447, 0, 'text', 'ღვინის დეგუსტაციის კურსი', '', '<p>&nbsp;</p>\n<p>პროგრამა განკუთვნილია: იმ პირებისთვის, ვისაც სურს შეისწავლოს ღვინის ორგანოლეპტიკური მახასიათებლების განსაზღვრა, ღვინის შემადგენლობა, დეგუსტაციის ჩატარებისათვის აუცილებელი მოთხოვნები, ან განავითაროს ღვინის შეფასების უნარები <br />კურსი მოიცავს: მეღვინეობაში არსებული ტერმინოლოგიის შესწავლას, ღვინის<br />წარმოების ტექნოლოგიებს, დეგუსტაციის პრინციპებს, ღვინოებს შორის<br />განსხვავებას, მათი ხარისხის განსაზღვრას, ღვინის დეგუსტაციის პრინციპებს.<br /> <br />1 ღვინის შემადგენლობა და მისი ხარისხის შემოწმება<br />2 ღვინის ორგანოლეპტიკური მახასიათებლები<br />3 ღვინის დაავადებების სახეობები <br />4 დეგუსტაციის ჩატარებისათვის აუცილებებლი პირობები<br />5 ღვინის არომატები: თეთრ, ვარდისფერ და წითელ ღვინოებში<br />6 ღვინის არომატების განსაზღვრა<br />7 შეფასების ტერმინოლოგია DLG-ის ხუთქულიანი სისტემის მიხედვით<br />8 პროფესიული დეგუსტაციის პირობები<br />9 ღვინის ნიმუშების მომზადების პრინციპები<br />10 პროფესიონალი დეგუსტატორის (სენსორული ექსპერტის) მიმართ არსებული მოთხოვნები<br />11 ღვინის შეხამება კერძებთან<br />12 ღვინის არომატების აღქმა<br />13 დეგუსტაციის ჩატარების სახეები</p>\n<p>კურსდამთავრებულის უპირატესობა: შეისწავლის მეღვინეობაში არსებულ ძირითად მიმართულებებს ღვინის დახასიათების და შეფასების მიმართულებით. შეძლებთ ღვინის მარნებში და ღვინის საწარმოებში დანერგოთ სწორი შეფასების კრიტერიუმები ხარისხიანი პროდუქტისათვის. მიღებული პრაქტიკა კი მოგცემთ საშუალებას დეგუსტაციის მოთხოვნები სრულად შეისწვლოთ.<br />სრული პროგრმის ხანგრძლივობა : 8 ლექცია</p>\n<p>პრაქტიკული ნაწილი: ღვინის სადეგუსტაციო სივრცეში დააგემოვნებთ ღვინოების სხვადასხვა სახეობებს.<br /> <br />კურსის ბოლოს ჩატარდება დასკვნითი ტესტირება და გაიცემა სერთიფიკატი!</p>\n<p>კურსს უძღვება: ანჟელა ღაჭავა - 5 წლიანი გამოცდილების მქონე მევენახე-<br />მეღვინეობის მაგისტრი, მეღვინე, ტრენერი. პროფესიული განათლების მასწავლებელი<br />მევენახეობა-მეღვინეობის მიმართულებით.</p>', 'Wine-tasting', '', '', '', 'ge', 1, 0, 1),
(341, 148, 7, 1707738704, 0, 'text', 'ღვინის დეგუსტაციის კურსი', '', '<p>პროგრამა განკუთვნილია: იმ პირებისთვის, ვისაც სურს შეისწავლოს ღვინის ორგანოლეპტიკური მახასიათებლების განსაზღვრა, ღვინის შემადგენლობა, დეგუსტაციის ჩატარებისათვის აუცილებელი მოთხოვნები, ან განავითაროს ღვინის შეფასების უნარები</p>\n<p>კურსი მოიცავს: მეღვინეობაში არსებული ტერმინოლოგიის შესწავლას, ღვინის<br />წარმოების ტექნოლოგიებს, დეგუსტაციის პრინციპებს, ღვინოებს შორის<br />განსხვავებას, მათი ხარისხის განსაზღვრას, ღვინის დეგუსტაციის პრინციპებს.<br /> <br />1 ღვინის შემადგენლობა და მისი ხარისხის შემოწმება<br />2 ღვინის ორგანოლეპტიკური მახასიათებლები<br />3 ღვინის დაავადებების სახეობები <br />4 დეგუსტაციის ჩატარებისათვის აუცილებებლი პირობები<br />5 ღვინის არომატები: თეთრ, ვარდისფერ და წითელ ღვინოებში<br />6 ღვინის არომატების განსაზღვრა<br />7 შეფასების ტერმინოლოგია DLG-ის ხუთქულიანი სისტემის მიხედვით<br />8 პროფესიული დეგუსტაციის პირობები<br />9 ღვინის ნიმუშების მომზადების პრინციპები<br />10 პროფესიონალი დეგუსტატორის (სენსორული ექსპერტის) მიმართ არსებული მოთხოვნები<br />11 ღვინის შეხამება კერძებთან<br />12 ღვინის არომატების აღქმა<br />13 დეგუსტაციის ჩატარების სახეები</p>\n<p>კურსდამთავრებულის უპირატესობა: შეისწავლის მეღვინეობაში არსებულ ძირითად მიმართულებებს ღვინის დახასიათების და შეფასების მიმართულებით. შეძლებთ ღვინის მარნებში და ღვინის საწარმოებში დანერგოთ სწორი შეფასების კრიტერიუმები ხარისხიანი პროდუქტისათვის. მიღებული პრაქტიკა კი მოგცემთ საშუალებას დეგუსტაციის მოთხოვნები სრულად შეისწვლოთ.<br />სრული პროგრმის ხანგრძლივობა : 8 ლექცია</p>\n<p>პრაქტიკული ნაწილი: ღვინის სადეგუსტაციო სივრცეში დააგემოვნებთ ღვინოების სხვადასხვა სახეობებს.<br /> <br />კურსის ბოლოს ჩატარდება დასკვნითი ტესტირება და გაიცემა სერთიფიკატი!</p>\n<p>კურსს უძღვება: ანჟელა ღაჭავა - 5 წლიანი გამოცდილების მქონე მევენახე-<br />მეღვინეობის მაგისტრი, მეღვინე, ტრენერი. პროფესიული განათლების მასწავლებელი<br />მევენახეობა-მეღვინეობის მიმართულებით.</p>', 'Wine tasting', '', '', '', 'en', 8, 0, 1),
(342, 148, 7, 1707738704, 0, 'text', 'ღვინის დეგუსტაციის კურსი', '', '<p><strong>პროგრამა განკუთვნილია:</strong> იმ პირებისთვის, ვისაც სურს შეისწავლოს ღვინის ორგანოლეპტიკური მახასიათებლების განსაზღვრა, ღვინის შემადგენლობა, დეგუსტაციის ჩატარებისათვის აუცილებელი მოთხოვნები, ან განავითაროს ღვინის შეფასების უნარები</p>\n<p><strong>კურსი მოიცავს</strong>: მეღვინეობაში არსებული ტერმინოლოგიის შესწავლას, ღვინის<br />წარმოების ტექნოლოგიებს, დეგუსტაციის პრინციპებს, ღვინოებს შორის<br />განსხვავებას, მათი ხარისხის განსაზღვრას, ღვინის დეგუსტაციის პრინციპებს.<br /> <br />1 ღვინის შემადგენლობა და მისი ხარისხის შემოწმება<br />2 ღვინის ორგანოლეპტიკური მახასიათებლები<br />3 ღვინის დაავადებების სახეობები <br />4 დეგუსტაციის ჩატარებისათვის აუცილებებლი პირობები<br />5 ღვინის არომატები: თეთრ, ვარდისფერ და წითელ ღვინოებში<br />6 ღვინის არომატების განსაზღვრა<br />7 შეფასების ტერმინოლოგია DLG-ის ხუთქულიანი სისტემის მიხედვით<br />8 პროფესიული დეგუსტაციის პირობები<br />9 ღვინის ნიმუშების მომზადების პრინციპები<br />10 პროფესიონალი დეგუსტატორის (სენსორული ექსპერტის) მიმართ არსებული მოთხოვნები<br />11 ღვინის შეხამება კერძებთან<br />12 ღვინის არომატების აღქმა<br />13 დეგუსტაციის ჩატარების სახეები</p>\n<p><strong>კურსდამთავრებულის უპირატესობა:</strong> შეისწავლის მეღვინეობაში არსებულ ძირითად მიმართულებებს ღვინის დახასიათების და შეფასების მიმართულებით. შეძლებთ ღვინის მარნებში და ღვინის საწარმოებში დანერგოთ სწორი შეფასების კრიტერიუმები ხარისხიანი პროდუქტისათვის. მიღებული პრაქტიკა კი მოგცემთ საშუალებას დეგუსტაციის მოთხოვნები სრულად შეისწვლოთ.<br /><strong>სრული პროგრმის ხანგრძლივობა : 8 ლექცია</strong></p>\n<p><strong>კურსის ღირებულება ჯგუფში: 450 ლარი</strong></p>\n<p><strong>წყვილში: 550 ლარი</strong></p>\n<p><strong>ინდივიდუალურად: 700 ლარი</strong></p>\n<p><strong>პრაქტიკული ნაწილი:</strong> ღვინის სადეგუსტაციო სივრცეში დააგემოვნებთ ღვინოების სხვადასხვა სახეობებს.<br /> <br />კურსის ბოლოს ჩატარდება დასკვნითი ტესტირება და გაიცემა სერთიფიკატი!</p>\n<p><strong>კურსს უძღვება:</strong> ანჟელა ღაჭავა - 5 წლიანი გამოცდილების მქონე მევენახე-<br />მეღვინეობის მაგისტრი, მეღვინე, ტრენერი. პროფესიული განათლების მასწავლებელი<br />მევენახეობა-მეღვინეობის მიმართულებით.</p>\n<pre id=\"tw-target-text\" class=\"tw-data-text tw-text-large tw-ta\" dir=\"ltr\" data-placeholder=\"თარგმანი\"><span class=\"Y2IQFc\" lang=\"en\">[registration]</span></pre>', 'Wine-tasting', '', '', '', 'ge', 8, 0, 1),
(344, 149, 40, 1723710983, 0, 'text', 'ინგლისური ენა სკოლის მოსწავლეებისთვის', '<p>ინგლისური ბავშვებისთის და აბიტურიენტებისთვის</p>', '<p><strong>ინგლისური ენა სკოლის ასაკის ბავშვებისთვის მე-4 დან მე-12 კლასის ჩათვლით</strong></p>\n<p>მეცადინეობები მიმდინარეობს, როგორც ინდივიდუალურად, ასევე წყვილში და ჯგუფში</p>\n<p>ლექციები ჩატარდება კვირაში: 2 ჯერ</p>\n<p>სწავლის ღირებულება თვეში</p>\n<p>ჯგუფში&nbsp; - 100 ლარი</p>\n<p>ინდივიდუალურად - 150 ლარი</p>\n<p>ინდივიდუალურად: 180 ლარი</p>\n<p><strong>აბიტურიენტების მომზადება</strong></p>\n<p>ჯგუფში - 120 ლარი</p>\n<p>წყვილში - 180 ლარი</p>\n<p>ინდივიდუალურად: 240 ლარი</p>', 'eng-ch', '', '', '', 'ge', 6, 0, 0);
INSERT INTO `navigation` (`id`, `idx`, `cid`, `date`, `nav_type`, `type`, `title`, `description`, `text`, `slug`, `usefull_type`, `cssclass`, `redirect`, `lang`, `position`, `visibility`, `status`) VALUES
(346, 150, 8, 1729513059, 0, 'text', 'MS SQL Server-ის ადმინისტრირება და MS SQL სერვერის გამოყენება და მხარდაჭერა', '<p>MS SQL Server-ის ადმინისტრირების და MS SQL სერვერის გამოყენება და მხარდაჭერის კურსები!</p>', '<p>ლექციების ჩატარება შესაძლებელია, როგორც დისტანციურად, ასევე ტრენინგ ცენტრში ან კორპორატიული დაკვეთის შემთხვევაში დამკვეთი კომპანიის სივრცეში!</p>\n<p><strong>1. MS SQL Server-ის ადმინისტრირების კურსი.</strong><br />კურსი განიხილავს რელაციური მონაცემთა ბაზების ადმინისტრირების მეთოდებს. თეორიული ცოდნის მიღების გარდა კურსის მონაწილეები დაეუფლებიან მონაცემთა ბაზების ადმინისტრირების პრაქტიკულ გამოცდილებასა და ჩვევებს. <br />კურსის ბოლოს მსმენელები მიიღებენ ცოდნის დამადასტურებელ სერტიფიკატს და დამოუკიდებლად შეძლებენ ადმინისტრირება გაუწიონ მონაცემთა ბაზებს.</p>\n<p><strong>სასწავლო კურსის შესწავლის წინაპირობები:</strong><br />&bull; Microsoft Windows ოპერაციული სისტემის და მისი ძირითადი ფუნქციების ცოდნა.<br />&bull; Transact-SQL-ზე მუშაობის გამოცდილება.<br />&bull; რელაციური მონაცემთა ბაზების ცოდნა.<br />&bull; გამოცდილება მონაცემთა ბაზების დიზაინის კუთხით.<br />კურსის შინაარსი:<br />&bull; SQL Server-ის დაინსტალირება.<br />&bull; SQL Server მონაცემთა ბაზების კონფიგურაცია.<br />&bull; SQL Server-ის აღდგენის მოდელების აღწერა.<br />&bull; მონაცემთა ბაზების სარეზერვო ასლების აღდგენა.<br />&bull; მონაცემთა ბაზების აღდგენა.<br />&bull; მონაცემების იმპორტი და ექსპორტი.<br />&bull; მომხმარებლების ავტორიზაცია.<br />&bull; სერვერული და მონაცემთა ბაზების როლები.<br />&bull; უფლებების გაცემა და კონფიგურაცია.<br />&bull; მონაცემთა ბაზების დაშიფვრა და აუდიტის გამოყენება.<br />&bull; SQL Server Agent-ის და Job-ების მართვა. <br />&bull; SQL Server აგენტის უსაფრთხოების კონფიგურაცია.<br />&bull; მონაცემთა ბაზის ფოსტის, შეტყობინებების და გაფრთხილებების კონფიგურაცია.<br />&bull; მონაცემთა ბაზების შენარჩუნება.<br />&bull; SQL Profiler-ის, SQL Trace-ის კონფიგურაცია და მონაცემთა ბაზის ძრავის Tuning Advisor-ის გამოიყენება.<br />&bull; მონაცემების მონიტორინგი დინამიკური მართვის თვალსაზრისით.<br /><strong>განსახილველი თემები:</strong><br /><strong>&nbsp;1: SQL Server მონაცემთა ბაზის ადმინისტრირების შესავალი.</strong><br />&bull; მონაცემთა ბაზის ადმინისტრირების მიმოხილვა.<br />&bull; SQL Server-ის პლატფორმის გაცნობა.<br />&bull; მონაცემთა ბაზების მართვის ინსტრუმენტები და ტექნიკა.<br /><strong>2: SQL Server-ის ინსტალაცია და კონფიგურაცია.</strong><br />&bull; SQL Server-ის ინსტალაციის დაგეგმვა. <br />&bull; SQL Server-ის ინსტალაცია. <br />&bull; პოსტ-ინსტალაციის კონფიგურაცია.<br /><strong>3: მონაცემთა ბაზების მეხსიერებაზე მუშაობა.</strong><br />&bull; მონაცემთა საცავის SQL Server-ისთვის წარდგენა.<br />&bull; სისტემური მონაცემთა ბაზების საცავის მართვა.<br />&bull; მომხმარებლების მონაცემთა ბაზის მონაცემთა საცავის მართვა.<br />&bull; მონაცემთა ბაზის ფაილების წაშლა.<br />&bull; ბუფერული ქეშის კონფიგურაცია.<br /><strong>4: სარეზერვო (Backup) სტრატეგიის დაგეგმვა და განხორციელება.</strong><br />&bull; აღდგენის მოდელები.<br />&bull; სარეზერვო ასლების სტრატეგიის დაგეგმვა.<br />&bull; მონაცემთა ბაზებისა და ტრანზაქციების ლოგ ჟურნალების აღდგენა.<br />&bull; სარეზერვო ასლების პარამეტრების გამოყენება.<br />&bull; სარეზერვო ასლების საიმედოობის უზრუნველყოფა.<br /><strong>5: MS SQL Server მონაცემთა ბაზების აღდგენა (Restore).</strong><br />&bull; აღდგენის პროცესის გაცნობა.<br />&bull; მონაცემთა ბაზების აღდგენა.<br />&bull; მოწინავე (Advanced) აღდგენის სცენარები .<br />&bull; Point-in-Time აღდგენა.<br /><strong>6: მონაცემთა იმპორტი და ექსპორტი.</strong><br />&bull; მონაცემთა მიმოცვლის მოდულის შესავალი.<br />&bull; მონაცემთა იმპორტი და ექსპორტი. <br />&bull; მონაცემთა ბაზების დაკოპირება და გადაადგილება. <br /><strong>7: SQL Server-ის მუშაობის მონიტორინგი.</strong><br />&bull; SQL Server-ის მონიტორინგის შესავალი.<br />&bull; დინამიკური მართვის View-ები და ფუნქციები.<br />&bull; Performance Monitor.<br /><strong>8: SQL Server-ის აქტივობის გამოკვლევა.</strong><br />&bull; SQL Server-ის დატვირთვის მოკვლევა.<br />&bull; Trace-ების გამოყენება.<br /><strong>დღე 9: უსაფრთხოების მართვა SQL Server-ში.</strong><br />&bull; SQL Server უსაფრთხოების შესავალი.<br />&bull; სერვერული დონის უსაფრთხოების მართვა.<br />&bull; მონაცემთა ბაზის დონის ძირითადი ასპექტები.<br />&bull; მონაცემთა ბაზის უფლებები.<br /><strong>10: მონაცემებზე წვდომის აუდიტი და დაშიფვრა.</strong><br />&bull; მონაცემებზე წვდომის აუდიტი SQL Server-ში.<br />&bull; აუდიტის განხორციელება SQL Server-ში.<br />&bull; მონაცემთა ბაზების დაშიფვრა.<br /><strong>11: SQL Server-ის მენეჯმენტის ავტომატიზირება.</strong><br />&bull; SQL Server-ის მართვის ავტომატიზაცია.<br />&bull; SQL Server Agent Job-ების განხორციელება.<br />&bull; SQL Server Agent Job-ების მართვა.<br />&bull; Job Step Security კონტექსტის მართვა.<br />&bull; Job-ების მართვა მრავალ სერვერზე.<br /><strong>12: ბაზების მონიტორინგი შეტყობინებებით და გაფრთხილებებით.</strong><br />&bull; SQL Server-ის შეცდომების მონიტორინგი. <br />&bull; მონაცემთა ბაზის ფოსტის (Database Mail) კონფიგურაცია.<br />&bull; ოპერატორების, შეტყობინებების და Alert-ების კონფიგურაცია.</p>\n<p><strong>კურსის ხანგრძლივობა: 12 ლექცია (კვირაში 2-3ჯერ)</strong><br /><strong>ლექციის ხანგრძლივობა: 1 სთ 30წთ</strong><br /><strong>ღირებულება:</strong></p>\n<p><strong>700 ლარი&nbsp; ჯგუფში - ადგილზე</strong></p>\n<p><strong>600 ლარი ჯგუფში დისტანციურად</strong></p>\n<p><strong>1050 ლარი - ინდივიდუალურად ადგილზე</strong></p>\n<p><strong>950 ლარი&nbsp; - ინდივიდუალურად&nbsp; დისტანციურად</strong></p>\n<p>[registration]</p>\n<p><strong>MS SQL სერვერის გამოყენება და მხარდაჭერა.</strong></p>\n<p><strong>სასწავლო კურსის მიზანია:</strong> კურსის მონაწილე გაეცნოს რელაციურ მონაცემთა ბაზებთან მუშაობის ძირითად მეთოდებს. კურსის ბოლოს მსმენელი მიიღებენ ცოდნის დამადასტურებელ სერტიფიკატს.</p>\n<p><strong>კურსის შინაარსი:</strong><br />&bull; SQL Server-ის პლატფორმის გაცნობა.<br />&bull; SQL Server-ის დაინსტალირება.<br />&bull; SQL Server მონაცემთა ბაზების კონფიგურაცია.<br />&bull; T-SQL-ის შესავალი, SELECT მოთხოვნების დაწერა.<br />&bull; DML-ის გამოყენება მონაცემთა მოდიფიცირებისთვის.<br />&bull; მრავალი ცხრილიდან მონაცემების ქუერინგი, Join-ები, მონაცემთა დაჯგუფება და გაერთიანება.<br />&bull; მონაცემთა დახარისხება და გაფილტვრა, SQL Server-ის მონაცემთა ტიპებთან მუშაობა.<br />&bull; მონაცემთა კონვერტაცია, შეზღუდვები.<br />&bull; ფუნქციები, პროცედურები, ტრიგერები და ინდექსები.</p>\n<p><strong>განსახილველი თემები:</strong></p>\n<p><strong>1: შესავალი Microsoft SQL Server-ში.</strong><br />&bull; SQL სერვერის ძირითადი არქიტექტურა.<br />&bull; SQL Server-ის პლატფორმის გაცნობა.<br />&bull; მონაცემთა ბაზების მართვის ინსტრუმენტები და ტექნიკა.<br />&bull; SQL Server გამოცემები და ვერსიები.<br />&bull; SQL Server-ის ინსტალაციის დაგეგმვა. <br />&bull; SQL Server-ის ინსტალაცია. <br />&bull; პოსტ-ინსტალაციის კონფიგურაცია. <br />&bull; SQL Server Management Studio-ში მუშაობა.<br /><strong>2: T-SQL-ის შესავალი, SELECT მოთხოვნების დაწერა.</strong><br />&bull; T-SQL-ის გაცნობა.<br />&bull; ნაკრებები (Sets) გაგება.<br />&bull; პრედიკატების ლოგიკის გაგება.<br />&bull; ლოგიკური ოპერაციები SELECT ბრძანებებში.<br />&bull; SELECT ბრძნებების დაწერა.<br />&bull; დუბლიკატების აღმოფხვრა DISTINCT ბრძანებით.<br />&bull; სვეტისა და ცხრილის მეტსახელების გამოყენება.<br />&bull; CASE გამოსახულებები.<br /><strong>3: DML&ndash;ის გამოყენება მონაცემთა მოდიფიცირებისთვის.</strong><br />&bull; მოდულის მიმოხილვა.<br />&bull; მონაცემთა დამატება ცხრილებში.<br />&bull; მონაცემების შეცვლა და წაშლა.<br />&bull; რიცხვების გენერირება.<br />&bull; ტრანზაქციები და ტრანზაქციების კონტროლი.<br /><strong>4: მრავალი ცხრილიდან მონაცემების ამოღება, მათი დაჯგუფება და გაერთიანება.</strong><br />&bull; Joins. <br />&bull; Inner Joins.<br />&bull; Outer Joins.<br />&bull; Querying with Cross Joins and Self Joins.<br />&bull; აგრეგატული ფუნქციები.<br />&bull; GROUP BY ფუნქციის გამოყენება.<br />&bull; HAVING გამოყენება.<br /><strong>5: მონაცემთა დახარისხება და გაფილტვრა. SQL Server-ის მონაცემთა ტიპებთან მუშაობა.</strong><br />&bull; მონაცემთა დახარისხება.<br />&bull; მონაცემთა გაფილტვრა პრედიკატებით.<br />&bull; მონაცემთა გაფილტვრა TOP და OFFSET-FETCH ბრძანებებით.<br />&bull; უცნობ მნიშვნელობებზე მუშაობა.<br />&bull; SQL Server-ის მონაცემთა ტიპების გაცნობა.<br />&bull; მონაცემთა ტიპებთან მუშაობა.<br />&bull; თარიღისა და დროის მონაცემებთან მუშაობა.<br /><strong>6: ჩაშენებული ფუნქციების გამოყენება.</strong><br />&bull; ბრძანებების წერა ჩაშენებული ფუნქციებით.<br />&bull; კონვერტაციის ფუნქციების გამოყენება.<br />&bull; ლოგიკური ფუნქციების გამოყენება.<br />&bull; ფუნქციების გამოყენება NULL თან სამუშაოდ.<br /><strong>7: ფუნქციების, პროცედურების და ტრიგერების აღწერა.</strong><br />&bull; ტრიგერები და მიმდევრობები, პროცედურები და ფუნქციები.<br />&bull; მათი გამოყენება SELECT ბრძანებებში.<br />&bull; შექმნა, შეცვლა და წაშლა.</p>\n<p><strong>8: მონაცემთა ორგანიზება და მათზე წდომა, შეზღუდვები.</strong><br />&bull; არაკლასტერული ინდექსი.<br />&bull; კლასტერული ინდექსი.<br />&bull; უნიკალური ინდექსი.<br />&bull; ინდექსის შექმნა.<br />&bull; ინდექსების მართვა.<br />&bull; ძირითადი გასაღები.<br />&bull; მეორადი გასაღები.</p>\n<p><strong>კურსის ხანგრძლივობა: 8 ლექცია (კვირაში 2-3ჯერ)</strong><br /><strong>ლექციის ხანგრძლივობა: 1 სთ30წთ</strong></p>\n<p><strong>600 ლარი&nbsp;&nbsp;ჯგუფში - ადგილზე</strong></p>\n<p><strong>500 ლარი ჯგუფში დისტანციურად</strong></p>\n<p><strong>950 ლარი - ინდივიდუალურად ადგილზე</strong></p>\n<p><strong>850 ლარი&nbsp; - ინდივიდუალურად&nbsp; დისტანციურად</strong></p>\n<p>[registration]</p>\n<p>&nbsp;</p>', 'SQL', '', '', 'SQL', 'ge', 7, 0, 0),
(353, 154, 72, 1761643986, 0, 'text', 'კომერციული ანალიტიკის კურსი', '<p>კომერციული ანალიტიკის კურსი</p>', '<p>კურსის მიზანი:<br />კურსის მიზანია მოამზადოს პროფესიონალები შესყიდვების, ბრენდის და პროდუქტების მენეჯმენტის მიმართულებით, რომლებიც სიღრმისეულად შეისწავლიან ანალიტიკურ მეთოდებს და შეძლებენ მათი გამოყენებას კომერციისა და ბიზნესის პრაქტიკაში.<br />ვისთვის არის განკუთვნილი:<br />კურსი განკუთვნილია გაყიდვების, შესყიდვების და მარკეტინგის სფეროში განვითარების მსურველთათვის, რომლებიც სურთ ანალიტიკური აზროვნების გაღრმავება და კომერციული პროცესების ეფექტიანად მართვა.</p>\n<p>1. Excel ინსტრუმენტების შესწავლა და გამოყენება <br />&bull;მონაცემთა ბაზების შექმნა და დაკავშირება (Vlookup / Hlookup), <br />&bull;მონაცემთა დაჯგუფება და ანალიტიკა (Pivot Table, What-If Analysis) <br />&bull; Data Management და Cleaning Techniques (მონაცემების ფილტრაცია, დუბლიკატების მოცილება, Validation) <br />&bull; Dynamic References, Named Ranges, Conditional Formatting <br />ფუნქციების შესწავლა და პრაქტიკული გამოყენება: <br />If, And, Or, Not, Vlookup, Iferror, Sumifs, Averageifs, Countifs, Stdev, Median, Correl, rand,Randbetween, Round, Int, Date, Eomonth, Concat, Left/Right/Mid, Text, Proper, Now, Month, Day &hellip;</p>\n<p>2. მარაგების მართვა და ABC ანალიზი <br />&bull; ოპტიმალური სტოკის მაჩვენებლების გაანგარიშება <br />&bull; დეფიციტების და Overstock-ის განსაზღვრა, FML -კრიტერიუმების დადგენა<br />&bull; ABC ანალიზი და პროდუქტების კატეგორიზაცია პრიორიტეტებით <br />&bull; პარეტოს პრინციპი და მისი როლი პროდუქტ-მენეჯმენტში <br />&bull; პრაქტიკული ქეისების განხილვა და ანალიზი რეალურ მაგალითებზე <br />&bull; სხვადასხვა კატეგორიების მართვის მეთოდები</p>\n<p>3. შესყიდვების დაგეგმვა <br />&bull; სტრატეგიების დაგეგმვა პროდუქტების / კატეგორიების მიხედვით <br />&bull; გაყიდვების ანალიზის გამოყენება შესყიდვების გეგმის ფორმირებაში<br />&bull; კომბინირებული სტრატეგიულ-ანალიტიკური მოდელი <br />&bull; შესყიდვების დაგეგმვის პარამეტრები <br />&bull; ოპტიმალური მარაგების ფორმირება</p>\n<p>4. ფინანსური და კომერციული კოეფიციენტების შეფასება: <br />&bull; მარჟა (Gross Margin%) <br />&bull; ფასნამატი (Markup) &ndash; კავშირი მარჟას და ფასნამატს შორის <br />&bull; მოგება-ზარალი და მომგებიანობა (Net Margin%) <br /> &bull; კომერციული მომგებიანობის კოეფიციენტი: Margin/Stock<br />&bull; მარაგების ბრუნვადობა (Inventory Turnover) &ndash; ნელი და სწრაფად ბრუნვადი საქონლის კრიტერიუმების დადგენა <br />&bull; ROI &ndash; პროექტის მომგებიანობა</p>\n<p>5. მარჟის და ფასწარმოქმნის ანალიზი და მართვა <br />&bull; შესყიდული საქონლის თვითღირებულების კალკულაცია <br />&bull; საფასო სტრატეგიები <br />&bull; კონკურენტულ გარემოში ფასების ცვლილებების მართვა <br />&bull; CVP (Cost-Volume-Profit) და Break-Even ანალიზი <br />&bull; სენსიტიურობის ანალიზი და მისი გამოყენება</p>\n<p>კურსის ღირებულება ინდივიდუალურად 700 ლარი <br />ჯგუფში 480 ლარი<br />ხანგრძლივობა 8 ლექცია</p>', 'Commercial analytics', '', '', '', 'en', 3, 0, 1),
(354, 154, 72, 1761643986, 0, 'text', 'კომერციული ანალიტიკის პრაქტიკული კურსი', '<p>კომერციული ანალიტიკის კურსი</p>', '<p><strong>კურსის მიზანი:</strong><br />კურსის მიზანია მოამზადოს პროფესიონალები შესყიდვების, ბრენდის და პროდუქტების მენეჯმენტის მიმართულებით, რომლებიც სიღრმისეულად შეისწავლიან ანალიტიკურ მეთოდებს და შეძლებენ მათი გამოყენებას კომერციისა და ბიზნესის პრაქტიკაში.<br />ვისთვის არის განკუთვნილი:<br />კურსი განკუთვნილია გაყიდვების, შესყიდვების და მარკეტინგის სფეროში განვითარების მსურველთათვის, რომლებიც სურთ ანალიტიკური აზროვნების გაღრმავება და კომერციული პროცესების ეფექტიანად მართვა.</p>\n<p><strong>1. Excel ინსტრუმენტების შესწავლა და გამოყენება</strong> <br />&bull;მონაცემთა ბაზების შექმნა და დაკავშირება (Vlookup / Hlookup), <br />&bull;მონაცემთა დაჯგუფება და ანალიტიკა (Pivot Table, What-If Analysis) <br />&bull; Data Management და Cleaning Techniques (მონაცემების ფილტრაცია, დუბლიკატების მოცილება, Validation) <br />&bull; Dynamic References, Named Ranges, Conditional Formatting <br />ფუნქციების შესწავლა და პრაქტიკული გამოყენება: <br />If, And, Or, Not, Vlookup, Iferror, Sumifs, Averageifs, Countifs, Stdev, Median, Correl, rand,Randbetween, Round, Int, Date, Eomonth, Concat, Left/Right/Mid, Text, Proper, Now, Month, Day &hellip;</p>\n<p><strong>2. მარაგების მართვა და ABC ანალიზი</strong> <br />&bull; ოპტიმალური სტოკის მაჩვენებლების გაანგარიშება <br />&bull; დეფიციტების და Overstock-ის განსაზღვრა, FML -კრიტერიუმების დადგენა<br />&bull; ABC ანალიზი და პროდუქტების კატეგორიზაცია პრიორიტეტებით <br />&bull; პარეტოს პრინციპი და მისი როლი პროდუქტ-მენეჯმენტში <br />&bull; პრაქტიკული ქეისების განხილვა და ანალიზი რეალურ მაგალითებზე <br />&bull; სხვადასხვა კატეგორიების მართვის მეთოდები</p>\n<p><strong>3. შესყიდვების დაგეგმვა</strong> <br />&bull; სტრატეგიების დაგეგმვა პროდუქტების / კატეგორიების მიხედვით <br />&bull; გაყიდვების ანალიზის გამოყენება შესყიდვების გეგმის ფორმირებაში<br />&bull; კომბინირებული სტრატეგიულ-ანალიტიკური მოდელი <br />&bull; შესყიდვების დაგეგმვის პარამეტრები <br />&bull; ოპტიმალური მარაგების ფორმირება</p>\n<p><strong>4. ფინანსური და კომერციული კოეფიციენტების შეფასება:</strong> <br />&bull; მარჟა (Gross Margin%) <br />&bull; ფასნამატი (Markup) &ndash; კავშირი მარჟას და ფასნამატს შორის <br />&bull; მოგება-ზარალი და მომგებიანობა (Net Margin%) <br /> &bull; კომერციული მომგებიანობის კოეფიციენტი: Margin/Stock<br />&bull; მარაგების ბრუნვადობა (Inventory Turnover) &ndash; ნელი და სწრაფად ბრუნვადი საქონლის კრიტერიუმების დადგენა <br />&bull; ROI &ndash; პროექტის მომგებიანობა</p>\n<p><strong>5. მარჟის და ფასწარმოქმნის ანალიზი და მართვა</strong> <br />&bull; შესყიდული საქონლის თვითღირებულების კალკულაცია <br />&bull; საფასო სტრატეგიები <br />&bull; კონკურენტულ გარემოში ფასების ცვლილებების მართვა <br />&bull; CVP (Cost-Volume-Profit) და Break-Even ანალიზი <br />&bull; სენსიტიურობის ანალიზი და მისი გამოყენება</p>\n<p><strong>კურსის ღირებულება ინდივიდუალურად 700 ლარი </strong><br /><strong>ჯგუფში 480 ლარი</strong><br /><strong>ხანგრძლივობა 8 ლექცია</strong></p>\n<p><strong>შეავსე</strong>&nbsp;<strong>სარეგისტრაციო</strong>&nbsp;<strong>ფორმა</strong>&nbsp;<strong>და</strong>&nbsp;<strong>დარეგისტრირდი</strong>&nbsp;<strong>ჯგუფში</strong><strong>:</strong></p>\n<p>[registration]</p>', 'Commercial-analytics', '', '', 'https://vipintellect.ge/ge//Commercial analytics', 'ge', 3, 0, 1),
(355, 155, 72, 1771410826, 0, 'text', 'სამშენებლო ხარისხის კონტროლი', '<p>სამშენებლო ხარისხის კონტროლი</p>', '<p><strong>ვისთვის არის აღნიშნული პროგრამა:</strong><br />პროგრამის მიზანია კვალიფიკაცის ამაღლება და პროფსეიონალური უნარების შესწავლა, მათთვის ვისაც სურს ცოდნის შეძენა სამშენებლო წარმოებაზე და ხარისხის კონტროლზე.</p>\n<p><br /><strong>ტრეინინგის თემატიკა:</strong><br />-მიწის სამუშაოების კონტროლი და ხარისხი 1სთ<br />-მონოლითის წარმოება და ხარისხის კონტროლი და მეთოდოლოგია 4სთ<br />-არქიტექტურული ნაწილის ხარისხი და კონტროლი; 4სთ<br />(ბლოკი, ლესვა, მოჭიმვა,)<br />-კარფანჯრების მონტაჯის ხარისხი 1სთ<br />-&bdquo;სველი&ldquo; და ვინტილირებადი ფასადის ხარისხი 2სთ<br />-სახურავის სენდვიჩების ხარისხი 2სთ<br />-კეთილმოწყობა 2სთ<br />(ასფალტი, ბილიკები, ბორდიურები, გამწვანება)</p>\n<p>კურსი მოიცავს: 8 ლექციას</p>\n<p>ლექციები ცატარდება: კვირაში 2 ჯერ</p>', 'https://vipintellect.ge/ge/building control', '', '', '', 'en', 5, 0, 1),
(356, 155, 72, 1771410826, 0, 'text', 'სამშენებლო ხარისხის კონტროლი', '<p>სამშენებლო ხარისხის კონტროლი</p>', '<p><strong>ვისთვის არის აღნიშნული პროგრამა:</strong><br />პროგრამის მიზანია კვალიფიკაცის ამაღლება და პროფსეიონალური უნარების შესწავლა, მათთვის ვისაც სურს ცოდნის შეძენა სამშენებლო წარმოებაზე და ხარისხის კონტროლზე.<br /><strong>ტრეინინგის თემატიკა:</strong><br />-მიწის სამუშაოების კონტროლი და ხარისხი 1სთ<br />-მონოლითის წარმოება და ხარისხის კონტროლი და მეთოდოლოგია 4სთ<br />-არქიტექტურული ნაწილის ხარისხი და კონტროლი; 4სთ<br />(ბლოკი, ლესვა, მოჭიმვა,)<br />-კარფანჯრების მონტაჯის ხარისხი 1სთ<br />-&bdquo;სველი&ldquo; და ვინტილირებადი ფასადის ხარისხი 2სთ<br />-სახურავის სენდვიჩების ხარისხი 2სთ<br />-კეთილმოწყობა 2სთ<br />(ასფალტი, ბილიკები, ბორდიურები, გამწვანება)</p>\n<p><strong>კურსი მოიცავს: 8 ლექციას</strong></p>\n<p><strong>ლექციები ცატარდება: კვირაში 2 ჯერ</strong></p>\n<p><strong>კურსის ღირებულება: 600 ლარი</strong></p>\n<p><strong>საუკეთესო კურსდამთავრებულებს გავუწევთ რეკომენდაციებს და მოთხოვნის შესაბამისად ხელს შევუწყოთ დასაქმებაში!</strong></p>\n<p><strong>კურსს უძღვებიან: შოთა კოხრეიძე -&nbsp;</strong>პრაქტიკოსი ტრენერი, მშენებელი 20 წლიანი გამოცდილებით.</p>\n<p><strong>შეავსე სარეგისტრაციო ფორმა და დარეგისტრირდი ჯგუფში:</strong></p>\n<p>[registration]</p>\n<p>&nbsp;</p>\n<p>&nbsp;</p>', 'https://vipintellect.ge/ge/building-control', '', '', 'https://vipintellect.ge/ge/bussines', 'ge', 5, 0, 1),
(357, 156, 72, 1771412535, 0, 'text', 'სამშენებლო ხარისხის კონტროლი', '<p>სამშენებლო ხარისხის კონტროლი</p>', '<p><strong>ვისთვის არის აღნიშნული პროგრამა:</strong><br />პროგრამის მიზანია კვალიფიკაცის ამაღლება და პროფსეიონალური უნარების შესწავლა, მათთვის ვისაც სურს ცოდნის შეძენა სამშენებლო წარმოებაზე და ხარისხის კონტროლზე.<br /><strong>ტრეინინგის თემატიკა:</strong><br />-მიწის სამუშაოების კონტროლი და ხარისხი 1სთ<br />-მონოლითის წარმოება და ხარისხის კონტროლი და მეთოდოლოგია 4სთ<br />-არქიტექტურული ნაწილის ხარისხი და კონტროლი; 4სთ<br />(ბლოკი, ლესვა, მოჭიმვა,)<br />-კარფანჯრების მონტაჯის ხარისხი 1სთ<br />-&bdquo;სველი&ldquo; და ვინტილირებადი ფასადის ხარისხი 2სთ<br />-სახურავის სენდვიჩების ხარისხი 2სთ<br />-კეთილმოწყობა 2სთ<br />(ასფალტი, ბილიკები, ბორდიურები, გამწვანება)</p>\n<p><strong>კურსი მოიცავს: 8 ლექციას</strong></p>\n<p><strong>ლექციები ცატარდება: კვირაში 2 ჯერ</strong></p>\n<p><strong>კურსის ღირებულება: 600 ლარი</strong></p>\n<p><strong>საუკეთესო კურსდამთავრებულებს გავუწევთ რეკომენდაციებს და მოთხოვნის შესაბამისად ხელს შევუწყოთ დასაქმებაში!</strong></p>\n<p><strong>კურსს უძღვებიან: შოთა კოხრეიძე -&nbsp;</strong>პრაქტიკოსი ტრენერი, მშენებელი 20 წლიანი გამოცდილებით.</p>\n<p><strong>შეავსე სარეგისტრაციო ფორმა და დარეგისტრირდი ჯგუფში:</strong></p>\n<p>[registration]</p>', 'building control', '', '', 'https://vipintellect.ge/ge/bussines/building control', 'en', 4, 0, 0),
(358, 156, 72, 1771412535, 0, 'text', 'სამშენებლო ხარისხის კონტროლი', '<p>სამშენებლო ხარისხის კონტროლი</p>', '<p><strong>ვისთვის არის აღნიშნული პროგრამა:</strong><br />პროგრამის მიზანია კვალიფიკაცის ამაღლება და პროფსეიონალური უნარების შესწავლა, მათთვის ვისაც სურს ცოდნის შეძენა სამშენებლო წარმოებაზე და ხარისხის კონტროლზე.<br /><strong>ტრეინინგის თემატიკა:</strong><br />-მიწის სამუშაოების კონტროლი და ხარისხი 1სთ<br />-მონოლითის წარმოება და ხარისხის კონტროლი და მეთოდოლოგია 4სთ<br />-არქიტექტურული ნაწილის ხარისხი და კონტროლი; 4სთ<br />(ბლოკი, ლესვა, მოჭიმვა,)<br />-კარფანჯრების მონტაჯის ხარისხი 1სთ<br />-&bdquo;სველი&ldquo; და ვინტილირებადი ფასადის ხარისხი 2სთ<br />-სახურავის სენდვიჩების ხარისხი 2სთ<br />-კეთილმოწყობა 2სთ<br />(ასფალტი, ბილიკები, ბორდიურები, გამწვანება)</p>\n<p><strong>კურსი მოიცავს: 8 ლექციას</strong></p>\n<p><strong>ლექციები ცატარდება: კვირაში 2 ჯერ</strong></p>\n<p><strong>კურსის ღირებულება: 600 ლარი</strong></p>\n<p><strong>საუკეთესო კურსდამთავრებულებს გავუწევთ რეკომენდაციებს და მოთხოვნის შესაბამისად ხელს შევუწყოთ დასაქმებაში!</strong></p>\n<p><strong>კურსს უძღვებიან: შოთა კოხრეიძე -&nbsp;</strong>პრაქტიკოსი ტრენერი, მშენებელი 20 წლიანი გამოცდილებით.</p>\n<p><strong>შეავსე სარეგისტრაციო ფორმა და დარეგისტრირდი ჯგუფში:</strong></p>\n<p>[registration]</p>', 'building-control', '', '', '', 'ge', 4, 0, 0);
