(396, 198, 0, 1494187200, '2017-05-08', 'staff', 'მედეა ჯინჯიხაძე', '<p>საჯარო და კერძო სექტორის HR ბიზნეს პარტნიორების სასწავლო კურსის ტრენერი</p>', 'მრავალწლიანი სამუშაო გამოცდილების მქონე ექსპერტი ადამიანური რესურსების მართვისა და ბიზნეს კონსალტინგის სფეროში. ', 'empty', 'ge', 0, 0),
(397, 199, 0, 1572033600, '2019-10-26', 'news', 'ტრენინგ კურსი სამედიცინო ხარისხის კონტროლი და მართვა!', '<p>28 ოქტომბერს, ორშაბათს, 18 სთ 30 წთ-ზე ტარდება გაცნობითი საპრეენტაციო შეხვედრა ტრენინგზე: ,,სამედიცინო ხარისხის კონტროლი და მართვა\"!</p>', 'Hidden Field', 'empty', 'en', 0, 0),
(398, 199, 0, 1572033600, '2019-10-26', 'news', 'ტრენინგ კურსი სამედიცინო ხარისხის კონტროლი და მართვა!', '<p>28 ოქტომბერს, ორშაბათს, 18 სთ 30 წთ-ზე ტარდება გაცნობითი საპრეენტაციო შეხვედრა ტრენინგზე: ,,სამედიცინო ხარისხის კონტროლი და მართვა\"!</p>', 'Hidden Field', 'empty', 'ge', 0, 0),
(399, 200, 0, 1572033600, '2019-10-26', 'news', 'საშუალო და მცირე ზომის სასტუმროს მართვის კურსი იწყება!', '<p>29 ოქტომბერს 4 სთ-ზე ტარდება პირველი ლექია&nbsp;საშუალო და მცირე ზომის სასტუმროს მართვის კურსზე!</p>\n<h1 id=\"seo_h1_tag\" class=\"_5gmx\" data-testid=\"event-permalink-event-name\">&nbsp;</h1>', 'Hidden Field', 'empty', 'en', 0, 0),
