(443, 222, 0, 1662667200, '2022-09-09', 'news', 'ლოგისტიკა და შესყიდვების მართვა!', '<p>10 სექტემბერს 12 საათზე ვიწყებთ ახალ ჯგუფს!</p>\n<p>ჯერ კიდევ შეიძლება შემოგვიერთდეთ!</p>\n<p>კურსი მოიცავს 16 საათს</p>\n<p>კურსის ღირებულება : 550 ლარი</p>\n<p>&nbsp;</p>', 'Hidden Field', 'empty', 'en', 0, 0),
(444, 222, 0, 1662667200, '2022-09-09', 'news', 'ლოგისტიკა და შესყიდვების მართვა!', '<p>10 სექტემბერს 12 საათზე ვიწყებთ ახალ ჯგუფს!</p>\n<p>ჯერ კიდევ შეიძლება შემოგვიერთდეთ!</p>\n<p>კურსი მოიცავს 16 საათს</p>\n<p>კურსის ღირებულება : 550 ლარი</p>\n<p>&nbsp;</p>', 'Hidden Field', 'empty', 'ge', 0, 0),
(445, 223, 0, 1662667200, '2022-09-09', 'news', '12 სექტემბერს ვიწყებთ კტრენინგებს ჯანდაცვის მიმართულებით!', '<p>12 სექტემბერს 19 საათზე ტარდება ონლაინ საპრეზენტაციო შეხვედრა ჯანდაცვის მენეჯმენტის და სამედიცინო ხარისხის კონტროლის და მართვის კურსით დაინტერესებულ პირებთან!</p>\n<p>&nbsp;</p>', 'Hidden Field', 'empty', 'en', 0, 0),
(446, 223, 0, 1662667200, '2022-09-09', 'news', '12 სექტემბერს ვიწყებთ კტრენინგებს ჯანდაცვის მიმართულებით!', '<p>12 სექტემბერს 19 საათზე ტარდება ონლაინ საპრეზენტაციო შეხვედრა ჯანდაცვის მენეჯმენტის და სამედიცინო ხარისხის კონტროლის და მართვის კურსით დაინტერესებულ პირებთან!</p>\n<p>&nbsp;</p>', 'Hidden Field', 'empty', 'ge', 0, 0),
(447, 224, 0, 1662667200, '2022-09-09', 'news', 'ტურიზმის სკოლა აცხადებს მიღებას!', '<p>მიმდინარეობს ჯგუფების შევსება</p>\n<p>შემომყვანი ტურ ოპერატორი</p>\n<p>გამყვანი ტურ ოპერატორი</p>\n<p>რუსულენოვანი ტურიზმის გიდი</p>\n<p>ინგლისურენოვანი ტურიზმის გიდი</p>\n<p>სასტუმროს ადმინისტრატორის კურსი</p>', 'Hidden Field', 'empty', 'en', 0, 0),
